window.__QUIZ_SUBJECT__=[{"id": "objective>Commerce>1993>1", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The function of commerce in production is that it", "images": [], "options": {"A": "helps in the extraction of raw materials", "B": "provides a link between the different arms of production", "C": "is the only branch that satisfies wants", "D": "yields results"}, "answer": "B", "explanation": "The function of commerce in production is to provide a link between the different arms of production. Commerce facilitates the movement of goods and services from producers to consumers, ensuring that production processes are connected and efficient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>2", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Arrange the following occupational activities in the sequences in which they are performed    I. Wholesaling  II. Fishing  III. Canning  IV. Retailing", "images": [], "options": {"A": "I, II and IV", "B": "III, I, IV and III", "C": "II, I, IV and II", "D": "II, III, I and IV"}, "answer": "D", "explanation": "The correct sequence of activities is II (Fishing), III (Canning), I (Wholesaling), and IV (Retailing). Fishing is the primary activity where raw materials are obtained, followed by canning as a processing step, then wholesaling to distribute the products, and finally retailing to sell to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>3", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Which of the following is not a basic want of man?", "images": [], "options": {"A": "Transport", "B": "Food", "C": "Water", "D": "Clothing"}, "answer": "A", "explanation": "Transport is not a basic want of man; rather, it is a means to satisfy basic wants such as food, water, clothing, and shelter. Basic wants are essential for survival, while transport is a service that facilitates access to these wants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>4", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following comes last in the chain of distribution?", "images": [], "options": {"A": "Consumer", "B": "Manufacturer", "C": "Retailer", "D": "Wholesaler"}, "answer": "A", "explanation": "The consumer comes last in the chain of distribution. The chain typically flows from the manufacturer to the wholesaler, then to the retailer, and finally to the consumer, who is the end user of the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>5", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not an aid to trade?", "images": [], "options": {"A": "Transport", "B": "Production", "C": "Banking", "D": "Insurance"}, "answer": "B", "explanation": "Production is not considered an aid to trade; rather, it is the process of creating goods and services. Aids to trade include transport, banking, insurance, and warehousing, which support the distribution and sale of products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>6", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Trade can be described as", "images": [], "options": {"A": "Purchase of goods and services", "B": "Production of goods", "C": "Buying and selling", "D": "Distribution of goods"}, "answer": "C", "explanation": "Trade can be described as 'Buying and selling' because it involves the exchange of goods and services between parties. This definition encompasses the core activities of trade, which is fundamentally about the transaction process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>7", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "A system in which people provide their own needs directly is known as", "images": [], "options": {"A": "Sub-standard economy", "B": "Subsistence economy", "C": "Mixed economy", "D": "Monetized economy"}, "answer": "B", "explanation": "A system in which people provide their own needs directly is known as a 'Subsistence economy'. In this type of economy, individuals or communities produce most of what they need to survive, relying on their own resources rather than engaging in trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>8", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Which of the following is not a branch of production?", "images": [], "options": {"A": "Consumption", "B": "Extraction", "C": "Manufacturing", "D": "Distribution"}, "answer": "A", "explanation": "'Consumption' is not a branch of production. The branches of production typically include extraction (gathering raw materials), manufacturing (creating products), distribution (getting products to consumers), and direct services (providing services directly to consumers). Consumption refers to the use of goods and services, not their production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>9", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "In which class of occupation would doctors, teachers and entertainers be grouped?", "images": [], "options": {"A": "Extractive", "B": "Industrial", "C": "Direct service", "D": "Commercial"}, "answer": "C", "explanation": "Doctors, teachers, and entertainers are grouped under 'Direct service' occupations because they provide services directly to individuals or groups, fulfilling immediate needs and demands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>10", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following occupations come under the extractive industry?    I. Cattle-rearing, lumbering, farming  II. Mining, quarrying and hunting  III. Ship building, road construction, iron beding  IV. Singing, dancing, hair-dressing", "images": [], "options": {"A": "I, II and III only", "B": "I, II and IV only", "C": "I and II only", "D": "II, III and IV only"}, "answer": "C", "explanation": "Occupations that come under the extractive industry include 'I and II only', which are cattle-rearing, lumbering, farming (I) and mining, quarrying, and hunting (II). These activities involve extracting natural resources from the environment. Ship building, road construction, and hair-dressing do not fall under the extractive industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>11", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Department stores are usually located", "images": [], "options": {"A": "Where low income earners live", "B": "In surban towns", "C": "At city centers", "D": "In low rental areas"}, "answer": "C", "explanation": "Department stores are typically located at city centers because these areas have high foot traffic and accessibility, which are crucial for attracting customers. City centers often have a diverse population and are easily reachable by public transport, making them ideal for retail businesses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>12", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Which of the following statements is true of the manufacturing industry?", "images": [], "options": {"A": "The factors of production cannot move to other occupations", "B": "It is involved in changing raw materials to finished goods", "C": "Its products cannot be distributed to consumers", "D": "It does not benefit from the services of direct labour"}, "answer": "B", "explanation": "The manufacturing industry is primarily involved in transforming raw materials into finished goods. This process includes various stages such as processing, assembling, and packaging, which are essential for creating products that can be sold to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>13", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Any action taken by a company outside its stated objective is regarded as", "images": [], "options": {"A": "Caveat vendetta", "B": "A trespass", "C": "Ultra vires", "D": "Uberrimae fidei"}, "answer": "C", "explanation": "Any action taken by a company outside its stated objectives is referred to as 'ultra vires.' This legal term means 'beyond the powers' and indicates that the company is acting outside the scope of its authority as defined in its corporate charter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>14", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Incorporation simply means the", "images": [], "options": {"A": "Floating of a company", "B": "Reorganization of company", "C": "Birth of a company", "D": "Registration of the Memorandum of Association"}, "answer": "D", "explanation": "Incorporation refers to the legal process of forming a corporation, which includes the registration of the Memorandum of Association. This document outlines the company's objectives, structure, and governance, marking the official birth of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>15", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "What document is issued by a public limited company when offering shares for sales?", "images": [], "options": {"A": "Proposal forms", "B": "Policy certificate", "C": "Prospectus", "D": "Quotation"}, "answer": "C", "explanation": "A prospectus is a formal document issued by a public limited company when offering shares for sale. It provides detailed information about the company, its financial status, and the terms of the share offering, helping potential investors make informed decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>16", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A business unit whose membership ranges from 2 -50 is a", "images": [], "options": {"A": "Public corporation", "B": "Partnership", "C": "Public company", "D": "Private company"}, "answer": "B", "explanation": "A business unit whose membership ranges from 2-50 is typically classified as a Partnership. Partnerships are formed by two or more individuals who agree to share the profits and losses of a business. The other options do not fit this membership criterion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>17", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "Founders shares are usually referred to as deferred shares because the holders", "images": [], "options": {"A": "Are not entitled to any dividend", "B": "Receives their dividends before other shareholders", "C": "Are the managers of company", "D": "Receive dividends after other shareholders"}, "answer": "D", "explanation": "Founders shares are often referred to as deferred shares because the holders receive dividends after other shareholders. This means that they are typically paid last in the distribution of dividends, which is why they are considered 'deferred'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>18", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "Preference shareholders are different from ordinary shareholders because", "images": [], "options": {"A": "Preference shareholders are creditors to the company", "B": "The number of shares held by preference shareholders is more", "C": "Preference shareholders take a fixed percentage of dividends", "D": "The shares of preference shareholders cannot be sold on the stock exchange"}, "answer": "C", "explanation": "Preference shareholders are different from ordinary shareholders primarily because they receive a fixed percentage of dividends before any dividends are paid to ordinary shareholders. This fixed dividend is a key characteristic of preference shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>19", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The reward of share holding in a company is", "images": [], "options": {"A": "Profit", "B": "Dividend", "C": "Interest", "D": "Bonus"}, "answer": "B", "explanation": "The reward of shareholding in a company is typically referred to as a Dividend. Dividends are payments made to shareholders out of the company's profits, representing a share of the earnings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>20", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of capital to a sole proprietor?", "images": [], "options": {"A": "Loan from friends", "B": "Personal savings", "C": "Ploughing back profit", "D": "Borrowing through debentures"}, "answer": "D", "explanation": "Borrowing through debentures is not a source of capital for a sole proprietor. Debentures are a form of long-term debt instrument used by companies to borrow money, and they are not applicable to sole proprietorships, which typically rely on personal savings, loans from friends, and other personal sources for capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>21", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is not an important reason for government ownership of industries?", "images": [], "options": {"A": "Provision of essential services", "B": "Large capital requirements", "C": "Avoiding duplication of services", "D": "Making high profit"}, "answer": "D", "explanation": "The option 'Making high profit' is not an important reason for government ownership of industries. Governments typically nationalize industries to provide essential services, avoid duplication, and prevent monopolies, rather than to maximize profits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>22", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "In a limited partnership, the liability of most of the partners is", "images": [], "options": {"A": "Pegged", "B": "Unlimited", "C": "Limited", "D": "Unpredictable"}, "answer": "C", "explanation": "In a limited partnership, the liability of most partners is 'Limited'. This means that their financial liability is restricted to the amount they invested in the partnership, unlike general partners who have unlimited liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>23", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "The rights, responsibilities and liabilities of each partner are specified in the", "images": [], "options": {"A": "Memorandum of association", "B": "Prospectus", "C": "Articles of association", "D": "Deed of partnership"}, "answer": "D", "explanation": "The rights, responsibilities, and liabilities of each partner in a partnership are specified in the 'Deed of partnership'. This legal document outlines the terms of the partnership agreement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>24", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following statements is not true?", "images": [], "options": {"A": "Government does not nationalize business owned by its citizens", "B": "Government nationalizes foreign businesses", "C": "Government does not give nationalized industries to private owners", "D": "Government nationalizes viable industries"}, "answer": "A", "explanation": "The statement 'Government does not nationalize business owned by its citizens' is not true. Governments can nationalize businesses owned by citizens, especially in cases where they believe it is in the public interest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>25", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "When an industry is nationalized, ownership belongs to the", "images": [], "options": {"A": "Shareholders", "B": "Government", "C": "Tax payers", "D": "Indigenes"}, "answer": "B", "explanation": "When an industry is nationalized, ownership belongs to the 'Government'. Nationalization means that the government takes control of the industry, making it publicly owned rather than privately owned.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>26", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "Which of the following are advantages of indigenization?    I. The economy is controlled by the nationals  II. Entrepreneurial skill is developed  III. Foreigners are encouraged to invest in Nigeria  IV. The standard of living of the indigenes is improved", "images": [], "options": {"A": "I and II only", "B": "I, II and III only", "C": "III and IV only", "D": "I, II and IV only"}, "answer": "D", "explanation": "The advantages of indigenization include that the economy is controlled by the nationals (I), entrepreneurial skills are developed (II), and the standard of living of the indigenes is improved (IV). However, option III is incorrect because indigenization typically discourages foreign investment rather than encouraging it. Therefore, the correct answer is 'I, II and IV only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>27", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "NATIONALIZATION AND PRIVATIZATION", "question": "One of the main problems of nationalization is that", "images": [], "options": {"A": "Nationals may not welcome the change of ownership", "B": "Foreigners are not able to control the economy", "C": "Repatriation of profit is increased", "D": "There may be capital flight"}, "answer": "A", "explanation": "One of the main problems of nationalization is that nationals may not welcome the change of ownership. This can lead to resistance and lack of support for the nationalized entities, which can hinder their effectiveness and success.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>28", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "NATIONALIZATION AND PRIVATIZATION", "question": "The process of selling government business to the public is known as", "images": [], "options": {"A": "Naturalization", "B": "Nationalization", "C": "Privatization", "D": "Commercialization"}, "answer": "C", "explanation": "The process of selling government business to the public is known as privatization. This involves transferring ownership of a public sector enterprise to private individuals or organizations, which is aimed at increasing efficiency and competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>29", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "The handling of telephone and telex services is done by", "images": [], "options": {"A": "NITEL", "B": "NIPOST", "C": "COURIER", "D": "NEC"}, "answer": "A", "explanation": "The handling of telephone and telex services is primarily done by NITEL (Nigerian Telecommunications Limited), which was the main telecommunications provider in Nigeria. NIPOST is responsible for postal services, while COURIER, NEC, and NECA do not specifically handle telephone and telex services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>30", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "A Post Office service which provides an alternative to delivery of mails by a postman is the", "images": [], "options": {"A": "Post Office Box", "B": "Postcode", "C": "Post Office Guide", "D": "Business Reply Service"}, "answer": "A", "explanation": "A Post Office service that provides an alternative to delivery of mails by a postman is the Post Office Box. This service allows individuals and businesses to receive their mail at a secure location rather than at their home or office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>31", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A service whereby NIPOST undertakes to collect money due to the sender of a parcel is called", "images": [], "options": {"A": "C.O.D", "B": "C.W.O", "C": "C.I.F", "D": "F.O.B"}, "answer": "A", "explanation": "The service where NIPOST collects money due to the sender of a parcel is known as C.O.D (Cash on Delivery). This service allows the sender to receive payment for the parcel upon delivery, ensuring that the sender is compensated before the recipient takes possession of the item.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>32", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "The cost of advertising a product is ultimately borne by the", "images": [], "options": {"A": "Manufacturer", "B": "Wholesaler", "C": "Agent", "D": "Consumer"}, "answer": "D", "explanation": "The cost of advertising a product is ultimately borne by the consumer. This is because the expenses incurred in advertising are typically passed down the supply chain, leading to higher prices for the end consumer who ultimately pays for the marketing efforts through the price of the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>33", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is used to stimulate sales?", "images": [], "options": {"A": "Finance", "B": "Insurance", "C": "Warehousing", "D": "Advertising"}, "answer": "D", "explanation": "Advertising is used to stimulate sales. It involves promoting a product or service to increase awareness and encourage purchases. Effective advertising can create demand and influence consumer behavior, leading to increased sales.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>34", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Which of the following assigns a name to a product?", "images": [], "options": {"A": "Copyright", "B": "Packaging", "C": "Labelling", "D": "Patent"}, "answer": "C", "explanation": "Labelling is the process that assigns a name to a product. It involves providing information about the product, including its name, ingredients, usage instructions, and other relevant details. Labelling is crucial for branding and consumer recognition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>35", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The insured is prevented from making profit from claims under more than one policy for the same risk by the principle of", "images": [], "options": {"A": "Contribution", "B": "Subrogation", "C": "Utmost good faith", "D": "Proximate cause"}, "answer": "A", "explanation": "The principle of Contribution prevents the insured from making a profit from claims under more than one policy for the same risk. This principle ensures that if a loss occurs, the insured can only recover the actual loss suffered, rather than profiting from multiple insurance claims.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>36", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is a form of sales promotion?", "images": [], "options": {"A": "Advertising through radio", "B": "Advertising by television", "C": "Distributing printed sales literature", "D": "Offering free samples to customers"}, "answer": "D", "explanation": "Offering free samples to customers is a direct form of sales promotion as it encourages potential buyers to try a product without any cost, which can lead to increased sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>37", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "The performance of business activities that directs the flow of goods and services from the producer to the consumer is", "images": [], "options": {"A": "Marketing", "B": "Merchandising", "C": "Transportation", "D": "Production"}, "answer": "A", "explanation": "Marketing is the performance of business activities that directs the flow of goods and services from the producer to the consumer. It encompasses various activities including advertising, sales, and distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>38", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not an element of the marketing mix?", "images": [], "options": {"A": "Product", "B": "Pricing", "C": "Promotion", "D": "Purchases"}, "answer": "D", "explanation": "Purchases are not considered an element of the marketing mix. The marketing mix typically includes Product, Price, Promotion, and Place (the 4 Ps).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>39", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "The concept that consumers decide what goods and services shall be produced is known as consumer", "images": [], "options": {"A": "Protection", "B": "Surplus", "C": "Sovereignty", "D": "Behaviour"}, "answer": "C", "explanation": "Consumer sovereignty refers to the concept that consumers dictate what goods and services are produced based on their preferences and purchasing decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>40", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "A person who sells goods belonging to another person in his own name and received commission is a", "images": [], "options": {"A": "Wholesaler", "B": "Retailer", "C": "Sole trader", "D": "Factor"}, "answer": "D", "explanation": "A factor is a person who sells goods belonging to another person in his own name and receives a commission. This role is distinct from wholesalers and retailers, who typically sell their own goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>41", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "When an insured person admits that he has indemnified, he means that", "images": [], "options": {"A": "The insurance company has accepted his claims", "B": "The damaged property has been recovered", "C": "He has paid his premium fully", "D": "The insurance company has restored him to his former position"}, "answer": "D", "explanation": "When an insured person admits that he has indemnified, it means that the insurance company has restored him to his former position. Indemnification in insurance refers to the process of compensating the insured for their loss, thereby restoring them to the financial state they were in before the loss occurred.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>42", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The difference between an overdraft and a loan is that an overdraft", "images": [], "options": {"A": "Does not yield interest", "B": "Is given to savings account holders only", "C": "Yields interest on the total balance in the account", "D": "Yields interest only on the sum drawn"}, "answer": "D", "explanation": "The difference between an overdraft and a loan is that an overdraft yields interest only on the sum drawn. An overdraft allows a customer to withdraw more money than they have in their account, and interest is charged only on the amount overdrawn, unlike a loan which typically has a fixed interest rate on the entire amount borrowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>43", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The excess value of the assets of a business owner its liabilities is", "images": [], "options": {"A": "Capital owned", "B": "Working capital", "C": "Issued capital", "D": "Liquid capital"}, "answer": "A", "explanation": "The excess value of the assets of a business over its liabilities is referred to as capital owned. This represents the net worth of the business, which is calculated by subtracting total liabilities from total assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>44", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Cash is said to be legal tender because it", "images": [], "options": {"A": "Can be converted into money order", "B": "Can be offered and accepted for payment", "C": "Is negotiable", "D": "Also takes the form of bank draft"}, "answer": "B", "explanation": "Cash is said to be legal tender because it can be offered and accepted for payment. Legal tender is a medium of payment recognized by the law that must be accepted if offered in payment of a debt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>45", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cross postal order is", "images": [], "options": {"A": "Generally acceptable for payment", "B": "Easily converted to cash", "C": "The same as money order", "D": "Cashed through a post office"}, "answer": "D", "explanation": "A cross postal order is cashed through a post office. A cross postal order is a type of money order that is crossed, meaning it can only be deposited into a bank account and not cashed directly, which is typically done at a post office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>46", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A bank whose name is printed on a cheque leaf is known as the", "images": [], "options": {"A": "Drawer", "B": "Payer", "C": "Drawee", "D": "Payee"}, "answer": "C", "explanation": "The bank whose name is printed on a cheque leaf is known as the Drawee. The drawee is the bank that is responsible for paying the amount specified on the cheque when it is presented for payment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>47", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "A person who wants to undertake an insurance policy usually completes", "images": [], "options": {"A": "A proposal form", "B": "A promotion form", "C": "An application form", "D": "An agreement form"}, "answer": "A", "explanation": "A person who wants to undertake an insurance policy usually completes a proposal form. This form is a formal request for insurance coverage and includes details about the individual and the type of insurance they are seeking.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>48", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The capital that is needed to meet the day-to-day running of a business is the", "images": [], "options": {"A": "Fixed capital", "B": "Reserved capital", "C": "Circulating capital", "D": "Liquid capital"}, "answer": "C", "explanation": "The capital that is needed to meet the day-to-day running of a business is known as Circulating capital. This type of capital is used for the ongoing operational expenses of a business, such as inventory and wages.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>49", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES", "question": "An association of local, independent retailers formed to encourage buying in bulk from manufacturers is known as", "images": [], "options": {"A": "Voluntary chain", "B": "Producer co-operative society", "C": "Multiple store", "D": "Department store"}, "answer": "A", "explanation": "An association of local, independent retailers formed to encourage buying in bulk from manufacturers is known as a Voluntary chain. This type of organization allows retailers to benefit from collective purchasing power while maintaining their independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>50", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Third Party Insurance covers, damages", "images": [], "options": {"A": "To both passengers and the vehicle", "B": "Caused by the vehicle insured", "C": "To all parties concerned", "D": "To both vehicles involved"}, "answer": "C", "explanation": "Third Party Insurance covers damages to all parties concerned. This type of insurance protects the insured from claims made by others for damages or injuries caused by the insured's vehicle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>51", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A bank may dishonour a cheque if", "images": [], "options": {"A": "It is not crossed", "B": "An alteration on the cheque is initial", "C": "The amount on the cheques is less than the amount in the account", "D": "The amount on the cheque is more than the amount in the account"}, "answer": "D", "explanation": "A bank may dishonour a cheque if the amount on the cheque is more than the amount in the account. This is because the bank cannot process a cheque that exceeds the available balance, as it would result in an overdraft unless prior arrangements have been made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>52", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "Which of the following is not one of the 4m's of business resources?", "images": [], "options": {"A": "Method", "B": "Men", "C": "Money", "D": "Machine"}, "answer": "D", "explanation": "The 4M's of business resources typically refer to Men, Money, Material, and Method. 'Machine' is not one of the 4M's, making it the correct answer to the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>53", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "The charge paid for failing to off-load a vehicle within a stipulated time is called", "images": [], "options": {"A": "Freight", "B": "Demurrage", "C": "Fare", "D": "Floating charge"}, "answer": "B", "explanation": "The charge paid for failing to off-load a vehicle within a stipulated time is called 'Demurrage'. Demurrage is a term used in shipping and logistics that refers to the fees incurred when cargo is not loaded or unloaded within the agreed timeframe. This charge compensates the carrier for the additional time the vehicle is held up, which could have been used for other shipments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>54", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The working capital of a company is", "images": [], "options": {"A": "Current assets less current liabilities", "B": "Fixed assets less current liabilities", "C": "Fixed assets less fixed liabilities", "D": "Current assets less fixed liabilities"}, "answer": "A", "explanation": "The working capital of a company is defined as current assets less current liabilities. This measure indicates the short-term financial health of a company and its efficiency in using its assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>55", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : MEANING & SCOPE", "question": "Which of the following defines communication?", "images": [], "options": {"A": "Movement of goods", "B": "Transmission of information", "C": "Movement of people", "D": "Storing of information"}, "answer": "B", "explanation": "Communication is defined as the transmission of information. This encompasses the exchange of messages, ideas, or data between individuals or groups, which is fundamental in both personal and business contexts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>56", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : MEANING & SCOPE", "question": "The telephone service through which one can dial any number, local, trunk or overseas is known as", "images": [], "options": {"A": "Internal communication system", "B": "Standard dialling system", "C": "Subscriber's trunk dialling system", "D": "International telecommunication"}, "answer": "C", "explanation": "The telephone service that allows one to dial any number, whether local, trunk, or overseas, is known as the Subscriber's Trunk Dialling (STD) system. This system enables direct dialing without the need for operator assistance, facilitating easier communication over long distances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>57", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following is not a function of warehousing?", "images": [], "options": {"A": "Production in anticipation of demand", "B": "Availability of goods where needed", "C": "Availability of goods when needed", "D": "Reduction of price fluctuations"}, "answer": "A", "explanation": "The function of warehousing includes providing storage facilities, ensuring availability of goods where and when needed, and reducing price fluctuations. However, 'Production in anticipation of demand' is not a function of warehousing; it is related to production planning and inventory management. T", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>58", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Goods discharged from ships on which import duties have not been paid are kept in the", "images": [], "options": {"A": "Ordinary warehouse", "B": "Private warehouse", "C": "Public warehouse", "D": "Bonded warehouse"}, "answer": "D", "explanation": "Goods discharged from ships on which import duties have not been paid are kept in a 'Bonded warehouse'. This type of warehouse allows for the storage of goods without the payment of duties until they are released for sale. Therefore, the correct option is E.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>59", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "The machine used in sending telex messages is known as", "images": [], "options": {"A": "Photocopier", "B": "Typewriter", "C": "Teleprinter", "D": "Punching machine"}, "answer": "C", "explanation": "The machine used in sending telex messages is known as a 'Teleprinter'. A teleprinter is a device that can send and receive typed messages over a communication line, making it suitable for telex communication. Therefore, the correct option is C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>60", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "which of the following services is not rendered by NIPOST?", "images": [], "options": {"A": "Poste Retante", "B": "Express delivery", "C": "C.W.O", "D": "Telegram"}, "answer": "C", "explanation": "NIPOST (Nigerian Postal Service) provides various services, including registered post, telegrams, express delivery, and Poste Retante. However, 'C.W.O' (which stands for Cash on Delivery) is not a service rendered by NIPOST. Therefore, the correct option is C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>61", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "Which of the following is the safest means of sending a postal order from Lagos to a friend in Jos?", "images": [], "options": {"A": "Registered letter", "B": "Recorded delivery", "C": "Railex", "D": "First class man"}, "answer": "A", "explanation": "The safest means of sending a postal order from Lagos to a friend in Jos would be through a 'Registered letter'. Registered letters provide a tracking system and require a signature upon delivery, ensuring the safety of the contents. Therefore, the correct option is A.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>62", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following protects consumers against poor quality goods?", "images": [], "options": {"A": "Nigerian Chambers of Commerce", "B": "Standard Organization of Nigeria", "C": "Trade Association", "D": "Manufacturing Association of Nigeria"}, "answer": "B", "explanation": "The Standard Organization of Nigeria (SON) is responsible for setting standards and ensuring the quality of goods and services in Nigeria. It protects consumers by ensuring that products meet certain quality standards, thus safeguarding against poor quality goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>63", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following terms of price quotation includes cost of transportation to the buyer's premises?", "images": [], "options": {"A": "FOB", "B": "C & F", "C": "FOR", "D": "FAS"}, "answer": "B", "explanation": "C & F (Cost and Freight) includes the cost of goods and the cost of transportation to the buyer's premises. This term indicates that the seller pays for the transportation of the goods to a specified port, but the risk is transferred to the buyer once the goods are loaded onto the shipping vessel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>64", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Net Profit is the", "images": [], "options": {"A": "Excess of income over expenses", "B": "Total income from the sale of goods", "C": "Difference between sales and purchases", "D": "Amount of purchase less closing stock"}, "answer": "A", "explanation": "Net Profit is defined as the excess of income over expenses. It represents the actual profit made by a business after all costs, including operating expenses, interest, taxes, and depreciation, have been deducted from total revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>65", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Who is liable for the contract entered into by the agent on behalf of his principal? The", "images": [], "options": {"A": "Agent", "B": "Principal", "C": "Agent and the principal", "D": "Third party"}, "answer": "B", "explanation": "In a principal-agent relationship, the principal is liable for the contracts entered into by the agent on their behalf, as long as the agent acts within the scope of their authority. The agent acts as a representative of the principal, and thus the principal bears the responsibility for the agent's actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>66", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "An installmental buying system where ownership immediately transfers to the buyer is known as", "images": [], "options": {"A": "Deferred payment", "B": "Hire-purchase", "C": "Spot buying", "D": "Cash sales"}, "answer": "B", "explanation": "Hire-purchase is an installment buying system where ownership of the goods is transferred to the buyer immediately upon the signing of the agreement, even though payment is made in installments. This contrasts with other systems where ownership is retained by the seller until full payment is made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>67", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "A document that is sent to a buyer when credit is not allowed is", "images": [], "options": {"A": "Invoice", "B": "Consignment note", "C": "Debit note", "D": "proforma invoice"}, "answer": "A", "explanation": "An invoice is a document that requests payment for goods or services provided. When credit is not allowed, the seller sends an invoice to the buyer to indicate the amount due for immediate payment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>68", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is true of a delivery note? It", "images": [], "options": {"A": "Is sent in anticipation of delivery", "B": "Does not show the prices of the goods", "C": "Gives additional information about the goods", "D": "Shows the pictures of goods being delivered"}, "answer": "B", "explanation": "A delivery note is a document that accompanies a shipment of goods. It typically does not show prices, as its primary purpose is to confirm the delivery of goods and provide details about the items delivered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>69", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "A parcel of shoes valued at #2,000 was invoiced0 at #200 only. Which of the following would be used by the seller to correct this error?", "images": [], "options": {"A": "An invoice for #2,000", "B": "A credit note for #1,800", "C": "A debit note for #1,800", "D": "A debit note for #2,000"}, "answer": "C", "explanation": "To correct the invoicing error where a parcel of shoes valued at #2,000 was invoiced at #200, the seller would issue a debit note for the difference. A debit note is used to indicate an increase in the amount owed by the buyer, correcting the original invoice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>70", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "An increase in turnover is an increase in", "images": [], "options": {"A": "Liquid capital", "B": "The volume of sales", "C": "Current assets", "D": "Fixed assets"}, "answer": "B", "explanation": "An increase in turnover refers to an increase in the volume of sales. Turnover is a measure of the total sales generated by a business over a specific period, and an increase indicates that the business is selling more products or services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>71", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "A retailer's mark-up is", "images": [], "options": {"A": "Profit divided by the average stock", "B": "Sales divided by the average stock", "C": "Gross profit less indirect expenses", "D": "The selling price less the cost price"}, "answer": "D", "explanation": "A retailer's mark-up is defined as the selling price less the cost price. It represents the difference between the cost of goods sold and the price at which they are sold, reflecting the retailer's profit margin.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>72", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Foreign trade is also known as", "images": [], "options": {"A": "Domestic trade", "B": "International trade", "C": "Counter trade", "D": "Entreport trade"}, "answer": "B", "explanation": "Foreign trade refers to the exchange of goods and services between countries, which is commonly known as international trade. This term encompasses all trade activities that occur across national borders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>73", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following documents in foreign trade states where goods are manufactured?", "images": [], "options": {"A": "Bill of lading", "B": "Consular invoice", "C": "Certificate of Origin", "D": "Insurance Certificate"}, "answer": "C", "explanation": "The Certificate of Origin is a document used in international trade that certifies the country in which the goods were manufactured. It is important for customs purposes and to determine tariffs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>74", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "New shares are offered to the public through", "images": [], "options": {"A": "Acceptance houses", "B": "The stock exchange", "C": "Issuing houses", "D": "Discount houses"}, "answer": "C", "explanation": "New shares are typically offered to the public through issuing houses, which are financial institutions that specialize in the issuance of new securities. They help companies raise capital by facilitating the sale of shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>75", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Speed is an important consideration for the choice of a means of transport where goods are", "images": [], "options": {"A": "Bulky", "B": "Inferior", "C": "Fragile", "D": "Perishable"}, "answer": "D", "explanation": "Speed is particularly crucial for the transport of perishable goods, such as food items, which can spoil quickly. Therefore, choosing a fast means of transport is essential to ensure these goods reach their destination in good condition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>76", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The main disadvantage of water transport is that it", "images": [], "options": {"A": "Is safe", "B": "Is slow", "C": "Can carry heavy goods", "D": "Can go long distances"}, "answer": "B", "explanation": "The main disadvantage of water transport is that it is generally slow compared to other modes of transport, such as air or road transport. While it can carry heavy goods and travel long distances, the speed factor is a significant drawback.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>77", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "A company that acquires a majority of the shares of other companies with voting rights is regarded as", "images": [], "options": {"A": "A consortium", "B": "A holding company", "C": "An amalgamator", "D": "A subsidiary company"}, "answer": "B", "explanation": "A company that acquires a majority of the shares of other companies with voting rights is known as a holding company. A holding company does not necessarily produce goods or services itself; rather, it owns shares of other companies to control them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>78", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Air transport is of considerable importance today because it", "images": [], "options": {"A": "Is faster than other means of transport", "B": "Can deliver goods to owner's destination", "C": "Is relatively cheaper", "D": "Can carry bulky goods"}, "answer": "A", "explanation": "Air transport is considered important today primarily because it is faster than other means of transport. This speed allows for quick delivery of goods and passengers over long distances, making it a preferred choice for time-sensitive shipments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>79", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "When goods are sold, which of the following makes the transfer of ownership effective?", "images": [], "options": {"A": "Banking", "B": "Transportation", "C": "Communication", "D": "Warehousing"}, "answer": "B", "explanation": "The transfer of ownership of goods is made effective through transportation. Once goods are physically delivered to the buyer, ownership is transferred, which is a fundamental principle in sales transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>80", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "The organization that aims at protecting the business interests of a particular area is the", "images": [], "options": {"A": "Trade Association", "B": "Manufacturers Association of Nigeria", "C": "Chamber of Commerce", "D": "Confederation of Industrialists"}, "answer": "C", "explanation": "The organization that aims at protecting the business interests of a particular area is known as the Chamber of Commerce. This organization advocates for the interests of businesses in a specific region and provides support and resources to its members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>81", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following are advantages of road over air transport?    I. Flexibility  II. Speed  III. Cost  IV. Delivery to owners destination  V. Comfort", "images": [], "options": {"A": "I, III and IV only", "B": "I, II, III and V only", "C": "II, III and V only", "D": "I, II and IV only"}, "answer": "A", "explanation": "The advantages of road transport over air transport include flexibility, cost-effectiveness, and the ability to deliver directly to the owner's destination. While speed is generally an advantage of air transport, road transport offers more flexibility in routes and schedules, making it suitable for many types of deliveries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>82", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES", "question": "A group of persons that agrees to pool its resources to achieve a particular objective is known as a", "images": [], "options": {"A": "Consortium", "B": "Holding company", "C": "Cartel", "D": "Trust"}, "answer": "A", "explanation": "A consortium is a group of individuals or organizations that come together to pool their resources for a common goal. This aligns with the definition provided in the question.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>83", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "If a motor assembly  plant absorbs a tyre manufacturing company solely for its tyre needs, such an arrangement is known as", "images": [], "options": {"A": "Vertical integration", "B": "lateral integration", "C": "Horizontal integration", "D": "Diagonal integration"}, "answer": "A", "explanation": "Vertical integration occurs when a company expands its operations into different stages of production within the same industry. In this case, the motor assembly plant absorbing a tyre manufacturing company for its tyre needs is an example of vertical integration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>84", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is formed with a view to fixing output for members so that price is maintained at a high level?", "images": [], "options": {"A": "Price Control Board", "B": "Chamber of Commerce", "C": "Cartels", "D": "Holding Companies"}, "answer": "C", "explanation": "Cartels are formed by a group of producers to regulate production, fix prices, and limit competition among themselves, which helps maintain high prices. This matches the description in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>85", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is not the function of a Trade Association?", "images": [], "options": {"A": "Conducting research", "B": "Providing technical information", "C": "Giving credit facilities", "D": "Settling disputes among member"}, "answer": "C", "explanation": "Trade Associations typically do not provide credit facilities; their primary functions include conducting research, providing technical information, settling disputes among members, and educating members. Therefore, 'Giving credit facilities' is not a function of a Trade Association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>86", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "The act whereby a manager assigns some of his duties and powers t a subordinate is known as", "images": [], "options": {"A": "Authority", "B": "Assignment", "C": "Decision making", "D": "Delegation"}, "answer": "D", "explanation": "Delegation is the process by which a manager assigns some of their responsibilities and authority to subordinates. This is the correct term for the action described in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>87", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is a compulsory requirement by the commercial banks when granting loans to customers?", "images": [], "options": {"A": "Collateral", "B": "Referee", "C": "Interest", "D": "Insurance"}, "answer": "A", "explanation": "Collateral is a compulsory requirement for commercial banks when granting loans. It serves as security for the loan, ensuring that the bank can recover its funds in case the borrower defaults.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>88", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "One advantage of personal selling is the", "images": [], "options": {"A": "Low cost", "B": "Immediate feedback", "C": "Appeal to many people at a time", "D": "Self service"}, "answer": "B", "explanation": "One advantage of personal selling is the immediate feedback it provides. Sales representatives can engage directly with customers, allowing them to address concerns and adjust their sales approach in real-time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>89", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "An author's exclusive right to his published and unpublished work is known as", "images": [], "options": {"A": "Patent right", "B": "Fundamental human right", "C": "Copy right", "D": "Authorship"}, "answer": "C", "explanation": "An author's exclusive right to his published and unpublished work is known as copyright. Copyright protects the creator's intellectual property, allowing them to control the use and distribution of their work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>90", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following media combines the advantages of sound and motion?", "images": [], "options": {"A": "Radio", "B": "Neon sign", "C": "Bill Board", "D": "Television"}, "answer": "D", "explanation": "Television combines the advantages of sound and motion, making it a powerful medium for communication and advertising. It engages viewers through both auditory and visual stimuli.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>91", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Which of the following is not an essential element of a contract?", "images": [], "options": {"A": "Offer and acceptance", "B": "All contracts must be in writing", "C": "Intention to create legal relations", "D": "legality of the object"}, "answer": "B", "explanation": "Not all contracts must be in writing to be valid; many can be oral or implied. The essential elements of a contract include offer and acceptance, intention to create legal relations, legality of the object, and consideration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>92", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "What is the total number of the member countries of ECOWAS?", "images": [], "options": {"A": "14", "B": "15", "C": "16", "D": "17"}, "answer": "B", "explanation": "The Economic Community of West African States (ECOWAS) has 15 member countries. This organization was established to promote economic integration and cooperation among its member states.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>93", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following measures cannot be used to correct a balance of payment deficit in Nigeria?", "images": [], "options": {"A": "Imposing import licenses", "B": "Devaluing the Naira", "C": "Placing total ban on some commodities", "D": "Increasing imports"}, "answer": "D", "explanation": "Increasing imports cannot be used to correct a balance of payment deficit, as it would likely worsen the deficit by increasing the outflow of foreign currency. Other measures like imposing import licenses, devaluing the Naira, and increasing import duties are typically used to reduce imports and improve the balance of payments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1993>94", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "A foreign bill of exchange is drawn by the", "images": [], "options": {"A": "Importer", "B": "Shipping and forwarding agent", "C": "Importer's bank", "D": "Exporter"}, "answer": "D", "explanation": "A foreign bill of exchange is typically drawn by the exporter. This document is used in international trade to facilitate payment for goods and services, and it represents a promise to pay a specified amount at a future date.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>95", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "The main objective of ECOWAS is", "images": [], "options": {"A": "Promoting economic cooperation and development", "B": "Promoting industry", "C": "Promoting transport", "D": "Promoting agricultural production"}, "answer": "A", "explanation": "The main objective of ECOWAS is to promote economic cooperation and development among its member states. This includes fostering trade, investment, and economic growth in the region.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>96", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The retailer operates from a stall while the wholesaler operates from a", "images": [], "options": {"A": "Supermarket", "B": "Mobile shop", "C": "Hypermarket", "D": "Warehouse"}, "answer": "D", "explanation": "The retailer typically operates from a stall or a shop, while the wholesaler operates from a warehouse. A warehouse is a large building where goods are stored before being distributed to retailers or customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1993>97", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following is not an insurable risk?", "images": [], "options": {"A": "Fire accident", "B": "Life assurance", "C": "Burglary", "D": "Loss of profit"}, "answer": "D", "explanation": "Loss of profit is not an insurable risk because it is not a direct physical loss or damage. Insurable risks typically involve tangible assets or liabilities, while loss of profit is a financial consequence that arises from other events, such as a fire or burglary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>98", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is the basic function of a Personnel Department?", "images": [], "options": {"A": "Recruiting staff", "B": "Organizing training for staff dependents", "C": "Settling disputes among trade unions", "D": "Processing staff salaries and wages"}, "answer": "A", "explanation": "The basic function of a Personnel Department is recruiting staff. This involves identifying staffing needs, attracting candidates, and selecting individuals to fill those positions, which is fundamental to the department's role in managing human resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>99", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The management techniques that anticipates the future and determines the appropriate line of action is known as", "images": [], "options": {"A": "Planning", "B": "Organizing", "C": "Consulting", "D": "Directing"}, "answer": "A", "explanation": "Planning is the management technique that anticipates the future and determines the appropriate line of action. It involves setting objectives and outlining the steps necessary to achieve them, which is essential for effective management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1993>100", "subject": "Commerce", "year": "1993", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Span of control is the", "images": [], "options": {"A": "Ability of the supervisor to control the staff", "B": "Qualification possessed by the supervisor", "C": "Number of staff under the control of a supervisor", "D": "Authority of the supervisor to control the staff"}, "answer": "C", "explanation": "Span of control refers to the number of staff under the control of a supervisor. It is a key concept in organizational structure, as it affects how effectively a supervisor can manage their team and ensure efficient communication and oversight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>1", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Which of the following is not true of commerce?", "images": [], "options": {"A": "It is part of production", "B": "It creates time and place utility", "C": "It is the life blood of a nation's economic activities", "D": "Commercialization activities began after the goods are produced"}, "answer": "A", "explanation": "The statement 'It is part of production' is not true of commerce. Commerce is primarily concerned with the distribution and sale of goods and services, while production refers to the creation of goods. Therefore, commerce does not directly involve the production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>2", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Capital owned is the same as", "images": [], "options": {"A": "authorised capital", "B": "issued capital", "C": "net worth of a business", "D": "fixed assets of a business"}, "answer": "C", "explanation": "Capital owned refers to the net worth of a business, which is the total assets minus total liabilities. This is a measure of the financial health of a business and indicates the owner's equity in the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>3", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A business that has no upper limit to the number of owners is", "images": [], "options": {"A": "partnership", "B": "private company", "C": "finance company", "D": "public limited company"}, "answer": "D", "explanation": "A public limited company is a business that can have an unlimited number of owners (shareholders). This type of company can sell shares to the public, which allows for a larger pool of capital and ownership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>4", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An agreement between two parties which can be enforced is called", "images": [], "options": {"A": "an agency", "B": "a contract", "C": "a consideration", "D": "an offer"}, "answer": "B", "explanation": "An agreement between two parties that can be enforced by law is called a contract. Contracts are legally binding agreements that outline the rights and obligations of the parties involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>5", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following terms related to insurance?    I. Proximate cause  II. Letter of hypothecation  III. Indemnity  IV. Caveat emptor  V. Uberimae fidei", "images": [], "options": {"A": "I, II and IV only", "B": "II, IV and V only", "C": "I, III and V only", "D": "II, III and V only"}, "answer": "C", "explanation": "The terms related to insurance are proximate cause, indemnity, and uberimae fidei. Proximate cause refers to the primary cause of a loss, indemnity is the principle that ensures a policyholder is compensated for their loss without profit, and uberimae fidei means utmost good faith, which is a fundamental principle in insurance contracts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1994>6", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not used by the Central Bank to restrict lending by commercial banks?", "images": [], "options": {"A": "Management of national debt", "B": "Reserve Requirement", "C": "Open Market Operations", "D": "Cash Ratio"}, "answer": "D", "explanation": "The Cash Ratio is not typically used by the Central Bank to restrict lending by commercial banks. Instead, it is a measure of the amount of cash that banks must hold against their deposits. The other options, such as Management of national debt, Reserve Requirement, Open Market Operations, and Special Deposit, are all tools used by Central Banks to control the money supply and influence lending.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1994>7", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following relies on the government for  its initial capital ?", "images": [], "options": {"A": "Co-operative Society", "B": "Private Limited Company", "C": "Public Corporation", "D": "Public Limited Company"}, "answer": "C", "explanation": "A Public Corporation relies on the government for its initial capital. Public Corporations are typically established by the government to provide services or goods that are deemed essential for the public. They are funded by government resources, unlike Private Limited Companies or Public Limited Companies, which rely on private investment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>8", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A cheque does not contain", "images": [], "options": {"A": "cheque number", "B": "cashier's signature", "C": "payee's name", "D": "drawee's name"}, "answer": "B", "explanation": "A cheque does not contain the cashier's signature. A cheque typically includes the cheque number, payee's name, drawee's name, and date of issue. The cashier's signature is not a standard requirement for a cheque; instead, it is usually signed by the account holder.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>9", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The most acceptance and convenient means of payment in foreign trade is", "images": [], "options": {"A": "letter of credit", "B": "bank-draft", "C": "telegraphic money order", "D": "promissory note"}, "answer": "A", "explanation": "The most accepted and convenient means of payment in foreign trade is a letter of credit. A letter of credit is a document issued by a bank guaranteeing payment to a seller, provided that the seller meets the terms and conditions specified in the letter. It is widely used in international trade to mitigate risks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>10", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "An establishment that specialises in taking care of  risks is called", "images": [], "options": {"A": "a hire-purchase company", "B": "an accepting house", "C": "an insurance company", "D": "a finance company"}, "answer": "C", "explanation": "An establishment that specializes in taking care of risks is called an insurance company. Insurance companies provide financial protection against various risks by pooling resources from policyholders and compensating them in case of loss or damage. This is a fundamental concept in risk management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>11", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "An association of firms, producing similar commodities , formed in order to keep up prices by restricting output is called", "images": [], "options": {"A": "a chamber of commerce", "B": "a customers union", "C": "an amalgamation", "D": "a cartel"}, "answer": "D", "explanation": "The correct term for an association of firms that produce similar commodities and aim to keep prices stable by restricting output is a 'cartel'. A cartel is a formal agreement among competing firms to control prices or limit production, which can lead to higher prices for consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>12", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following is an example of a commercial occupation?", "images": [], "options": {"A": "Wrestling", "B": "Welding", "C": "Shipping", "D": "Brick laying"}, "answer": "C", "explanation": "Shipping is a commercial occupation as it involves the transportation of goods for trade. It is a key component of commerce, facilitating the movement of products from producers to consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>13", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following should be considered when transporting fragile and perishable goods?    I. Speed  II. Cost  III. Safety  IV. Flexibility  V. Convenience", "images": [], "options": {"A": "I and II only", "B": "III, IV and V only", "C": "I, III and IV only", "D": "I, III and V only"}, "answer": "C", "explanation": "When transporting fragile and perishable goods, speed, safety, and flexibility are crucial. Speed ensures that goods reach their destination quickly to prevent spoilage, safety protects the goods during transit, and flexibility allows for adjustments in transport methods as needed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>14", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following carries the bulk of goods involved in foreign trade?", "images": [], "options": {"A": "Cargo planes", "B": "Cargo liners", "C": "Tramp vessels", "D": "Steam ship"}, "answer": "B", "explanation": "Cargo liners are vessels specifically designed for the transportation of goods in bulk, particularly in foreign trade. They operate on fixed routes and schedules, making them a primary means of transporting large quantities of goods internationally.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>15", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A stock exchange is a market for", "images": [], "options": {"A": "old stocks of goods", "B": "capital goods only", "C": "raising new shares", "D": "existing shares of quoted companies"}, "answer": "D", "explanation": "A stock exchange is primarily a market for existing shares of quoted companies. It facilitates the buying and selling of shares that are already in circulation, providing liquidity to investors and enabling price discovery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>16", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following gives a temporary protection to the insured while the policy is being drawn up?", "images": [], "options": {"A": "Proposal form", "B": "Cover note", "C": "Endorsement", "D": "Ex gratia payment"}, "answer": "B", "explanation": "A cover note is a temporary document issued by an insurance company that provides proof of insurance coverage until the actual policy is finalized. It serves as a temporary protection for the insured while the policy is being drawn up.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>17", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "Which of the following is not a function of management?", "images": [], "options": {"A": "Staffing", "B": "Planning", "C": "Organising", "D": "Distribution"}, "answer": "D", "explanation": "Distribution is not typically considered a core function of management. The primary functions of management include staffing, planning, organizing, and directing. Distribution is more related to logistics and marketing rather than management itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>18", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Which of the following is responsible for the welfare of staff in an organisation?", "images": [], "options": {"A": "Accounts Department", "B": "Administrative Department", "C": "Personnel Department", "D": "Sales Department"}, "answer": "C", "explanation": "The Personnel Department, also known as Human Resources, is responsible for the welfare of staff in an organization. This department handles employee relations, benefits, training, and overall employee well-being.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>19", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of th following is not a marketing function?", "images": [], "options": {"A": "Packaging", "B": "Branding", "C": "Advertising", "D": "Accounting"}, "answer": "D", "explanation": "Accounting is not a marketing function. Marketing functions typically include activities related to promoting and selling products, such as packaging, branding, advertising, and pricing. Accounting focuses on financial record-keeping and reporting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>20", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is not an aim of advertising?", "images": [], "options": {"A": "drive away smaller firms", "B": "satisfy consumers", "C": "help firms compete with others", "D": "make one's product known"}, "answer": "A", "explanation": "Driving away smaller firms is not an aim of advertising. The primary aims of advertising include satisfying consumers, helping firms compete, making products known, and increasing sales. Advertising is intended to promote products and services positively, not to harm competitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>21", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "In which of the following environments does a firm that uses out-dated equipment operate?", "images": [], "options": {"A": "Economic", "B": "Technological", "C": "Social", "D": "Political"}, "answer": "B", "explanation": "A firm that uses outdated equipment operates in a 'Technological' environment. The technological environment refers to the state of technology and innovation that affects how businesses operate. Outdated equipment indicates that the firm is not keeping up with technological advancements, which can impact efficiency and competitiveness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>22", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is sent when credit is not allowed?", "images": [], "options": {"A": "Debit note", "B": "Proforma invoice", "C": "Credit note", "D": "Statement"}, "answer": "A", "explanation": "When credit is not allowed, a 'Debit note' is sent. A debit note is a document issued by a buyer to a seller, indicating that a certain amount has been debited to the seller's account. It is used when goods are returned or when there is a need to adjust the amount owed, especially when credit terms are not applicable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>23", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE", "question": "Which of the following does not determine the form of a business unit?", "images": [], "options": {"A": "Available capital", "B": "Risk bearing", "C": "Nearness to market", "D": "Ownership"}, "answer": "C", "explanation": "While available capital, risk bearing, ownership, and nature of business are all factors that influence the structure of a business, 'Neareness to market' does not inherently determine the form of a business unit. It may affect operational decisions but is not a foundational determinant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>24", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Agents who link buyers with sellers receive", "images": [], "options": {"A": "factorage", "B": "brokerage", "C": "bonus", "D": "interest"}, "answer": "B", "explanation": "Agents who link buyers with sellers receive 'brokerage'. Brokerage is a fee or commission paid to an agent or broker for facilitating a transaction between two parties. This is a common practice in various industries, including real estate and finance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>25", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a feature of supermarkets?", "images": [], "options": {"A": "Standard shop fronts", "B": "Self service", "C": "Use of trolleys", "D": "Small number of sales assistants"}, "answer": "D", "explanation": "A feature that is not characteristic of supermarkets is 'Small number of sales assistants'. Supermarkets typically employ a large number of sales assistants to manage the self-service model and assist customers, which contrasts with the option provided.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>26", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is an objectives of indigenisation? To", "images": [], "options": {"A": "increase foreign participation in business", "B": "attract foreign capital", "C": "help Nigerian entrepreneurs become monopolists", "D": "help citizens participate fully in the economy"}, "answer": "D", "explanation": "The objective of indigenisation is to help citizens participate fully in the economy. This involves empowering local entrepreneurs and businesses to take part in economic activities, thereby reducing reliance on foreign entities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>27", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "In which of the following are the objectives of a company stated?", "images": [], "options": {"A": "Annual Report", "B": "Articles of Association", "C": "Certificate of Incorporation", "D": "Memorandum of Association"}, "answer": "D", "explanation": "The objectives of a company are typically stated in the Memorandum of Association. This document outlines the company's purpose, the scope of its activities, and the powers it has to achieve its objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>28", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "The coming together of firms at different stages of the production is known as", "images": [], "options": {"A": "horizontal integration", "B": "vertical integration", "C": "consortium", "D": "cartel"}, "answer": "B", "explanation": "The coming together of firms at different stages of production is known as vertical integration. This strategy allows companies to control more of their supply chain, from raw materials to final product distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>29", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "The storing of goods under proper conditions until they are required is a function of", "images": [], "options": {"A": "stock taking", "B": "warehousing", "C": "stock control", "D": "merchandising"}, "answer": "B", "explanation": "The storing of goods under proper conditions until they are required is a function of warehousing. Warehousing involves the storage of goods in a facility designed to protect them until they are needed for distribution or sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>30", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Rate of turnover is the", "images": [], "options": {"A": "number of times opening stock is sold during a period", "B": "rate paid by retailers stocks", "C": "rate paid to agents for turn", "D": "number of times average stock is sold during a period"}, "answer": "D", "explanation": "Rate of turnover refers to the number of times average stock is sold during a period. It is a measure of how efficiently a company is managing its inventory and generating sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>31", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A postal order, either crossed or open is only valid for a period of", "images": [], "options": {"A": "12 months", "B": "10 months", "C": "8 months", "D": "6 months"}, "answer": "A", "explanation": "A postal order, whether crossed or open, is valid for a period of 12 months. This is a standard duration for postal orders to ensure that they are used within a reasonable timeframe.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>32", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "NATIONALIZATION AND PRIVATIZATION", "question": "The process of taking over private business by government is known as", "images": [], "options": {"A": "naturalisation", "B": "nationalisation", "C": "privatisation", "D": "commercialisation"}, "answer": "B", "explanation": "The process of taking over private business by the government is known as nationalisation. This involves the transfer of ownership from private to public sector, often to control key industries or services for the public good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>33", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is not the objective of Consumer Association? To", "images": [], "options": {"A": "ensure that fair prices are charged", "B": "educate consumers on their rights", "C": "prevent fake goods from entering the market", "D": "ensure correct specifications as to quality of goods"}, "answer": "D", "explanation": "Ensuring correct specifications as to quality of goods is not typically an objective of Consumer Associations. Their main goals include ensuring fair pricing, educating consumers, preventing fake goods, and advocating for consumer protection laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>34", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Zaico Ltd invoiced goods valued at #80,000 to Victory Ltd for #8,000. Which of the following will Zaico Ltd send to Victory Ltd to correct the error?", "images": [], "options": {"A": "Consignment note", "B": "Credit note", "C": "Advice note", "D": "Debit note"}, "answer": "B", "explanation": "To correct the error in invoicing, Zaico Ltd would send a Credit note to Victory Ltd. A Credit note is issued to reduce the amount owed by the buyer, typically used when there has been an overcharge or error in the original invoice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>35", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Which of the following is an example of extractive industry?", "images": [], "options": {"A": "Sewing dresses", "B": "Constructing bridges", "C": "Baking bread", "D": "Digging for precious stones"}, "answer": "D", "explanation": "Digging for precious stones is an example of an extractive industry. Extractive industries involve the extraction of natural resources from the earth, such as mining for minerals, oil, and gas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>36", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The raising of new capital by allowing existing shareholders the privilege to buy shares at preferential rate is called", "images": [], "options": {"A": "bonus issue", "B": "private placing", "C": "offer for sale", "D": "rights issue"}, "answer": "D", "explanation": "The correct term for raising new capital by allowing existing shareholders the privilege to buy shares at a preferential rate is called a 'rights issue'. This process allows current shareholders to purchase additional shares at a discounted price before the shares are offered to the public, thus giving them the first opportunity to maintain their proportional ownership in the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>37", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The agreed amount payable to a policy holder when the event insured against occurs is", "images": [], "options": {"A": "surrender value", "B": "sum assured", "C": "indemnity", "D": "insurable interest"}, "answer": "B", "explanation": "The agreed amount payable to a policyholder when the event insured against occurs is known as the 'sum assured'. This is the amount that the insurer agrees to pay upon the occurrence of the insured event, such as death or total disability, as specified in the insurance policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>38", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The rate at which one country's products are exchanged for the products of another is", "images": [], "options": {"A": "balance of trade", "B": "balance on current account", "C": "terms of trade", "D": "balance of payments"}, "answer": "C", "explanation": "The rate at which one country's products are exchanged for the products of another is referred to as the 'terms of trade'. This concept measures the relative prices of exports to imports and indicates the economic health of a country in terms of its trade relationships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>39", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following is not performed by the shipping and forwarding agents?", "images": [], "options": {"A": "Reservation of shipping space", "B": "Collection of payment from the importer", "C": "Collection of goods from the factory", "D": "Preparation of the bill of lading"}, "answer": "B", "explanation": "Shipping and forwarding agents typically do not collect payment from the importer; this task is usually handled by the seller or a financial institution. Their primary roles include reserving shipping space, preparing bills of lading, and arranging for marine insurance, among other logistical tasks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>40", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A group of firms that produce similar goods or services is called", "images": [], "options": {"A": "an industry", "B": "a trade association", "C": "a cartel", "D": "a holding company"}, "answer": "A", "explanation": "A group of firms that produce similar goods or services is called 'an industry'. An industry encompasses all businesses that produce similar products or services, and it is a broader term than a trade association or cartel, which may represent specific interests within that industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>41", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Retail outlets which sell from specialised vans are", "images": [], "options": {"A": "supermarkets", "B": "multiple shops", "C": "mail order firms", "D": "mobile shops"}, "answer": "D", "explanation": "Retail outlets that sell from specialized vans are referred to as 'mobile shops'. These are vehicles that are equipped to sell goods directly to consumers, often in various locations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>42", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "Which of the following is a problem facing mail order business?", "images": [], "options": {"A": "Expensive shop fronts", "B": "Cost of postage and advertisement", "C": "Commission to agents", "D": "Increase in branded goods"}, "answer": "B", "explanation": "A significant problem facing mail order businesses is the 'Cost of postage and advertisement'. These costs can be substantial and impact the overall profitability of the business, as they are necessary for reaching customers and delivering products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>43", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "When the exporter arranges for the despatch of goods but leaves the cost of transport to be paid by the importer, the price quoted is", "images": [], "options": {"A": "carriage forward", "B": "franco", "C": "loco", "D": "free on board"}, "answer": "A", "explanation": "When the exporter arranges for the dispatch of goods but leaves the cost of transport to be paid by the importer, the price quoted is known as 'carriage forward'. This means that the buyer is responsible for the shipping costs once the goods are dispatched.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>44", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The practice of selling, goods in foreign countries at lower prices than obtainable in the exporting country is known as", "images": [], "options": {"A": "hedging", "B": "black market", "C": "dumping", "D": "speculation"}, "answer": "C", "explanation": "The practice of selling goods in foreign countries at lower prices than obtainable in the exporting country is known as 'dumping'. This can be a strategy used to gain market share in a foreign market by undercutting local prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>45", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The process of entrusting part of the work of a superior and the corresponding authority to a subordinate in an organisation is called", "images": [], "options": {"A": "delegation", "B": "deputising", "C": "coordinating", "D": "supervision"}, "answer": "A", "explanation": "The process of entrusting part of the work of a superior and the corresponding authority to a subordinate in an organization is called 'delegation'. This is a key management skill that allows for more efficient operation and development of employees.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>46", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Which of the following is not considered by banks when granting loans to customers?", "images": [], "options": {"A": "Character of the customer", "B": "Period of business", "C": "Amount needed", "D": "Period of repayment"}, "answer": "A", "explanation": "The factor not considered by banks when granting loans is Character of the customer. Period of repayment, Amount needed, Purpose of the loan are typically considered by banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>47", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Import duty imposed on a commodity according to the quantity imported is", "images": [], "options": {"A": "ad valorem duty", "B": "customs duty", "C": "excise duty", "D": "specific duty"}, "answer": "D", "explanation": "Import duty imposed on a commodity according to the quantity imported is known as 'specific duty'. This type of duty is calculated based on a fixed amount per unit of the imported good, rather than a percentage of its value, which distinguishes it from ad valorem duty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>48", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A cheque that is drawn on a bank is called", "images": [], "options": {"A": "certified cheque", "B": "bank draft", "C": "bank note", "D": "order cheque"}, "answer": "D", "explanation": "A cheque that is drawn on a bank is called an 'order cheque'. This type of cheque is payable to a specific person or entity and requires the bank to pay the amount specified to the person named on the cheque.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>49", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following forms of transport moves crude oil to the ports for export?", "images": [], "options": {"A": "Rail", "B": "Pipeline", "C": "Road", "D": "Air"}, "answer": "B", "explanation": "The form of transport that moves crude oil to the ports for export is 'Pipeline'. Pipelines are specifically designed for the efficient and safe transportation of liquids, including crude oil, over long distances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>50", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES", "question": "The rebate given to the retailer by the wholesaler to enable him to make profit is known as", "images": [], "options": {"A": "trade discount", "B": "cash discount", "C": "credit guarantee", "D": "commission"}, "answer": "A", "explanation": "The rebate given to the retailer by the wholesaler to enable him to make a profit is known as 'trade discount'. This discount is provided to incentivize retailers to purchase goods in bulk and is typically deducted from the invoice price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>51", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Who among the following is not involved in foreign trade?", "images": [], "options": {"A": "Factor", "B": "Del Credere Agent", "C": "Wholesale Merchant", "D": "Jobber"}, "answer": "A", "explanation": "A 'Factor' is a financial intermediary that buys receivables from businesses and provides immediate cash. They are involved in trade finance but not directly in foreign trade. The other options (Del Credere Agent, Wholesale Merchant, Jobber, Forwarding Agent) are all involved in facilitating or executing foreign trade transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>52", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following belongs to the capital market?", "images": [], "options": {"A": "Commercial bank", "B": "Stock exchange", "C": "Ministry of Finance", "D": "Chamber of Commerce"}, "answer": "B", "explanation": "The 'Stock exchange' is a platform where securities, including stocks and bonds, are bought and sold, making it a key component of the capital market. The other options (Commercial bank, Ministry of Finance, Chamber of Commerce, Discount House) do not directly represent the capital market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>53", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "The giving of clear instructions and information to all concerned in an organisation to ensure proper understanding of decisions and policies is", "images": [], "options": {"A": "organising", "B": "planning", "C": "communicating", "D": "directing"}, "answer": "C", "explanation": "The process of 'communicating' involves giving clear instructions and information to ensure that all members of an organization understand decisions and policies. This is essential for effective management and coordination within an organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>54", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce is not concerned with", "images": [], "options": {"A": "changing the place of a product", "B": "changing the form of a product", "C": "changing ownership of a product", "D": "warehousing of a product"}, "answer": "D", "explanation": "Commerce is primarily concerned with the exchange of goods and services, which includes changing ownership, distribution, and warehousing. However, 'warehousing of a product' is more about storage rather than the actual commerce process, which focuses on the transaction and movement of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>55", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "An alternative term for ordinary shares is", "images": [], "options": {"A": "unit trust", "B": "gilt-edged securities", "C": "equities", "D": "bonus issues"}, "answer": "C", "explanation": "The term 'equities' is commonly used as an alternative term for ordinary shares. Equities represent ownership in a company, while the other options refer to different financial instruments or investment vehicles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>56", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "The retail of goods through currency operated machines is known as", "images": [], "options": {"A": "mail order business", "B": "automatic vending", "C": "party selling", "D": "impulse buying"}, "answer": "B", "explanation": "The retail of goods through currency operated machines is known as automatic vending. Automatic vending refers to the use of machines that dispense products when a customer inserts currency or a card. This method allows for quick and convenient access to goods without the need for human interaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>57", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Any paid form of non-personal presentation of ideas, goods or services by an identified sponsor is known as", "images": [], "options": {"A": "market research", "B": "market orientation", "C": "open market operation", "D": "advertising"}, "answer": "D", "explanation": "Any paid form of non-personal presentation of ideas, goods or services by an identified sponsor is known as advertising. Advertising is a marketing communication that aims to promote products or services to consumers through various media channels, and it is typically paid for by the sponsor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>58", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The art of achieving stated objectives of a business organisation in a most efficient way through the use of human and material resources is", "images": [], "options": {"A": "planning", "B": "co-ordinating", "C": "management", "D": "motivation"}, "answer": "C", "explanation": "The art of achieving stated objectives of a business organisation in a most efficient way through the use of human and material resources is known as management. Management involves planning, organizing, leading, and controlling an organization's resources to achieve specific goals effectively and efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>59", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following encourages free trade among member nations?", "images": [], "options": {"A": "IMF", "B": "UNO", "C": "WHO", "D": "EEC"}, "answer": "D", "explanation": "The organization that encourages free trade among member nations is the EEC (European Economic Community). The EEC was established to promote economic integration and free trade among its member states, facilitating the movement of goods, services, and capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>60", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "ECOWAS headquarters is located in", "images": [], "options": {"A": "Ghana", "B": "Nigeria", "C": "Senegal", "D": "Sierra Leone"}, "answer": "B", "explanation": "ECOWAS (Economic Community of West African States) headquarters is located in Nigeria. ECOWAS is a regional political and economic union of fifteen countries located in West Africa, and its headquarters is situated in Abuja, Nigeria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>61", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following refers to the practice of importing for re-export?", "images": [], "options": {"A": "Counter trade", "B": "Dumping", "C": "Entreport trade", "D": "Forward trading"}, "answer": "C", "explanation": "The practice of importing goods for the purpose of re-exporting them is known as 'Entreport trade'. This involves bringing goods into a country and then exporting them again, often with some processing or value addition. This is distinct from other trade practices like counter trade or dumping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>62", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "Firms merge in order to", "images": [], "options": {"A": "discourage the employment of specialists", "B": "encourage competition", "C": "discourage the use of each other's bye-product", "D": "create a monopoly"}, "answer": "D", "explanation": "Firms often merge to create a monopoly, which allows them to dominate the market and reduce competition. This can lead to increased market power and the ability to set prices without the pressure of competitors. Mergers can also lead to economies of scale and increased efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>63", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Those who buy and sell shares on their own account in the stock exchange are", "images": [], "options": {"A": "underwriters", "B": "brokers", "C": "clerks", "D": "jobbers"}, "answer": "D", "explanation": "Those who buy and sell shares on their own account in the stock exchange are referred to as 'jobbers'. Jobbers act as market makers, providing liquidity to the market by buying and selling shares for their own profit, as opposed to brokers who act on behalf of clients.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>64", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is not a trade association?", "images": [], "options": {"A": "Nigeria Union of Teachers", "B": "Nigerian Medical Association", "C": "Patent Medicine dealers Association", "D": "Motor Spare Parts Dealers Union"}, "answer": "A", "explanation": "The Nigeria Union of Teachers is not a trade association; it is a professional association that represents teachers. Trade associations typically represent businesses or industries, while professional associations represent individuals in a profession.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>65", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "Which of the following must any form of money possess in order to be generally acceptable?", "images": [], "options": {"A": "Divisibility", "B": "Mobility", "C": "Durability", "D": "Legality"}, "answer": "D", "explanation": "For any form of money to be generally acceptable, it must possess 'Legality'. This means that the money must be recognized by the government as a valid medium of exchange. While other characteristics like divisibility and durability are important, legality is essential for acceptance in transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>66", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is not a factor of production?", "images": [], "options": {"A": "Labour", "B": "Profit", "C": "Capital", "D": "Land"}, "answer": "B", "explanation": "Profit is not a factor of production. The factors of production are typically classified as land, labor, capital, and enterprise. Profit is the financial gain obtained after all expenses are subtracted from revenue, and it is not a resource used in the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>67", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of short-term capital?", "images": [], "options": {"A": "Trade credit", "B": "Overdraft", "C": "Bonus issue", "D": "Discounting bills"}, "answer": "C", "explanation": "A bonus issue is not a source of short-term capital. It refers to the issuance of additional shares to existing shareholders, which does not provide immediate cash flow. In contrast, trade credit, overdrafts, discounting bills, and money market instruments are all sources of short-term capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>68", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Debentures differ from shares in that", "images": [], "options": {"A": "they form part of the capital of the business", "B": "rewards are usually paid out of profit", "C": "ownership is open to the public", "D": "they are usually secured by  a charge on the company assets"}, "answer": "D", "explanation": "Debentures differ from shares in that they are usually secured by a charge on the company assets. Debentures are a form of debt financing, meaning they represent a loan made to the company, while shares represent ownership in the company. The rewards for debenture holders are fixed interest payments, which are paid before any profits are distributed to shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>69", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following is responsible for carrying out the monetary policy of a country?", "images": [], "options": {"A": "The Ministry of Finance", "B": "International Monetary Fund", "C": "Internal Revenue Board", "D": "The Centrak Bank"}, "answer": "D", "explanation": "The Central Bank is responsible for carrying out the monetary policy of a country. It manages the country's currency, money supply, and interest rates, and it plays a crucial role in stabilizing the economy. Other options listed do not have the primary responsibility for monetary policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>70", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following indicates that manufacturer from whom goods are to be bought?", "images": [], "options": {"A": "Open indent", "B": "Closed indent", "C": "Consignment note", "D": "Export invoice"}, "answer": "A", "explanation": "An open indent indicates the manufacturer from whom goods are to be bought. It is a document that specifies the details of the order and the supplier. Closed indent, consignment note, export invoice, and certificate of origin serve different purposes in the trade process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>71", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "When applications are received for more shares that are offered for sale, the issue is said to be", "images": [], "options": {"A": "under subscribed", "B": "selling above par", "C": "selling below par", "D": "over subscribed"}, "answer": "D", "explanation": "When applications are received for more shares than are offered for sale, the issue is termed 'over subscribed'. This means that the demand for shares exceeds the supply, leading to a situation where investors may not receive the full amount of shares they applied for.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>72", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Which of the following is not a branch of commerce?", "images": [], "options": {"A": "Trade", "B": "Transport", "C": "Warehousing", "D": "Production"}, "answer": "D", "explanation": "Production is not considered a branch of commerce. Commerce primarily involves the activities of trade, transport, warehousing, and banking, which facilitate the buying and selling of goods and services. Production, on the other hand, refers to the creation of goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>73", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following is most suitable for demonstrating the features of a new product?", "images": [], "options": {"A": "Radio", "B": "Newspaper", "C": "Loud speaker", "D": "Television"}, "answer": "D", "explanation": "Television is most suitable for demonstrating the features of a new product due to its visual and auditory capabilities, allowing for a more engaging presentation. It can showcase the product in action, highlight its features, and create a strong emotional connection with the audience.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>74", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Building societies secure the loans granted to customers by", "images": [], "options": {"A": "debentures", "B": "stocks", "C": "bonds", "D": "mortgages"}, "answer": "D", "explanation": "Building societies secure the loans granted to customers by mortgages. A mortgage is a loan specifically used to purchase real estate, where the property itself serves as collateral for the loan. This means that if the borrower fails to repay, the building society can take possession of the property.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>75", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A country resorts to counter trade when", "images": [], "options": {"A": "it does not belong to any cartel organisation", "B": "its imports are less than exports", "C": "it wants to raise domestic production", "D": "its foreign exchange is not sufficient to pay for import"}, "answer": "D", "explanation": "A country resorts to counter trade when its foreign exchange is not sufficient to pay for imports. Counter trade involves trading goods and services for other goods and services instead of using cash, which can help countries that face foreign exchange shortages to still engage in international trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>76", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "An actuary is the expert who", "images": [], "options": {"A": "assesses the extent of risk sustained by an insured", "B": "calculates the premium payable for an insurance policy", "C": "brings clients to an insurance company for a commission", "D": "undertakes to cover a risk or part of it"}, "answer": "A", "explanation": "An actuary is a professional who assesses the financial implications of risk and uncertainty. They use mathematics, statistics, and financial theory to study uncertain future events, particularly in the insurance and finance fields. Therefore, the correct option is that an actuary assesses the extent of risk sustained by an insured.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>77", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following is common to ocean liner and train?", "images": [], "options": {"A": "Move on rails", "B": "Form of land transport", "C": "Travel according to schedule", "D": "Fitte with long coaches"}, "answer": "C", "explanation": "Both ocean liners and trains operate on schedules, which means they have set times for departures and arrivals. This is a common characteristic that allows passengers to plan their travel accordingly. The other options do not apply to both modes of transport.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>78", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is used when goods are sent through  a common carrier?", "images": [], "options": {"A": "Receipt", "B": "Delivery note", "C": "Proforma invoice", "D": "Consignment note"}, "answer": "D", "explanation": "A consignment note is a document that accompanies goods when they are sent through a common carrier. It serves as a receipt for the goods and provides details about the shipment. The other options do not specifically relate to the process of sending goods via a common carrier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>79", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The issue of shares to interested existing shareholders in proportion to their holding is known as", "images": [], "options": {"A": "private placing", "B": "rights issue", "C": "bonus issue", "D": "issue by prospectus"}, "answer": "B", "explanation": "A rights issue is a way for companies to raise capital by giving existing shareholders the right to purchase additional shares in proportion to their existing holdings. This allows shareholders to maintain their ownership percentage in the company. The other options do not accurately describe this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>80", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Which of the following is not an essential element of valid contract?", "images": [], "options": {"A": "Offer", "B": "Acceptance", "C": "Legal", "D": "Compensation"}, "answer": "D", "explanation": "Compensation is not an essential element of a valid contract. The essential elements of a valid contract typically include offer, acceptance, legal purpose, and consideration. Compensation may be a result of a contract but is not a necessary element for the contract to be valid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>81", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "Which of the following provides that the cash price of all goods be clearly shown?", "images": [], "options": {"A": "Sale of Goods Act", "B": "Fair Trading Act", "C": "Food and Drugs Act", "D": "Hire Purchase Act"}, "answer": "B", "explanation": "The Fair Trading Act is designed to protect consumers by ensuring that they are provided with accurate information about goods and services, including the requirement that the cash price of all goods be clearly shown.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>82", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following categories of workers does not provide direct services?", "images": [], "options": {"A": "Teachers", "B": "Doctors", "C": "Wholesalers", "D": "Musicians"}, "answer": "C", "explanation": "Wholesalers do not provide direct services to consumers; instead, they sell goods in bulk to retailers or other businesses, acting as intermediaries in the supply chain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>83", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Places as a component of the marketing mix is the same as", "images": [], "options": {"A": "market centre", "B": "central location", "C": "distribution", "D": "communication"}, "answer": "C", "explanation": "In the marketing mix, 'places' refers to the distribution channels through which products reach consumers. This includes the locations where products are sold and how they are delivered to the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>84", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Which of the following is not a reason for Stock  Control?", "images": [], "options": {"A": "check pilfering of goods", "B": "distinguish a firm's stock of goods from others", "C": "meet customer's demand at all times", "D": "know the amount of goods in stock at any point in time"}, "answer": "B", "explanation": "Distinguishing a firm's stock of goods from others is not a primary reason for stock control. Stock control mainly focuses on managing inventory levels, preventing loss, and ensuring that customer demand is met.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>85", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "The activities of competitors in the market are part of the", "images": [], "options": {"A": "technological environment", "B": "social environment", "C": "legal environment", "D": "economic environment"}, "answer": "D", "explanation": "The activities of competitors in the market are part of the economic environment, as they influence market dynamics, pricing strategies, and overall competition within the industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>86", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The amount of capital supplied by the owners of a company is known as", "images": [], "options": {"A": "loan capital", "B": "working capital", "C": "capital employed", "D": "share capital"}, "answer": "D", "explanation": "The amount of capital supplied by the owners of a company is known as 'share capital'. Share capital represents the funds raised by a company in exchange for shares of stock. This is the money that the owners (shareholders) invest in the company, which is used for business operations and growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>87", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following takes possession of goods and sells in his own name?", "images": [], "options": {"A": "Factor", "B": "Del credere agent", "C": "Auctioneer", "D": "Broker"}, "answer": "A", "explanation": "A 'Factor' is an agent who takes possession of goods and sells them in his own name. Factors typically buy goods from manufacturers and sell them to retailers, taking on the risk of selling the goods. This distinguishes them from brokers, who act as intermediaries without taking possession.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>88", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "A patent is usually granted to an individuals whose work", "images": [], "options": {"A": "can be linked with an existing artistic work", "B": "is a new invention", "C": "took many years to accomplish", "D": "is a transfer from foreign invention"}, "answer": "B", "explanation": "A patent is usually granted for 'a new invention'. This legal protection allows the inventor exclusive rights to their invention for a certain period, preventing others from making, using, or selling the invention without permission. The essence of a patent is that it must be novel and non-obvious.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1994>89", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is not a tool for sales promotion?", "images": [], "options": {"A": "Advertising", "B": "Free samples", "C": "Personal selling", "D": "Publicity"}, "answer": "A", "explanation": "Advertising is not typically considered a tool for sales promotion; rather, it is a broader marketing strategy aimed at creating awareness and interest in a product or service. Sales promotion tools are more direct incentives to encourage immediate sales, such as free samples or discounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>90", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Business risks that can be insured against include    I. imitation of a company's product  II. damages caused by the use of a company's product  III. changes in fashion  IV. damages caused by fire  V. damages caused by flood", "images": [], "options": {"A": "I, II and V only", "B": "II and IV only", "C": "III and IV only", "D": "IV and V only"}, "answer": "D", "explanation": "Business risks that can be insured against include damages caused by fire and damages caused by flood. These are insurable risks because they can be quantified and are typically covered by property insurance policies. In contrast, risks like imitation of a product or changes in fashion are not insurable as they are more related to market dynamics and competition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1994>91", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "A group of firms that agree to operate a common price is a", "images": [], "options": {"A": "cartel", "B": "customs union", "C": "price ring", "D": "holding company"}, "answer": "A", "explanation": "A cartel is a group of firms that agree to coordinate their pricing and production decisions to maximize their collective profits. This is done to reduce competition among the member firms and can lead to higher prices for consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>92", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "It is important for banks to maintain a high percentage of cash ratio in order to", "images": [], "options": {"A": "make more profits", "B": "invest in long term ventures", "C": "encourage more cash deposits", "D": "meet their customers demand for cash at any time"}, "answer": "D", "explanation": "Banks maintain a high cash ratio to ensure they can meet customer demands for cash at any time. This is crucial for maintaining liquidity and trust in the banking system, allowing customers to withdraw their deposits whenever needed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>93", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following does not aim at protecting the consumer?", "images": [], "options": {"A": "Hire Purchase Act", "B": "Weight and Measure Act", "C": "Indigenisation Act", "D": "Food and Drugs Act"}, "answer": "C", "explanation": "The Indigenisation Act does not primarily aim at protecting consumers; rather, it focuses on promoting local ownership and control of businesses. In contrast, the other acts listed are specifically designed to protect consumer rights and interests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>94", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES", "question": "Small unit shops continue to exist inspite of stiff competition by large stores because they", "images": [], "options": {"A": "are located near large shops", "B": "employ travelling salesmen", "C": "stock one line of goods", "D": "maintain personal contact with their customers"}, "answer": "D", "explanation": "Small unit shops often maintain personal contact with their customers, which helps build loyalty and repeat business. This personal touch can be a significant advantage over larger stores, which may not offer the same level of customer service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>95", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is primarily responsible for projecting the image of a company?", "images": [], "options": {"A": "Sales Department", "B": "Personnel Department", "C": "Public Relations Department", "D": "Accounts Department"}, "answer": "C", "explanation": "The Public Relations Department is primarily responsible for projecting the image of a company. This department manages communication with the public and media, shaping how the company is perceived and maintaining its reputation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>96", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not a barrier to smooth trade among ECOWAS member nations?", "images": [], "options": {"A": "Differences in currencies and languages", "B": "Establishment of a common tariff", "C": "Constant changes in government", "D": "Political and ideological differences"}, "answer": "B", "explanation": "The establishment of a common tariff is not a barrier to trade; rather, it is a measure that facilitates trade among member nations by standardizing tariffs and reducing trade barriers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>97", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "Which of the following features of money facilitates small transactions?", "images": [], "options": {"A": "Portability", "B": "Durability", "C": "Divisibility", "D": "Scarcity"}, "answer": "C", "explanation": "Divisibility is a feature of money that allows it to be broken down into smaller units, making it easier to conduct small transactions. This means that money can be divided into smaller denominations to accommodate various transaction sizes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1994>98", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following widens the market for goods?", "images": [], "options": {"A": "Warehousing", "B": "Transport", "C": "Insurance", "D": "Banking"}, "answer": "B", "explanation": "Transport widens the market for goods by enabling the movement of products from one location to another, thus allowing sellers to reach a larger customer base beyond their immediate vicinity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>99", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is centrally controlled?", "images": [], "options": {"A": "Multiple shop", "B": "Mobile shop", "C": "Department store", "D": "Supermarket"}, "answer": "C", "explanation": "A department store is centrally controlled as it operates under a single management structure, unlike multiple shops or mobile shops which may operate independently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1994>100", "subject": "Commerce", "year": "1994", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "The fastest means of sending written information to a parent company abroad is the", "images": [], "options": {"A": "telegram", "B": "telephone", "C": "telex", "D": "courier service"}, "answer": "D", "explanation": "Courier service is the fastest means of sending written information to a parent company abroad, as it provides expedited delivery options compared to other methods like telegrams or express letters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>1", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Which of the following is not a branch of commerce?", "images": [], "options": {"A": "insurance", "B": "warehousing", "C": "trade", "D": "computerization"}, "answer": "D", "explanation": "Commerce is an umbrella term for complex economic systems for exchange of goods and services. It includes activities such as insurance, warehousing, and trade. However, computerization is not a branch of commerce. It is a tool that can be used in commerce, but it is not a branch of commerce itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>2", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following is not a negotiable instrument?", "images": [], "options": {"A": "share certificate", "B": "cheque", "C": "bill of exchange", "D": "debenture"}, "answer": "A", "explanation": "A negotiable instrument is a document guaranteeing the payment of a specific amount of money, either on demand, or at a set time, with the payer named on the document. Examples of negotiable instruments include cheques, bills of exchange, and debentures. However, a share certificate is not a negotiable instrument. It is a document issued by a company evidencing that the person named on the certificate is the owner of the number of shares stated on it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>3", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Those involved in obtaining the gifts of nature from land and sea are engaged in", "images": [], "options": {"A": "Extractive occupation", "B": "manufacturing occupation", "C": "constructive occupation", "D": "commercial occupation"}, "answer": "A", "explanation": "Extractive occupation refers to the process of extracting or obtaining natural resources from the land or sea. This includes activities such as mining, fishing, forestry, and agriculture. Therefore, those involved in obtaining the gifts of nature from land and sea are engaged in extractive occupation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>4", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "When a company sells shares to existing shareholders at preferential rate, that is called", "images": [], "options": {"A": "rights issue", "B": "bonus issue", "C": "private placing", "D": "sale by auction"}, "answer": "A", "explanation": "Rights issue is a method used by companies to raise additional capital by offering existing shareholders the opportunity to purchase new shares at a preferential rate. Therefore, when a company sells shares to existing shareholders at a preferential rate, it is called a rights issue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>5", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following must be include in the articles of association?", "images": [], "options": {"A": "voting rights of the shareholders", "B": "the objects of the business", "C": "the address of the registered office", "D": "statement that liability is limited"}, "answer": "A", "explanation": "The Articles of Association is a document that specifies the regulations for a company's operations and defines the company's purpose. It includes the voting rights of the shareholders, which determines how the company is controlled. The other options such as the objects of the business and the address of the registered office are included in the Memorandum of Association, not the Articles of Association. The statement that liability is limited is a feature of a limited liability company, not necessarily a requirement in the Articles of Association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>6", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following enables production to take place ahead of demand?", "images": [], "options": {"A": "transporting", "B": "advertising", "C": "importing", "D": "warehousing"}, "answer": "D", "explanation": "Warehousing enables production to take place ahead of demand. It allows for the storage of goods until they are needed. This means that production doesn't have to align exactly with demand, as goods can be produced in advance and then stored. Transporting, advertising, and importing are all important parts of the production and sales process, but they do not specifically enable production to take place ahead of demand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>7", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Called-up capital is the amount", "images": [], "options": {"A": "paid on allotment", "B": "paid on first call", "C": "paid on application", "D": "demanded on shares issued"}, "answer": "D", "explanation": "Called-up capital refers to the portion of share capital that shareholders have been asked to pay. It is the total amount of money that a company has asked its shareholders to contribute to the shares they have been issued. Therefore, the correct answer is 'demanded on shares issued'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>8", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following is true about cummulative preference shares?", "images": [], "options": {"A": "any unpaid dividend is carried forward", "B": "the shareholders can obtain a capital refund", "C": "they are entitled to further share in profit", "D": "any unpaid dividend is forfeited"}, "answer": "A", "explanation": "Cumulative preference shares are a type of preference shares where the dividend payable accumulates, if not paid. If the company does not declare a dividend in any year, the unpaid dividends are carried forward to the next years. Therefore, the correct answer is 'any unpaid dividend is carried forward'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>9", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "A public limited company has the rights and duties of an individual because it", "images": [], "options": {"A": "has a board of directors", "B": "has a trading certificate", "C": "has a corporate status", "D": "has a memorandum of association"}, "answer": "C", "explanation": "A public limited company has the rights and duties of an individual because it has a corporate status. This is known as 'corporate personhood', a legal concept which means that, as far as the law is concerned, a corporation is a legal person with its own rights and responsibilities separate from the individuals who make it up. This allows it to enter into contracts, sue and be sued, and own property in its own name.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>10", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "When firms producing similar commodities join together, that is", "images": [], "options": {"A": "vertical merger", "B": "holding company", "C": "horizontal merger", "D": "cartel"}, "answer": "C", "explanation": "When firms producing similar commodities join together, it is known as a horizontal merger. This is a type of merger, or business consolidation, that occurs between firms that operate in the same industry, usually as competitors offering the same good or service. Horizontal mergers are common in industries with fewer firms, as competition tends to be higher and the synergies and potential gains in market share are much greater for merging firms in such an industry.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>11", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The total indebtedness of a business is the same as its", "images": [], "options": {"A": "liabilities", "B": "liquid capital", "C": "solvency", "D": "capital employed"}, "answer": "A", "explanation": "The total indebtedness of a business refers to all the money that the business owes, which is the same as its liabilities. Liabilities are a company's legal financial debts or obligations that arise during the course of business operations. They are settled over time through the transfer of economic benefits including money, goods, or services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>12", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "All activities involved in the distribution and exchange of goods and services are referred to as", "images": [], "options": {"A": "trade", "B": "market survey", "C": "advertising", "D": "commerce"}, "answer": "D", "explanation": "Commerce refers to all activities involved in the distribution and exchange of goods and services. It includes trade, which is the buying and selling of goods, and aids to trade, such as transport, insurance, warehousing, advertising, and banking.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>13", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Land as a factor of production comprises", "images": [], "options": {"A": "all resources provided by nature", "B": "the earth surface only", "C": "land surface and vegetation", "D": "efforts to exploits the earth"}, "answer": "A", "explanation": "Land, in terms of economics and commerce, refers to all naturally occurring resources. This includes not only the surface of the earth, but also the minerals, water, flora, fauna, and the benefits that come from the climate, wind, and other natural phenomena.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>14", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Goods are usually classified into", "images": [], "options": {"A": "saleable and non saleable goods", "B": "inferior and superior goods", "C": "luxurious and essential goods", "D": "producer and consumer goods"}, "answer": "D", "explanation": "In economics, goods are usually classified into producer goods and consumer goods. Producer goods, also known as capital goods, are used in the production of either more complex capital goods or consumer goods. Consumer goods are the end result of production and manufacturing and are what a consumer will see on the store shelf. Other classifications like saleable and non-saleable, inferior and superior, luxurious and essential are not standard economic classifications of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>15", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Del-credere commission is an", "images": [], "options": {"A": "allowance paid to a supplier", "B": "extra allowance paid for guaranteeing recovery of debts", "C": "allowance paid to all commission agents", "D": "allowance paid by the agent"}, "answer": "B", "explanation": "Del-credere commission is a type of commission that a principal pays to its agent for the guarantee of payment on goods sold. The agent guarantees that the buyer will pay for the goods. If the buyer is unable to pay, the agent will pay the principal. Therefore, it is an extra allowance paid for guaranteeing recovery of debts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>16", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following is classified as invisible item in the balance of payments?", "images": [], "options": {"A": "export of goods", "B": "import of machinery", "C": "gifts", "D": "salaries of expatriates"}, "answer": "C", "explanation": "Invisible items in the balance of payments refer to non-tangible transactions between a country and the rest of the world. These include services, income, and current transfers. Gifts fall under current transfers and are therefore classified as invisible items in the balance of payments. They do not involve physical goods but rather are transactions where one party provides a resource but receives nothing tangible in return.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>17", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following is quoted when the buyer is responsible for the cost of loading the goods from the seller's warehouse up to his own warehouse?", "images": [], "options": {"A": "LOCO", "B": "F.O.R", "C": "F.A.S", "D": "C.I.F"}, "answer": "A", "explanation": "LOCO is a trade term that requires the seller to deliver goods to a place agreed upon by the buyer. The buyer is then responsible for all costs and risks associated with transporting the goods from that place to their final destination. This means the buyer is responsible for the cost of loading the goods from the seller's warehouse up to his own warehouse.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>18", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A trade in which many countries exchange goods and services is called", "images": [], "options": {"A": "bilateral trade", "B": "entrepot trade", "C": "economic union", "D": "multilateral trade"}, "answer": "D", "explanation": "Multilateral trade refers to the exchange of goods and services among multiple countries. Each participant in such trade can be a seller and a buyer. Bilateral trade is between two countries, entrepot trade involves importing goods from one country and then re-exporting them to another, and economic union is a type of trade agreement where member countries have a single market without any trade barriers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>19", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is used to ascertain the correct value of imports for purposes of assessing customs duty?", "images": [], "options": {"A": "certificate of origin", "B": "open-indent", "C": "bill of lading", "D": "ships manifest"}, "answer": "C", "explanation": "The bill of lading is a document issued by a carrier to acknowledge receipt of cargo for shipment. It details the type, quantity, and destination of the goods being carried, which is crucial for assessing customs duty.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>20", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The best method of making payment to an overseas supplier is by", "images": [], "options": {"A": "bankdraft", "B": "bill of exchange", "C": "travellers cheque", "D": "letter of credit"}, "answer": "D", "explanation": "The best method of making payment to an overseas supplier is by letter of credit. A letter of credit is a letter from a bank guaranteeing that a buyer's payment to a seller will be received on time and for the correct amount. In the event that the buyer is unable to make payment on the purchase, the bank will be required to cover the full or remaining amount of the purchase. It is therefore considered the safest method for an international transaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>21", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A refund usually granted for goods imported and later re-exported is called", "images": [], "options": {"A": "commission", "B": "discount", "C": "customs drawback", "D": "dock due"}, "answer": "C", "explanation": "A customs drawback is a refund on certain kinds of taxes and duties paid by importers. This refund is usually granted for goods that were imported and then re-exported. The purpose of this refund is to encourage international trade by reducing the costs for exporters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>22", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is a declaration by the captain of a ship as to the cargo on board?", "images": [], "options": {"A": "bill of lading", "B": "mate's receipt", "C": "ship's manifest", "D": "bill of sight"}, "answer": "C", "explanation": "A ship's manifest is a document that lists all cargo on board of a ship. It is prepared by the ship's master (captain) and is used for customs and other regulatory purposes. It includes details such as the quantity and type of goods being transported, and the destination of the ship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>23", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "When the balance of trade is unfavourable which of the following conditions prevails?", "images": [], "options": {"A": "exports exceed imports", "B": "imports exceed exports", "C": "customs duty is high", "D": "invisible exports exceed visible imports"}, "answer": "B", "explanation": "An unfavorable balance of trade, also known as a trade deficit, occurs when the value of a country's imports exceeds the value of its exports. In other words, more goods and services are bought from foreign countries than are sold abroad. Therefore, the correct answer is 'imports exceed exports'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>24", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "When a seller decides to sell his goods at a specific price for a specific period, he is making", "images": [], "options": {"A": "a sales promotion", "B": "a bid", "C": "an auction sale", "D": "a firm offer"}, "answer": "D", "explanation": "A firm offer is a contractual agreement that binds the offeror to keep an offer open for a specified period of time. It means the seller has decided to sell his goods at a specific price for a specific period. Therefore, the correct answer is 'a firm offer'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>25", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retailer who receives a trade discount of 331/3% and a cash discount of 10% on goods worth N360 would pay", "images": [], "options": {"A": "N240", "B": "N226", "C": "N216", "D": "N204"}, "answer": "C", "explanation": "First, calculate the trade discount by multiplying the cost of the goods by the trade discount rate. This gives N360 * 33.33/100 = N120. Subtract this from the original cost to get the price after the trade discount, which is N360 - N120 = N240. Then, calculate the cash discount by multiplying the price after the trade discount by the cash discount rate. This gives N240 * 10/100 = N24. Subtract this from the price after the trade discount to get the final price the retailer would pay, which is N240 - N24 = N216.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>26", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following documents is used when goods are sent on approval?", "images": [], "options": {"A": "catalogue", "B": "delivery note", "C": "receipt", "D": "pro forma invoice"}, "answer": "D", "explanation": "A pro forma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is often used to declare the value of the trade. It differs from a simple invoice in that it is generally used in international trade or when goods are sent on approval, and it is not a request for payment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>27", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Terms of trade refers to", "images": [], "options": {"A": "agreement between two trading countries", "B": "conditions attached to specific trade transactions", "C": "the relationship between export and import prices", "D": "the difference between the value of imports and exports"}, "answer": "C", "explanation": "Terms of trade refers to the relationship between export and import prices. It is an economic concept that represents the ratio of export prices to import prices. If a country's export prices rise by a greater rate than that of its import prices, its terms of trade have favorably improved. Improving terms of trade indicates that a country can buy more imports for any given level of exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>28", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Another name for shares, stocks and debentures traded in the stock exchange is", "images": [], "options": {"A": "collateral", "B": "securities", "C": "wares", "D": "participating preference shares"}, "answer": "B", "explanation": "Shares, stocks, and debentures traded in the stock exchange are collectively referred to as securities. In finance, a security is a tradable financial asset. The term commonly refers to any form of financial instrument, but its legal definition varies by jurisdiction. In some countries and languages, the term 'security' is commonly used in day-to-day parlance to mean any form of financial instrument, even though the underlying legal and regulatory regime may not have such a broad definition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>29", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following belongs to the capital market?", "images": [], "options": {"A": "commercial bank", "B": "savings bank", "C": "stock exchange", "D": "bureau de change"}, "answer": "C", "explanation": "The capital market is a market where buyers and sellers engage in trade of financial securities like bonds, stocks, etc. A stock exchange is part of the capital market where stock buyers and sellers meet to do transactions. Commercial banks and savings banks are part of the money market, not the capital market. Bureau de change is involved in the exchange of currencies, not securities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>30", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following is not true of insurance?", "images": [], "options": {"A": "a large number of people face the same risk", "B": "possibility of making a profit out of an event", "C": "only as small number will actually suffer the loss in any one year", "D": "a large number makes a small contribution to a common pool"}, "answer": "B", "explanation": "Insurance is a risk transfer mechanism where the loss of a few is shared among many. It is not a mechanism for making a profit out of an event. The other options correctly describe the principles of insurance: a large number of people face the same risk, only a small number will actually suffer the loss in any one year, and a large number makes a small contribution to a common pool.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>31", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following policies qualifies the holder to income tax relief?", "images": [], "options": {"A": "accident insurance", "B": "public liability insurance", "C": "comprehensive insurance", "D": "endowment assurance"}, "answer": "D", "explanation": "Endowment assurance is a life insurance contract designed to pay a lump sum after a specific term (on its 'maturity') or on earlier death. The premiums paid towards endowment assurance policies qualify for tax benefits under Section 80C of the Income Tax Act. This is not the case with accident insurance, public liability insurance, or comprehensive insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>32", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not a feature of good bank security? The", "images": [], "options": {"A": "asset must be easily converted into cash", "B": "value of the asset must not be easily ascertained", "C": "ownership of the asset must be in doubt", "D": "value of the asset must be less than the amount loaned"}, "answer": "B", "explanation": "A good bank security should have a value that can be easily ascertained. This is because the bank needs to know the value of the asset to determine how much they can loan against it. If the value of the asset cannot be easily ascertained, it poses a risk to the bank. The other options are incorrect because a good bank security should be easily converted into cash (liquidity), the ownership of the asset should not be in doubt, and the value of the asset should be more than the amount loaned (to cover for potential losses).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>33", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Selling a bill at less than the face value for immediate cash before the due date is to", "images": [], "options": {"A": "retire the bill", "B": "honour the bill", "C": "discount the bill", "D": "protest the bill"}, "answer": "C", "explanation": "Discounting a bill means selling a bill at less than its face value for immediate cash before the due date. This is done to get immediate cash and is a common practice in business. The difference between the face value of the bill and the amount received is the discount, which is the profit for the buyer of the bill.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>34", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is a non-indemnity insurance?", "images": [], "options": {"A": "marine", "B": "life", "C": "fire", "D": "bad debts"}, "answer": "B", "explanation": "Non-indemnity insurance is a type of insurance where the insured is paid a specified amount upon the occurrence of a specific event, regardless of the actual loss incurred. Life insurance is a non-indemnity insurance because the insurer pays a predetermined amount to the beneficiary upon the death of the insured, regardless of the financial loss suffered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>35", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following regulates and controls the activities of Nigeria stock exchange? The", "images": [], "options": {"A": "Central Bank", "B": "Association of Commercial Banks", "C": "Securities Exchange Commission (SEC)", "D": "Nigerian Association of Chambers of Commerce"}, "answer": "C", "explanation": "The Securities Exchange Commission (SEC) is the main regulatory institution of the Nigerian capital market. It is supervised by the Federal Ministry of Finance. The main function of SEC is to oversee the Nigerian Stock Exchange to ensure orderly and equitable dealings in securities, and protect the market against insider trading abuses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>36", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A cheque drawn by a bank on itself is a", "images": [], "options": {"A": "credit transfer", "B": "direct debt", "C": "certified cheque", "D": "bankdraft"}, "answer": "D", "explanation": "A bank draft is a type of check where the payment is guaranteed to be available by the issuing bank. Technically, a bank draft is an order from one bank to another, or to a separate branch of the same bank, to pay a specified sum to the person named in the draft. Therefore, a bank draft is a check drawn by a bank on itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>37", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "Which of the following is formed primarily to promote saving and loans among the members", "images": [], "options": {"A": "consumer co-operative society", "B": "producer co-operative society", "C": "co-operative wholesale society", "D": "co-operative thrift and credit society"}, "answer": "D", "explanation": "A co-operative thrift and credit society is primarily formed to promote savings and loans among its members. It is a type of co-operative society where members contribute a certain amount of money and give loans to members from the money collected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>38", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Mr. ojo borrowed N54,000 from a commercial bank and deposited his life insurance certificate with the bank. The certificate deposited serves as", "images": [], "options": {"A": "a loan repayment", "B": "a current asset", "C": "an interest charged", "D": "a collateral security"}, "answer": "D", "explanation": "When Mr. Ojo deposits his life insurance certificate with the bank, it serves as a collateral security. Collateral security refers to an asset that a borrower offers to a lender to secure a loan. If the borrower defaults on their loan payments, the lender can seize the collateral to recoup its losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>39", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "When an insurance policy is declared void because of a false declaration, the principle involved is ?", "images": [], "options": {"A": "indemnity", "B": "insurable interest", "C": "proximate cause", "D": "utmost good faith"}, "answer": "D", "explanation": "The principle involved when an insurance policy is declared void because of a false declaration is 'utmost good faith'. This principle, also known as 'uberrima fides', requires all parties in an insurance contract to deal in good faith, making a full declaration of all material facts in the insurance proposal. This means that the insured must disclose all facts about the risk to be covered that might influence the insurer's decision to accept the risk and on what terms. If the insured makes a false declaration, the insurer may declare the policy void.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>40", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A mortgage bank is primarily concerned with financing the acquisition of", "images": [], "options": {"A": "motor vehicles", "B": "research equipment", "C": "computer machines", "D": "dwelling houses"}, "answer": "D", "explanation": "A mortgage bank is primarily concerned with financing the acquisition of 'dwelling houses'. Mortgage banks are financial institutions that provide long-term loans to individuals and businesses for the purchase of real estate, particularly residential properties. They use the property being purchased as collateral for the loan. If the borrower defaults on the loan, the bank can seize the property and sell it to recover its money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>41", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "An insurance policy which gives cover against claims made by employees who suffer injury at work is", "images": [], "options": {"A": "comprehensive insurance", "B": "employers' liability insurance", "C": "personal accident insurance", "D": "consequential loss insurance"}, "answer": "B", "explanation": "Employers' liability insurance is a type of insurance policy that protects employers from liabilities arising from disease, fatality, or injury to employees resulting from workplace conditions or practices. Therefore, it covers claims made by employees who suffer injury at work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>42", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "What is the working capital of KO Ltd which has N3,500 in fixed assets, cash balance of N 4,170. trade debtors N1,150 and sundry creditors of N1,800?", "images": [], "options": {"A": "N7,020.00", "B": "N5,320.00", "C": "N4,720.00", "D": "N3,520.00"}, "answer": "D", "explanation": "Working capital is subtracting current liabilities from current assets.    Current liability = 1800    Current assets = 4170 +1150  = 5320    WC = 5320 - 1800  = #3520", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>43", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The nominal value of share of a public limited company is 50k and the market value is 65k. the company's shares is selling", "images": [], "options": {"A": "above per value", "B": "at per value", "C": "below per value", "D": "ex dividend"}, "answer": "A", "explanation": "The nominal value of a share is its face value, the value stated on the share certificate. The market value is the price at which the share is currently trading in the market. If the market value is higher than the nominal value, the share is selling 'above par value'. In this case, the nominal value is 50k and the market value is 65k, so the share is selling above par value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>44", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Turnover of a business is the same as the", "images": [], "options": {"A": "profit of the business", "B": "sales of the business", "C": "assets of the business", "D": "purchases of the business"}, "answer": "B", "explanation": "The turnover of a business refers to the total sales made by a business during a certain period. It is the gross revenue of the business, not the profit, assets, or purchases. Therefore, the turnover of a business is the same as the sales of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>45", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Opening stock plus purchases less closing stock gives", "images": [], "options": {"A": "the rate of turnover", "B": "cost of goods sold", "C": "working capital", "D": "net profit"}, "answer": "B", "explanation": "The formula for calculating the cost of goods sold (COGS) is: Opening Stock + Purchases - Closing Stock. This gives the total cost of all the goods that were sold during the period. The rate of turnover, working capital, and net profit are different financial metrics that cannot be calculated using this formula.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>46", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The part of the assets of a business that is available as cash or near cash is called?", "images": [], "options": {"A": "liquid capital", "B": "working capital", "C": "capital employed", "D": "reserved capital"}, "answer": "A", "explanation": "Liquid capital refers to the part of the assets of a business that is available as cash or near cash. It is the most liquid form of assets and can be quickly used to meet any immediate financial obligations. Working capital refers to the difference between a company's current assets and current liabilities. Capital employed refers to the total amount of capital that a company has utilized in order to generate profits. Reserved capital is a part of the profits that a company keeps aside to meet any future contingencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>47", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of capital to a limited company?", "images": [], "options": {"A": "equipment leasing", "B": "debt factoring", "C": "debentures", "D": "transporting"}, "answer": "D", "explanation": "A source of capital for a company refers to where a company gets its money from to finance its operations. The options provided are all sources of capital except for 'transporting'. Transporting is a function or activity of a company, not a source of capital. Equipment leasing, debt factoring, and debentures are all ways a company can raise capital. Equipment leasing is when a company rents equipment instead of buying it, which can save capital. Debt factoring is when a company sells its invoices to a third party (the 'factor') at a discount in order to receive immediate cash. Debentures are long-term debt instruments issued by a company to raise capital.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1995>48", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Which of the following enables goods to be available where they are needed", "images": [], "options": {"A": "advertising", "B": "communication", "C": "warehousing", "D": "transporting"}, "answer": "D", "explanation": "The availability of goods where they are needed is facilitated by transportation. Transportation involves the movement of goods from one place to another. It ensures that goods produced at a particular location reach the market or the final consumer. Advertising, communication, and warehousing do not directly ensure the availability of goods where they are needed. Advertising is about promoting the goods, communication is about exchanging information, and warehousing is about storing the goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1995>49", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The provision and administration of air traffic controls at benin airport is the function of", "images": [], "options": {"A": "Okada Airline", "B": "Nigeria Airways", "C": "Concord Airline", "D": "Nigeria Airports Authority"}, "answer": "D", "explanation": "The provision and administration of air traffic controls at any airport is the function of the airport authority. In this case, it is the Nigeria Airports Authority. They are responsible for the management of all commercial airports in Nigeria and provide air navigation services in Nigeria. The airlines mentioned in the other options are responsible for their respective flight operations, not air traffic control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1995>50", "subject": "Commerce", "year": "1995", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following ensures regular transportation of gas and liquid products in all weather conditions?", "images": [], "options": {"A": "train", "B": "aeroplane", "C": "tanker", "D": "pipeline"}, "answer": "D", "explanation": "The transportation of gas and liquid products in all weather conditions is ensured by pipelines. Pipelines are specially designed for the safe, efficient, and often long-distance transportation of products including natural gas, crude oil, and refined products. They are not affected by weather conditions unlike trains, aeroplanes, and tankers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>1", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES", "question": "Which of the following is not the duty of an entrepreneur?", "images": [], "options": {"A": "provision of initial capital", "B": "bearing of risks", "C": "organization of other factors of production", "D": "decision on the amount of tax pay"}, "answer": "D", "explanation": "An entrepreneur is responsible for the provision of initial capital, bearing of risks, and organization of other factors of production. However, the decision on the amount of tax to pay is not the duty of an entrepreneur. This is usually determined by the government's tax regulations and policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>2", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The difference between the total amount of money received by a country and the total amount paid to other countries within a given period is the", "images": [], "options": {"A": "trade gap", "B": "balance of trade", "C": "balance of payments", "D": "current account balance"}, "answer": "B", "explanation": "The difference between the total amount of money received by a country and the total amount paid to other countries within a given period is referred to as the balance of trade. The balance of trade is a significant part of a country's balance of payments. It is the largest component of a country's balance of payments. It is the difference between a country's exports and its imports. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>3", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following is used to transmit typed messages over long distances?", "images": [], "options": {"A": "Dictaphone", "B": "Teleprinter", "C": "Computer", "D": "Telephone"}, "answer": "B", "explanation": "A teleprinter is a telecommunication device that can be used to send and receive typed messages from point to point and point-to-multipoint over various types of communications channels. They were adapted to provide a user interface to early mainframe computers and minicomputers, sending typed data to the computer and printing the response. Some models could also be used to create punched tape for data storage (either from typed input or from data received from a remote source) and to read back such tape for local printing or transmission.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>4", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "When a company buys up firms supplying it with raw materials, this is an example of", "images": [], "options": {"A": "horizontal integration", "B": "a holding company", "C": "backward integration", "D": "consortium"}, "answer": "C", "explanation": "Backward integration is a type of vertical integration that includes the purchase of, or merger with, suppliers. Companies pursue backward integration when it is expected to result in improved efficiency and cost savings. For example, a bakery might buy a wheat processor or a wheat farm to have a ready and cheap supply of wheat flour. Therefore, when a company buys up firms supplying it with raw materials, it is an example of backward integration.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>5", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Industrial, commercial and direct services are branches of", "images": [], "options": {"A": "manufacturing", "B": "occupation", "C": "exchange", "D": "distribution"}, "answer": "B", "explanation": "Industrial, commercial and direct services are branches of occupation. Occupation refers to the regular activity performed by people to earn a living. It is broadly classified into three categories: business, employment, and profession. Business can be further divided into industry, commerce, and direct services. Industry involves the production of goods and materials, while commerce is concerned with the exchange of goods and services from the producer to the final consumer. Direct services refer to the services provided directly to the consumer like teaching, doctor, lawyer etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>6", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The primary purpose of credit cards is to", "images": [], "options": {"A": "obtain goods without paying cash on the spot", "B": "obtain a loan from the bank", "C": "obtain a loan from a trader", "D": "persuade a business man to cash a cheque"}, "answer": "A", "explanation": "The primary purpose of credit cards is to obtain goods without paying cash on the spot. A credit card is a payment card issued to users to enable the cardholder to pay a merchant for goods and services based on the cardholder's promise to the card issuer to pay them for the amounts plus the other agreed charges. The card issuer (usually a bank) creates a revolving account and grants a line of credit to the cardholder, from which the cardholder can borrow money for payment to a merchant or as a cash advance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>7", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Containers are suitable for transporting goods by", "images": [], "options": {"A": "sea only", "B": "road only", "C": "sea and rail only", "D": "road, sea and rail"}, "answer": "D", "explanation": "Containers are versatile in their usage for transportation. They can be used for transporting goods by road, sea, and rail. This is because containers are designed to be moved from one mode of transport to another without unloading and reloading the contents. This is known as intermodal transport.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>8", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following is not a credit instrument used in business transactions?", "images": [], "options": {"A": "Luncheon voucher", "B": "Bill of exchange", "C": "Promissory note", "D": "Fuel voucher"}, "answer": "A", "explanation": "A luncheon voucher is not a credit instrument used in business transactions. It is a type of meal ticket. On the other hand, a bill of exchange and a promissory note are both credit instruments. A bill of exchange is a binding agreement by one party to pay a fixed amount of cash to another party on demand or at a predetermined date. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date. A fuel voucher is a type of voucher that can be exchanged for fuel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>9", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "An insurance company shares its accepted risk with others in the form of", "images": [], "options": {"A": "reinsurance", "B": "subrogation", "C": "mutual insurance", "D": "fidelity guarantee insurance"}, "answer": "A", "explanation": "Reinsurance is a practice where an insurance company reduces its possible maximum loss by obtaining insurance from another insurer to carry part of the risk. This is done to share the accepted risk with others. Subrogation, mutual insurance, and fidelity guarantee insurance do not involve sharing of risk with others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>10", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Which of the following stresses the use of only specialists to head departments?", "images": [], "options": {"A": "Committee organisation structure", "B": "Line organisation structure", "C": "line and staff organisation structure", "D": "Functional organisation structure"}, "answer": "D", "explanation": "A functional organization structure is a type of organizational structure where the organization is divided into smaller groups based on specialized functional areas, such as IT, finance, or marketing. This structure emphasizes the use of specialists to head departments. The other options, such as Committee organisation structure, Line organisation structure, and line and staff organisation structure, do not necessarily stress the use of only specialists to head departments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>11", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The process of involving local businessmen in the ownership and control of businesses that were formerly owned by foreigners is called", "images": [], "options": {"A": "nationalization", "B": "industrialization", "C": "indeginization", "D": "commercialization"}, "answer": "C", "explanation": "Indigenization is the process of involving local businessmen in the ownership and control of businesses that were formerly owned by foreigners. Nationalization refers to the process of a government taking control of a company or industry, which can occur for a variety of reasons. Industrialization is the process by which an economy is transformed from primarily agricultural to one based on the manufacturing of goods. Commercialization is the process of introducing a new product or production method into commerce—making it available on the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>12", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following functions is not performed by retailers?", "images": [], "options": {"A": "Breaking bulk", "B": "Ensuring regular stock for consumers", "C": "Branding and packaging", "D": "Insuring goods for customers"}, "answer": "D", "explanation": "Retailers perform a variety of functions including breaking bulk (dividing larger quantities of goods into smaller lots), ensuring regular stock for consumers, and sometimes even branding and packaging. However, insuring goods for customers is typically not a function performed by retailers. This is usually done by insurance companies or is the responsibility of the customer themselves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>13", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "Which of these management functions involves checking performance against set standards?", "images": [], "options": {"A": "Controlling", "B": "Coordinating", "C": "Planning", "D": "Directing"}, "answer": "A", "explanation": "Controlling is the management function that involves checking performance against set standards. It involves measuring actual performance, comparing this with set standards, and taking corrective action if necessary. This is to ensure that the organization's plans are being implemented correctly and to see if goals are being achieved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>14", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The form given by the Customs Authority to enable an importer examine goods before the arrival of the bill of lading is known as", "images": [], "options": {"A": "entry for warehousing", "B": "certificate of origin", "C": "bill of sight", "D": "bill of exchange"}, "answer": "C", "explanation": "A bill of sight is a document given by the Customs Authority to enable an importer examine goods before the arrival of the bill of lading. It is a temporary document that allows the goods to be inspected before the actual documents arrive. This is to ensure that the goods are as described and meet the required standards.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>15", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "An organization that builds access roads for the benefit of the community in which it is located has fulfilled its", "images": [], "options": {"A": "legal responsibility", "B": "political responsibility", "C": "social responsibility", "D": "technological responsibility"}, "answer": "C", "explanation": "Social responsibility refers to the ethical framework which suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. In this case, building access roads for the benefit of the community is a form of social responsibility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>16", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following is applicable to foreign trade only?", "images": [], "options": {"A": "Pro forma invoice", "B": "insurance policy", "C": "Order", "D": "Consular invoice"}, "answer": "D", "explanation": "A consular invoice is a document, often used in foreign trade, that is required by some foreign countries. It is used as a control measure to ensure the quality and value of goods shipped, and it is issued by the consul of the country the goods are being shipped to. Therefore, it is applicable to foreign trade only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>17", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The department that deals with internal grievances and maintenance of discipline in an organization is the", "images": [], "options": {"A": "accounts", "B": "maintenance", "C": "personnel", "D": "public relations"}, "answer": "C", "explanation": "The personnel department in an organization is responsible for dealing with internal grievances and maintaining discipline. This department is also known as the human resources department. It handles issues related to employees such as hiring, compensation, performance management, organization development, safety, wellness, benefits, employee motivation, communication, administration, and training.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>18", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Another name for consignment note is", "images": [], "options": {"A": "qoutation", "B": "waybill", "C": "debit note", "D": "receipt"}, "answer": "B", "explanation": "A consignment note is also known as a waybill. It is a document issued by a carrier giving details and instructions relating to the shipment of a consignment of goods. Typically it will show the names of the consignor and consignee, the point of origin of the consignment, its destination, and route.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>19", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION", "question": "Specialization is possible as a result of", "images": [], "options": {"A": "good roads", "B": "education", "C": "demand for goods", "D": "exchange"}, "answer": "D", "explanation": "Specialization is possible as a result of exchange. Specialization refers to the concept where a nation or an individual concentrates its productive efforts on producing a limited variety of goods. It is based on the principle of 'division of labor' where tasks are divided among different people according to their expertise. This is possible only when there is an exchange mechanism in place that allows the trading of goods and services. Therefore, the correct answer is 'exchange'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>20", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC         In which of the boxes in the organization chart would you locate the shareholders of OLUWA PLC?", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "F", "B": "X", "C": "V", "D": "T"}, "answer": "D", "explanation": "When a corporation is initially incorporated, the original owners are routinely the first shareholders. Therefore, T represent the shareholders of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>21", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The position of the departmental manager would be located in box", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "T", "B": "F", "C": "W", "D": "X"}, "answer": "D", "explanation": "In smaller businesses, the initial owners remain the sole shareholders throughout the life of the corporation. Employees, managers, and owners may all be stockholders in the company where they handle the daily operations of the business. Therefore, X represent the departmental manager of the company", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>22", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The bond of directors of Oluwa plc would be in Box", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "V", "B": "W", "C": "X", "D": "U"}, "answer": "D", "explanation": "Company's director represents the will and wants of the shareholders. They are notably known to act in the place of the shareholders and their goals. Therefore, U represent the bond of directors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>23", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The position of the accounts clerk would be located in box", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "F", "B": "T", "C": "V", "D": "U"}, "answer": "A", "explanation": "An accounting clerk is a member of a company's accounting department, responsible for assisting with both clerical and administrative tasks. In general, an accounting clerk takes care of basic office tasks that involve reporting, bookkeeping, research, as well as the resolution of discrepancies related to any of the tasks he or she performs. F represent the position of an account clerk of the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>24", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The managing director would be located in box", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "V", "B": "T", "C": "U", "D": "W"}, "answer": "A", "explanation": "A company's managing director does the following work: Manages the company's budget and allocates its resources. Create strategic business plans for meeting the company's goals. V represent the position for a managing director.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>25", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       which of the following is represented by the chart?", "images": ["Commerce/imgs/1996/fg.png"], "options": {"A": "committee organization", "B": "staff organization", "C": "line and staff organization", "D": "line organization"}, "answer": "C", "explanation": "Line and staff organization is the organization structure, in which there is a normal departmentation of the regular business operations, and there is the functional specialist to perform specialised activities. While line authority relies on command, line and staff authority is based on command and advise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>26", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following may serve as delivery note?", "images": [], "options": {"A": "Debit note", "B": "Credit note", "C": "Invoice", "D": "Advice note"}, "answer": "D", "explanation": "A delivery note may serve as an Advice note. A delivery note is a document that is included with a shipment of goods sent out to a customer. It lists the description and amount of goods delivered. An advice note is a written piece of communication often included with a shipment of goods that provides details about the delivery. The advice note can also serve as proof of delivery. Therefore, the correct answer is 'Advice note'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>27", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Mr Chidi insured his house against fire. The house was destroyed by flood. Which of the following principles prevented him from being compensated?", "images": [], "options": {"A": "Uberrimae fidei", "B": "Subrogation", "C": "Indemnity", "D": "Proximate cause"}, "answer": "D", "explanation": "The principle of Proximate Cause in insurance states that the loss of an insured risk must be caused by the risk insured against. In this case, Mr Chidi insured his house against fire, but the house was destroyed by flood, which is a different risk. Therefore, the principle of Proximate Cause prevents him from being compensated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>28", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The price charged for leasing a ship is known as", "images": [], "options": {"A": "way bill", "B": "haulage", "C": "clean bill", "D": "freight"}, "answer": "D", "explanation": "Freight is the term used to describe the price charged for transporting goods by sea or waterway, which includes leasing a ship. Therefore, the price charged for leasing a ship is known as freight.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>29", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Goods in bonded warehouses are under the strict supervision of the", "images": [], "options": {"A": "Customs Authority", "B": "Ports Authority", "C": "Importer", "D": "Clearing agent"}, "answer": "A", "explanation": "Goods in bonded warehouses are under the strict supervision of the Customs Authority. A bonded warehouse is a secured area where imported goods are stored until the import duties are paid. These warehouses are under the control and supervision of the Customs Authority to ensure that the import duties are paid before the goods are released.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>30", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following regulates and controls the activities of the Nigerian Stock Exchange?", "images": [], "options": {"A": "The Nigerian Capital Market Association", "B": "The Securities and Exchange Commission", "C": "The Nigerian Deposit Insurance Commission", "D": "The Nigerian Reinsurance Corporation"}, "answer": "B", "explanation": "The Securities and Exchange Commission regulates and controls the activities of the Nigerian Stock Exchange. The Securities and Exchange Commission (SEC) is the main regulatory institution of the Nigerian capital market. It is supervised by the Federal Ministry of Finance. The main function of the SEC is to oversee the Nigerian Stock Exchange to ensure orderly and equitable dealings in securities, and protect the market against insider trading abuses.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>31", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Which of the following is drawn up as a guide to the running of a Partnership?", "images": [], "options": {"A": "Deed of Agreement", "B": "Partnership Act", "C": "Memorandum of Association", "D": "Prospectus"}, "answer": "A", "explanation": "A Deed of Agreement is drawn up as a guide to the running of a Partnership. This document outlines the rights, responsibilities, and obligations of each partner in the partnership. It is a legally binding document that is used to manage disputes, disagreements, and other issues that may arise in the course of the partnership. The Partnership Act is a law that governs partnerships, but it is not drawn up by the partners themselves. The Memorandum of Association and the Prospectus are documents related to a company, not a partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>32", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The law governing the operations of companies and partnership in Nigeria is the", "images": [], "options": {"A": "Nigerian Companies Decree", "B": "Nigerian Partnership Act", "C": "Nigerian Enterprises Promotion Decree", "D": "Companies And Allied Matters Decree"}, "answer": "D", "explanation": "The law governing the operations of companies and partnerships in Nigeria is the Companies And Allied Matters Decree. This law provides the legal framework for the formation, management, and winding up of companies and partnerships. The Nigerian Companies Decree and the Nigerian Partnership Act do not exist, while the Nigerian Enterprises Promotion Decree is related to the promotion of Nigerian enterprises, not the operations of companies and partnerships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>33", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is a non-indemnity insurance?", "images": [], "options": {"A": "Personal Accident Insurance", "B": "Burglary Insurance", "C": "Fire Insurance", "D": "Consequential loss Insurance"}, "answer": "A", "explanation": "Non-indemnity insurance is a type of insurance where the insured is paid a specified amount regardless of the actual loss suffered. Personal Accident Insurance is a type of non-indemnity insurance because the insured is paid a specified amount in the event of an accident, regardless of the actual loss suffered.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>34", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The document issued to a newly formed public company to commence business is called the", "images": [], "options": {"A": "certificate of incorporation", "B": "articles of association", "C": "memorandum of association", "D": "trading certificate"}, "answer": "D", "explanation": "A trading certificate is a document issued by the registrar of companies to a public company, allowing it to commence business. This is after the company has met certain requirements, including having a certain minimum amount of share capital. The certificate of incorporation, articles of association, and memorandum of association are all documents that are part of the process of forming a company, but they do not give the company the right to commence business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>35", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Small scale retail attracts a lot of new entrepreneurs in West Africa because", "images": [], "options": {"A": "many people have had good training in retail trade", "B": "it is easy to succeed with the business", "C": "banks are always ready to lend retailers", "D": "only a small amount of capital is needed to start the business"}, "answer": "D", "explanation": "Small scale retail attracts a lot of new entrepreneurs in West Africa because it requires only a small amount of capital to start the business. This is because the cost of setting up a small scale retail business is relatively low compared to other types of businesses. This makes it an attractive option for new entrepreneurs who may not have a lot of capital to invest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>36", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "In marine insurance, the deliberate throwing of some goods into the sea to prevent the ship from sinking is an example of", "images": [], "options": {"A": "a constructive loss", "B": "a partial loss", "C": "a general average loss", "D": "a total loss"}, "answer": "C", "explanation": "In marine insurance, the deliberate throwing of some goods into the sea to prevent the ship from sinking is an example of a general average loss. A general average loss refers to a loss that occurs when a deliberate act is performed to save the vessel, cargo, or both from a common peril. In this case, the act of throwing goods into the sea is done to lighten the ship and prevent it from sinking, which is a common peril.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1996>37", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Tax levied on goods at each stage of their movement from production to the final consumer is known as", "images": [], "options": {"A": "customs drawback", "B": "ad valorem duty", "C": "specific tax", "D": "value added tax"}, "answer": "D", "explanation": "Value Added Tax (VAT) is a type of tax that is assessed incrementally. It is levied at each stage of the production and distribution process and is based on the value added to the product at each stage. This is different from other types of taxes which are levied on the total value of the product or service at one stage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>38", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "An association of businessmen engaged in both commerce and industry is called", "images": [], "options": {"A": "trade association", "B": "Trade union", "C": "chamber of commerce", "D": "trust"}, "answer": "C", "explanation": "A Chamber of Commerce is a form of business network, e.g., a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community. They are not a trade union (which is an organization of workers who have come together to achieve common goals such as protecting the integrity of its trade, improving safety standards, etc.), a trade association (which is an organization founded and funded by businesses that operate in a specific industry), or a trust (which is a fiduciary relationship in which one party, known as a trustor, gives another party, the trustee, the right to hold title to property or assets for the benefit of a third party).", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>39", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "When the government decides to run a statutory corporation as a profit-oriented enterprise, this is known as", "images": [], "options": {"A": "nationalization", "B": "commercialization", "C": "take-over bid", "D": "privatization"}, "answer": "B", "explanation": "Commercialization is the process of managing or running something principally for financial gain. When the government decides to run a statutory corporation as a profit-oriented enterprise, it is commercializing that corporation. Nationalization is the process of transforming private assets into public assets by bringing them under the public ownership of a national government or state. A take-over bid is a type of corporate action in which an acquiring company makes an offer to the target company's shareholders to buy the target company's shares. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>40", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The primary aim of commerce is to", "images": [], "options": {"A": "produce goods and services", "B": "warehouse goods", "C": "advertise goods and services", "D": "exchange goods and services"}, "answer": "D", "explanation": "The primary aim of commerce is to exchange goods and services. Commerce is the conduct of trade among economic agents. Generally, commerce refers to the exchange of goods, services or something of value, between businesses or entities. Producing goods and services is the role of production, not commerce. Warehousing goods is a part of the distribution aspect of commerce, but not its primary aim. Advertising goods and services is a part of the promotion aspect of commerce, but not its primary aim.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>41", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Which of the following has a fixed rate of dividend?", "images": [], "options": {"A": "Debenture", "B": "Ordinary share", "C": "Founder's share", "D": "Preference share"}, "answer": "D", "explanation": "Preference shares have a fixed rate of dividend. This means that the dividends paid to preference shareholders are a fixed percentage of the nominal value of the shares. This is unlike ordinary shares where dividends can fluctuate based on the company's profits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>42", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not a barrier to the smooth functioning of ECOWAS?", "images": [], "options": {"A": "Different currencies", "B": "Different languages", "C": "Adequate population", "D": "Political crisis"}, "answer": "C", "explanation": "Adequate population is not a barrier to the smooth functioning of ECOWAS. In fact, a large population can be beneficial as it provides a larger market for goods and services. Barriers to the smooth functioning of ECOWAS would include factors that hinder trade and cooperation such as different currencies, different languages, and political crises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>43", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The capital market is a market", "images": [], "options": {"A": "for long term loans", "B": "for new shares of public companies", "C": "where money is deposited", "D": "where foreign currencies are bought and sold"}, "answer": "A", "explanation": "The capital market is a market for long-term loans. It is a market where individuals and institutions with surplus funds are linked with those requiring long-term financing. It is not primarily for new shares of public companies, nor is it a place where money is deposited or where foreign currencies are bought and sold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>44", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following is primarily established to promote the growth of industry in Nigeria?", "images": [], "options": {"A": "NITEL", "B": "UBA", "C": "NIPOST", "D": "NIDB"}, "answer": "D", "explanation": "The Nigerian Industrial Development Bank (NIDB) is primarily established to promote the growth of industry in Nigeria. It provides long-term financing to industrial enterprises. NITEL, UBA, and NIPOST are not primarily established for the growth of industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>45", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Another name for sea taxi is", "images": [], "options": {"A": "tramp", "B": "liner", "C": "special freighter", "D": "voyage charter"}, "answer": "A", "explanation": "A sea taxi is also known as a tramp. A tramp is a ship that does not have a fixed schedule or published ports of call. Unlike a liner, which has a fixed schedule and routes, a tramp goes wherever the charterer decides, much like a taxi.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>46", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Contracts for the carriage of goods by sea are generally called", "images": [], "options": {"A": "charter by demise", "B": "charter parties", "C": "voyage charters", "D": "time charter"}, "answer": "B", "explanation": "Contracts for the carriage of goods by sea are generally called charter parties. A charter party is a legal term in shipping where a shipowner hires out their vessel to a charterer for a specific journey or a period of time. The charterer then has control over where the ship goes and what it carries. The other options, charter by demise, voyage charters, and time charter, are types of charter parties, but the general term for these contracts is charter parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>47", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE", "question": "A nation's earnings from tourism are classified as", "images": [], "options": {"A": "visible exports", "B": "invisible exports", "C": "visible imports", "D": "invisible imports"}, "answer": "B", "explanation": "A nation's earnings from tourism are classified as 'invisible exports'. This is because they are part of the service sector and do not involve the physical movement of goods across borders. Therefore, they are not 'visible' in the traditional sense. The term 'export' is used because the service (in this case, tourism) is provided to foreign individuals or entities, bringing money into the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>48", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An association of employees in an organization is called a", "images": [], "options": {"A": "trade union", "B": "trade association", "C": "consumer association", "D": "credit union"}, "answer": "A", "explanation": "An association of employees in an organization is called a 'trade union'. Trade unions are organizations that represent the interests of workers or employees in a particular industry or occupation. They negotiate with employers on issues such as wages, working conditions, and employment policies. Trade associations, on the other hand, represent the interests of businesses in a particular industry. Consumer associations represent the interests of consumers, and credit unions are cooperative financial institutions where members can borrow from pooled deposits at low interest rates.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1996>49", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "A firm that accepts a portion of the risk involved in an insurance contract is", "images": [], "options": {"A": "a broker", "B": "an actuary", "C": "a speculator", "D": "an underwriter"}, "answer": "D", "explanation": "An underwriter is a person or company that takes on the risk involved in an insurance contract. They assess the risk and exposure of potential clients and decide how much coverage the client should receive and how much they should pay for it. In this case, the firm that accepts a portion of the risk involved in an insurance contract is an underwriter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1996>50", "subject": "Commerce", "year": "1996", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Musa places the bicycle for sale at #800.00 and Dada had agreed to pay the amount. In this transaction, Musa is the", "images": [], "options": {"A": "offeror", "B": "offeree", "C": "buyer", "D": "guarantor"}, "answer": "A", "explanation": "In a sales transaction, the person who places the item for sale is known as the offerer or seller. They are the ones who make the offer which the other party can accept or reject. In this case, Musa is the offerer because he is the one who placed the bicycle for sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>1", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Extractive occupation is an example of", "images": [], "options": {"A": "construction industry", "B": "manufacturing industry", "C": "tertiary industry", "D": "primary industry"}, "answer": "D", "explanation": "Extractive occupations are those that involve the extraction of raw materials from the earth. This includes activities such as mining, fishing, lumbering, and farming. These occupations fall under the primary industry, which is concerned with the extraction of raw materials. Therefore, the correct answer is 'primary industry'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1997>2", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "The fastest means of sending a printed message from Lagos to London is through", "images": [], "options": {"A": "aeroplane", "B": "telephone", "C": "cablegram", "D": "telex"}, "answer": "D", "explanation": "The fastest means of sending a printed message from Lagos to London would be through telex. Telex is a networked system of teleprinters, which can send and receive text-based messages instantly. While an aeroplane can physically transport a printed message, it is not as fast as electronic transmission. A telephone is used for voice communication, not printed messages. A cablegram is a dated term for a telegram sent by submarine cable, which is also not as fast as telex.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>3", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "An association that mobilizes the savings of members and channels them to needy members is known as", "images": [], "options": {"A": "Consumer Co-operative", "B": "Producer Co-operative", "C": "Thrift and Credit Co-operative", "D": "Multi-purpose Co-operative"}, "answer": "C", "explanation": "A Thrift and Credit Co-operative is a type of co-operative that mobilizes the savings of its members and channels them to needy members. This is done through loans and other forms of financial assistance. The other options do not accurately describe this type of co-operative.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>4", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "If Ade issues a Union Bank cheque to Chukwu, the Union Bank is the", "images": [], "options": {"A": "drawee", "B": "payee", "C": "drawer", "D": "acceptor"}, "answer": "A", "explanation": "In the context of a cheque, the drawee is the bank or other financial institution that is asked to pay the amount. In this case, Union Bank is the drawee because it is the bank that is asked to pay the amount of the cheque to Chukwu. The drawer is the person who writes the cheque (in this case, Ade), and the payee is the person to whom the cheque is made out (in this case, Chukwu). The acceptor is not a term used in the context of a cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>5", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is the clearing house for all the banks in the country?", "images": [], "options": {"A": "The Federal Mortgage Bank of Nigeria", "B": "The Nigerian Industrial Development Bank", "C": "The Central Bank of Nigeria", "D": "The Nigerian Bank for Commerce and Industry"}, "answer": "C", "explanation": "The Central Bank of Nigeria serves as the clearing house for all the banks in the country. A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The Central Bank of Nigeria provides this service for all other banks in the country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>6", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "Commerce developed as a result of", "images": [], "options": {"A": "speculation", "B": "competition", "C": "specialization", "D": "importation"}, "answer": "C", "explanation": "Commerce developed as a result of specialization. Specialization refers to the method of production where a business, area or economy focuses on the production of a limited scope of products or services to gain greater degrees of productive efficiency within an overall system. This leads to trade as people exchange the goods and services that they specialize in for other goods and services they need, hence leading to the development of commerce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1997>7", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "An overdraft can only be granted to the holder of a", "images": [], "options": {"A": "fixed deposit", "B": "savings deposit", "C": "loan account", "D": "current account"}, "answer": "D", "explanation": "An overdraft is a facility provided by banks to their customers (usually businesses) to withdraw more money from their account than what is actually available. This facility is typically provided only to current account holders. A current account is a type of deposit account that caters to professionals and businessmen alike. Dealing largely with liquid deposits, this product allows for withdrawal of funds and checks being written against the balance and does not limit the number of transactions in a day.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>8", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Use the diagram below to answer the questions         The appropriate label for X on the diagram is", "images": ["Commerce/imgs/1997/jhj.png"], "options": {"A": "commerce", "B": "industry", "C": "direct services", "D": "occupations"}, "answer": "A", "explanation": "X on the diagram represent commerce which is divided into trade and aids to trade.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>9", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Use the diagram below to answer the questions       The appropriate label for Y on the diagram is", "images": ["Commerce/imgs/1997/jhj.png"], "options": {"A": "branches of commerce", "B": "distribution channel", "C": "direct services", "D": "aids to trade"}, "answer": "D", "explanation": "Y on the diagram represent Aids to trade. Aids to trade helps to facilitate trade and it includes: banking, transportation, communication, insurance, warehousing, etc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>10", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Use the diagram below to answer the questions       The appropriate label for P on the diagram is", "images": ["Commerce/imgs/1997/jhj.png"], "options": {"A": "home trade", "B": "agent", "C": "wholesale", "D": "co-operatives"}, "answer": "C", "explanation": "P represent Wholesale Trade. The wholesale trade is a type of trade in which goods are sold to the retailer in large quantities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>11", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of capital to a partnership?", "images": [], "options": {"A": "Buying on credit", "B": "Ploughed back profit", "C": "Borrowing", "D": "Shares"}, "answer": "D", "explanation": "A partnership is a type of business where two or more people share ownership, as well as the risk of loss and the potential for profit. The sources of capital for a partnership can include buying on credit, ploughed back profit, and borrowing. However, shares are not a source of capital for a partnership. Shares are typically associated with corporations, where the business is owned by shareholders. In a partnership, the partners contribute capital and share in the profits and losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>12", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following functions of the wholesaler helps to stabilize prices", "images": [], "options": {"A": "Financing", "B": "Advice to retailers", "C": "Provision of credit", "D": "Warehousing"}, "answer": "D", "explanation": "The function of the wholesaler that helps to stabilize prices is Warehousing. Warehousing involves the storage of goods. By storing goods, wholesalers can release them into the market when there is demand, thus preventing a surplus or shortage of goods which can lead to price instability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>13", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The rebate given to the retailer by the wholesaler to enable him make profit is known as", "images": [], "options": {"A": "commission", "B": "mark-up", "C": "trade discount", "D": "cash discount"}, "answer": "C", "explanation": "The rebate given to the retailer by the wholesaler to enable him make profit is known as trade discount. A trade discount is a reduction in the listed price of an item when it's sold for resale. It's used as an incentive for the retailer to carry and promote a wholesaler's product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>14", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION", "question": "Division of labour often results in", "images": [], "options": {"A": "a decrease in production", "B": "an increase in production", "C": "waste of time", "D": "uneconomic use of tools"}, "answer": "B", "explanation": "Division of labour refers to the breaking down of a production process into small tasks, with each task performed by a specialist. It often results in an increase in production because it allows workers to focus on a few tasks, thereby improving their efficiency and productivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1997>15", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "Who among the following is not an agent?", "images": [], "options": {"A": "Broker", "B": "Factor", "C": "Jobber", "D": "Manufacturer's representative"}, "answer": "C", "explanation": "In commerce, an agent is a person or entity that has been legally empowered to act on behalf of another person or entity. A broker, factor, and manufacturer's representative are all types of agents as they act on behalf of others in commercial transactions. However, a jobber is not an agent. A jobber is a trader who purchases goods from manufacturers and sells them to retailers or consumers. Unlike agents, jobbers take ownership of the goods they deal in.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>16", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Who among the following comes first in the channel of distribution?", "images": [], "options": {"A": "Consumer", "B": "Retailer", "C": "Consignor", "D": "Manufacturer"}, "answer": "D", "explanation": "In the channel of distribution, the manufacturer comes first. The manufacturer is the one who produces the goods. After production, the goods are then passed on to the wholesaler, then to the retailer, and finally to the consumer. So, the correct answer is Manufacturer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>17", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The services rendered by Nigerian Airways to foreign companies are part of Nigeria's", "images": [], "options": {"A": "visible exports", "B": "visible imports", "C": "invisible exports", "D": "invisible imports"}, "answer": "C", "explanation": "The services rendered by Nigerian Airways to foreign companies are part of Nigeria's invisible exports. Invisible exports refer to the sale of services to foreign countries. These services can include transportation, tourism, banking, and insurance services. In this case, the services provided by Nigerian Airways to foreign companies are considered as an export of services from Nigeria to other countries, hence they are termed as invisible exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>18", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "One of the characteristics of a debenture is that", "images": [], "options": {"A": "it yields a fixed rate of dividends", "B": "it has no redemption date", "C": "it yields a fixed rate of interest", "D": "its holder has a voting right"}, "answer": "C", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. One of the characteristics of a debenture is that it yields a fixed rate of interest, not dividends. Therefore, the correct answer is 'it yields a fixed rate of interest'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>19", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : ADVANTAGES & DISADVANTAGES", "question": "Which of the following is a disadvantage of credit transaction?", "images": [], "options": {"A": "increases turnover", "B": "facilitates the sale of durable goods", "C": "encourages the habit of saving", "D": "encourages bad debt"}, "answer": "D", "explanation": "Credit transaction refers to a transaction where the goods are sold and delivered, but the payment is made at a later date. While it has several advantages like increasing turnover and facilitating the sale of durable goods, one of the disadvantages is that it can encourage bad debt. Bad debt is money that is owed to a company and is unlikely to be paid. Therefore, the correct answer is 'encourages bad debt'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>20", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "In which of the following do the goods become the property of the buyer on the payment of first installment", "images": [], "options": {"A": "Hire-purchase", "B": "Deferred payment", "C": "Leasehold", "D": "Cash with order"}, "answer": "A", "explanation": "In a hire-purchase agreement, the goods become the property of the buyer after the payment of the first installment. This is because the hire-purchase agreement is a type of installment plan where the buyer takes possession of the items immediately but ownership of the goods is transferred only when the full payment has been completed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>21", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following government legislation is not aimed at consumer protection?", "images": [], "options": {"A": "Taxation Law", "B": "Sales of Goods Act", "C": "Food and Drugs Act", "D": "Standards Organization Act"}, "answer": "A", "explanation": "Taxation Law is not aimed at consumer protection. It is a body of laws and rules which govern the process of government levying taxes on citizens and businesses. The other options like Sales of Goods Act, Food and Drugs Act, and Standards Organization Act are all aimed at protecting the rights and interests of consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>22", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Self-service, mail order and automatic vending are examples of", "images": [], "options": {"A": "marketing mix", "B": "sales promotion", "C": "public relations", "D": "selling techniques"}, "answer": "D", "explanation": "Self-service, mail order, and automatic vending are examples of selling techniques. Selling techniques are strategies that companies use to promote and sell their products or services. These techniques can vary depending on the nature of the product or service, the target audience, and other factors. In this case, self-service, mail order, and automatic vending are all methods that allow customers to purchase products or services without the need for a salesperson or other intermediary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1997>23", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Span of control is defined as the", "images": [], "options": {"A": "authority of the supervisor", "B": "qualification possessed by the supervisor", "C": "number of staff in the organization", "D": "number of subordinates reporting directly to a supervisor"}, "answer": "D", "explanation": "Span of control refers to the number of subordinates that a manager or supervisor can effectively manage. This can vary depending on the nature of the work, the skills of the manager or supervisor, and the skills of the subordinates. In this case, the span of control is defined as the number of subordinates reporting directly to a supervisor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>24", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "An established pattern of relationships among members of an organization is known as", "images": [], "options": {"A": "organizational behaviour", "B": "organizational structure", "C": "organizational manual", "D": "organizational climate"}, "answer": "B", "explanation": "An established pattern of relationships among members of an organization is known as organizational structure. Organizational structure refers to how individual and team work within an organization are coordinated. It defines how tasks are divided, grouped, and coordinated in an organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>25", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The aspect of management which ensures that there is no deviation from the set standards is called", "images": [], "options": {"A": "controlling", "B": "planning", "C": "commanding", "D": "organizing"}, "answer": "A", "explanation": "The aspect of management which ensures that there is no deviation from the set standards is called controlling. Controlling is the process of comparing actual performance with the set standards of the organization's goals and then taking corrective action as necessary. It's a fundamental aspect of management that allows an organization to track performance and ensure that necessary changes are made in a timely manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>26", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "When a Public Limited Company is incorporated it means that", "images": [], "options": {"A": "it is entitled to commence business", "B": "It has been given certificate of trading", "C": "It has a legal existence", "D": "its shares cannot be transferred"}, "answer": "C", "explanation": "Incorporation of a Public Limited Company means that it has a legal existence separate from its owners. It can own property, sue and be sued in its own name. This is a concept known as 'corporate personality'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>27", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The Manager,  Afribank,  Lagos.    Please pay to Great Nigeria Insurance Company, from my account, a sum of #125.00 at the end of every month until further notice, starting from this month.    The above instruction is a", "images": [], "options": {"A": "bill of exchange", "B": "certified cheque", "C": "promissory note", "D": "standing order"}, "answer": "D", "explanation": "The instruction given in the question is a standing order. A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The other options do not fit the description given in the question. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party at a predetermined future date. A certified cheque is a type of cheque for which the bank verifies that sufficient funds exist in the account to cover the cheque, and so it cannot be bounced. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>28", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retailer's mark-up is his", "images": [], "options": {"A": "total cost less total sales", "B": "total sales less total returns", "C": "gross profit less expenses", "D": "selling price less cost price"}, "answer": "D", "explanation": "A retailer's mark-up is the difference between the cost of a good or service and its selling price. It is calculated by subtracting the cost price from the selling price. This is the retailer's gross profit before any expenses are deducted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>29", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Debenture is an example of", "images": [], "options": {"A": "fixed capital", "B": "share capital", "C": "loan capital", "D": "working capital"}, "answer": "C", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. It is an example of loan capital, which is a form of long-term debt. Debentures are backed only by the general creditworthiness and reputation of the issuer. Fixed capital refers to any kind of real or physical capital (fixed asset) that is not used up in the production of a product, share capital refers to all funds raised by a company in exchange for shares of either common or preferred shares of stock, and working capital is a measure of both a company's operational efficiency and its short-term financial health.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>30", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not an acceptable collateral security for a bank loan?", "images": [], "options": {"A": "Certificate of occupancy", "B": "Life assurance policy", "C": "Lien on deposit account", "D": "Warehouse warrant"}, "answer": "B", "explanation": "A life assurance policy is not an acceptable collateral security for a bank loan. Collateral is something pledged as security for repayment of a loan, to be forfeited in the event of a default. A life assurance policy does not meet this criteria as it is a contract with an insurance company. In exchange for premium payments, the insurance company provides a lump-sum payment, known as a death benefit, to beneficiaries upon the insured's death. It does not have a guaranteed value that can be used as collateral.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>31", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Which of the following is the basic principle of marketing concept?", "images": [], "options": {"A": "Seller-oriented", "B": "Producer-oriented", "C": "Consumer-oriented", "D": "Manufacturer-oriented"}, "answer": "C", "explanation": "The basic principle of marketing concept is being consumer-oriented. This means that the company focuses on meeting the needs and wants of the consumers rather than just focusing on the product or the producer. The company designs its marketing strategy around what the consumer needs or wants, and not just on what the company wants to sell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>32", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The compensation given to brokers who sell shares to jobbers is called", "images": [], "options": {"A": "premium", "B": "commission", "C": "salary", "D": "interest"}, "answer": "B", "explanation": "The compensation given to brokers who sell shares to jobbers is called commission. In the stock market, a commission is a service charge assessed by a broker or investment advisor in return for providing investment advice and/or handling the purchase or sale of a security.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>33", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "The Stock Exchange does not deal in", "images": [], "options": {"A": "shares", "B": "treasury bills", "C": "debentures", "D": "stocks"}, "answer": "B", "explanation": "The Stock Exchange does not deal in treasury bills. Treasury bills are short-term debt obligations issued by a national government to finance their spending. They are not traded in the stock exchange but in the money market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>34", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The insurance principle which expects the insured and the insurer to disclose all facts about a proposed contract is called", "images": [], "options": {"A": "uberrimae fidei", "B": "indemnity", "C": "proximate cause", "D": "insurable interest"}, "answer": "A", "explanation": "The principle of 'uberrimae fidei' or utmost good faith is a fundamental principle of insurance. According to this principle, the insurance contract must be signed by both parties (i.e., the insurer and the insured) in an absolute good faith or belief or trust. The person getting insured must willingly disclose and surrender to the insurer his complete true information regarding the subject matter of insurance. The insurer's liability gets void (i.e., legally revoked or cancelled) if any facts, about the subject matter of insurance are either omitted, hidden, falsified or presented in a wrong manner.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>35", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is not covered by fire insurance policy?", "images": [], "options": {"A": "Consequential loss", "B": "Gas explosion", "C": "Domestic boilers", "D": "Lightning"}, "answer": "A", "explanation": "Fire insurance policies typically do not cover consequential losses. Consequential loss is an indirect loss, which is not caused directly by the insured peril, but is the result of another loss, which is directly caused by the insured peril. For example, if a fire occurs and a business must close for repairs, the loss of income during the closure would be considered a consequential loss.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>36", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not considered when siting a retail shop?", "images": [], "options": {"A": "Advertising", "B": "Rent", "C": "Accessibility", "D": "Target population"}, "answer": "A", "explanation": "When siting a retail shop, factors such as rent, accessibility, and target population are considered. Rent is important because it determines the cost of maintaining the shop at that location. Accessibility is crucial because it determines how easy it is for customers to reach the shop. The target population is also considered because it determines the potential customer base. However, advertising is not a factor considered when siting a retail shop. Advertising is a strategy used to promote the shop and its products after it has been established.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>37", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "The law stipulating that labels should contain full details about a product is known as the", "images": [], "options": {"A": "Hire-purchase Act", "B": "Price Control Act", "C": "Standards Organisation of Nigeria Act", "D": "Trade description Act"}, "answer": "D", "explanation": "The Trade Description Act is the law that stipulates that labels should contain full details about a product. This law is designed to prevent manufacturers, retailers or service industry providers from misleading consumers as to what they are spending their money on. This can include information about the product, how it works, what it contains, and any other relevant information. The other options, Hire-purchase Act, Price Control Act, and Standards Organisation of Nigeria Act, do not specifically deal with product labeling.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>38", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : MEANING AND TYPES", "question": "A design which distinguishes the goods of one producer from those of others is called", "images": [], "options": {"A": "patent-right", "B": "copyright", "C": "trade mark", "D": "licence"}, "answer": "C", "explanation": "A design which distinguishes the goods of one producer from those of others is called a trade mark. A trademark is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others. It is a type of intellectual property consisting of a recognizable sign, design, or expression which distinguishes products or services of a particular source from those of others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>39", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "Which of the following is responsible for the maintenance of the quality of goods produced", "images": [], "options": {"A": "Customs and Exercise Department", "B": "Sanitary Inspectors", "C": "Standards Organization of Nigeria", "D": "Federal Environmental Protection Agency"}, "answer": "C", "explanation": "The Standards Organization of Nigeria is responsible for the maintenance of the quality of goods produced. It is the apex standardization body in Nigeria. It was established to ensure that goods and services produced or imported into Nigeria meet the minimum requirements of Nigerian Industrial Standards (NIS), and are safe and fit for their intended uses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>40", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document stating the particular country from which goods are imported is called", "images": [], "options": {"A": "certificate of origin", "B": "export invoice", "C": "consular invoice", "D": "export licence"}, "answer": "A", "explanation": "A Certificate of Origin (CoO) is a document that states the country of origin of a particular product. It is used in international trade and is important because it helps to determine whether certain goods are eligible for import, or whether goods are subject to duties. It is usually issued by a Chamber of Commerce and contains information like the exporter, the importer, and a description of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>41", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following makes it possible for people to collect their letters at their convenient time ?", "images": [], "options": {"A": "Franking", "B": "Record Delivery", "C": "Post Office Box", "D": "Business Reply Service"}, "answer": "C", "explanation": "A Post Office Box (P.O. Box) is a uniquely addressable lockable box located on the premises of a post office station. It allows people to receive mail at a place other than their home. This makes it possible for people to collect their letters at their convenient time as the mail is securely stored in the box until it is collected by the owner.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1997>42", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following is not a function of the Nigerian Ports Authority?", "images": [], "options": {"A": "Checking smuggling activities", "B": "Handling of goods", "C": "Collection of harbour dues", "D": "Decongestion of ports"}, "answer": "A", "explanation": "The function of checking smuggling activities is not a direct function of the Nigerian Ports Authority. This function is primarily carried out by the Nigerian Customs Service. The Nigerian Ports Authority is responsible for the administration of the ports, handling of goods, collection of harbour dues, and decongestion of ports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>43", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following indicates special crossing on a cheque? Two parallel lines with", "images": [], "options": {"A": "\"& Co\" and \"not negotiable\"", "B": "the abbreviation \"& Co\" only", "C": "\"account payee\" only", "D": "the name of a particular bank"}, "answer": "C", "explanation": "In special crossing, the name of a bank is inserted between the transerve lines. This restricts payment to a specific named bank. The forms special crossing are:   - non negotiable: cheque cannot be paid to any person except the bearer of the name on the cheque. e.g \"& Co\" or \" Non-negotiable\" etc.  - Alc payee only: the cheques are to be paid into the account of the person or firm named on the cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>44", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is usually sent to prospective buyer when the seller expects payment of the goods dispatched?", "images": [], "options": {"A": "Pro-forma invoice", "B": "Advice note", "C": "Consignment note", "D": "Statement of account"}, "answer": "A", "explanation": "A Pro-forma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is usually sent when the seller expects payment for the goods dispatched. It typically describes the purchased items and notes the cost along with other important information like shipping weight and transport charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>45", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "A company which acquires more than 50% voting shares of another company is called?", "images": [], "options": {"A": "a trust", "B": "a cartel", "C": "a holding company", "D": "a consortium"}, "answer": "C", "explanation": "A holding company is a company that owns the stocks of other companies. The term is usually used to refer to a company that does not produce goods or services itself, but its purpose is to own shares of other companies. If a company acquires more than 50% voting shares of another company, it is called a holding company because it has controlling interest in the company.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>46", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "Which of the following is true of a merger?", "images": [], "options": {"A": "Original names of the companies are retained", "B": "Expansion is restricted", "C": "All debts are written off", "D": "The company formed acquires a new name"}, "answer": "D", "explanation": "A merger is a business strategy of combining two or more companies into a single company. In most cases, the merged companies acquire a new name to represent the new entity formed. This is done to create a new corporate identity. Therefore, the statement 'The company formed acquires a new name' is true of a merger.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>47", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following covers damages to the body of a ship and its machinery?", "images": [], "options": {"A": "Freight insurance", "B": "Cargo insurance", "C": "General average insurance", "D": "Hull insurance"}, "answer": "D", "explanation": "Hull insurance is a type of marine insurance that covers damages to the body of a ship and its machinery. It is designed to provide coverage for physical damages to the ship, including the hull and machinery. Therefore, the statement 'Hull insurance covers damages to the body of a ship and its machinery' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>48", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The major disadvantage of pipeline transportation is that it", "images": [], "options": {"A": "does not involve too much labour", "B": "reduces road congestion", "C": "is fast", "D": "is not easy to detect damages"}, "answer": "D", "explanation": "The major disadvantage of pipeline transportation is that it is not easy to detect damages. This is because pipelines are often buried underground or under the sea, making it difficult to visually inspect them for damages. This can lead to undetected leaks or ruptures, which can cause significant environmental damage and financial loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1997>49", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following are true of a bill of lading?     i. it is a means of payment in foreign trade.   ii. it is document of title to goods.   iii. it is a contract of carriage.   iv. it is usually drawn in triplicate.", "images": [], "options": {"A": "i and iii only", "B": "i, ii and iii only", "C": "ii and iii only", "D": "ii, iii and iv only"}, "answer": "D", "explanation": "A bill of lading is a document used in trade to detail the goods being transported, the destination, and the party responsible for the shipment. It serves as a contract of carriage, a document of title to goods, and is usually drawn in triplicate. However, it is not a means of payment in foreign trade. Therefore, the statements ii, iii, and iv are correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1997>50", "subject": "Commerce", "year": "1997", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The difference between the total amount owed to a country and the total amount owed by it is", "images": [], "options": {"A": "trade surplus", "B": "terms of trade", "C": "balance of payments", "D": "balance of trade"}, "answer": "D", "explanation": "The difference between the total amount owed to a country and the total amount owed by it is referred to as the balance of trade. The balance of trade is the difference between the value of a country's exports and the value of its imports. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit. The balance of trade is a significant part of a country's balance of payments, which includes all transactions between a country's residents and its nonresidents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>1", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce is concerned mainly with the", "images": [], "options": {"A": "production of goods and services", "B": "distribution of goods and services", "C": "consumption of goods and services", "D": "storing of goods"}, "answer": "B", "explanation": "Commerce is primarily concerned with the distribution of goods and services. It involves activities that bridge the gap between the producers and the consumers. These activities include buying, selling, transportation, storage, banking, insurance etc. It does not directly involve in the production or consumption of goods and services, nor the storing of goods, although these are related activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>2", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The two main branches of trade are", "images": [], "options": {"A": "commerce and aids to trade", "B": "home and foreign trade", "C": "foreign and entreport trade", "D": "whole sale and retail trade"}, "answer": "B", "explanation": "Trade is divided or classified into home and foreign trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>3", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Who among the following is not engaged in a commercial occupation", "images": [], "options": {"A": "a stock brocker", "B": "an engineer", "C": "a banker", "D": "a common carrier"}, "answer": "B", "explanation": "An engineer is not engaged in a commercial occupation. A commercial occupation is one that involves trading, buying or selling of goods and services with the aim of making a profit. An engineer, on the other hand, is a professional who applies the principles of science and mathematics to develop economical solutions to technical problems. Their work is predominantly intellectual and varied and not of a character which requires them to sell goods or services for profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>4", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "On which of the following grounds may a company be compulsorily wound up?", "images": [], "options": {"A": "the company is making abnormal profits", "B": "it did not declare dividends every year", "C": "its products compete with that of a government company", "D": "it fails to commence business within a year of its incorporation"}, "answer": "D", "explanation": "A company may be compulsorily wound up if it fails to commence business within a year of its incorporation. This is because the law requires that a company must start its business operations within a specified period after its incorporation. If it fails to do so, it may be seen as not being serious about its business operations, and hence, may be wound up. The other options do not provide valid grounds for compulsory winding up of a company.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>5", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : FEATURES AND IMPORTANCE", "question": "The management and control of co-operative societies are in the hands of the", "images": [], "options": {"A": "contributors", "B": "Board of Directors", "C": "Committee", "D": "Financial controller"}, "answer": "C", "explanation": "The management and control of co-operative societies are usually in the hands of a committee. A co-operative society is a voluntary association of individuals, united by common bond, who have come together to pursue their economic goals for their own benefits. They are managed by a committee elected from and by the members. The committee is responsible for making decisions and overseeing the activities of the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>6", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Key industries and those requiring huge capital are usually established as", "images": [], "options": {"A": "public corporations", "B": "public limited companies", "C": "private limited companies", "D": "holding companies"}, "answer": "A", "explanation": "Key industries and those requiring huge capital are established as public corporations because they involve significant public interest, large-scale investment, and often need government oversight and funding to ensure stability and accessibility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>7", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Movement of commercial vehicles in Nigeria is controlled by the", "images": [], "options": {"A": "Nigerian Ports Authority", "B": "National Association of Road Transport Workers", "C": "Federal Ministry of Transport", "D": "Nigerian Customs Authority"}, "answer": "C", "explanation": "The movement of commercial vehicles in Nigeria is controlled by the Federal Ministry of Transport. This is because the ministry is responsible for the formulation and management of the government's policies on transportation in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>8", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward of entrepreneurship as a factor of production is", "images": [], "options": {"A": "interest", "B": "commission", "C": "profit", "D": "salary"}, "answer": "C", "explanation": "The reward for entrepreneurship as a factor of production is profit. Entrepreneurs take on the risk of creating a business and if the business is successful, they earn profits. This is different from interest (which is the reward for capital), commission (which is a type of payment for services), and salary (which is the reward for labor).", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>9", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A document issued to a buyer showing the quantity description and prices of goods bought is called", "images": [], "options": {"A": "a catalogue", "B": "an invoice", "C": "a price list", "D": "an order"}, "answer": "B", "explanation": "An invoice is a document issued by a seller to a buyer that outlines the products or services that have been purchased, their quantities, and their prices. It serves as a request for payment and as a record of sale.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>10", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following describes the marketing mix?", "images": [], "options": {"A": "Distribution, production policy, promotion, pricing policy", "B": "Product planning, development , market research, price", "C": "Product, Price, place, development", "D": "Communication, advertising, pricing, promotion"}, "answer": "A", "explanation": "The marketing mix is a business tool used in marketing and by marketers. The marketing mix is often crucial when determining a product or brand's offer, and is often associated with the 4 P's: price, product, promotion, and place. Therefore, the first option is correct as it includes all these elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>11", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Which of the following is not a negotiable instrument?", "images": [], "options": {"A": "Invoice", "B": "Money order", "C": "Cheque", "D": "Promissory note"}, "answer": "A", "explanation": "A negotiable instrument is a document guaranteeing the payment of a specific amount of money, either on demand, or at a set time, with the payer usually named on the document. More specifically, it is a document contemplated by a contract, which warrants the payment of money, the amount of which is in flux until paid. Examples of negotiable instruments include checks, promissory notes, drafts, and certificates of deposit. An invoice is not a negotiable instrument because it does not guarantee payment of a specific amount of money. It is simply a document sent by a provider of a product or service to the purchaser, requiring payment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>12", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following is not a function of the Nigerian Airport Authority?", "images": [], "options": {"A": "Maintains the buildings and tarmac", "B": "Collects airport taxes", "C": "Controls movement of aircrafts", "D": "Maintains all aircrafts in the country"}, "answer": "D", "explanation": "The Nigerian Airport Authority is responsible for maintaining the buildings and tarmac, collecting airport taxes, and controlling the movement of aircrafts. However, it is not responsible for maintaining all aircrafts in the country. This is typically the responsibility of individual airlines or aircraft owners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>13", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Another name for a foreign order is", "images": [], "options": {"A": "consular invoice", "B": "dock warrant", "C": "standing order", "D": "indent"}, "answer": "D", "explanation": "A foreign order is also known as an indent. An indent is a commercial document that is used to order goods from a foreign country. It contains details about the type, quality, and quantity of goods to be imported.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>14", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "An agreement to deliver goods in the future after payment of the final installment is known as?", "images": [], "options": {"A": "credit sales", "B": "hire purchase", "C": "conditional sale", "D": "trade-in-sale"}, "answer": "B", "explanation": "An agreement to deliver goods in the future after payment of the final installment is known as hire purchase. In a hire purchase agreement, the buyer takes the goods on hire and agrees to pay the amount in installments. The ownership of the goods is transferred after the payment of the last installment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>15", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is a pre-sales service to the consumer?", "images": [], "options": {"A": "Installement of the product", "B": "Provision of credit facilities", "C": "Maintenance of product for a period of time", "D": "Transportation and delivery services"}, "answer": "B", "explanation": "Pre-sales services are activities that are performed before a customer purchases a product. These services are designed to help customers make better and informed decisions about their purchases. Provision of credit facilities is a pre-sales service because it involves providing customers with the financial means to purchase a product. This service is usually provided by financial institutions or by the seller itself. It helps to increase sales by making products affordable to customers who may not have the full amount to pay at once.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>16", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Rate of stock turnover is calculated to determine", "images": [], "options": {"A": "total volume of sales", "B": "number of times goods are bought and sold", "C": "number of times goods are counted", "D": "total value of goods in the store"}, "answer": "B", "explanation": "The rate of stock turnover is a measure of the number of times inventory is sold or used in a time period such as a year. It is calculated to determine the number of times goods are bought and sold. The equation for the rate of stock turnover is: Cost of Goods Sold / Average Inventory at cost. This ratio provides insight into a company's inventory management and sales. A higher turnover rate indicates that a company is selling goods quickly, and therefore, has efficient business practices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>17", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "Which of the following is not a feature of hire purchase?", "images": [], "options": {"A": "Customer pays initial deposit", "B": "Customer pays purchase price plus interest", "C": "Payment is by instalment", "D": "Ownership of goods passes to the customer on payment of a deposit"}, "answer": "D", "explanation": "In a hire purchase agreement, the ownership of the goods does not pass to the customer upon payment of a deposit. Instead, ownership is transferred only after the final payment has been made. Therefore, the statement 'Ownership of goods passes to the customer on payment of a deposit' is not a feature of hire purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>18", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is not connected with after-sales services?", "images": [], "options": {"A": "Installment", "B": "Granting trade discount", "C": "Providing spare parts", "D": "Repairing of product"}, "answer": "B", "explanation": "After-sales services are services provided after a customer has purchased a product. These typically include services such as product support, customer service, product warranties, returns, and repairs. Granting trade discounts is not an after-sales service. It is a sales strategy used to encourage customers to buy in bulk or to buy more frequently. Therefore, 'Granting trade discount' is not connected with after-sales services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>19", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Credit in business transaction is?", "images": [], "options": {"A": "a form of loan", "B": "compliment to a good customer", "C": "provision of services", "D": "a means of saving money"}, "answer": "A", "explanation": "Credit in business transactions is essentially a form of loan. It is an agreement where a business sells goods or services to a customer with the understanding that payment will be made at a later date. This is different from a compliment to a good customer, provision of services, or a means of saving money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>20", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following is true of rail transport?", "images": [], "options": {"A": "Suitable for perishable goods", "B": "Fast over long distances", "C": "Maximum handling of goods", "D": "Gaurantees safety of goods"}, "answer": "B", "explanation": "Rail transport is particularly effective over long distances. It is not necessarily suitable for perishable goods as it can take longer than other methods of transport. It does not guarantee the safety of goods, as accidents can still occur. While it can handle a large amount of goods, it does not necessarily handle the maximum amount compared to other methods like shipping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>21", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not a means of controlling credit by the Central Bank?", "images": [], "options": {"A": "Fixing the bank rate", "B": "Open market operations", "C": "Clearing inter-bank indebtedness", "D": "Special deposits"}, "answer": "C", "explanation": "The Central Bank controls credit through various means such as fixing the bank rate, open market operations, and special deposits. However, clearing inter-bank indebtedness is not a means of controlling credit by the Central Bank. Clearing inter-bank indebtedness is a process that involves settling debts between banks, which is not a direct method of credit control.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>22", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not a function of Development Banks?", "images": [], "options": {"A": "Give long-term loans", "B": "invest directly into Agriculture", "C": "Issue currency notes", "D": "Give technical advice to investors"}, "answer": "C", "explanation": "Development Banks are financial institutions that provide long-term loans, invest directly into Agriculture, and give technical advice to investors. However, issuing currency notes is not a function of Development Banks. This function is typically performed by the Central Bank.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>23", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following is an example of insurable risk?", "images": [], "options": {"A": "Change in consumer's taste", "B": "The probability of a third world war", "C": "Flood resulting from excessive rain in a year", "D": "The death of a business partner"}, "answer": "D", "explanation": "Insurable risks are those risks that insurance companies agree to take on in exchange for premiums. These risks are predictable and have the potential to cause significant financial loss. The death of a business partner is an example of an insurable risk because it is a predictable event that could cause significant financial loss to a business. The other options are not insurable risks because they are either too unpredictable (the probability of a third world war), not directly linked to financial loss (change in consumer's taste), or are generally not covered by insurance policies (flood resulting from excessive rain in a year).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>24", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "If Mr Olu insures Mr Obi's house, the insurer may, in event of a loss, refuse to pay compensation based on the principle of", "images": [], "options": {"A": "utmost good faith", "B": "subrogation", "C": "insurable interest", "D": "indemnity"}, "answer": "C", "explanation": "The principle of insurable interest states that the person getting an insurance policy must have a financial interest in the object of the insurance. In other words, the insured must stand to suffer a financial loss if the insured event occurs. If Mr Olu insures Mr Obi's house, Mr Olu does not have an insurable interest in Mr Obi's house unless he stands to suffer a financial loss if the house is damaged. Therefore, the insurer may refuse to pay compensation based on the principle of insurable interest. The principles of utmost good faith, subrogation, and indemnity are also important in insurance, but they do not directly relate to the scenario described in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>25", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "Which of the following shows the quality of money", "images": [], "options": {"A": "Ability to represent both small and large values", "B": "Used for deffered payments", "C": "Used as a unit for account", "D": "Facilitating exchange"}, "answer": "A", "explanation": "The quality of money is shown by its ability to represent both small and large values. This is because money serves as a standard of value, which means it provides a basis for measuring and comparing the value of goods and services. It can represent the value of a small item like a candy bar as well as a large item like a car or a house.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>26", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The speculator in the stock exchange market who sells securities in anticipation of a fall in price is called a", "images": [], "options": {"A": "bull", "B": "jobber", "C": "bear", "D": "stag"}, "answer": "C", "explanation": "In the stock exchange market, a speculator who sells securities in anticipation of a fall in price is called a 'bear'. This is because they 'bear' the market down. They sell securities they do not own in the hope that they can buy them back at a lower price in the future, thus making a profit from the price difference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>27", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "An action taken by a seller to avoid risks from unforeseeable price fluctuation is known as", "images": [], "options": {"A": "tendering", "B": "aunctioneering", "C": "quotation", "D": "hedging"}, "answer": "D", "explanation": "Hedging is a risk management strategy used in limiting or offsetting probability of loss from fluctuations in the prices of commodities, currencies, or securities. In effect, hedging is a transfer of risk. Therefore, an action taken by a seller to avoid risks from unforeseeable price fluctuation is known as hedging.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>28", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "The insurance policy against claims from customers who might be injured within the business premises is called", "images": [], "options": {"A": "life assurance policy", "B": "endowment policy", "C": "fidelity guarantee insurance", "D": "employers liability insurance"}, "answer": "D", "explanation": "Employers liability insurance is a policy that protects employers from liabilities arising from disease, fatality, or injury to employees resulting from workplace conditions or practices. Therefore, the insurance policy against claims from customers who might be injured within the business premises is called employers liability insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>29", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "An offer of new shares made to existing shareholders at a preferential price is called?", "images": [], "options": {"A": "bonus issue", "B": "rights issue", "C": "private placing", "D": "debenture"}, "answer": "B", "explanation": "A rights issue is an invitation to existing shareholders to purchase additional new shares in the company. This type of issue gives existing shareholders securities called rights. With the rights, the shareholder can purchase new shares at a discount to the market price on a stated future date. The company is giving shareholders a chance to increase their exposure to the stock at a discount price. But if the shareholders do not want to buy additional shares, they have the option to sell their rights to other investors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>30", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "A trader started business with #30,000 and spent #20,000 in buying premises and equipment, the balance of #10,000 is his", "images": [], "options": {"A": "authorised capital", "B": "fixed capital", "C": "working capital", "D": "capital owned"}, "answer": "C", "explanation": "Working capital is a measure of both a company's operational efficiency and its short-term financial health. The working capital is calculated as: Working Capital = Current Assets – Current Liabilities. If a company's current assets do not exceed its current liabilities, then it may run into trouble paying back creditors in the short term. The worst-case scenario is bankruptcy. A declining working capital ratio over a longer time period could also be a red flag that warrants further analysis. In this case, the trader has #10,000 left after buying premises and equipment, which he can use for his day-to-day business operations, hence it's his working capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>31", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "New shares are offered for sale to the public through", "images": [], "options": {"A": "acceptable houses", "B": "the stock exchange", "C": "issuing houses", "D": "discount houses"}, "answer": "C", "explanation": "New shares are offered for sale to the public through issuing houses. Issuing houses are financial institutions that act as intermediaries between companies seeking to raise capital and the public. They help companies to issue new shares to the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>32", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Cash-in-hand and at bank as well as debtors are examples of", "images": [], "options": {"A": "current assets", "B": "fixed assets", "C": "capital owned", "D": "capital employed"}, "answer": "A", "explanation": "Cash-in-hand and at bank as well as debtors are examples of current assets. Current assets are short-term assets that can be converted into cash within one year. They include cash, marketable securities, accounts receivable (debtors), and inventory.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>33", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Money spent on acquiring vehicles, furniture and fittings by a manufacturing company is termed", "images": [], "options": {"A": "Circulation capital", "B": "working capital", "C": "fictitious capital", "D": "fixed capital"}, "answer": "D", "explanation": "Money spent on acquiring vehicles, furniture, and fittings by a manufacturing company is termed as 'Fixed Capital'. Fixed capital refers to any kind of real or physical capital (fixed asset) that is not used up in the production of a product. These items provide the infrastructure necessary for a company to operate and generate income.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>34", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Small ships which are used to carry goods and passengers across rivers or canals called", "images": [], "options": {"A": "tramps", "B": "coasters", "C": "tankers", "D": "ferries"}, "answer": "D", "explanation": "Small ships which are used to carry goods and passengers across rivers or canals are called 'Ferries'. A ferry is a vessel used to carry passengers, and sometimes vehicles and cargo as well, across a body of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>35", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following would best be conveyed by rail transport", "images": [], "options": {"A": "Bread", "B": "Shoes", "C": "Potatoes", "D": "Tomatoes"}, "answer": "C", "explanation": "Rail transport is best suited for the transportation of bulk goods, not perishable goods. Among the options, potatoes are the most suitable for rail transport because they are bulk goods and not as perishable as bread or tomatoes. Shoes can also be transported by rail, but they are not bulk goods and are usually transported in smaller quantities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>36", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Gases are best transported", "images": [], "options": {"A": "through canals", "B": "by sea", "C": "by air", "D": "through pipelines"}, "answer": "D", "explanation": "Gases are best transported through pipelines. This is because pipelines provide a continuous flow of gas, which is not possible with other modes of transport. Pipelines are also safer and more efficient for transporting gases, as they reduce the risk of leaks and explosions that can occur with other modes of transport.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>37", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Speed is an important consideration for choice of a means of transport where goods are", "images": [], "options": {"A": "bulky", "B": "inferior", "C": "fragile", "D": "perishable"}, "answer": "D", "explanation": "Speed is an important consideration for the choice of a means of transport where goods are perishable. Perishable goods are items that decay or become less fresh over time if not kept under certain conditions. These goods, such as fruits, vegetables, dairy products, meats, and flowers, need to be transported as quickly as possible to prevent them from spoiling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>38", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following facilities is very useful to an organization that posts a large number of mails regularly?", "images": [], "options": {"A": "Franking machine", "B": "Business reply service", "C": "Mail transfer", "D": "Post restante"}, "answer": "A", "explanation": "A franking machine is very useful to an organization that posts a large number of mails regularly. A franking machine is a device that prints a postage stamp and other markings directly on envelopes or labels. It allows businesses to handle their own mail requirements, reducing the time spent waiting in line at the post office. It also offers flexibility in paying for postage, as it can be re-credited online 24/7.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>39", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : MEANING & SCOPE", "question": "Which of the following defines communication in commerce?", "images": [], "options": {"A": "Movement of files", "B": "Transmission of information", "C": "Movement of people", "D": "Storing of information"}, "answer": "B", "explanation": "Communication in commerce is defined as the transmission of information. It involves the exchange of ideas, messages, or information, by speech, signals, writing, or behavior. It is a vital part of any business as it helps in the smooth running of operations and also aids in decision making.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>40", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Contraband goods seized by the Customs and Excise Authority are kept in the", "images": [], "options": {"A": "ordinary warehouse", "B": "bonded warehouse", "C": "public auctioneer's store", "D": "state warehouse"}, "answer": "D", "explanation": "Contraband goods seized by the Customs and Excise Authority are kept in the state warehouse. A state warehouse is a government-owned facility where goods that have been seized by customs due to various reasons such as smuggling or non-payment of duties are stored.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>41", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Business activities responsible for identifying, anticipating and satisfying customer's requirements profitably are called", "images": [], "options": {"A": "advertising", "B": "public relations", "C": "marketing", "D": "sales promotion"}, "answer": "C", "explanation": "Marketing is the business activity responsible for identifying, anticipating and satisfying customer's requirements profitably. It involves understanding the needs and wants of the customer and creating a process to meet these needs profitably. Advertising, public relations, and sales promotion are all components of marketing, but they do not encompass the entire process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1998>42", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is a demerit of advertising?", "images": [], "options": {"A": "Increases per-unit cost of goods", "B": "Leads to increased profit for producers", "C": "Provides information for customers", "D": "Reduces per-unit cost of goods"}, "answer": "A", "explanation": "One of the demerits of advertising is that it increases the per-unit cost of goods. This is because the cost of advertising is often added to the cost of production, which is then passed on to the consumer in the form of higher prices. The other options are generally considered benefits of advertising, not demerits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>43", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is a form of public relations?", "images": [], "options": {"A": "Feature articles", "B": "Window display", "C": "Catalogue", "D": "Transportation and delivery services"}, "answer": "A", "explanation": "Public relations involves managing the spread of information between an individual or an organization and the public. Feature articles are a form of public relations as they are used to provide information about an organization or its products to the public. Window display, catalogue, and transportation and delivery services are not forms of public relations as they do not involve the management of information between an organization and the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>44", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "When a firm sets a low price for new product, this is said to be", "images": [], "options": {"A": "market swimming", "B": "competitive pricing", "C": "penetration pricing", "D": "loss leader pricing"}, "answer": "C", "explanation": "Penetration pricing is a marketing strategy used by businesses to attract customers to a new product or service by initially offering a lower price than its competitors. This strategy is used to gain market share and increase sales volume. The other options, market swimming, competitive pricing, and loss leader pricing do not accurately describe the scenario of setting a low price for a new product.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>45", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Use the following information to answer the questions    Ola presented his motor-cycle for sale to Musa at a cost of #8,000. Musa agreed and bought the vehicle at the same amount.    The #8,000 for the sale is", "images": [], "options": {"A": "an offer", "B": "an acceptance", "C": "a consideration", "D": "a warranty"}, "answer": "C", "explanation": "In the context of contract law, consideration refers to something of value that is given in exchange for something else. In this case, the #8,000 that Musa paid to Ola for the motorcycle is the consideration. It is the price paid for the promise of the other party.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>46", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Use the following information to answer the questions    Ola presented his motor-cycle for sale to Musa at a cost of #8,000. Musa agreed and bought the vehicle at the same amount.  Ola is the", "images": [], "options": {"A": "offeror", "B": "offeree", "C": "acceptor", "D": "guarantor"}, "answer": "A", "explanation": "In a contract, the person who proposes the terms of an agreement is known as the offeror, while the person to whom the offer is made is known as the offeree. In this case, Ola is the one who presented his motorcycle for sale, thus he is the offeror.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>47", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "When an acceptance to an offer is conditional, the offer becomes", "images": [], "options": {"A": "accepted", "B": "a counter offer", "C": "valid", "D": "void"}, "answer": "B", "explanation": "When an acceptance to an offer is conditional, it is considered a counter offer. This is because the acceptance is not absolute and unqualified. In law, for an acceptance to be valid, it must be absolute and unqualified. A conditional acceptance, therefore, amounts to a counter-offer which the original offeror is free to accept or reject.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1998>48", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "A mercantile agent having title to goods in his possession is known as", "images": [], "options": {"A": "factor", "B": "broker", "C": "jobber", "D": "auctioneer"}, "answer": "A", "explanation": "A mercantile agent having title to goods in his possession is known as a factor. A factor is a type of agent who is entrusted with the possession of goods to be sold in his own name but on behalf of his principal. The other options, broker, jobber, and auctioneer, do not have title to the goods in their possession.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>49", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "A transporter who had to sell some perishable goods without the authority of the owner becomes an agent by", "images": [], "options": {"A": "estoppel", "B": "necessity", "C": "ratification", "D": "conduct"}, "answer": "B", "explanation": "In law, an agent by necessity is a person who, without prior authorization, acts on behalf of another person (the principal) in an emergency situation where that other person is unable to act (e.g., due to physical absence, incapacity, or lack of opportunity). In this case, the transporter had to sell perishable goods without the authority of the owner due to necessity, hence he becomes an agent by necessity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1998>50", "subject": "Commerce", "year": "1998", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A contract to take possession of goods on instalmental", "images": [], "options": {"A": "credit sale", "B": "conditional sale", "C": "hire purchase", "D": "trade-in-sale"}, "answer": "C", "explanation": "A hire purchase contract is a type of contract where the buyer takes possession of goods and pays in instalments. The ownership of the goods is transferred only after the full payment is made. Therefore, a contract to take possession of goods on instalment is a hire purchase contract.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>1", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "A shoe repairer is engaged in a", "images": [], "options": {"A": "service occupation", "B": "manufacturing occupation", "C": "extractive occupation", "D": "commercial occupation"}, "answer": "A", "explanation": "A shoe repairer is engaged in a service occupation. This is because he/she provides a service of repairing shoes rather than manufacturing, extracting, or selling them. A service occupation refers to a job where a person provides a service rather than a tangible product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>2", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The goods that are used for the production of other goods are known as", "images": [], "options": {"A": "commercial goods", "B": "consumer goods", "C": "capital goods", "D": "non-durable"}, "answer": "C", "explanation": "The goods that are used for the production of other goods are known as capital goods. Capital goods are goods that are used in producing other goods, rather than being bought by consumers. They are one of the three types of producer goods, the other two being land and labour. These goods are important to businesses, because they use capital goods to help their company move forward and thrive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>3", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION", "question": "Which of the following brings about specialization?", "images": [], "options": {"A": "Recruitment of staff", "B": "Division of labour", "C": "Business resource", "D": "Employer of labour"}, "answer": "B", "explanation": "Specialization is brought about by the division of labour. Division of labour refers to the breaking down of large jobs into smaller tasks that are performed by different workers. This allows workers to focus on a specific task, thereby becoming experts or 'specialists' in that area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>4", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following refers to all the resources used in creating utilities?", "images": [], "options": {"A": "Fixed capital", "B": "Factors of production", "C": "Entrepreneurship", "D": "Labour"}, "answer": "B", "explanation": "Factors of production refer to the resources used in the production of goods and services. These include land, labour, capital, and entrepreneurship. These resources are used in creating utilities, which are the attributes of a product or service that satisfy consumers' wants and needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>5", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following enables people to consume a variety of goods and services?", "images": [], "options": {"A": "Labour", "B": "Capital", "C": "Land", "D": "Exchange"}, "answer": "D", "explanation": "Exchange enables people to consume a variety of goods and services. In economics, exchange refers to the process by which goods or services are traded. People exchange goods and services they have for goods and services they want. This allows for the consumption of a variety of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>6", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES", "question": "A business unit in which profits are shared on the basis of members' patronage is known as", "images": [], "options": {"A": "partnership", "B": "public limited company", "C": "Co-operative society", "D": "private limited company"}, "answer": "C", "explanation": "A Co-operative society is a business unit in which profits are shared on the basis of members' patronage. In a cooperative society, members pool their resources to undertake a business or service they all benefit from. The profits are then shared among the members based on their contribution or patronage to the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>7", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A public limited company wishing to obtain more capital may have to", "images": [], "options": {"A": "apply for subvention", "B": "buy treasury bills", "C": "buy second-hand securities", "D": "issue debentures"}, "answer": "D", "explanation": "A public limited company wishing to obtain more capital may issue debentures. Debentures are a type of debt instrument that is not secured by physical assets or collateral. They are backed only by the general creditworthiness and reputation of the issuer. By issuing debentures, the company gets to borrow capital at a fixed rate of interest and repay it at a later date. This is a common way for companies to raise additional capital.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>8", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "The safe keeping of goods from the point of production to the time they are needed is", "images": [], "options": {"A": "standardizing", "B": "warehousing", "C": "hoarding", "D": "stock controlling"}, "answer": "B", "explanation": "The safe keeping of goods from the point of production to the time they are needed is warehousing. Warehousing involves the storage of goods in a commercial building for the purpose of providing a secure and safe environment where the goods can be stored until they are needed. This process ensures that goods are available when needed, thus preventing shortages and enabling continuous production or sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>9", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "The document which regulates the operations of a partnership is known as", "images": [], "options": {"A": "Deed", "B": "Articles of Association", "C": "Prospectus", "D": "Certificate of trading"}, "answer": "A", "explanation": "The document which regulates the operations of a partnership is known as a Deed. A partnership deed, also known as a partnership agreement, is a document that outlines in detail the rights and responsibilities of all parties to a business operation. It has the force of law and is designed to guide the partners in the conduct of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>10", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "A company is said to be insolvent when", "images": [], "options": {"A": "it makes a loss in any one year", "B": "its total liabilities exceed total assets", "C": "the ordinary shareholders receive no dividend from the company", "D": "the preference shareholders could not be paid by the company"}, "answer": "B", "explanation": "A company is said to be insolvent when its total liabilities exceed its total assets. Insolvency is a state of financial distress in which a business or individual is unable to pay its bills. It can lead to insolvency proceedings, in which legal action will be taken against the insolvent entity, and assets may be liquidated to pay off outstanding debts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>11", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is formed in order to enforce the rights and powers of buyers in relation to sellers?", "images": [], "options": {"A": "Consortium", "B": "Trade Association", "C": "Consumer Association", "D": "Holding company"}, "answer": "C", "explanation": "A Consumer Association is formed to enforce the rights and powers of buyers in relation to sellers. It is a type of organization that is founded by consumers for consumers. They work to protect and promote the rights of consumers against unethical and unfair business practices. A Consortium is a group of companies that come together to undertake a task that is beyond their individual resources. A Trade Association is an organization founded and funded by businesses that operate in a specific industry. A Holding company is a type of firm that owns other investments, including whole companies, instead of engaging in operating activity itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>12", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "use the following information to answer the questions    A public Limited Company whose nominal capital is made up of 400,000 ordinary shares of 50k each, decided to issue 50% of it to the public and realized only 50% of the amount due    What is the company's registered capital?", "images": [], "options": {"A": "#50,000.00", "B": "#80,000.00", "C": "#200,000.00", "D": "#400,000.00"}, "answer": "C", "explanation": "The company's registered capital is the total nominal value of the shares that the company is allowed to issue. In this case, the company has 400,000 ordinary shares of 50k each. Therefore, the registered capital is 400,000 shares * 50k = #200,000.00. The fact that the company decided to issue only 50% of it to the public and realized only 50% of the amount due does not change the registered capital. The registered capital is based on the nominal value of the shares, not on the amount of shares issued or the amount of money realized from the issue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>13", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "use the following information to answer the questions    A public Limited Company whose nominal capital is made up of 400,000 ordinary shares of 50k each, decided to issue 50% of it to the public and realized only 50% of the amount due  What is the paid up capital?", "images": [], "options": {"A": "#50,000.00", "B": "#100,000.00", "C": "#150,000.00", "D": "#200,000.00"}, "answer": "A", "explanation": "Nominal capital: 400,000 shares x 50,000 kobo/share = 20,000,000,000 kobo  To naira = #200,000.00    Issued capital: 50% of nominal capital = 50% x #200,000.00   = #100,000.00    Paid-up capital: 50% of issued capital = 50% x #100,000.00   = #50,000.00", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>14", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "use the following information to answer the questions    A public Limited Company whose nominal capital is made up of 400,000 ordinary shares of 50k each, decided to issue 50% of it to the public and realized only 50% of the amount due  What is the called-up capital", "images": [], "options": {"A": "#50,000.00", "B": "#100,000.00", "C": "#200,000.00", "D": "#400,000.00"}, "answer": "B", "explanation": "The called up capital is calculated as:     =  50%  x 200,000  = #100,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>15", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following documents is used to advertise shares to the public?", "images": [], "options": {"A": "Letter of allotment", "B": "Articles of association", "C": "Memorandum of association", "D": "Prospectus"}, "answer": "D", "explanation": "A prospectus is a legal document issued by companies that are offering securities for sale. It is used to advertise shares to the public. It contains details about the company, its business, and the securities being offered. The memorandum of association and the articles of association are documents that govern the company's relationship with the outside world and the company's internal affairs respectively. The letter of allotment is a document sent to the applicant of a share indicating the number of shares allotted to them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>16", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : ADVANTAGES AND DISADVANTAGES", "question": "A major advantage of the private company over a partnership is that the private company", "images": [], "options": {"A": "can sell shares", "B": "has limited liability", "C": "can publish its account", "D": "is allowed to borrow from commercial banks"}, "answer": "B", "explanation": "The major advantage of a private company over a partnership is that a private company has limited liability. This means that the financial liability of the shareholders is limited to their shares. In a partnership, partners have unlimited liability, which means they are personally liable for the partnership's debts. While private companies can sell shares, publish its account, and borrow from commercial banks, these are not exclusive advantages over partnerships.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>17", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following is a contract of carriage and a document of title?", "images": [], "options": {"A": "indent", "B": "Bill of lading", "C": "Pro forma invoice", "D": "is allowed to borrow from commercial banks"}, "answer": "B", "explanation": "A bill of lading is a legal document between the shipper of goods and the carrier detailing the type, quantity and destination of the goods being carried. The bill of lading also serves as a receipt of shipment when the goods are delivered at the predetermined destination. This is a standard document in shipping and freight, which serves as a contract of carriage and a document of title.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>18", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a feature of a Department Store?", "images": [], "options": {"A": "One-stop-shopping", "B": "Deals in one line of goods", "C": "Use of trolleys", "D": "Convenient location"}, "answer": "B", "explanation": "A department store is a retail establishment offering a wide range of consumer goods in different areas of the store, each area ('department') specializing in a product category. 'Deals in one line of goods' is not a feature of a department store because department stores typically offer a wide variety of goods, not just one line of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>19", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A major cost component of running a mail order firm is the", "images": [], "options": {"A": "printing of catalogues", "B": "paying salemen's salaries", "C": "renting shops", "D": "travelling expenses"}, "answer": "A", "explanation": "A mail order firm is a type of business where customers place orders for products through mail, telephone, or online, and the products are then delivered to them. The major cost component of running such a business is the printing of catalogues. This is because the catalogues, which contain detailed descriptions and images of the products, are the primary means through which customers learn about the products and make their purchasing decisions. Therefore, the cost of printing these catalogues is a significant part of the overall operating cost of a mail order firm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>20", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "A bill of exchange becomes negotiable when it is", "images": [], "options": {"A": "accepted", "B": "protested", "C": "dishonoured", "D": "discounted"}, "answer": "A", "explanation": "A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed amount of money to another party on demand or at a predetermined date. It becomes negotiable when it is accepted. Acceptance means that the party on whom the bill is drawn agrees to pay the bill when it is due. Once accepted, the bill can be transferred from one person to another, as it becomes a negotiable instrument. Therefore, a bill of exchange becomes negotiable when it is accepted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>21", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "What is the purpose of a debit note? To", "images": [], "options": {"A": "reduce the credit in the buyer's account", "B": "reduce the debit charged to an invoice", "C": "compensate for damaged goods returned", "D": "allow for rebate"}, "answer": "A", "explanation": "A debit note is a document sent by a buyer to its seller, or in other words, a purchaser to its vendor while returning goods received on credit. The purpose of a debit note is to reduce the amount that the buyer owes to the seller, which is why it reduces the credit in the buyer's account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>22", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Status enquiry is necessary when", "images": [], "options": {"A": "goods are ordered from a mail order firm", "B": "money is withdrawn from a fixed deposit account", "C": "granting credit to a new customer", "D": "goods are produced according to specification"}, "answer": "C", "explanation": "Status enquiry is a process where a business checks the creditworthiness of a new customer before granting them credit. This is to ensure that the customer has the ability to pay for the goods or services on credit. Therefore, status enquiry is necessary when granting credit to a new customer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>23", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Trade discount is given to the buyer for", "images": [], "options": {"A": "prompt payment", "B": "credit purchase", "C": "cash purchase", "D": "retailer's mark-up"}, "answer": "D", "explanation": "Trade discount is a reduction in price given by the wholesaler/producer to the retailer at the list price of the goods. The main aim of trade discount is to encourage the buyer to buy in more quantities. So, it is given to the retailer for the retailer's mark-up.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>24", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Government can borrow money from the public through", "images": [], "options": {"A": "the issuing of treasury bills", "B": "increasing taxation", "C": "increasing the lending rate", "D": "establishing more banks"}, "answer": "A", "explanation": "The government can borrow money from the public through the issuing of treasury bills. Treasury bills are short-term debt instruments issued by the government through the Central Bank to provide short term funding for the government. They are sold at a discount and redeemed at par, the difference being the interest earned by the holder.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>25", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Insurance is necessary because of the need to", "images": [], "options": {"A": "pool resources together", "B": "meet uncertainties in future", "C": "make profit", "D": "lend money to individuals"}, "answer": "B", "explanation": "Insurance is necessary because it provides a means to manage risks and protect against potential future losses or uncertainties. It is a tool that allows individuals or businesses to replace the uncertainty of a potential significant financial loss with a known smaller payment (the insurance premium).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>26", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Notes and coins are legal tender because they are", "images": [], "options": {"A": "printed by the Central Bank", "B": "backed by law", "C": "backed by gold", "D": "issued by all banks"}, "answer": "B", "explanation": "Notes and coins are considered legal tender because they are backed by law. This means that they are recognized by the government as a valid form of payment for debts. It's not because they are printed by the Central Bank or backed by gold or issued by all banks. The key factor is the legal recognition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>27", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "If a company is described as \"listed\" it means", "images": [], "options": {"A": "its shares can be traded on the stock exchange", "B": "It is about to be voluntarily liquidated", "C": "it is duly registered by the registrar of companies", "D": "it has been blacklisted"}, "answer": "A", "explanation": "A listed company refers to a company whose shares are traded on a stock exchange. It means the company has complied with the listing requirements of a particular stock exchange and its shares are available for trading to the public on that exchange.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>28", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The counterfoil of a cheque book enables the drawer to", "images": [], "options": {"A": "request for a new cheque book", "B": "reconcile his book of accounts", "C": "know who the debtors are", "D": "obtain an overdraft from the bank"}, "answer": "B", "explanation": "The counterfoil of a cheque book is used by the drawer to keep a record of the cheques they have issued. This helps in reconciling their book of accounts by comparing the cheques issued with the bank statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>29", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "Which of the following qualities of money is generally undermined by inflation?", "images": [], "options": {"A": "Stability", "B": "Scarcity", "C": "Durability", "D": "Portability"}, "answer": "A", "explanation": "Inflation undermines the stability of money. Stability in this context refers to the ability of money to maintain its value over time. Inflation erodes the purchasing power of money, meaning that you need more money to buy the same goods and services. This instability can lead to uncertainty and economic instability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>30", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES", "question": "One advantage of communication by telephone is", "images": [], "options": {"A": "the conversation can be very short", "B": "it is less expensive", "C": "feedback is instantenous", "D": "the conversation is strictly private"}, "answer": "C", "explanation": "The advantage of communication by telephone is that feedback is instantaneous. This means that the person on the other end of the line can respond immediately to what you are saying, allowing for a real-time exchange of ideas. This is not necessarily the case with other forms of communication, such as email or letter, where there can be a delay between sending a message and receiving a response.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>31", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following is the fastest means of sending a document from one place to another?", "images": [], "options": {"A": "Facsimile", "B": "Courier service", "C": "Express mail", "D": "Registered mail"}, "answer": "A", "explanation": "Facsimile, also known as fax, is a telecommunication technology used to transfer copies of documents, especially using affordable devices operating over the telephone network. It is faster than courier service, express mail, and registered mail because it sends a copy of the document electronically, rather than physically transporting the original document.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>32", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following is a disadvantage of canal transport? it is", "images": [], "options": {"A": "narrow and cannot support big vessels", "B": "not suitable for small ferriers", "C": "often for short journey", "D": "suitable for carrying only goods"}, "answer": "A", "explanation": "Canals are narrow and cannot support big vessels. They are man-made waterways, and their size is limited by the cost and practicality of construction. Therefore, they are not suitable for large vessels, which require deep and wide waterways. The other options are not necessarily disadvantages of canal transport. Canals can be used for both small and large ferries, they can be used for both short and long journeys, and they can carry both goods and passengers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>33", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A manufacturer of machinery who wants to reduce cost of promotion can use", "images": [], "options": {"A": "samples", "B": "public relations techniques", "C": "showrooms", "D": "catalogues"}, "answer": "D", "explanation": "A manufacturer of machinery can reduce the cost of promotion by using catalogues. Catalogues are a cost-effective way of showcasing products to a large audience. They provide detailed information about the products including their features, prices, and uses. This eliminates the need for expensive promotional methods like samples, showrooms, and public relations techniques.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>34", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Direct selling by a producer to a consumer is possible when the", "images": [], "options": {"A": "goods have to be made on demand", "B": "manufacturer has a good knowledge of the market", "C": "customer buys in small quantities", "D": "goods are fashionable"}, "answer": "A", "explanation": "Direct selling by a producer to a consumer is possible when the goods have to be made on demand. This is because the producer can directly interact with the consumer to understand their specific requirements and customize the product accordingly. This eliminates the need for intermediaries, thereby making the process more efficient and cost-effective. The other options do not necessarily imply a direct selling scenario.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>35", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "The task of grouping consumers according to their buying habits is known as market", "images": [], "options": {"A": "diversification", "B": "development", "C": "expansion", "D": "segmentation"}, "answer": "D", "explanation": "Market segmentation is the process of dividing a market of potential customers into groups, or segments, based on different characteristics. The segments created are composed of consumers who will respond similarly to marketing strategies and who share traits such as similar interests, needs, or locations. Hence, the task of grouping consumers according to their buying habits is known as market segmentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>36", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not an economic grouping?", "images": [], "options": {"A": "ECOWAS", "B": "GATT", "C": "ECOMOG", "D": "EEC"}, "answer": "C", "explanation": "ECOMOG is not an economic grouping. It stands for Economic Community of West African States Monitoring Group. It was a West African multilateral armed force established by the Economic Community of West African States (ECOWAS). ECOWAS and EEC are economic groupings, while GATT (General Agreement on Tariffs and Trade) is an international trade agreement. Therefore, ECOMOG is the correct answer as it is not an economic grouping.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>37", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Business losses in nationalized industries are borne by the", "images": [], "options": {"A": "Shareholders", "B": "Debenture holders", "C": "Board of directors", "D": "Public"}, "answer": "D", "explanation": "Nationalized industries are owned by the state or government. Therefore, any losses incurred by these industries are borne by the public, as the government uses public funds to finance these industries. Shareholders, debenture holders, and board of directors are associated with private companies, not nationalized industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>38", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following can be sold through a vending machine?", "images": [], "options": {"A": "cigarettes", "B": "shirts", "C": "handbags", "D": "shoes"}, "answer": "A", "explanation": "Vending machines are automated machines that provide items such as snacks, beverages, cigarettes, and lottery tickets to consumers after money, a credit card, or a specially designed card is inserted into the machine. Therefore, cigarettes can be sold through a vending machine. Shirts, handbags, and shoes are typically not sold through vending machines due to their size and the need for customers to try them on before purchasing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>1999>39", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is the most suitable channel of distribution for technical goods?", "images": [], "options": {"A": "manufacturer-retailer-consumer", "B": "manufacturer-wholesaler-retailer-consumer", "C": "manufacturer-wholesaler-consumer", "D": "manufacturer-consumer"}, "answer": "D", "explanation": "For technical goods, direct distribution from manufacturer to consumer is often the most suitable channel. This approach allows the manufacturer to provide specialized knowledge, support, and customization directly to the consumer, ensuring that the technical requirements and complexities of the product are properly communicated and managed. This direct interaction can also improve customer satisfaction and reduce potential issues related to intermediaries who may lack the necessary expertise.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>40", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following implies that the price quoted includes the cost of insurance and carriage?", "images": [], "options": {"A": "F.O.B", "B": "F.A.S", "C": "C.O.D", "D": "C.I.F"}, "answer": "D", "explanation": "C.I.F stands for Cost, Insurance, and Freight. This implies that the price quoted includes the cost of the goods, the freight or transport costs, and the cost of insurance. On the other hand, F.O.B (Free On Board) means that the seller is responsible for the cost of getting the goods to the shipping vessel and the buyer is responsible for the cost from there onwards. F.A.S (Free Alongside Ship) means that the seller is responsible for the cost of getting the goods alongside the ship. C.O.D (Cash On Delivery) means that payment is made on delivery rather than in advance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>41", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Bonded warehouses are controlled by", "images": [], "options": {"A": "Export Promotion Council", "B": "Ports Authority", "C": "Customs and Excise Authority", "D": "Clearing and Forwarding agents"}, "answer": "C", "explanation": "Bonded warehouses are controlled by the Customs and Excise Authority. A bonded warehouse is a secured area where imported goods are stored until the import duties are paid. It is under the control of customs authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>42", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A hire purchase transaction becomes a sale when the", "images": [], "options": {"A": "hirer accepts the hire purchase terms", "B": "finance company agrees to pay", "C": "hirer takes possession of goods", "D": "hirer pays full cost of the goods"}, "answer": "D", "explanation": "A hire purchase transaction becomes a sale when the hirer pays the full cost of the goods. Hire purchase is a system where the buyer pays for goods in regular installments while using them. The transaction becomes a sale when the total price is paid, and the ownership of the goods is transferred to the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>43", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Which of the following serves as a receipt for goods kept in a bonded warehouse?", "images": [], "options": {"A": "Dock Warrant", "B": "Bill of Sight", "C": "Foul bill", "D": "Dock due"}, "answer": "A", "explanation": "A Dock Warrant serves as a receipt for goods kept in a bonded warehouse. A bonded warehouse is a secured warehouse where goods are stored until customs duty is paid or goods are cleared for export. The Dock Warrant is a document issued by a warehouse keeper, which certifies that the holder of the warrant has the right to the goods specified in it. It is a transferable document and can be used as collateral for borrowing money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>44", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following have lien on goods in their possession until their commission is paid?", "images": [], "options": {"A": "Brokers", "B": "Factors", "C": "Auctioneers", "D": "Wholesale merchants"}, "answer": "B", "explanation": "Factors have a lien on goods in their possession until their commission is paid. A factor is an agent who conducts business under his own name for another party, often taking possession of the goods. In commerce, a lien is a right to keep possession of property belonging to another person until a debt owed by that person is discharged. Therefore, factors have the right to retain possession of the goods until they are paid their commission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>45", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Use the following diagram to answer the Questions         From the diagram, the distribution of goods to the consumers would be considered under", "images": ["Commerce/imgs/1999/nnd.png"], "options": {"A": "place", "B": "price", "C": "promotion", "D": "product"}, "answer": "A", "explanation": "Place mix is concerned with the distribution of goods and services to the consumers at the required place. It is also known as channel of distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>46", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Use the following diagram to answer the Questions       The above diagram which shows consumers' needs as the focus of attention illustrates the meaning of", "images": ["Commerce/imgs/1999/nnd.png"], "options": {"A": "market segmentation", "B": "marketing concept", "C": "market research", "D": "sales orientation"}, "answer": "B", "explanation": "Marketing concept is the idea or belief that consumers/customers should be treated as kings. The interest and desires of consumers/customers must be taken into consideration in bringing out products or any business activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>47", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A picture which indicates that success in life can only be achieved through the use of the product is an example of", "images": [], "options": {"A": "market research", "B": "persuasive advertising", "C": "mass selling", "D": "informative advertising"}, "answer": "B", "explanation": "The question describes a scenario where a product is being advertised in a way that suggests success in life can only be achieved through the use of the product. This is a form of persuasive advertising. Persuasive advertising is a type of advertising where the advertiser uses persuasive techniques to convince the audience that they need the product or service being advertised. It often appeals to the emotions of the audience and can use various strategies, including the promise of success or happiness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>48", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A contract of sale of goods where ownership passes to the buyer on the payment of first installment is", "images": [], "options": {"A": "hire purchase", "B": "cash with order", "C": "deferred payment", "D": "cash on delivery"}, "answer": "C", "explanation": "The question describes a contract of sale of goods where ownership passes to the buyer on the payment of the first installment. This is known as a deferred payment contract. In a deferred payment contract, the buyer takes possession of the goods immediately but pays for them over a period of time in installments. The ownership of the goods passes to the buyer as soon as the first installment is paid. This is different from a hire purchase agreement where the ownership of the goods does not pass to the buyer until the final installment is paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>1999>49", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Mr Ajai did not disclose that he stores drums of petrol when he took a fire insurance policy. Under which of the following principles will the insurance company reject his claims", "images": [], "options": {"A": "Subrogation", "B": "Utmost good faith", "C": "Insurable interest", "D": "Proximate cost"}, "answer": "B", "explanation": "The principle of 'Utmost good faith' applies in this case. This principle, also known as 'Uberrima Fides', implies that both parties in an insurance contract must disclose all facts material to the risk being insured, whether asked for or not. Mr Ajai did not disclose that he stores drums of petrol, which is a material fact that could increase the risk of fire. Therefore, the insurance company can reject his claims based on this principle.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>1999>50", "subject": "Commerce", "year": "1999", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A bill of exchange is retired when it is", "images": [], "options": {"A": "paid before maturity", "B": "marked \"accepted\"", "C": "discounted", "D": "dishonoured"}, "answer": "A", "explanation": "A bill of exchange is said to be retired when it is paid before its maturity. This is a situation where the drawee pays the drawer or holder before the due date. The other options do not correctly describe the retirement of a bill of exchange. Marking 'accepted' is a commitment to pay, not the act of payment. Discounting a bill involves selling it to a bank or other financial institution before it is due, not paying it. Dishonouring a bill means not paying it, which is the opposite of retiring it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>1", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Which of the following can be defined as trade and aid trade?", "images": [], "options": {"A": "Advertising", "B": "Commerce", "C": "Wholesaling", "D": "Retailing"}, "answer": "B", "explanation": "Commerce can be defined as the exchange of goods and services for money or in kind, usually on a scale large enough to require transportation from place to place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2000>2", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of finance to a sole proprietor?", "images": [], "options": {"A": "Trade credits", "B": "Overdrafts", "C": "Debentures", "D": "Leasing of equipment"}, "answer": "C", "explanation": "A sole proprietorship is a type of business entity that is owned and run by one individual and in which there is no legal distinction between the owner and the business. The owner is in direct control of all elements and is legally accountable for the finances of such business including debts, loans, losses, etc. Debentures are a source of finance typically used by corporations, not sole proprietors. A debenture is a type of debt instrument that is not secured by physical assets or collateral. Instead, they are backed by the general creditworthiness and reputation of the issuer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>3", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Partners who allow their names to be used in a partnership but do not take part in the management of the business are?", "images": [], "options": {"A": "Active partners", "B": "Limited partners", "C": "General partners", "D": "Norminal partners"}, "answer": "D", "explanation": "Nominal partners are those who lend their name to a partnership but do not have any real interest in the business. They do not invest any capital, do not share in the profits or losses, and do not take part in the management of the business. Their association with the business is in name only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>4", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A private company is one which?", "images": [], "options": {"A": "Must publish its audited account", "B": "Floats its shares on the stock exchange market", "C": "Restricts the rights to transfer its shares", "D": "Is owned by a maximum of twenty members"}, "answer": "C", "explanation": "A private company is a type of company that offers limited liability, or legal protection for its shareholders but that places certain restrictions on its ownership. These restrictions are defined in the company's bylaws or regulations and are meant to prevent any hostile takeover attempt. The main restriction is that the right to transfer its shares is restricted, shareholders must first offer them to existing shareholders before selling them to an outsider.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>5", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "The coming together of two or more firms at different stages of production is?", "images": [], "options": {"A": "Horizontal merger", "B": "Vertical merger", "C": "Amalgamation", "D": "Cartel"}, "answer": "B", "explanation": "A vertical merger is a merger between two or more firms that operate at different stages in the production process for a specific finished product. This is different from a horizontal merger, which involves companies at the same stage of production. Amalgamation is the combination of one or more companies into a new entity. A cartel is a group of independent market participants who collude with each other in order to improve their profits and dominate the market.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>6", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The total value of fixed and current assets is?", "images": [], "options": {"A": "Working capital", "B": "Capital employed", "C": "Fixed capital", "D": "Capital owned"}, "answer": "B", "explanation": "Capital employed, also known as funds employed, is the total amount of capital used for the acquisition of profits. It is the value of all the assets employed in a business and can be calculated as fixed assets plus current assets or equity plus long-term liabilities. Working capital is the difference between current assets and current liabilities. Fixed capital refers to any kind of real or physical capital (fixed asset) that is not used up in the production of a product. Capital owned refers to the total assets minus total liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>7", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following equation to answer the below questions  Gross Profit = (Closing Stock + P) less (Opening Stock + G)    What is P in the above equation?", "images": [], "options": {"A": "Purchase returns", "B": "Net profit", "C": "Sales", "D": "Carriage outwards"}, "answer": "C", "explanation": "In the equation above, P represent sales i.e Closing stock + sales", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>8", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following equation to answer the below questions  Gross Profit = (Closing Stock + P) less (Opening Stock + G)  What is G in the above equation?", "images": [], "options": {"A": "Sales returns", "B": "Carriage inwards", "C": "Purchases", "D": "Sales"}, "answer": "C", "explanation": "'G' in the equation represents 'Purchases' which is correctly represented by option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>9", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is true about cummulative preference shares?", "images": [], "options": {"A": "Unpaid dividends are carried forward", "B": "Shareholders can secure capital refund on demand", "C": "Shareholders are entitled to further share of profit", "D": "Dividends are paid into a special account"}, "answer": "A", "explanation": "Cumulative preference shares are a type of preference shares where the dividend is accumulated if the company is unable to pay it due to loss or inadequate profits. If the company is not able to pay the dividend in a particular year, then the company will pay it in the future when it earns profits. So, the correct answer is 'Unpaid dividends are carried forward'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>10", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A debenture is mortaged when it is?", "images": [], "options": {"A": "Not secured on the assets of a company", "B": "Secured on the assets of a company", "C": "Irredeemable", "D": "Redeemable"}, "answer": "B", "explanation": "A debenture is said to be mortgaged when it is secured on the assets of a company. This means that if the company fails to pay the debenture holders, they have the right to sell the assets on which the debentures are secured to recover their money. So, the correct answer is 'Secured on the assets of a company'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>11", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail outlet which sells a fairly narrow range of goods with a number of branches in a different towns is a?", "images": [], "options": {"A": "Supermarket", "B": "Mail-order", "C": "mobile shop", "D": "multiple shop"}, "answer": "D", "explanation": "A multiple shop is a retail outlet that sells a fairly narrow range of goods and has a number of branches in different towns. This is different from a supermarket which typically sells a wide range of goods, a mail-order which sells goods through mail, and a mobile shop which is a shop on wheels that can move from place to place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>12", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A consignment note is used when?", "images": [], "options": {"A": "Goods are wrapped and labelled for easy identification", "B": "Goods are despatched to agents through transporters", "C": "Damaged goods are being returned", "D": "There is over-invoicing"}, "answer": "B", "explanation": "A consignment note is used when goods are dispatched to agents through transporters. It serves as a document of title that is issued by a carrier to a shipper, signed by the carrier or his agent and given to the consignor at the time of receipt of the shipment. It is not used when goods are wrapped and labelled for easy identification, when damaged goods are being returned, or when there is over-invoicing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>13", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is not contained in an advice note?", "images": [], "options": {"A": "Type of goods", "B": "Price of goods", "C": "Date of despatch", "D": "Means of despatch"}, "answer": "B", "explanation": "An advice note is a document sent to a customer to inform them that goods ordered have been dispatched. It usually contains information such as the type of goods, the date of dispatch, and the means of dispatch. However, it does not typically include the price of goods. The price is usually contained in an invoice, not an advice note.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>14", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A refund of the duty collected on goods imported and processed for re-export is?", "images": [], "options": {"A": "Excise duty", "B": "Excise drawback", "C": "Preferential duty", "D": "Value added tax"}, "answer": "B", "explanation": "A refund of the duty collected on goods imported and processed for re-export is known as an excise drawback. This is a refund of excise duty paid on goods that are subsequently exported. Excise duty is a tax on certain types of goods produced or sold within a country. When these goods are exported, the duty can be refunded, which is known as an excise drawback.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>15", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "When a county's total visible and invisible exports are more than its visible and invisible imports, it has?", "images": [], "options": {"A": "Favourable balance of payments", "B": "Favourable balance of trade", "C": "Unfavourable balance of trade", "D": "Unfavourable balance of payments"}, "answer": "A", "explanation": "When a country's total visible (tangible goods) and invisible (services, investments) exports exceed its total visible and invisible imports, it indicates a favorable balance of payments. This overall positive balance reflects that the country is earning more from exports and services than it is spending on imports and foreign services.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>16", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a function of a retailer?", "images": [], "options": {"A": "Supplying goods to final consumer", "B": "Bulk breaking", "C": "Giving information to the wholesaler", "D": "Branding and packaging of goods"}, "answer": "D", "explanation": "Retailers are intermediaries in the distribution channel that sell goods and services to the final consumers. They perform various functions such as supplying goods to final consumers, bulk breaking (buying in large quantities and selling in small quantities), and providing information to the wholesaler about consumer preferences. However, branding and packaging of goods is typically not a function of retailers. These are usually done by manufacturers or producers. Therefore, the correct answer is 'Branding and packaging of goods'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>17", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A merchant who wishes to order goods from a foreign country sends?", "images": [], "options": {"A": "An invoice", "B": "An indent", "C": "An advice note", "D": "A credit note"}, "answer": "B", "explanation": "A merchant who wishes to order goods from a foreign country sends an indent. An indent is a purchase order often placed through an agent or broker, specifying the details of the goods or commodities the buyer wishes to purchase. It includes details such as the type, quality, and price of the goods, among other things.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>18", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "The production of goods in anticipation of demand is possible because of the existence of?", "images": [], "options": {"A": "Packaging", "B": "Advertising", "C": "Warehousing", "D": "Branding"}, "answer": "C", "explanation": "The production of goods in anticipation of demand is possible because of the existence of warehousing. Warehousing allows for the storage of goods until they are needed. This means that production can occur in anticipation of future demand, with the produced goods being stored in a warehouse until the demand arises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>19", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is sent in reply to a letter of enquiry?", "images": [], "options": {"A": "Quotation", "B": "Order", "C": "Consular invoice", "D": "Advice note"}, "answer": "A", "explanation": "A letter of enquiry is usually sent by a potential customer to a supplier, in order to request a quotation or ask for information about the supplier's products or services. Therefore, the supplier would reply with a 'Quotation' which provides the requested information, including the price of the goods or services, the terms of sale, and other relevant details.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>20", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "The abbreviated phrase E&OE is usually printed on?", "images": [], "options": {"A": "An invoice", "B": "A cheque", "C": "A delivery note", "D": "A debit note"}, "answer": "A", "explanation": "E&OE stands for 'Errors and Omissions Excepted'. This phrase is often printed on invoices to indicate that while every effort has been made to ensure the accuracy of the information on the document, there may be some errors or omissions. This is a legal term used to protect the issuer of the document, typically the seller, from any liability for unintentional errors or omissions in the quoted prices, descriptions, or other information on the invoice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>21", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following refers to a price reduction based on the size of order?", "images": [], "options": {"A": "Cash discount", "B": "Trade discount", "C": "Seasonal discount", "D": "Cash on delivery"}, "answer": "B", "explanation": "A trade discount refers to a reduction in price based on the size or quantity of an order. It is a strategy used by businesses to encourage bulk buying. The more a customer buys, the larger the discount they receive. This is different from a cash discount, which is a reduction in price given to customers who pay their bills promptly. A seasonal discount is a price reduction during certain times of the year, while cash on delivery is a type of transaction where payment is made at the time of delivery rather than in advance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>22", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following is not a means of payment in foreign trade?", "images": [], "options": {"A": "Telegraphic money order", "B": "Specially crossed cheque", "C": "Letters of credit", "D": "Debit transfer"}, "answer": "B", "explanation": "A specially crossed cheque is not a means of payment in foreign trade. This is because a crossed cheque is a cheque that has been marked specifying an instruction about the way it is to be redeemed. A crossed cheque cannot be immediately cashed but must be deposited into a bank account. This makes it unsuitable for foreign trade where immediate payment is often required. On the other hand, telegraphic money orders, letters of credit, and debit transfers are all commonly used methods of payment in foreign trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>23", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A bill of exchange on maturity is allowed", "images": [], "options": {"A": "Seven days grace", "B": "Five days grace", "C": "Four days grace", "D": "Three days grace"}, "answer": "D", "explanation": "A bill of exchange is a written order that instructs the payer (drawee) to pay a specified amount of money to the payee (drawer) on a particular date. When a bill of exchange matures (becomes due), the drawee is allowed a short period of time, known as \"days of grace,\" before the payment must be made.    A bill of exchange is typically allowed a three-day grace period after its nominal due date for payment. This means the payer has three extra days to fulfill the payment obligation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>24", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Which of the following is not a financial institution?", "images": [], "options": {"A": "Commodity board", "B": "Insurance company", "C": "Clearing house", "D": "Stock exchange"}, "answer": "A", "explanation": "A financial institution is an establishment that conducts financial transactions such as investments, loans and deposits. This includes banks, insurance companies, brokerage firms, etc. A commodity board, on the other hand, is not a financial institution. It is a government body that is responsible for the marketing and development of a particular commodity. It does not conduct financial transactions like the other options listed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>25", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "When a customer writes a cheque in his own name and withdraws cash with it from his own account,he is both the?", "images": [], "options": {"A": "Drawee and the payee", "B": "Drawer and the payer", "C": "Drawee and the payer", "D": "Drawer and the payee"}, "answer": "D", "explanation": "When a customer writes a cheque in his own name and withdraws cash with it from his own account, he is both the drawer and the payee. The drawer is the person who writes the cheque, and the payee is the person to whom the cheque is payable. In this case, since the customer is writing the cheque to himself, he is both the drawer and the payee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>26", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is a means of payment through the post office?", "images": [], "options": {"A": "Standing order", "B": "Promissory note", "C": "Money order", "D": "Telegraphic transfer"}, "answer": "C", "explanation": "A money order is a means of payment through the post office. It is a payment order for a pre-specified amount of money. As it is required that the funds be prepaid for the amount shown on it, it is a more trusted method of payment than a cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>27", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Which of the following encourages people to save towards owning a house?", "images": [], "options": {"A": "Merchant bank", "B": "Development bank", "C": "Mortage bank", "D": "Commercial bank"}, "answer": "C", "explanation": "A mortgage bank encourages people to save towards owning a house. Mortgage banks are financial institutions that lend money to individuals to purchase homes or other real estate. The borrower pays back the loan over time, usually with interest. This encourages people to save as they can use these savings to pay off their mortgage and eventually own the house.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>28", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following services is not rendered by commercial banks?", "images": [], "options": {"A": "Business advice", "B": "Currency notes issue", "C": "Accepting deposits", "D": "Credit transfer"}, "answer": "B", "explanation": "Commercial banks do not issue currency notes. The issuance of currency notes is typically the responsibility of a country's central bank or monetary authority. Commercial banks provide services such as accepting deposits, providing business advice, and facilitating credit transfers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>29", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "A retirement insurance policy which encourages the assured to receive income for a specific period is?", "images": [], "options": {"A": "Annuity", "B": "Endownment", "C": "Whole life", "D": "Fidelity guarantee"}, "answer": "A", "explanation": "An annuity is a type of insurance product that provides a steady income for a specific period of time, often until the end of the insured's life. This is typically used for retirement planning. The other options do not fit the description given in the question. An endowment policy is a life insurance contract designed to pay a lump sum after a specific term or on death. Whole life insurance provides coverage for the life of the insured and also builds up a cash value. Fidelity guarantee insurance provides cover for the loss of money or property sustained as a direct result of acts of fraud, theft or dishonesty by an employee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>30", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "A house worth ⋕50,000 was insured against fire for ⋕30,000. Fire destroyed and caused damage worth ⋕20,000 on the house. Under which insurance principle will the owner be entitled to a commission of ⋕20,000?", "images": [], "options": {"A": "Contribution", "B": "Subrogation", "C": "Indemnity", "D": "Uberrimae fidei"}, "answer": "C", "explanation": "The principle of indemnity is a key aspect of insurance contracts, which states that the insured should not profit from a loss but should be returned to the same financial position that existed before the loss. In this case, the house was insured for ⋕30,000, and the damage was worth ⋕20,000. Therefore, the owner is entitled to a compensation of ⋕20,000, which is the value of the damage. The principle of contribution applies when the insured has taken out multiple policies on the same risk. The principle of subrogation allows an insurer to pursue the third party that caused an insurance loss to the insured. Uberrimae fidei, or utmost good faith, is a legal doctrine which governs insurance contracts, requiring all parties to reveal any information that might influence the other's decision to enter into the contract.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>31", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "When an insurance company indemnifies the insured and takes over his rights,  this is known as?", "images": [], "options": {"A": "Abandonment", "B": "Subrogation", "C": "Proximate cause", "D": "Contribution"}, "answer": "B", "explanation": "Subrogation is a term describing a legal right held by most insurance carriers to legally pursue a third party that caused an insurance loss to the insured. This is done as a means of recovering the amount of the claim paid by the insurance carrier to the insured for the loss.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>32", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "In public limited liabilities companies,equities are referred to as?", "images": [], "options": {"A": "Preference shares", "B": "Authorized capital", "C": "Ordinary shares", "D": "Called-up capital"}, "answer": "C", "explanation": "In public limited liability companies, equities are referred to as Ordinary shares. Ordinary shares, also known as common shares, give their owners the right to vote at the company's annual general meetings and to receive any company dividends. Preference shares, on the other hand, have a fixed dividend, but holders do not have voting rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>33", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "The method of sending messages by the teleprinter is?", "images": [], "options": {"A": "Telephone", "B": "Cablegram", "C": "Telex", "D": "Railex"}, "answer": "C", "explanation": "Telex is a networked system of teleprinters, similar to a telephone network, for the purposes of sending text-based messages. The term 'teleprinter' is a device that can send and receive messages through various communication channels, and Telex is the method that uses teleprinters to send messages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>34", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "The information on terms of carriage of mails is found in?", "images": [], "options": {"A": "Business journal", "B": "Post office guide", "C": "Trade directory", "D": "Service manual"}, "answer": "B", "explanation": "The Post Office Guide is a publication by the postal department of a country that provides information on the terms and conditions, procedures, restrictions, and charges for various postal services, including the carriage of mails.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>35", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Rail transport is less flexible than road transport because?", "images": [], "options": {"A": "Rail lines runs between specific terminals", "B": "Train is slow over long distances", "C": "Only bulky goods are carried by rail", "D": "Road transport is suitable for short distances"}, "answer": "A", "explanation": "Rail transport is less flexible than road transport because rail lines run between specific terminals. This means that the routes and times are fixed, unlike road transport where vehicles can go to different routes at any time. This makes rail transport less flexible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>36", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following is suitable for moving only goods from one sea port to another?", "images": [], "options": {"A": "Ocean liner", "B": "Cargo liner", "C": "Ferry", "D": "Coaster"}, "answer": "B", "explanation": "A cargo liner is a type of ship that is specifically designed to transport goods from one sea port to another. They are built to carry a variety of goods, including containers, vehicles, and bulk cargo. Ocean liners, ferries, and coasters are types of ships, but they are not specifically designed for moving goods from one sea port to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>37", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The marketing activity that stimulates immediate demand for a product is?", "images": [], "options": {"A": "Sales promotion", "B": "Publicity", "C": "Consumer relations", "D": "Personal selling"}, "answer": "A", "explanation": "Sales promotion is a marketing strategy where the product is promoted using short-term attractive initiatives to stimulate its demand and increase its sales. This is different from other marketing activities like publicity (which is about raising general awareness of the product, not immediate demand), consumer relations (which is about maintaining ongoing relationships with customers), and personal selling (which is a more direct form of selling, not necessarily aimed at immediate demand stimulation).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>38", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Which of these is not a basic marketing function?", "images": [], "options": {"A": "Exchange", "B": "Production", "C": "Facilitation", "D": "Information"}, "answer": "B", "explanation": "The basic marketing functions include exchange (the process of trading products between the buyer and the seller), facilitation (supporting the exchange process, e.g., through financing, risk taking, etc.), and information (providing information about the product to the potential buyers). Production, however, is not a marketing function. It is a separate function that involves creating the product that will later be marketed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>39", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Branding is a tool for?", "images": [], "options": {"A": "Competitive advertising", "B": "Consumerism", "C": "Marketing research", "D": "Pricing policy"}, "answer": "A", "explanation": "Branding is a marketing practice in which a company creates a name, symbol or design that is easily identifiable as belonging to the company. This helps to identify a product and distinguish it from other products and services. Branding is important because not only is it what makes a memorable impression on consumers but it allows your customers and clients to know what to expect from your company. Therefore, it can be seen as a tool for competitive advertising.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>40", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Firms wishing to defend established products as well as launch new ones will make use of?", "images": [], "options": {"A": "Franchising", "B": "Product differentiation", "C": "Branding", "D": "Advertising"}, "answer": "C", "explanation": "Branding is the process of creating a unique name and image for a product in the consumer's mind, making it stand out from the competition.  A strong brand can help protect established products and create a platform for launching new ones under the same umbrella.  It provides a consistent image and message across all products, building trust and loyalty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>41", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is a method of sales promotion?", "images": [], "options": {"A": "Radio gingles", "B": "Poster display", "C": "Trade fair", "D": "Television broadcast"}, "answer": "C", "explanation": "Sales promotion refers to the activities that supplement and coordinate personal selling and advertising to attract customers to buy a product. Trade fair is a method of sales promotion where companies display and demonstrate their new products and services. Radio jingles, poster display, and television broadcast are methods of advertising, not sales promotion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2000>42", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "The deliberate and sustained efforts to maintain a good image of a company is known as?", "images": [], "options": {"A": "Personal relations", "B": "Public relations", "C": "Professional relations", "D": "Industrial relations"}, "answer": "B", "explanation": "Public relations is the deliberate, planned and sustained effort to establish and maintain mutual understanding between an organization and its publics. It involves activities that are aimed at improving the image of a company and the relationship it has with its customers, employees, investors, and the public. Personal relations, professional relations, and industrial relations do not fit the definition of the term in the context of the question.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2000>43", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A contract of sale where ownership passes to the buyer on the payment of the first instalment is known as?", "images": [], "options": {"A": "Hire purchase", "B": "Lease", "C": "Cash on delivery", "D": "Credit sale"}, "answer": "D", "explanation": "A contract of sale where ownership passes to the buyer on the payment of the first instalment is known as a credit sale. In a credit sale, the buyer takes ownership of the item right after the first payment is made, even though the full payment is not yet complete. This is different from a hire purchase where the ownership is transferred only after the full payment is made. Lease and cash on delivery do not fit into this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>44", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "Which of the following agents guarantees payment for transacttions entered into on behalf of the principal?", "images": [], "options": {"A": "Auctioneer", "B": "Factor", "C": "Broker", "D": "Del credere"}, "answer": "D", "explanation": "A del credere agent is an agent who, in consideration of an extra commission, guarantees to his principal that the parties to whom he sells will pay. If they do not, he will. Therefore, a del credere agent guarantees payment for transactions entered into on behalf of the principal. An auctioneer, factor, and broker do not provide this guarantee.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2000>45", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following is not a means of consumer protection?", "images": [], "options": {"A": "Price control", "B": "Sale of Goods Act", "C": "Trade description Act", "D": "Tax laws"}, "answer": "D", "explanation": "Consumer protection refers to the practices and laws that ensure the rights of consumers are protected and that businesses are fair and honest. Among the options, Price control, Sale of Goods Act, and Trade description Act are all means of consumer protection. Price control prevents businesses from setting prices too high; the Sale of Goods Act ensures that goods sold are of satisfactory quality; and the Trade Description Act prevents businesses from providing misleading descriptions of goods or services. However, Tax laws are not a means of consumer protection. They are primarily used to collect revenue for the government and do not directly protect consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>46", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Which of the following is a basic requirement for a valid contract?", "images": [], "options": {"A": "Representation", "B": "Consideration", "C": "Interest", "D": "Performance"}, "answer": "B", "explanation": "A valid contract requires several elements: offer, acceptance, consideration, and the intention to create legal relations. Among the options, only 'Consideration' is a basic requirement for a valid contract. Consideration refers to what is being exchanged in the contract, it could be money, services, goods, etc. 'Representation' is not a requirement for a valid contract, it refers to the statements made by the parties before the contract is formed. 'Interest' and 'Performance' are also not basic requirements for a valid contract.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>47", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "A counter-offer in a contract is regarded as ?", "images": [], "options": {"A": "An acceptance", "B": "An invitation to threat", "C": "A rejection", "D": "A consideration"}, "answer": "C", "explanation": "A counter-offer in a contract is regarded as a rejection of the original offer and the simultaneous making of a new offer. It means the original offer cannot be accepted anymore because it has been destroyed by the counter-offer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>48", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following is not a right of the consumer?", "images": [], "options": {"A": "Safety", "B": "Choice", "C": "Discount", "D": "Value"}, "answer": "C", "explanation": "The right to discount is not a recognized right of the consumer. The recognized consumer rights include the right to safety, the right to be informed, the right to choose, and the right to be heard.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2000>49", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following is an agreement to transport goods but not a document of title?", "images": [], "options": {"A": "Air-way bill", "B": "Bill of lading", "C": "Charter party", "D": "Freight note"}, "answer": "C", "explanation": "A Charter Party is an agreement to transport goods but not a document of title. It is a contract between the owner of a vessel and the charterer for the use of a vessel. The charterer takes over the vessel for either a certain amount of time (a time charter) or for a certain point-to-point voyage (a voyage charter), and has a wide latitude in directing the vessel's operations. This differentiates a charter party from other forms of maritime transport documents, such as a bill of lading, which merely serve as receipt and evidence of the contract of carriage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2000>50", "subject": "Commerce", "year": "2000", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "In which of the following classes of occupation would you place a doctor?", "images": [], "options": {"A": "Extractive", "B": "Commercial", "C": "Direct services", "D": "Indirect services"}, "answer": "C", "explanation": "A doctor falls under the category of Direct Services. Direct services are those services that are directly consumed by the consumer. They are intangible products such as accounting, banking, cleaning, consultancy, education, insurance, expertise, medical treatment, or transportation. In this case, a doctor provides a medical treatment service that is directly consumed by the patient.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>1", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Which of the following best describes commerce?", "images": [], "options": {"A": "Buying and selling of goods and services", "B": "Buying,selling and distribution of goods and services", "C": "Preserving goods untill they are needed", "D": "Making goods and services known to people"}, "answer": "B", "explanation": "Commerce is best described as the buying, selling and distribution of goods and services. It involves not just the exchange of goods and services, but also their transportation, storage, and distribution from the place of production to the place of consumption.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>2", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Those who are engaged in explioting natural resources are in", "images": [], "options": {"A": "Extractive occupation", "B": "Constructive occupation", "C": "Commercial occupation", "D": "Manufacturing occupation"}, "answer": "A", "explanation": "Those who are engaged in exploiting natural resources are in the extractive occupation. This is because they are involved in the extraction of natural resources from the earth such as mining, fishing, forestry, and agriculture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>3", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is classified under primary production?", "images": [], "options": {"A": "Cloth making", "B": "Shoe making", "C": "Coal mining", "D": "Road construction"}, "answer": "C", "explanation": "Primary production refers to the sector of an economy that makes direct use of natural resources. This includes agriculture, forestry, fishing and mining. In this case, coal mining is a form of primary production as it involves extraction of coal (a natural resource) directly from the earth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>4", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The mark-up of a retailer represents the?", "images": [], "options": {"A": "Gross profit", "B": "Opening stock", "C": "Closing stock", "D": "Net profit"}, "answer": "A", "explanation": "The mark-up of a retailer represents the gross profit. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. In retail, the markup is the difference between the wholesale cost of an item and the price your store sells it for. This difference in price is your retail store's gross profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>5", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The number of times the average stock of a business is sold within a given period is?", "images": [], "options": {"A": "Turnover", "B": "Rate of turnover", "C": "Sales return", "D": "Current ratio"}, "answer": "B", "explanation": "The number of times the average stock of a business is sold within a given period is referred to as the 'Rate of turnover'. This is a measure of the efficiency of a company in managing its inventory. It calculates how quickly a company moves its inventory or stock through its business and converts it into sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>6", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Branding is an aspect of marketing mix associated with?", "images": [], "options": {"A": "Price", "B": "Product", "C": "Place", "D": "Distribution"}, "answer": "B", "explanation": "Branding is an aspect of the marketing mix associated with 'Product'. Branding is a marketing practice in which a company creates a name, symbol or design that is easily identifiable as belonging to the company. This helps to identify a product and distinguish it from other products and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>7", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following is most appropriate for a \"Cash with Order\" terms of sale?", "images": [], "options": {"A": "Proforma invoice", "B": "Credit note", "C": "Debit note", "D": "Consignment note"}, "answer": "A", "explanation": "A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is often used to declare the value of the trade. It is not a true invoice because it is not used to record accounts receivable for the seller and accounts payable for the buyer. 'Cash with Order' means that the buyer pays when ordering the goods and they are dispatched only after payment is received. Therefore, a proforma invoice is most appropriate for a 'Cash with Order' terms of sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>8", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Which of the following businesses must have at least one member with unlimited liability?", "images": [], "options": {"A": "Limited liability company", "B": "Limited partnership", "C": "Nominal partnership", "D": "Public enterprise"}, "answer": "B", "explanation": "A limited partnership is a form of partnership similar to a general partnership, except that in addition to one or more general partners (GPs), there are one or more limited partners (LPs). It is a partnership in which only one partner is required to be a general partner with unlimited liability, and the other partner can have limited liability. Therefore, a limited partnership must have at least one member with unlimited liability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>9", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : FEATURES/CHARACTERISTICS", "question": "Which of the following is a feature of sole proprietorship?", "images": [], "options": {"A": "Issues of shares", "B": "Limited liability", "C": "Limited capital", "D": "Legal entity"}, "answer": "C", "explanation": "A sole proprietorship is a type of business entity that is owned and run by one individual and in which there is no legal distinction between the owner and the business. The owner receives all profits and has unlimited personal liability for all losses. Therefore, the feature of a sole proprietorship is limited capital, not limited liability, issues of shares or being a legal entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>10", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following is used to advertise the activities of a company?", "images": [], "options": {"A": "Memorandum of association", "B": "Articles of association", "C": "Certificate of incorporation", "D": "Prospectus"}, "answer": "D", "explanation": "A prospectus is a formal document that is required by and filed with the Securities and Exchange Commission that provides details about an investment offering for sale to the public. In the context of a company, a prospectus is used to advertise the activities of a company, not the memorandum of association, articles of association or certificate of incorporation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>11", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "Which of the following requires a certificate of trading to start business?", "images": [], "options": {"A": "Partnership", "B": "Private Limited Company", "C": "Cooperative Society", "D": "Public Limited Company"}, "answer": "D", "explanation": "A Public Limited Company requires a certificate of trading to start business. This is because a Public Limited Company is a type of business that offers its securities (stock/shares, bonds/loans, etc.) for sale to the general public, typically through a stock exchange. The certificate of trading is a legal document that confirms that the company is legally allowed to start trading. This is different from a Private Limited Company, Partnership, or Cooperative Society, which do not require a certificate of trading to start business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>12", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "A business firm which controls more than half of another firm's equity is a?", "images": [], "options": {"A": "Holding company", "B": "Consortium", "C": "Cartel", "D": "Syndicate"}, "answer": "A", "explanation": "A Holding company is a business firm which controls more than half of another firm's equity. This is because a holding company is a type of firm that owns other companies' outstanding stock. The term usually refers to a company that does not produce goods or services itself; rather, its purpose is to own shares of other companies to form a corporate group. Holding companies allow the reduction of risk for the owners and can allow the ownership and control of a number of different companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>13", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is an example of itinerant trade?", "images": [], "options": {"A": "Mobile shops", "B": "Mail order business", "C": "Staff holding", "D": "Selling from kiosk"}, "answer": "A", "explanation": "Itinerant trade refers to a retail business where the retailer does not have a fixed place of business. Instead, they move from place to place with their goods and services. Mobile shops are a perfect example of this as they move around to reach their customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>14", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not an objective of ECOWAS?", "images": [], "options": {"A": "Expansion of trade", "B": "Encouraging free movements of persons within nmember states", "C": "Improvement of infrasturctural facilities", "D": "Promoting common language"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Its mission is to promote economic integration in all fields of economic activity, particularly industry, transport, telecommunications, energy, agriculture, natural resources, commerce, monetary and financial issues, social and cultural matters. Promoting a common language is not one of its objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>15", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The expert who calculates premium for an insurance company is?", "images": [], "options": {"A": "An underwriter", "B": "An actuary", "C": "A broker", "D": "An assessor"}, "answer": "B", "explanation": "An actuary is a business professional who deals with the financial impact of risk and uncertainty. Actuaries use mathematics, statistics, and financial theory to study uncertain future events, especially those of concern to insurance and pension programs. They evaluate the likelihood of those events, design creative ways to reduce the likelihood and decrease the impact of adverse events that actually do occur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>16", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following means restoring the insured to the position he was just before the loss occured?", "images": [], "options": {"A": "Indemnity", "B": "Subrogation", "C": "Proximate cause", "D": "Utmost good faith"}, "answer": "A", "explanation": "Indemnity is a contractual obligation of one party (indemnifier) to compensate the loss occurred to the other party (indemnity holder) due to the act of the indemnitor or any other party. In simple terms, indemnity is a promise made by one party to make good the loss suffered by the other party. The principle of indemnity is such principle of insurance stating that an insured may not be compensated by the insurance company in an amount exceeding the insured's economic loss. In other words, the insured should not profit from a loss or damage caused by an insured peril.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>17", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is not a means of payment in foreign trade?", "images": [], "options": {"A": "Telegraphic transfer", "B": "Cheque", "C": "Letter of credit", "D": "Bill of exchange"}, "answer": "B", "explanation": "Cheques are not typically used as a means of payment in foreign trade. This is because cheques are not considered as secure and reliable as other methods such as telegraphic transfers, letters of credit, and bills of exchange. These other methods provide more security and assurance that payment will be received. A cheque can be easily cancelled or may not be honored if there are insufficient funds in the account, making it a risky choice for international trade transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>18", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "The act of keeping products in good condition untill they are needed is?", "images": [], "options": {"A": "Insurance", "B": "Ware housing", "C": "Communication", "D": "Advertising"}, "answer": "B", "explanation": "Warehousing is the act of keeping products in good condition until they are needed. Warehousing involves the storage of goods in a protected and safe environment to prevent damage or loss. It also involves the management of goods within the warehouse, including their receipt, storage, and dispatch. Insurance, communication, and advertising are important aspects of commerce, but they do not directly involve the physical storage and preservation of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>19", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "A person who decides what to produce and combines the other factors of production is the?", "images": [], "options": {"A": "Entrepreneur", "B": "Distributor", "C": "Engineer", "D": "Retailer"}, "answer": "A", "explanation": "An entrepreneur is a person who decides what to produce and combines the other factors of production. They are the ones who take the risk of starting a business, make decisions about the type of product or service to offer, and manage the business operations. The other options, distributor, engineer, and retailer, do not fit the description given in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>20", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The authority given to a bank to make regular payments on behalf of a customer for a specific purpose is known as?", "images": [], "options": {"A": "Bank draft", "B": "Credit transfer", "C": "Standing order", "D": "Certified cheque"}, "answer": "C", "explanation": "A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The set amount will be paid regularly until the customer cancels it. A bank draft is a type of check where the payment is guaranteed to be available by the issuing bank. Credit transfer is a method of transferring money from one bank account to another. A certified cheque is a type of cheque for which the bank verifies that sufficient funds exist in the account to cover the cheque, and so it cannot be bounced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>21", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A bundle of shares is called?", "images": [], "options": {"A": "Stock", "B": "Bonus issue", "C": "Debenture", "D": "Rights issue"}, "answer": "A", "explanation": "A bundle of shares is called a stock. In finance, stock (also capital stock) is all of the shares into which ownership of a corporation or company is divided. It represents a claim on part of the corporation's assets and earnings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>22", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Agricultural cooperative banks are best classified under?", "images": [], "options": {"A": "Commercial banks", "B": "Savings banks", "C": "Merchant banks", "D": "Specialized banks"}, "answer": "D", "explanation": "Agricultural cooperative banks are best classified under specialized banks. Specialized banks are banks that are set up to cater to specific sectors or industries. Agricultural cooperative banks, for instance, are set up to provide banking and related services to the agricultural sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>23", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following is a creditor legally bound to accept for settlement of a debt?", "images": [], "options": {"A": "Bank draft", "B": "Bank note", "C": "Money order", "D": "Cheque"}, "answer": "B", "explanation": "A creditor is legally bound to accept a bank note for settlement of a debt. A bank note is a type of negotiable instrument, which is a document that guarantees the payment of a specific amount of money, either on demand, or at a set time, with the payer named on the document. Other options like bank draft, money order, and cheque are not legally binding for a creditor to accept for debt settlement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>24", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "All human effort geared towards the production of goods and services is?", "images": [], "options": {"A": "Entrepreneurship", "B": "Labour", "C": "Capital", "D": "Occupation"}, "answer": "B", "explanation": "All human effort geared towards the production of goods and services is referred to as labour. Labour in economics refers to the human effort that is used in the production of goods and services. Entrepreneurship, capital, and occupation are all components of the production process, but they are not the human effort itself.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>25", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following abbreviations indicates that the seller reserves the right to correct errors on the invoice?", "images": [], "options": {"A": "E. & O.E", "B": "C.I.F", "C": "C.O.D", "D": "C.W.O"}, "answer": "A", "explanation": "E. & O.E stands for Errors and Omissions Excepted. This abbreviation is used by sellers to indicate that they reserve the right to correct any errors or omissions on the invoice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>26", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A document from a seller which corrects an under-charge on a buyer's account is known as?", "images": [], "options": {"A": "Proforma invoice", "B": "Credit note", "C": "Debit note", "D": "Statement of account"}, "answer": "C", "explanation": "A Debit Note is a document issued by a seller to a buyer indicating an under-charge on the buyer's account. It increases the amount that the buyer has to pay to the seller.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>27", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A price quotation that covers the cost of goods and all other expenses incurred in delivering the goods to the buyer is called?", "images": [], "options": {"A": "CIF", "B": "FAS", "C": "Franco", "D": "Loco"}, "answer": "A", "explanation": "CIF stands for Cost, Insurance, and Freight. It is a pricing term that includes the cost of goods, insurance, and all transportation costs to the named place of destination. This means that the seller pays for the transportation of the goods up to the point of destination. Therefore, CIF is a price quotation that covers the cost of goods and all other expenses incurred in delivering the goods to the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>28", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "An agent who takes possession of goods and sells in his own name is known as?", "images": [], "options": {"A": "A broker", "B": "A del credere agent", "C": "An auctioneer", "D": "A factor"}, "answer": "D", "explanation": "A factor is an agent who takes possession of goods and sells them in his own name. Unlike a broker or an auctioneer, a factor has the power to alter the legal relationship between the owner and the buyer. He can sell the goods in his own name and does not have to disclose the principal's name. A del credere agent, on the other hand, is an agent who, for an extra commission, guarantees his principal that the third parties with whom he deals will fulfill their contractual obligations.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>29", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following is not a service rendered by the wholesaler to the manufacturer?", "images": [], "options": {"A": "Warehousing", "B": "Quality Control", "C": "Financing", "D": "Bulk-breaking"}, "answer": "A", "explanation": "An adverse balance of payment is a situation where a country's imports are greater than its exports. To correct this, a country would need to either decrease its imports or increase its exports. Therefore, increasing imports would not correct an adverse balance of payment, it would actually worsen it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>30", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "The extra commission for pledging full settlement of the purchase price of goods is given to a?", "images": [], "options": {"A": "Del credere agent", "B": "Factor", "C": "Broker", "D": "Jobber"}, "answer": "A", "explanation": "A del credere agent is a type of agent who not only sells goods on behalf of the principal but also guarantees payment from the buyer. In return for this additional responsibility, the del credere agent typically receives an extra commission. This extra commission compensates for the risk taken in guaranteeing the full settlement of the purchase price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>31", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following is not used to correct an adverse balance of payment?", "images": [], "options": {"A": "Increasing imports", "B": "Increasing exports", "C": "Decreasing imports", "D": "Devaluation"}, "answer": "A", "explanation": "An adverse balance of payment is a situation where a country's imports are greater than its exports. To correct this, a country can increase exports, decrease imports, or devalue its currency to make its goods cheaper and more attractive to foreign buyers. Increasing imports would worsen the situation, not correct it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>32", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "When a bill is paid before its due at a lesser value, it is?", "images": [], "options": {"A": "Accepted", "B": "Discounted", "C": "Dishonoured", "D": "Retired"}, "answer": "B", "explanation": "When a bill is paid before its due date at a lesser value, it is said to be 'discounted'. This is because the holder of the bill is willing to accept less than the face value in return for getting the money earlier. This is a common practice in finance and is known as discounting a bill.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>33", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following is not a function of Ports Authority?", "images": [], "options": {"A": "Ensuring safe movements of ships", "B": "Collecting imports and export duties", "C": "Providing warehousing services", "D": "Ensuring law and order in the harbours"}, "answer": "B", "explanation": "The Ports Authority is responsible for ensuring the safe movement of ships, providing warehousing services, and ensuring law and order in the harbours. However, the collection of import and export duties is not a function of the Ports Authority. This function is typically performed by the Customs and Excise Department or a similar government agency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>34", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The portion of authorized capital made available to the public for subscription is?", "images": [], "options": {"A": "Called-up capital", "B": "Paid-up capital", "C": "Call in arrears", "D": "Issued capital"}, "answer": "D", "explanation": "The portion of authorized capital that is made available to the public for subscription is known as issued capital. Authorized capital is the maximum amount of share capital that a company is authorized to issue to shareholders. Issued capital refers to the portion of this capital that the company has actually issued to shareholders. Called-up capital refers to the portion of issued capital that shareholders have been asked to pay, while paid-up capital is the portion of called-up capital that shareholders have actually paid.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>35", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer questions 35 to 37.  XY Ltd's stock as at 1st February, 1998 was ⋕2,000 and as at December was ⋕4,000. It purchased goods worth ⋕6,000 during the year and paid ⋕1,000 for rent.    The average stock is?", "images": [], "options": {"A": "⋕2,000", "B": "⋕3,000", "C": "⋕4,000", "D": "⋕6,000"}, "answer": "B", "explanation": "The average stock is calculated by adding the opening stock and the closing stock and then dividing by 2. In this case, the opening stock is ⋕2,000 and the closing stock is ⋕4,000. Therefore, the average stock is (2000 + 4000) / 2 = ⋕3,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>36", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer questions 35 to 37.  XY Ltd's stock as at 1st February, 1998 was ⋕2,000 and as at December was ⋕4,000. It purchased goods worth ⋕6,000 during the year and paid ⋕1,000 for rent.The cost of goods sold is?", "images": [], "options": {"A": "⋕2,000", "B": "⋕4,000", "C": "⋕6,000", "D": "⋕8,000"}, "answer": "B", "explanation": "The cost of goods sold is calculated by adding the opening stock to the purchases and then subtracting the closing stock. In this case, the opening stock is ⋕2,000, the purchases are ⋕6,000, and the closing stock is ⋕4,000. Therefore, the cost of goods sold is (2000 + 6000) - 4000 = ⋕4,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>37", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer questions 35 to 37.  XY Ltd's stock as at 1st February, 1998 was ⋕2,000 and as at December was ⋕4,000. It purchased goods worth ⋕6,000 during the year and paid ⋕1,000 for rent.The rate of stock turnover is?", "images": [], "options": {"A": "1.3 times", "B": "1.5 times", "C": "2.0 times", "D": "3.0 times"}, "answer": "A", "explanation": "The rate of stock turnover is calculated by dividing the cost of goods sold by the average inventory. In this case, the cost of goods sold is the initial stock plus purchases minus the final stock, which is (2000 + 6000 - 4000) = ⋕4000. The average inventory is the sum of the initial and final stock divided by 2, which is (2000 + 4000) / 2 = ⋕3000. Therefore, the rate of stock turnover is 4000 / 3000 = 1.33 times, which is approximately 1.3 times.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>38", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A specially designed container to convey crude oil or liquid from one location to another is a?", "images": [], "options": {"A": "Launche", "B": "Tanker", "C": "Ferry", "D": "Coaster"}, "answer": "B", "explanation": "A specially designed container to convey crude oil or liquid from one location to another is a tanker. Tankers are large ships designed to transport huge volumes of cargo, including oil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>39", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a market function?", "images": [], "options": {"A": "Advertising", "B": "Insurance", "C": "Packaging", "D": "Transportation"}, "answer": "B", "explanation": "A market function refers to the various activities that are performed by different market participants in the process of buying and selling goods and services. These functions include advertising, packaging, and transportation. However, insurance is not a market function. Insurance is a risk management tool used to hedge against a certain loss. It is not directly involved in the buying and selling of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>40", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a feature of a departmental store?", "images": [], "options": {"A": "Located at the centre of a city", "B": "Bulk buying", "C": "Attractive layout", "D": "Selling one line of goods"}, "answer": "D", "explanation": "A departmental store is a large retail establishment that offers a wide variety of goods grouped into departments. It is usually located at the centre of a city, practices bulk buying to get goods at lower prices, and has an attractive layout to entice customers. However, selling one line of goods is not a feature of a departmental store. Departmental stores are characterized by their wide range of product offerings across multiple product lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>41", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following is a function of a warehouse?", "images": [], "options": {"A": "Stabilizing prices", "B": "Increasing competition", "C": "Stimulating demand", "D": "Controlling quality"}, "answer": "A", "explanation": "A warehouse is a building for storing goods. Warehouses are used by manufacturers, importers, exporters, wholesalers, transport businesses, customs, etc. One of the main functions of a warehouse is to stabilize prices by adjusting the supply of goods in response to changes in demand. This is achieved by storing goods when their supply exceeds demand and releasing them when the demand is greater than the supply.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>42", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "The term \"21/2  30 days\" refers to?", "images": [], "options": {"A": "Mark-up", "B": "Trade discount", "C": "Cash discount", "D": "Value added tax"}, "answer": "C", "explanation": "The term \"21/2  30 days\" refers to a cash discount. A cash discount is a deduction allowed by the seller of goods or by the provider of services in order to motivate the customer to pay within a specified time. The term \"21/2  30 days\" means that the buyer will get a 2% cash discount if he/she pays within 30 days.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>43", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The turnover of a company will improve if the company increases?", "images": [], "options": {"A": "Advertising", "B": "Prices of goods", "C": "Production", "D": "Warehousing facilities"}, "answer": "C", "explanation": "The turnover of a company refers to the total sales made by a company during a certain period. It can be improved by increasing the production of goods or services. More production means more goods or services to sell, which can lead to an increase in sales, hence improving the turnover. Advertising, increasing prices of goods, and improving warehousing facilities may contribute to the turnover, but they are not direct factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>44", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "An association of businessmen including manufacturers,traders,bankers and people engaged in business in an area is known as?", "images": [], "options": {"A": "Trade association", "B": "Chamber of commerce", "C": "Trade union", "D": "Cooperative society"}, "answer": "B", "explanation": "A Chamber of Commerce is an association of businessmen including manufacturers, traders, bankers, and people engaged in business in an area. It is a network of local businesses aimed to further the interests of businesses. Trade associations, trade unions, and cooperative societies are different types of organizations with different purposes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>45", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Product,pricing distribution and promotion are elements of?", "images": [], "options": {"A": "Marketing mix", "B": "Marketing research", "C": "Sales promotion", "D": "Product orientation"}, "answer": "A", "explanation": "The elements of the marketing mix are often called the Four P's: Product, Price, Place (distribution), and Promotion. These are variables that a marketing manager can control in order to best satisfy customers in the target market. The marketing mix is portrayed in the following diagram: The Marketing Mix Diagram. The marketing mix is a crucial tool to help understand what the product or service can offer and how to plan for a successful product offering.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>46", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The greatest advantage of air transport over all other means of transport is its?", "images": [], "options": {"A": "Comfort", "B": "Safety", "C": "Speed", "D": "Flexibility"}, "answer": "C", "explanation": "The greatest advantage of air transport over all other means of transport is its speed. Air transport is the fastest method of transport and therefore, it is a crucial mode of transport for areas which require emergency supplies, quick delivery, etc. It can cover very long distances in a very short time. For instance, it takes approximately 8-10 hours to travel from America to Europe by air, whereas it would take several days to weeks by ship or by road.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2001>47", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The exchange of goods for goods in foreign trade is known as?", "images": [], "options": {"A": "Visible trade", "B": "Smuggling", "C": "Counter trade", "D": "Entreport trade"}, "answer": "C", "explanation": "Counter trade refers to the exchange of goods or services which are paid for, in whole or part, with other goods or services, rather than with money. In the context of foreign trade, this would involve the exchange of goods for goods between different countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>48", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A speculator on the stock exchange market who sells securities for fear of a fall in their prices is called?", "images": [], "options": {"A": "A bull", "B": "A bear", "C": "A stag", "D": "An underwriter"}, "answer": "B", "explanation": "In stock market terminology, a 'bear' is an investor who believes that a particular security, a sector, or the overall market is about to fall. This belief often leads them to sell off their securities to avoid potential losses. Therefore, a speculator who sells securities for fear of a fall in their prices is referred to as a 'bear'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2001>49", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "The law by which the seller transfers the property in goods to the buyer at an agreed price is the?", "images": [], "options": {"A": "Hire Purchase Act", "B": "Trade Description Act", "C": "Foods and Drugs Act", "D": "Sale of Goods Act"}, "answer": "D", "explanation": "The Sale of Goods Act is the law that governs the sale of goods, including the transfer of ownership from seller to buyer at an agreed price. The other options do not directly deal with the transfer of ownership of goods at an agreed price. The Hire Purchase Act deals with the purchase of goods by paying in installments, the Trade Description Act deals with false or misleading descriptions of goods, and the Foods and Drugs Act deals with the regulation of food and drug products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2001>50", "subject": "Commerce", "year": "2001", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is a means of payment to persons abroad through the post office?", "images": [], "options": {"A": "Postal order", "B": "Cheque", "C": "Bank draft", "D": "Telegraphic money order"}, "answer": "A", "explanation": "A postal order is a means of sending money through the post office to someone in another location, including abroad. It is a prepaid voucher that the recipient can then cash at their local post office. Cheques and bank drafts are typically used for transactions within the same country, and a telegraphic money order involves sending money via a telegraph or wire service, not the post office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>1", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The distribution and exchange of goods and services for the satisfaction of wants is the concern of?", "images": [], "options": {"A": "Production", "B": "Utility", "C": "Commerce", "D": "Industry"}, "answer": "C", "explanation": "Commerce is concerned with the distribution and exchange of goods and services for the satisfaction of wants. It involves activities that directly deal with the buying, selling, and exchange of goods and services. Production, on the other hand, is the process of creating goods and services. Utility refers to the ability of a good or service to satisfy a want or need. Industry is a group of companies that operate in a specific market segment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>2", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Transforming raw materials into finished products is an example of a?", "images": [], "options": {"A": "Primary production", "B": "Secondary production", "C": "Tertiary production", "D": "Direct service"}, "answer": "B", "explanation": "Transforming raw materials into finished products is an example of secondary production. Primary production involves the extraction of raw materials, such as mining, fishing, and agriculture. Secondary production involves the transformation of these raw materials into finished or semi-finished products. Tertiary production involves the provision of services to consumers and businesses, such as retail, transportation, and professional services. Direct service is a type of tertiary production that involves providing a service directly to the consumer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>3", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Which of the following is concerned with the actual production of goods and services?", "images": [], "options": {"A": "Commerce", "B": "Trade", "C": "Industry", "D": "Service"}, "answer": "C", "explanation": "Industry is concerned with the actual production of goods and services. It involves the conversion of raw materials into finished goods. This process includes all the stages from the procurement of raw materials to the delivery of the finished goods. Commerce and Trade, on the other hand, are concerned with the distribution of the finished goods, while Service is a type of economic activity that does not result in ownership and it is not connected with the production of goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>4", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following has no limit to its membership?", "images": [], "options": {"A": "Ordinary partnership", "B": "Private Limited Company", "C": "Limited partnership", "D": "Co-operative society"}, "answer": "D", "explanation": "A Co-operative society has no limit to its membership. A co-operative society is a voluntary association of individuals who come together to protect and promote their common interests. It is formed by the people who have common needs and who want to cooperate with each other for their mutual benefits. The membership of a co-operative society is open to all, irrespective of their religion, caste, and gender. The other options like Ordinary partnership, Private Limited Company, and Limited partnership have a limit to their membership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>5", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : DISSOLUTION AND LIQUIDATION", "question": "Which of the following does *not* lead to the dissolution of a partnership?", "images": [], "options": {"A": "Absence of a deed of partnership", "B": "Withdrawal of a partner", "C": "Incapacity of any of the partners", "D": "Completion of contractual term"}, "answer": "A", "explanation": "A partnership is a business arrangement where two or more individuals share ownership. In terms of dissolution, the absence of a deed of partnership does not lead to the dissolution of a partnership. A deed of partnership is a legal document that sets out the terms and conditions of the partnership, but its absence does not dissolve the partnership. However, withdrawal of a partner, incapacity of any of the partners, or completion of the contractual term can lead to dissolution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>6", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The refund of a duty which  had been paid on imported goods that are later re-exported is known as?", "images": [], "options": {"A": "Export tax", "B": "Surtax", "C": "Custom's drawback", "D": "Mate's receipt"}, "answer": "C", "explanation": "Custom's drawback is a refund of specific duties, internal revenue taxes, and certain fees collected upon the importation of goods. Such refunds are only issued upon the exportation or destruction of goods under U.S. Customs and Border Protection supervision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>7", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "An offer by one company to buy up all or greater part of another company's shares is known as?", "images": [], "options": {"A": "Merger", "B": "Take-over bid", "C": "Absorption", "D": "Liquidation"}, "answer": "B", "explanation": "A take-over bid is an offer by one company to buy up all or greater part of another company's shares. This is usually done with the intention of gaining control over the other company. A merger is when two companies combine to form a new entity. Absorption is when one company completely takes over another company, causing the latter to cease its existence. Liquidation is the process of bringing a business to an end and distributing its assets to claimants.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>8", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following are features of a limited liability company?  I. Separate legal entity  II. Right to sue but not be sued  III. Has its own corporate name  IV. The liability of members is limited", "images": [], "options": {"A": "I,II and III", "B": "II,III and IV", "C": "I,II and IV", "D": "I,III and IV"}, "answer": "D", "explanation": "A limited liability company has the following features: It is a separate legal entity, meaning it has its own legal personality separate from its owners. It has the right to sue and be sued. It has its own corporate name. The liability of its members is limited to the amount they have invested in the company. Therefore, options I, III, and IV are correct. Option II is incorrect because a limited liability company can be sued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>9", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is an internal source of capital to a business concern?", "images": [], "options": {"A": "Trade credit", "B": "Debenture", "C": "Overdraft", "D": "Retained profit"}, "answer": "D", "explanation": "Retained profit is an internal source of capital for a business. It refers to the earnings that are kept in the company rather than distributed to the owners or shareholders as dividends. This money can be used for reinvestment in the business, for expansion, or to pay off debts. The other options listed are external sources of capital. Trade credit is a type of short-term financing provided by suppliers. A debenture is a type of debt instrument issued by companies to raise capital. An overdraft is a facility provided by banks that allows an account holder to withdraw more money than they have in their account, up to a certain limit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>10", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information to answer the question    Ndu enterprises had the following state of affairs:Stock 1st jan was ₦3500 and 1st December was ₦3,000. His purchases was ₦30,000 and sales was ₦38,000 while a total of rent and electricity bills of ₦4,500 was paid.    What is the gross profit?", "images": [], "options": {"A": "₦8,000", "B": "₦7,500", "C": "₦6,500", "D": "₦3,500"}, "answer": "B", "explanation": "Gross profit=Revenue - cost of goods sold  Gross profit=[(₦38,000 + (₦3,000) - (₦30,000 + ₦3,500)]                      =₦41,000 - ₦33,500                      =₦7,500", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>11", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer the question    Ndu enterprises had the following state of affairs:Stock 1st jan was ₦3500 and 1st December was ₦3,000. His purchases was ₦30,000 and sales was ₦38,000 while a total of rent and electricity bills of ₦4,500 was paid.    The rate of stock turnover is?", "images": [], "options": {"A": "1.2 times", "B": "1.3 times", "C": "4.6 times", "D": "9.4 times"}, "answer": "D", "explanation": "The rate of stock turnover is calculated by dividing the cost of goods sold by the average inventory. The cost of goods sold is calculated by adding the opening stock and purchases, then subtracting the closing stock. The average inventory is calculated by adding the opening and closing stock, then dividing by 2. Therefore, the rate of stock turnover is (₦3500 + ₦30,000 - ₦3,000) / ((₦3500 + ₦3,000) / 2) = 9.4 times.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>12", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer the question    Ndu enterprises had the following state of affairs:Stock 1st jan was ₦3500 and 1st December was ₦3,000. His purchases was ₦30,000 and sales was ₦38,000 while a total of rent and electricity bills of ₦4,500 was paid.    The turnover for the period is?", "images": [], "options": {"A": "₦38,000", "B": "₦33,500", "C": "₦30,000", "D": "₦4,500"}, "answer": "A", "explanation": "The turnover for the period is the total sales made during the period. Therefore, the turnover is ₦38,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>13", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "When shares are sold \"EX-DIV\" it means that?", "images": [], "options": {"A": "No dividend is paid on the shares", "B": "The buyer receives the dividend", "C": "The seller receives the dividend", "D": "The stock exchange retains the dividend"}, "answer": "A", "explanation": "EX-DIV mean Ex-dividend. It means that an investor who buys the stock on its ex-dividend date or later will not be eligible to receive the declared dividend.    It simply means the shareholder (buyer) will not be entitled to the next dividend.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>14", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Detailed information about a public offer of a company's shares is contained in the?", "images": [], "options": {"A": "Memorandum of Association", "B": "Articles of Association", "C": "Letter of enquiry", "D": "Prospectus"}, "answer": "D", "explanation": "Detailed information about a public offer of a company's shares is contained in the Prospectus. A prospectus is a legal document issued by companies that are offering securities for sale. It contains details about the offer, the company, its management, financial statements, and other information that can help a potential investor make an informed decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>15", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "Where two or more companies agree to work on a project too large for one of them, this is called?", "images": [], "options": {"A": "Consortium", "B": "Merger", "C": "Combination", "D": "Cartel"}, "answer": "A", "explanation": "A consortium is a group made up of two or more individuals, companies or governments that work together toward achieving a chosen objective. Companies often form a consortium to collaborate on joint ventures that are too large or too complex for one entity to handle alone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>16", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail outlet meant to sell only a particular manufacturer's product is known as a?", "images": [], "options": {"A": "Co-operative shop", "B": "Chain store", "C": "Department store", "D": "Tied shop"}, "answer": "D", "explanation": "A tied shop is a type of retail outlet that sells only a particular manufacturer's product. This is often the case when the manufacturer wants to control the distribution and quality of their product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>17", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The rate at which a country's currency is converted to the currency of another country is known as?", "images": [], "options": {"A": "Terms of trade", "B": "Terms of payment", "C": "Exchange rate", "D": "Bank rate"}, "answer": "C", "explanation": "The rate at which one country's currency is converted to the currency of another country is known as the Exchange rate. It is the value of a foreign nation's currency in terms of the home nation's currency. For example, if the exchange rate between the dollar and the euro is 1.2, then a product that costs 1 euro in Europe will cost 1.2 dollars in the U.S.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>18", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Which of the following requires acceptance before it can be valid?", "images": [], "options": {"A": "Promissory note", "B": "Bill of exchange", "C": "Letter of credit", "D": "Cheque"}, "answer": "B", "explanation": "A bill of exchange requires acceptance before it can be valid. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date. The person who is to pay; the drawee, must accept that he will pay the stated amount at the maturity of the bill by signing his acceptance on the bill. Without this acceptance, the bill of exchange is not valid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>19", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "An unfavourable balance of trade for a country means that her?", "images": [], "options": {"A": "Exports exceeds import", "B": "Visible import exceeds visible export", "C": "Invisible exports exceeds visible imports", "D": "Imports and exports are equal"}, "answer": "B", "explanation": "An unfavourable balance of trade for a country means that the value of its imports (visible imports) exceeds the value of its exports (visible exports). This is because the country is spending more on buying goods from other countries than it is earning from selling its own goods to other countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>20", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "In international trade, the direct exchange of goods for goods is?", "images": [], "options": {"A": "Bilateral trade", "B": "Counter trade", "C": "Multilateral trade", "D": "Entrepot trade"}, "answer": "B", "explanation": "In international trade, the direct exchange of goods for goods is known as counter trade. This is a form of barter trade where goods are exchanged directly for other goods without the use of money as a medium of exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>21", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A chain store is also known as a?", "images": [], "options": {"A": "Departmental store", "B": "Multiple shop", "C": "Supermarket", "D": "Hypermarket"}, "answer": "B", "explanation": "A chain store is also known as a multiple shop. This is because a chain store is a part of a group of the same stores owned and operated by a single organization. Each store sells the same type of goods and under the same brand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>22", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Department stores usually?", "images": [], "options": {"A": "Offer a wide variety of goods", "B": "Specialise in selling only household goods", "C": "Offer a few line of goods", "D": "Sell on cash on delivery basis"}, "answer": "A", "explanation": "Department stores usually offer a wide variety of goods. This is because a department store is a large retail establishment that specializes in selling a wide range of products. These products are often divided into departments, each of which specializes in a specific type of goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>23", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "An agreement by which a buyer pays instalmentally but does not own the goods until final settlement is made is", "images": [], "options": {"A": "Hire purchase", "B": "Deferred payment", "C": "Conditional sale", "D": "Features trading"}, "answer": "A", "explanation": "A hire purchase is a method of buying goods through making installment payments over time. The term 'hire purchase' is commonly used in the United Kingdom and it's more commonly known as an installment plan in the United States. However, the buyer does not own the goods until the final payment of the installment is made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>24", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is sent by a customer who wishes to know the price,quality and terms of sale of a product", "images": [], "options": {"A": "Quotation", "B": "Letter of Enquiry", "C": "Proforma invoice", "D": "Advice note"}, "answer": "B", "explanation": "A Letter of Enquiry is a formal method of requesting information about a product or service. It is typically sent by a potential customer who wishes to know the price, quality, and terms of sale of a product. The other options do not fit the description given in the question. A quotation is a document that a seller provides to a buyer to offer goods or services at a stated price, under specified conditions. A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. An advice note is a document that provides details about the delivery of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>25", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The trade document signed by a representative of the country to which goods are being sent is known as?", "images": [], "options": {"A": "Consular invoice", "B": "Certificate of origin", "C": "Consignment note", "D": "Proforma invoice"}, "answer": "A", "explanation": "A Consular Invoice is a document that is required by some foreign countries. It is prepared by the consignor and certified by the consular official of the foreign country stationed in the country from where the goods are being sent. It describes the shipment of goods and shows information such as the consignor, consignee, and value of the shipment. This document is used by the country's customs officials to verify the value, quantity, and nature of the shipment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>26", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The drawer of a bill of exchange which is not discounted is also the", "images": [], "options": {"A": "Drawee", "B": "Acceptor", "C": "Endorser", "D": "Payee"}, "answer": "D", "explanation": "The drawer of a bill of exchange which is not discounted is also the payee. In a bill of exchange, the drawer is the person who creates or 'draws' the bill. If the bill is not discounted, it means that the drawer has not sold the bill to a bank or other financial institution for less than its face value. Therefore, the drawer will be the one to receive the payment when the bill is due, making them the payee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>27", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "What is the lifespan of a cheque which is drawn but not presented immediately for payment?", "images": [], "options": {"A": "30 days", "B": "2 months", "C": "6 months", "D": "12 months"}, "answer": "C", "explanation": "A cheque is considered stale and not valid for payment if it is not presented for payment within six months from the date of issue. This is a banking regulation to ensure that cheques are promptly presented for payment and to prevent fraud or misuse.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>28", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "When shares are fully paid they can be converted into?", "images": [], "options": {"A": "Bonds", "B": "Debentures", "C": "Stocks", "D": "Treasury bills"}, "answer": "C", "explanation": "When shares are fully paid, they can be converted into stocks. Stocks represent ownership in a company and constitute a claim on part of the company's assets and earnings. There are two main types of stock: common and preferred. Stocks are more versatile than shares because they can be divided into any amount. This means that a person can sell or transfer part of their stock to someone else, something that is not possible with shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>29", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The minimum charge at which the Central bank lends to commercial banks is called", "images": [], "options": {"A": "Discount rate", "B": "Bank rate", "C": "Market rate", "D": "Interest rate"}, "answer": "B", "explanation": "The Bank Rate is the minimum rate at which the Central Bank of a country lends money to the commercial banks. It is a tool used by Central Banks to control liquidity in the financial system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>30", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "The transfer of risks already undertaken from one insurance company to another is?", "images": [], "options": {"A": "Over-insurance", "B": "Re-insurance", "C": "Under insurance", "D": "Group insurance"}, "answer": "B", "explanation": "Re-insurance is the practice where an insurance company transfers a part of its risk to another insurance company to protect itself from large claims. It allows the insurer to remain solvent after major claims events.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>31", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Hull insurance is taken to cover", "images": [], "options": {"A": "Injury to the crew of the ship", "B": "Non-payment of freight", "C": "Damage to the cargo", "D": "Damage to the body of the ship"}, "answer": "D", "explanation": "Hull insurance is a type of marine insurance which in the shipping industry, is taken to cover any damage to the ship itself, i.e., the hull of the ship. It does not cover injury to the crew, non-payment of freight, or damage to the cargo. Therefore, the correct answer is 'Damage to the body of the ship'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>32", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The principle of subrogation imposes an obligation on the insured to?", "images": [], "options": {"A": "Disclose all material information", "B": "Have financial risks in the object insured", "C": "Collect compensation from only one insurer", "D": "Surrender legal rights after compensation"}, "answer": "D", "explanation": "The principle of subrogation is a legal principle in insurance claims where the insurance company, after paying out a claim, acquires the rights and remedies of the insured against a third party that caused the loss. This means that after the insured has been compensated for the loss, they must surrender their legal rights to the insurer to pursue recovery from the responsible party. Therefore, the correct answer is 'Surrender legal rights after compensation'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>33", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following is not a function of  money? it", "images": [], "options": {"A": "Is a medium of exchange", "B": "Serves as a store of value", "C": "Is easily recognizable", "D": "Makes deferred payments possible"}, "answer": "C", "explanation": "The function of money includes being a medium of exchange, serving as a store of value, and making deferred payments possible. However, being easily recognizable is not a function of money but rather a characteristic or quality that money should possess. Money needs to be easily recognizable to ensure that it is accepted by everyone in an economy for the exchange of goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>34", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Who among the following does not function in the stock exchange market?", "images": [], "options": {"A": "Bull", "B": "Broker", "C": "Jobber", "D": "Promoter"}, "answer": "D", "explanation": "In the stock exchange market, a bull is a market player who buys securities in anticipation that the price will rise. A broker is an individual or firm that charges a fee or commission for executing buy and sell orders submitted by an investor. A jobber is a trader who buys securities from brokers and sells them to investors. However, a promoter is not a functionary in the stock exchange market. A promoter is a person or company that helps a company to go public and raise capital, but they do not function in the stock exchange market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>35", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "The term legal tender  refers to?", "images": [], "options": {"A": "Coins and cheques", "B": "Coins and bank notes", "C": "Cheques and bank notes", "D": "Postal and money orders"}, "answer": "B", "explanation": "Legal tender refers to the medium of payment recognized by a legal system to be valid for meeting a financial obligation. This typically includes coins and bank notes. Cheques, postal and money orders are not considered legal tender because they are not issued by the government and their acceptance as a form of payment is a matter of agreement between the parties involved, not a legal requirement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>36", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following does not influence the choice of a means of transport?", "images": [], "options": {"A": "Distance", "B": "Value of goods", "C": "Urgency", "D": "Brand of vehicle"}, "answer": "D", "explanation": "The choice of a means of transport is influenced by factors such as the distance to be covered, the value of the goods to be transported, and the urgency of the delivery. The brand of the vehicle is not a primary factor influencing the choice of transport. It's more about the functionality and suitability of the vehicle for the specific transportation needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>37", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : REGISTRATION OF BUSINESS", "question": "A certificate of incorporation is best sent by", "images": [], "options": {"A": "Ordinary post", "B": "Recorded delivery", "C": "Express mail", "D": "Parcel post"}, "answer": "B", "explanation": "A certificate of incorporation is a legal document relating to the formation of a company or corporation. It is a license to form a corporation issued by the state government or, in some jurisdictions, by non-governmental entity/corporation. Its precise meaning depends upon the legal system in which it is used. Given its importance, it is best sent by recorded delivery. Recorded delivery is a mail service whereby the sender receives a receipt showing that the letter or package has been delivered. It provides proof of delivery, which is important for legal documents.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>38", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES", "question": "Which of the following is a disadvantage of the use of teleprinters in communication?", "images": [], "options": {"A": "Transmission speed is slow", "B": "Pictures cannot be transmitted", "C": "Transmission quality is poor", "D": "It cannot transmit during bad weather"}, "answer": "A", "explanation": "Teleprinters are an outdated form of technology that were used for the transmission of typed messages. One of the main disadvantages of teleprinters was their slow transmission speed. Modern technologies such as email and instant messaging have largely replaced teleprinters due to their faster transmission speeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>39", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "A label on a product such as \"Three Crown Milk\" is a form of", "images": [], "options": {"A": "Patent right", "B": "Branding", "C": "Copy right", "D": "Packaging"}, "answer": "B", "explanation": "A label on a product such as \"Three Crown Milk\" is a form of branding. Branding is a marketing practice in which a company creates a name, symbol or design that is easily identifiable as belonging to the company. This helps to identify a product and distinguish it from other products and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>40", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "ECOWAS is a form of?", "images": [], "options": {"A": "Economic union", "B": "Political union", "C": "Trade union", "D": "Free trade association"}, "answer": "A", "explanation": "ECOWAS (Economic Community of West African States) is a form of economic union. An economic union is a type of trade bloc which is composed of a common market with a customs union. The participant countries have both common policies on product regulation, freedom of movement of goods, services and the factors of production (capital and labour) and a common external trade policy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>41", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is a customer service?", "images": [], "options": {"A": "Delivery", "B": "Merchandizing", "C": "Branding", "D": "Market research"}, "answer": "A", "explanation": "Customer service refers to the assistance and advice provided by a company to those people who buy or use its products or services. Delivery is a part of customer service as it involves the action of delivering letters, parcels, or goods. It is the process of transporting goods from a source location to a predefined destination. Merchandising, branding, and market research are not directly related to customer service, they are more related to marketing and product management.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2002>42", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following type of cheque protects the holder against the risk of loss?", "images": [], "options": {"A": "Open cheque", "B": "Bearer cheque", "C": "Post dated cheque", "D": "Crossed cheque"}, "answer": "D", "explanation": "A crossed cheque is a cheque that has been marked specifying an instruction on the way it is to be redeemed. A pair of parallel lines, often appearing in the top left corner of the cheque, indicates it. The purpose of crossing a cheque is to ensure that the money is paid into an account of the intended beneficiary of the cheque. The crossing of cheques increases its security in that it cannot be cashed at a bank counter but must be paid into an account in exactly the same name as that which appears on the 'payee' line of the cheque (i.e., the person who should receive the payment). Therefore, a crossed cheque protects the holder against the risk of loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>43", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The grading of products to satisfy different buyers is referred to as?", "images": [], "options": {"A": "Product mix", "B": "Product differentiation", "C": "Product concept", "D": "Product line"}, "answer": "B", "explanation": "Product differentiation refers to a process where a business tries to distinguish its product from similar products in the market. This can be achieved through unique branding, advertising, or even through the product design itself. In this case, grading of products to satisfy different buyers is a form of product differentiation, as it involves creating different versions of a product to appeal to different customer segments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>44", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "If Baba is forced to agree to the terms of a contract at gun point, the contract is entered into", "images": [], "options": {"A": "Under duress", "B": "Through frustration", "C": "Through misinterpretation", "D": "By mistake"}, "answer": "A", "explanation": "A contract entered under duress is one where one party is forced to agree to the terms under threat or actual violence. In this case, if Baba is forced to agree to the terms of a contract at gun point, it means he is under duress. Therefore, the contract is entered into under duress.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>45", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "A major reason why government regulates business activities is to?", "images": [], "options": {"A": "Prevent producers from selling at profit", "B": "Provide employment to school leavers", "C": "Ensure fair practices and consumer protection", "D": "Force producers to export more goods"}, "answer": "C", "explanation": "Government regulates business activities primarily to ensure fair practices and consumer protection. This is done to prevent monopolies, protect consumers from unfair business practices, ensure fair competition and verify that businesses are abiding by the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>46", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Which of the following is not a method of discharging contract?", "images": [], "options": {"A": "Performance", "B": "Breach", "C": "Consideration", "D": "Frustration"}, "answer": "C", "explanation": "A contract can be discharged (ended) in several ways, including performance (when the terms of the contract are fulfilled), breach (when one party fails to fulfill the terms), and frustration (when unforeseen circumstances make it impossible to fulfill the terms). Consideration, however, is not a method of discharging a contract. Instead, it is a necessary element for the formation of a contract, referring to what is being exchanged in the contract (e.g., goods, services, money, etc.).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>47", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "In a contract offer is described as a counter offer if", "images": [], "options": {"A": "A new clause is introduced", "B": "It is not understood", "C": "It is not addressed to a particular person", "D": "It leaves no room for renegotiation"}, "answer": "A", "explanation": "In contract law, a counter-offer is an offer made in response to a previous offer by the other party during negotiations for a final contract. It is a new offer that changes the terms of the original offer in some way. This means that the original offer has been rejected and replaced with a new one. Therefore, a counter offer is described as such if a new clause is introduced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>48", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "The duty of an agent of necessity to a principal is based on?", "images": [], "options": {"A": "Trust", "B": "Ability", "C": "Negotiation", "D": "Mutual agreement"}, "answer": "A", "explanation": "The duty of an agent of necessity is based on trust. An agent of necessity acts on behalf of the principal in situations where immediate action is required to protect the principal's interests, and the principal trusts the agent to act in their best interest under those urgent circumstances. This trust is fundamental because the agent's actions are taken without prior approval or explicit instructions from the principal, relying on the trust that they will make decisions in the principal's best interest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2002>49", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The process by which the government takes over the ownership and control of an existing private business is?", "images": [], "options": {"A": "Industrialization", "B": "Privatization", "C": "Nationalization", "D": "Commercialization"}, "answer": "C", "explanation": "Nationalization is the process by which a government takes control of a company or industry, which can occur for a variety of reasons. When a government nationalizes a company, it provides compensation to shareholders, though not always at market prices. It uses nationalization to save good jobs or industries vital to the country's economy. Essentially, control and ownership are taken over by the state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2002>50", "subject": "Commerce", "year": "2002", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A voluntary body formed by people in the same line of business is known as?", "images": [], "options": {"A": "Trade union", "B": "Trade association", "C": "Cartel", "D": "Employers' association"}, "answer": "B", "explanation": "A Trade Association, also known as an industry trade group, business association, sector association or industry body, is an organization founded and funded by businesses that operate in a specific industry. An industry trade association participates in public relations activities such as advertising, education, political donations, lobbying and publishing, but its focus is collaboration between companies. Associations may offer other services, such as producing conferences, networking or charitable events or offering classes or educational materials.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2003>1", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The scope of commerce is limited to", "images": [], "options": {"A": "home and foreign trade", "B": "wholesale and retail trade", "C": "trade and aids-to-trade", "D": "wholesale and entrepot trade"}, "answer": "C", "explanation": "The scope of commerce is not limited to just home and foreign trade, or wholesale and retail trade, or wholesale and entrepot trade. It encompasses both trade and aids-to-trade. Trade involves the exchange of goods and services from the producer to the final consumer. Aids-to-trade, on the other hand, includes all the activities that facilitate trade such as transportation, banking, insurance, advertising, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>2", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "A worker who processes garri is engaged in", "images": [], "options": {"A": "extracting", "B": "manufacturing", "C": "exchange", "D": "constructing"}, "answer": "B", "explanation": "A worker who processes garri is engaged in manufacturing. Manufacturing is a process that involves converting raw materials into finished goods. In this case, the worker is converting cassava tubers (raw material) into garri (finished product). Extracting refers to the process of removal or taking out, while exchange refers to the process of giving one thing and receiving another in return, and constructing refers to building or making something, typically a structure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>3", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following is not a commercial occupation?", "images": [], "options": {"A": "Transportation", "B": "Warehousing", "C": "Banking", "D": "Fishing"}, "answer": "D", "explanation": "Commercial occupations are those that involve the buying and selling of goods and services, or activities that facilitate the buying and selling of goods and services. These include transportation, warehousing, and banking. Fishing, on the other hand, is a primary occupation that involves the extraction or production of raw materials. It is not a commercial occupation because it does not involve the buying and selling of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>4", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Industry is a branch of production because it", "images": [], "options": {"A": "is a division of commerce", "B": "increases utility of goods", "C": "involves the use of machines", "D": "deals with durable goods"}, "answer": "B", "explanation": "Industry is a branch of production because it increases the utility of goods. This is done through the transformation of raw materials into finished goods, which are then used to satisfy human wants. The process of transforming raw materials into finished goods increases their utility, making them more useful and valuable. This is why industry is considered a branch of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>5", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "When a public company receives the certificate of incorporation, this implies that", "images": [], "options": {"A": "it can go ahead and start business", "B": "it can no longer sue or be sued", "C": "the company's finds it difficult to raise capital", "D": "the company's assets exist separately from those of its members"}, "answer": "A", "explanation": "When a public company receives the certificate of incorporation, it means that it is legally recognized and can start its business operations. The certificate of incorporation is a legal document relating to the formation of a company or corporation. It is a license to form a corporation issued by the state government or, in some jurisdictions, by non-governmental entity/corporation. Its precise meaning depends upon the legal system in which it is used.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>6", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "The main feature of a holding company is", "images": [], "options": {"A": "that resources are used for the interest of the community", "B": "accepting responsibilities beyond the aims of private enterprises", "C": "that it has financial control over other companies", "D": "that it has profit-sharing schemes for employees"}, "answer": "C", "explanation": "A holding company is a type of firm that owns other investments, including whole companies, instead of engaging in operating activity itself. The main feature of a holding company is that it has financial control over other companies. It does this by owning a significant portion of these companies' stock. This allows the holding company to exert control over the management and operations of the underlying companies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>7", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "When a number of thrift societies come together and are registered, they become a", "images": [], "options": {"A": "holding company", "B": "credit union", "C": "trade union", "D": "consumer association"}, "answer": "B", "explanation": "When a number of thrift societies come together and are registered, they become a credit union. A credit union is a type of financial cooperative where members can borrow from pooled deposits at low interest rates. It's essentially a mutual financial institution that is owned and controlled by its members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>8", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following would not be stated in Memorandum of Association?", "images": [], "options": {"A": "Name clause", "B": "Registered office", "C": "Object clause", "D": "Rights of shareholders"}, "answer": "D", "explanation": "The Memorandum of Association is a document that sets out the constitution of a company and is therefore fundamental to its incorporation and operation. It includes the company's name, the location of the registered office, the object clause which outlines the scope of activities the company can engage in, and the liability of its members. However, it does not include the rights of shareholders. The rights of shareholders are typically outlined in the company's Articles of Association.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>9", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The greatest risk in a business venture is borne by the", "images": [], "options": {"A": "trade creditors", "B": "employees", "C": "trade debtors", "D": "entrepreneurs"}, "answer": "D", "explanation": "The greatest risk in a business venture is borne by the entrepreneurs. This is because entrepreneurs are the ones who invest their money and other resources into the business. If the business fails, they stand to lose all their investment. Trade creditors, employees, and trade debtors do not bear as much risk as the entrepreneurs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>10", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partner with an unlimited liability is known as a", "images": [], "options": {"A": "dormant partner", "B": "nominal partner", "C": "general partner", "D": "active partner"}, "answer": "C", "explanation": "A partner with an unlimited liability is known as a general partner. In a partnership, a general partner is one who is personally liable for all the debts of the business. This means that if the business cannot pay its debts, the general partner's personal assets can be used to pay off the debts. A dormant partner is one who does not take part in the day-to-day operations of the business, a nominal partner is one who lends his name to the business without having any real interest or participation in it, and an active partner is one who participates in the management and operations of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>11", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES", "question": "A partnership without a deed shares profits/losses", "images": [], "options": {"A": "in the ratio of partners' capital", "B": "equally among the partners", "C": "proportionate to patronage", "D": "proportionate to assets introduced"}, "answer": "B", "explanation": "In the absence of a partnership deed, profits and losses are shared equally among the partners. This is a basic rule in partnership, as stated in the Partnership Act. The other options are incorrect because they suggest that the sharing of profits and losses is based on factors such as capital contribution, patronage, or assets introduced, which is not the case without a partnership deed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>12", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The total amount of money actually received by a company out of the issued capital is", "images": [], "options": {"A": "paid-up capital", "B": "unissued capital", "C": "reserved capital", "D": "called-up capital"}, "answer": "A", "explanation": "The total amount of money actually received by a company out of the issued capital is known as paid-up capital. This is the amount of money that shareholders have contributed towards the capital of the company. The other options are incorrect: unissued capital refers to the part of the authorized capital which has not yet been issued to shareholders; reserved capital is a portion of the capital which the company has decided not to call up unless it is being wound up; called-up capital is the part of the issued capital which the company has asked its shareholders to pay.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>13", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "If the turnover of a business is ₦16,000 and the cost of goods sold is ₦12,000, what is the percentage of gross profit on sales?", "images": [], "options": {"A": "75%", "B": "40%", "C": "33.3%", "D": "25%"}, "answer": "D", "explanation": "The gross profit is calculated by subtracting the cost of goods sold from the turnover. The percentage of gross profit on sales is then calculated by dividing the gross profit by the turnover and multiplying by 100.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>14", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "In which of the following do shareholders always vote according to their shareholdings?", "images": [], "options": {"A": "Partnership", "B": "Cooperative society", "C": "Public limited company", "D": "Public corporation"}, "answer": "C", "explanation": "In a public limited company, shareholders vote according to their shareholdings. The number of votes a shareholder has is directly proportional to the number of shares they hold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>15", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A public company has an authorized capital of 60,000 shares A share costs 150K and the company has issued 36,000 shares. The issued capital would be", "images": [], "options": {"A": "₦90,000", "B": "₦60,000", "C": "₦54,000", "D": "₦36,000"}, "answer": "C", "explanation": "Issued capital = 36,000 share × 150k  =3,600×150100=₦54,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>16", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The rate of turnover of a company in a given year is 4 times while the average stock is ₦12,400. What is the turnover of the company?", "images": [], "options": {"A": "₦49,600", "B": "₦24,800", "C": "₦6,200", "D": "₦3,100"}, "answer": "A", "explanation": "The turnover of a company is calculated by multiplying the rate of turnover by the average stock. In this case, the turnover of the company would be 4 * ₦12,400 = ₦49,600. The correct option is option A.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>17", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following is the best channel for the sale of an aircraft?", "images": [], "options": {"A": "Producer - Wholesaler - Consumer", "B": "Producer - Retailer - Consumer", "C": "Producer - Consumer", "D": "Producer - Wholesaler - Retailer - Consumer"}, "answer": "C", "explanation": "The best channel for the sale of an aircraft is directly from the producer to the consumer. This is because an aircraft is a specialized and expensive product that is not typically sold through intermediaries like wholesalers or retailers. The buyer usually has specific requirements and will want to deal directly with the producer to ensure these are met.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>18", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is an advantage of large scale retailing?", "images": [], "options": {"A": "Decline in personal service", "B": "Pilfering", "C": "High overhead cost", "D": "One-stop shopping"}, "answer": "D", "explanation": "One-stop shopping is an advantage of large scale retailing. This means that customers can find a wide variety of products under one roof, saving them time and effort. This is in contrast to smaller retailers who may only specialize in a limited range of products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>19", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a function of the retailer?", "images": [], "options": {"A": "Buying in bulk and warehousing", "B": "Buying and selling in bits to consumers", "C": "Advising consumers on the right type of goods", "D": "Granting credits to customers"}, "answer": "A", "explanation": "The function of buying in bulk and warehousing is typically associated with wholesalers, not retailers. Retailers usually buy in smaller quantities from wholesalers and sell directly to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>20", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The refund made on goods re-exported after being imported is known as", "images": [], "options": {"A": "import duty", "B": "export duty", "C": "excise drawback", "D": "customs drawback"}, "answer": "D", "explanation": "Customs drawback is a refund on certain kinds of taxes and duties paid on imported goods that are later exported. Import duty and export duty are taxes levied on goods imported into and exported out of a country respectively, while excise drawback is a refund of excise duty paid on goods that are subsequently exported.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>21", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following requires the services of middlemen?", "images": [], "options": {"A": "Technical goods", "B": "Expensive goods", "C": "Convenience goods", "D": "Perishable goods"}, "answer": "C", "explanation": "Convenience goods require the services of middlemen. Middlemen are intermediaries between the producers and consumers. They help in the distribution of goods and services. Convenience goods are those types of goods that are regularly consumed and are readily available. Examples include bread, milk, and toothpaste. These goods require a wide distribution network to reach consumers, hence the need for middlemen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>22", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Entrepot trade means", "images": [], "options": {"A": "exchange of goods between two countries", "B": "exchange among many countries", "C": "exporting goods to be re-imported", "D": "importing goods to be re-exported"}, "answer": "D", "explanation": "Entrepot trade means importing goods to be re-exported. It is a form of international trade where goods are imported into a country not for domestic consumption but for re-export to other countries. The country involved in entrepot trade acts as a sort of 'warehouse' or 'transit point' for goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>23", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "To sell a bill at less than the face value before its maturity is", "images": [], "options": {"A": "discounting", "B": "retiring", "C": "accepting", "D": "noting"}, "answer": "A", "explanation": "Discounting a bill refers to the act of selling a bill for less than its face value before its maturity. This is usually done to raise immediate cash. The difference between the face value of the bill and its selling price is the 'discount'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>24", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following tells the customer exactly what has been sold to him, the amount due and any discount granted?", "images": [], "options": {"A": "Advice note", "B": "Statement", "C": "Invoice", "D": "Credit note"}, "answer": "C", "explanation": "An invoice is a commercial document issued by a seller to a buyer, relating to a sale transaction and indicating the products, quantities, and agreed prices for products or services the seller has provided the buyer. It indicates what has been sold, the amount due and any discount granted.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2003>25", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following documents is required when a bill of lading is not readily available to enable the goods to be landed?", "images": [], "options": {"A": "Bill of exchange", "B": "Certificate of origin", "C": "Consumer invoice", "D": "Bill of sight"}, "answer": "D", "explanation": "A Bill of Sight is a legal document that is used when the information about the goods to be landed is not known. It allows goods to be landed temporarily until the correct documents are presented. Therefore, when a bill of lading is not readily available, a Bill of Sight is required to enable the goods to be landed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>26", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Total assets minus current liabilities is equal to a company's", "images": [], "options": {"A": "gross profit", "B": "net profit", "C": "capital owned", "D": "capital employed"}, "answer": "D", "explanation": "Total assets minus current liabilities is equal to a company's capital employed. Capital employed, also known as funds employed, is the total amount of capital used for the acquisition of profits. It is the value of all the assets employed in a business and can be calculated from the balance sheet by taking the shareholders' equity (equity capital and reserves) plus non-current liabilities (long-term liabilities), or, equivalently, by subtracting current liabilities from total assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>27", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A public limited liability company can enter into contracts because it", "images": [], "options": {"A": "has many employes", "B": "has shareholders", "C": "is a legal entity", "D": "is allowed to take out debentures"}, "answer": "C", "explanation": "A public limited liability company can enter into contracts because it is a legal entity. A legal entity is an individual, company, or organization that has legal rights and is subject to obligations. This means that it can enter into contracts, sue and be sued, own property, and so on. The number of employees or shareholders, or the ability to take out debentures, does not directly grant the ability to enter into contracts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>28", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Taxes imposed on locally made goods are known as", "images": [], "options": {"A": "ad valorem duties", "B": "import duties", "C": "export drawback", "D": "excise duties"}, "answer": "D", "explanation": "Taxes imposed on locally made goods are known as excise duties. Excise duties are taxes imposed on goods produced within the country, as opposed to import duties which are taxes imposed on goods coming into the country. Ad valorem duties are taxes based on the value of the goods, and export drawback is a refund of duties on exported goods, so these options are not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>29", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following contains the complete information on goods available for sale?", "images": [], "options": {"A": "Invoice", "B": "Delivery note", "C": "Consignment note", "D": "Catalogue"}, "answer": "D", "explanation": "A catalogue contains the complete information on goods available for sale. It is a comprehensive list of products, including descriptions and prices, that a company has available for sale. An invoice, delivery note, and consignment note do not provide complete information on all goods available for sale, but rather specific information about a particular sale or shipment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2003>30", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is used to inform the buyer that goods ordered are on the way?", "images": [], "options": {"A": "Quotation", "B": "Proforma invoice", "C": "Advice note", "D": "Despatch book"}, "answer": "C", "explanation": "An advice note is used to inform the buyer that goods ordered are on the way. It is a document sent by the seller to the buyer, informing them that the goods they ordered have been dispatched. A quotation provides a price estimate, a proforma invoice is a preliminary bill of sale, and a despatch book records details of shipments, but none of these documents are specifically used to inform the buyer that goods are on the way.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2003>31", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Quantity discount is offered to persuade the buyer to", "images": [], "options": {"A": "pay promptly", "B": "defer payment", "C": "pay a disposit", "D": "buy more"}, "answer": "D", "explanation": "Quantity discount is a financial incentive for a buyer to purchase in bulk or large quantities. It is a type of discount that sellers use to incentivize buyers to purchase more of a given product. Therefore, the correct answer is 'buy more'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>32", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The process of dealing with a cheque once it has been paid into the creditor's bank is", "images": [], "options": {"A": "clearing", "B": "accepting", "C": "negotiating", "D": "discounting"}, "answer": "A", "explanation": "The process of dealing with a cheque once it has been paid into the creditor's bank is known as clearing. Clearing in banking terms refers to the process of transferring the funds from the payer's bank to the payee's bank. Once the cheque is cleared, the funds are transferred from the payer's account to the payee's account. Therefore, the correct answer is 'clearing'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>33", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "Selling of new shares to current shareholders at prices below the market value of the existing shares is", "images": [], "options": {"A": "bonus issue", "B": "rights issue", "C": "private placing", "D": "offer for sale"}, "answer": "B", "explanation": "Rights issue is a way by which a company can sell new shares in order to raise capital. Shares are offered to existing shareholders in proportion to their current shareholding, at a special price and for a specific time. The price at which the shares are offered is usually less than the current market price of the shares, making the offer attractive for shareholders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>34", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following types of insurance is taken against claims made by staff who get injured while at work?", "images": [], "options": {"A": "Fidelity guarantee insurance", "B": "Consequential loss insurance", "C": "Products liability insurance", "D": "Employers' liability insurance"}, "answer": "D", "explanation": "Employers' liability insurance is a policy that protects employers from financial loss if a worker has a job-related injury or illness not covered by workers' compensation. Employers' liability insurance can be packaged with workers' compensation insurance to further protect companies against the costs associated with workplace injuries, illnesses, and deaths not covered under workers' compensation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>35", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "If the insured has been fully indemnified, the insurers are entitled to take any advantage due to the insured. The principle of insurance involved is", "images": [], "options": {"A": "indemnity", "B": "subrogation", "C": "contribution", "D": "insurable interest"}, "answer": "B", "explanation": "The principle of insurance involved is subrogation. Subrogation is a term describing a legal right held by most insurance carriers to legally pursue a third party that caused an insurance loss to the insured. This is done as a means of recovering the amount of the claim paid to the insured for the loss.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>36", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Who among the following sells securities in anticipation of a fall in price?", "images": [], "options": {"A": "Bear", "B": "Stag", "C": "Jobber", "D": "Bull"}, "answer": "A", "explanation": "A 'Bear' is a person who sells securities in anticipation of a fall in price. This is because they believe that the price of the securities will decline in the future, and they can profit by selling now and buying later at a lower price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>37", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following provides a proof of posting and that the item has got to the addressee", "images": [], "options": {"A": "Certificate of posting", "B": "Recorded delivery", "C": "Registered letter", "D": "Express letter"}, "answer": "B", "explanation": "A recorded delivery provides a proof of posting and that the item has got to the addressee. This is because when you send something by recorded delivery, the recipient has to sign to confirm they've received it. This means you have proof it's been delivered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>38", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A transporter who does not reject carrying lawful goods to a destination is", "images": [], "options": {"A": "tramp vessel liner", "B": "ocean liner", "C": "common carrier", "D": "private carrier"}, "answer": "C", "explanation": "A common carrier is a transporter who does not reject carrying lawful goods to a destination. This is because a common carrier is a type of transportation service that transports goods or people for any person or company and that is responsible for any possible loss of the goods during transport. A common carrier offers its services to the general public under license or authority provided by a regulatory body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>39", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "One disadvantage of rail transport is", "images": [], "options": {"A": "suitability for fragile goods", "B": "obsence of pilferage", "C": "vulnerability to severe weather", "D": "inflexibility"}, "answer": "D", "explanation": "Rail transport is often considered inflexible because it operates on fixed tracks and schedules. This limits its ability to adapt to changing routes or delivery schedules compared to other modes of transport, such as road transport, which can offer more flexibility in terms of routes and delivery times. While rail transport is generally reliable and secure, its lack of adaptability to changes can be a significant disadvantage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>40", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following does not belong to the group?", "images": [], "options": {"A": "Posters", "B": "Window display", "C": "Free samples", "D": "Hoarding of goods"}, "answer": "D", "explanation": "The question is about items that are used for advertising or promotion. Posters, window displays, and free samples are all common methods of advertising or promoting products. However, 'hoarding of goods' is not a method of advertising or promotion. It refers to the practice of accumulating and hiding or storing a large quantity of something, often for future use. Therefore, it does not belong to the group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>41", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "A retailer sells his products at \"Buy-two-take-three\". The sales promotion method referred to is", "images": [], "options": {"A": "free samples", "B": "gift", "C": "premium", "D": "trade discount"}, "answer": "C", "explanation": "The sales promotion method referred to in the question is 'premium'. In marketing, a premium is a sales promotion where customers are given more of the product they are purchasing as an incentive. In this case, the retailer is offering an extra product (the third item) when two are purchased, hence the term 'Buy-two-take-three'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>42", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "When all producers in an industry combine to advertise their product instead of each firm advertising its own brand this is referred to as", "images": [], "options": {"A": "mass advertising", "B": "competitive advertising", "C": "persuasive advertising", "D": "direct advertising"}, "answer": "A", "explanation": "The advertising method referred to in the question is 'mass advertising'. Mass advertising, also known as cooperative advertising, is a form of advertising where multiple producers or sellers combine their resources to advertise a product collectively, rather than each firm advertising its own brand. This is often done to reach a larger audience and share advertising costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>43", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "It is often said that \"the consumer is always right\".  This describes the doctrine of", "images": [], "options": {"A": "consumer movement", "B": "consumer sovereignty", "C": "caveat emptor", "D": "consensus ad idem"}, "answer": "B", "explanation": "The phrase 'the consumer is always right' describes the doctrine of 'consumer sovereignty'. This concept implies that the preferences and needs of consumers dictate the production of goods and services. Businesses must cater to these needs and preferences to be successful. The other options do not accurately represent this concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>44", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Activities undertaken to create awareness for a product by giving out samples, premium or conducting contests are known as", "images": [], "options": {"A": "marketing mix", "B": "marketing concept", "C": "consumerism", "D": "sale promotion"}, "answer": "D", "explanation": "Activities undertaken to create awareness for a product by giving out samples, premium or conducting contests are known as 'sales promotion'. This is a marketing strategy used to stimulate consumer purchasing and dealer effectiveness. The other options do not accurately represent this concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>45", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Market skimming is an example of", "images": [], "options": {"A": "pricing policy", "B": "sales promotion", "C": "advertising", "D": "consumerism"}, "answer": "A", "explanation": "Market skimming is a pricing strategy where a marketer sets a relatively high price for a product or service at first, then lowers the price over time. It is a product pricing strategy by which a firm charges the highest initial price that customers will pay. As the demand of the first customers is satisfied, the firm lowers the price to attract another, more price-sensitive segment. Therefore, it is an example of a pricing policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2003>46", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "A void contract is one that", "images": [], "options": {"A": "is enforceable", "B": "has no maturity", "C": "has no legal effect", "D": "is discharged"}, "answer": "C", "explanation": "A void contract is a formal agreement that is illegitimate and unenforceable from the moment it is created. It has no legal effect. A contract can become void if it involves illegal matters, if one party is incapable of fulfilling it, or if the terms are impossible to fulfill. Therefore, a void contract is one that has no legal effect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>47", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following is not concerned about consumer protection?", "images": [], "options": {"A": "Foods and Drugs Act", "B": "Trade Descriptions Act", "C": "Price Control Act", "D": "General Agreement on Tariffs and Trade"}, "answer": "D", "explanation": "The General Agreement on Tariffs and Trade (GATT) is primarily concerned with the reduction of trade tariffs and barriers, and not directly with consumer protection. It is an international trade treaty designed to boost economic recovery after World War II by reducing tariffs and other international trade barriers. The other options like Foods and Drugs Act, Trade Descriptions Act, and Price Control Act are all directly related to consumer protection.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>48", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "In a law of contract, what is given in exchange for a promise to perform is", "images": [], "options": {"A": "offer", "B": "acceptance", "C": "consideration", "D": "warranty"}, "answer": "C", "explanation": "In a contract law, the term 'consideration' refers to something of value that is given in exchange for a promise to perform. It is the price paid for the promise of the other party and it could be in the form of money, services, goods, etc. An offer is a proposal to enter into an agreement with another person. An acceptance is a final and unqualified acceptance of the terms of an offer. A warranty is a term of a contract, but it is not what is given in exchange for a promise to perform.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>49", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The taking over by government of enterprises formerly owned by private persons is referred to as", "images": [], "options": {"A": "privatization", "B": "nationalization", "C": "commercialisation", "D": "indigenization"}, "answer": "B", "explanation": "Nationalization refers to the process of taking a private industry or private assets into public ownership by a national government or state. This is usually done when the government believes the companies are being mismanaged and can be run better for the benefit of all stakeholders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2003>50", "subject": "Commerce", "year": "2003", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following has as one of its objectives the removal obstacles to movement of people and goods across the boundaries of member countries?", "images": [], "options": {"A": "OAU", "B": "ECOWAS", "C": "OPEC", "D": "LCBC"}, "answer": "B", "explanation": "The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. One of its main objectives is to promote economic integration across the region which includes the removal of obstacles to the free movement of people, goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>1", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "Which of the following is not a function of commerce?", "images": [], "options": {"A": "advertising goods", "B": "creation of goods", "C": "increasing profit made", "D": "distribution of goods"}, "answer": "B", "explanation": "Commerce is concerned with the buying, selling and distribution of goods and services. It does not involve the creation of goods, which is the function of production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>2", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Any activity that changes raw material into consumer or industrial goods is", "images": [], "options": {"A": "constructive", "B": "assembling", "C": "extractive", "D": "manufacturing"}, "answer": "D", "explanation": "Manufacturing is the process of converting raw materials into finished goods for use by consumers or industries. This involves a series of operations, which may include designing, producing, and assembling the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>3", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION", "question": "The divisions of production are", "images": [], "options": {"A": "industry, banking and services", "B": "industry, manufacturing and services", "C": "industry, commerce and services", "D": "industry, transportation and services"}, "answer": "C", "explanation": "The divisions of production are typically categorized into three sectors: primary, secondary, and tertiary. The primary sector involves the extraction of raw materials (industry), the secondary sector involves manufacturing and construction (commerce), and the tertiary sector involves the provision of services (services). Therefore, the correct answer is 'industry, commerce and services'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>4", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Risks in business are borne by the", "images": [], "options": {"A": "consumer", "B": "entrepreneur", "C": "marketing manager", "D": "personnel manager"}, "answer": "B", "explanation": "In a business, the risks are borne by the entrepreneur. The entrepreneur is the individual who sets up the business, invests the capital, and takes on the risk of profit or loss. Therefore, the correct answer is 'entrepreneur'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>5", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "The main aim of credit and thrift societies is to", "images": [], "options": {"A": "settle disputes among members", "B": "educate their members", "C": "secure loans for members", "D": "encourage savings among members"}, "answer": "D", "explanation": "Credit and Thrift Societies are financial cooperatives whose main aim is to encourage savings among their members. They do this by providing a secure place for members to save and by offering loans to members from the pooled savings at reasonable rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>6", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETY : MEANING AND TYPES", "question": "In which of the following business units are profits shared on the basis of membership patronage?", "images": [], "options": {"A": "public enterprise", "B": "partnership", "C": "co-operative society", "D": "public limited liability company"}, "answer": "C", "explanation": "In a co-operative society, profits are shared on the basis of membership patronage. This means that the more a member uses the co-operative's services or products, the more profits they receive. This is different from other business units where profits are usually shared based on the amount of capital contributed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>7", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A business becomes a separate legal entity after it has", "images": [], "options": {"A": "started operation", "B": "been incorporated", "C": "been insured", "D": "been accepted by the public"}, "answer": "B", "explanation": "A business becomes a separate legal entity after it has been incorporated. Incorporation is the legal process used to form a corporate entity or company. A corporation is a separate legal entity from its owners, with its own rights and obligations. Therefore, the correct answer is 'been incorporated'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>8", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "The amalgamation of firms engaged in cotton processing and the manufacturing of textiles is", "images": [], "options": {"A": "horizontal integration", "B": "vertical integration", "C": "lateral integration", "D": "joint venture"}, "answer": "B", "explanation": "The amalgamation of firms engaged in cotton processing and the manufacturing of textiles is an example of vertical integration. Vertical integration is a strategy where a company expands its business operations into different steps on the same production path, such as when a manufacturer owns its supplier and/or distributor. In this case, cotton processing and textile manufacturing are different steps in the same production path. Therefore, the correct answer is 'vertical integration'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>9", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "A private company's ability to raise capital is limited because", "images": [], "options": {"A": "its borrowing powers are limited", "B": "membership does not exceed 50", "C": "shares cannot be made public", "D": "of limited collateral security"}, "answer": "C", "explanation": "A private company's ability to raise capital is limited because its shares cannot be made public. This means that a private company cannot sell its shares to the general public on the stock market to raise capital, unlike a public company. This limits the amount of capital a private company can raise.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>10", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "An increase in the volume of sales is also an increase in", "images": [], "options": {"A": "profit", "B": "turnover", "C": "fixed assets", "D": "owner's equity"}, "answer": "B", "explanation": "An increase in the volume of sales is also an increase in turnover. Turnover refers to the total sales made by a business in a certain period. It does not necessarily mean an increase in profit as this would depend on the cost of goods sold and other expenses. It also does not mean an increase in fixed assets or owner's equity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>11", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The working capital of a firm is calculated as", "images": [], "options": {"A": "current assets minus current liabilities", "B": "current liabilities minus fixed assets", "C": "value of all assets", "D": "value of issued capital"}, "answer": "A", "explanation": "Working capital is a financial metric which represents operating liquidity available to a business. It is calculated as current assets minus current liabilities. Current assets are the assets that a company owns and can be easily converted to cash within one year. Current liabilities are the company's debts or obligations that are due within one year. Therefore, working capital is a measure of a company's short-term liquidity - the ability to cover its short-term obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>12", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Dividend is always expressed as a percentage of total", "images": [], "options": {"A": "earnings of the business", "B": "value of shares owned", "C": "working capital", "D": "volume of business"}, "answer": "B", "explanation": "Dividend is a distribution of a portion of a company's earnings, decided by the board of directors, to a class of its shareholders. Dividends can be issued as cash payments, as shares of stock, or other property. It's usually expressed as a percentage of the value of shares owned. This is known as the dividend yield. It's calculated by dividing the annual dividend payment by the price paid for the stock. It measures how much cash flow you are getting for each dollar invested in an equity position.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>13", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is a duty of the Employers Association?", "images": [], "options": {"A": "procuring raw materials at regular intervals", "B": "establishing a uniform wage scale", "C": "negotiating with the government on sites for firms", "D": "discharging workers when production is low"}, "answer": "B", "explanation": "The Employers Association is a group of employers who come together to promote their common interests, particularly in negotiating with trade unions to establish a uniform wage scale. They do not procure raw materials, negotiate with the government on sites for firms, or discharge workers when production is low. These tasks are typically handled by individual companies or firms, not an association of employers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>14", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE ASSOCIATION : OBJECTIVES , MERIT & DEMERIT", "question": "A very effective way of resisting the producer's exploitation is to", "images": [], "options": {"A": "ban the producer", "B": "campaign against the company", "C": "form consumer's association", "D": "form a trade union"}, "answer": "C", "explanation": "Forming a consumer's association is a very effective way of resisting the producer's exploitation. Consumer associations are organizations that protect the rights of consumers and ensure fair trade practices. They can take collective action against exploitative practices by producers. Banning the producer or campaigning against the company may not be effective or practical, and forming a trade union is more relevant for workers, not consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>15", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following makes sales possible without a sales attendant?", "images": [], "options": {"A": "telex machine", "B": "fax machine", "C": "vending machine", "D": "franking machine"}, "answer": "C", "explanation": "A vending machine is a machine that dispenses items such as snacks, beverages, alcohol, cigarettes, lottery tickets to customers automatically, after the customer inserts currency or credit into the machine. This makes sales possible without a sales attendant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>16", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following distinguishes supermarkets from other retail outlets?", "images": [], "options": {"A": "use of self-service", "B": "standard shop fronts", "C": "sale of food items and household goods", "D": "provision of parking spaces and delivery services"}, "answer": "A", "explanation": "Supermarkets are distinguished from other retail outlets by their use of self-service. Customers in supermarkets pick the items they want from the shelves and pay for them at the checkout counter. This is different from other retail outlets where the sales attendant assists the customer in selecting and purchasing items.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>17", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Manufacturers sell directly to consumers when they", "images": [], "options": {"A": "want to make profit", "B": "wish to eliminate all transport costs", "C": "live far away from them", "D": "deal in perishable goods"}, "answer": "A", "explanation": "Manufacturers sell directly to consumers when they want to make a profit. This is because by eliminating the middlemen, they can sell their products at a higher price and thus make more profit. The other options are not necessarily true. For example, manufacturers may still have to incur transport costs even if they sell directly to consumers, and not all manufacturers who sell directly to consumers deal in perishable goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>18", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is regarded as a document of title in foreign trade?", "images": [], "options": {"A": "consular invoice", "B": "bill of lading", "C": "bill of sight", "D": "certificate of origin"}, "answer": "B", "explanation": "A bill of lading is considered a document of title in foreign trade. It is a legal document issued by a carrier to a shipper that details the type, quantity and destination of the goods being carried. A bill of lading also serves as a shipment receipt when the carrier delivers the goods at a predetermined destination. This is different from a consular invoice, which is a document that certifies the shipment of goods, a bill of sight, which is a document that lists goods that are being shipped, and a certificate of origin, which is a document that certifies the country in which the goods were produced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>19", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The most acceptable means of payment in foreign transaction is", "images": [], "options": {"A": "personal cheques", "B": "central bank cheques", "C": "irrevocable letters of credit", "D": "bankdrafts"}, "answer": "C", "explanation": "The most acceptable means of payment in foreign transactions is the irrevocable letter of credit. An irrevocable letter of credit is a financial instrument used in international trade to provide a guarantee to the seller that they will be paid no matter what, as long as they meet the terms and conditions set out in the letter. This is more secure than personal cheques, central bank cheques, or bank drafts because it cannot be cancelled or changed without the agreement of all parties involved.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>20", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following is not a function of the Ports Authority?", "images": [], "options": {"A": "controlling pollution in rivers", "B": "providing parking space for vehicles", "C": "providing storage and warehousing facilities at the docks", "D": "providing facilities for water traffic movement"}, "answer": "B", "explanation": "The function of the Ports Authority does not include providing parking space for vehicles. The Ports Authority is responsible for controlling pollution in rivers, providing storage and warehousing facilities at the docks, and providing facilities for water traffic movement. Providing parking space for vehicles is typically the responsibility of local government or private entities, not the Ports Authority.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>21", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE ( 2) : TERMS OF TRADE", "question": "Terms of trade refers to", "images": [], "options": {"A": "agreement between two trading countries", "B": "the difference between the value of imports and exports", "C": "the relationship between export and import prices", "D": "all payments made to other countries and receipts from them"}, "answer": "C", "explanation": "Terms of trade refers to the relationship between export and import prices. It is an economic term that refers to the relative price of imports in terms of exports and is used to analyze the health of a country's trade balance. If a country's terms of trade improve, it means that for every unit of exports sold, it can buy more units of imported goods. So, it's not about the agreement between two trading countries or the difference between the value of imports and exports or all payments made to other countries and receipts from them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>22", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "The aid to trade responsible for the preservation of perishable items is", "images": [], "options": {"A": "warehousing", "B": "insurance", "C": "transportation", "D": "advertising"}, "answer": "A", "explanation": "The aid to trade responsible for the preservation of perishable items is warehousing. Warehousing is the act of storing goods that will be sold or distributed later. While warehousing is used for storing goods, its role in commerce has evolved beyond simple storage of goods. Now, they also offer services like packing, transportation, and inventory management. So, it's not about insurance, transportation, or advertising.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>23", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following abbreviations permits the seller to correct any error in an invoice?", "images": [], "options": {"A": "F. O. R.", "B": "C. I. F.", "C": "E. & O. E", "D": "I. O. U."}, "answer": "C", "explanation": "E. & O. E stands for Errors and Omissions Excepted. This abbreviation is used by sellers to avoid liability for any errors or omissions in the invoice. It means that if there are any mistakes in the invoice, the seller has the right to correct them.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>24", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "C & F as a price quotation in foreign trade means that the buyer", "images": [], "options": {"A": "is responsible for clearing and forwarding the goods", "B": "has to pay for cost and freight", "C": "pays for both the freight and insurance", "D": "pays for insurance only"}, "answer": "B", "explanation": "C & F stands for Cost and Freight. This term is used in international trade, and it means that the seller is responsible for the costs associated with transporting goods to a specific location. However, the risk of damage or loss is transferred to the buyer as soon as the goods are loaded onto the ship at the port of origin.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>25", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A bill of exchange is made more negotiable if it has been", "images": [], "options": {"A": "endorsed", "B": "accepted", "C": "honoured instantly", "D": "given special crossing"}, "answer": "A", "explanation": "A bill of exchange becomes more negotiable when it is endorsed. Endorsement refers to the act of signing one's name on the back of a check, bill of exchange, or other negotiable instrument, with the effect of transferring the rights to the said instrument to another party. It makes the instrument 'negotiable' meaning it can be transferred from one person to another in the course of business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>26", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The primary objective of insurance is to", "images": [], "options": {"A": "prevent accidents", "B": "meet uncertainties in future", "C": "give loan to businessmen", "D": "control the flow of cash"}, "answer": "B", "explanation": "The primary objective of insurance is to provide protection against future risk, loss or damage. It is a risk management technique to hedge against future uncertainties. It does not prevent accidents, give loans to businessmen or control the flow of cash. It provides a cover against a sudden loss. Insurance is essentially a form of risk management in which risk is transferred to an insurance company in exchange for payments or premium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2004>27", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following services is rendered by Central Bank?", "images": [], "options": {"A": "provision of brokerage services", "B": "safe keeping of cash and other valuables", "C": "discounting bills of exchange", "D": "issuing currency notes"}, "answer": "D", "explanation": "The Central Bank is responsible for issuing currency notes. This is one of its primary functions. It has the exclusive right to issue banknotes and coins in the country. The other options are not primary services rendered by the Central Bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>28", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following gives businessmen the opportunity to buy shares of public limited companies?", "images": [], "options": {"A": "insurance companies", "B": "commercial banks", "C": "discount houses", "D": "the stock exchange"}, "answer": "D", "explanation": "The Stock Exchange gives businessmen the opportunity to buy shares of public limited companies. It is a marketplace where stocks, bonds, or other securities are bought and sold. The other options do not provide a platform for buying shares of public limited companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>29", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The liquid assets of commercial banks are", "images": [], "options": {"A": "treasury bills, bills of exchange and cash", "B": "cash, current account and other money bearing assets", "C": "deposit accounts and cash", "D": "cash only"}, "answer": "A", "explanation": "Liquid assets are assets that can be converted into cash quickly and with minimal impact to the price received. They are called liquid because they can be 'liquidated' (i.e., sold) quickly. For commercial banks, these include treasury bills, bills of exchange, and cash. Treasury bills are short-term securities issued by a government to finance its short-term requirements. Bills of exchange are a kind of check or promissory note without interest, used primarily in international trade. Cash is the most liquid asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>30", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "The insurance policy which covers damages to the body of a ship is", "images": [], "options": {"A": "marine insurance", "B": "cargo insurance", "C": "ship liability insurance", "D": "hull insurance"}, "answer": "D", "explanation": "Hull insurance is a type of marine insurance which specifically covers damages to the body of a ship. It is a type of insurance that ship owners purchase to provide coverage for physical damage to a ship. It covers the hull and machinery of the vessel. Marine insurance is a broader term that includes not only hull insurance, but also cargo insurance and liability insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>31", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following central bank functions inspires confidence in the banking system in case of emergency?", "images": [], "options": {"A": "issuing of currency", "B": "lender of last resort", "C": "banker's bank", "D": "banker to the government"}, "answer": "B", "explanation": "The function of the central bank that inspires confidence in the banking system in case of emergency is acting as the 'lender of last resort'. This means that in times of financial crisis, when commercial banks are unable to meet their obligations, the central bank steps in to provide funds to ensure the stability of the banking system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>32", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following proves that important documents have reached their destination?", "images": [], "options": {"A": "business reply services", "B": "telegram services", "C": "recorded delivery services", "D": "express delivery services"}, "answer": "C", "explanation": "Recorded delivery services provide proof that important documents have reached their destination. This service involves the recipient signing a document upon receipt, which is then kept as a record by the delivery service. This record can be used as proof that the documents were delivered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>33", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The main advantage of sea transport over air transport is", "images": [], "options": {"A": "capacity", "B": "safety", "C": "speed", "D": "patronage"}, "answer": "A", "explanation": "Sea transport has a much larger capacity compared to air transport. Ships can carry thousands of tons of cargo, while even the largest cargo planes can only carry a few hundred tons. This makes sea transport more cost-effective for transporting large quantities of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>34", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The mode of transport that conveys goods at low cost per unit is", "images": [], "options": {"A": "road", "B": "rail", "C": "pipeline", "D": "air"}, "answer": "B", "explanation": "Rail transport is the mode of transport that conveys goods at low cost per unit. This is because trains can carry a large amount of goods at once, reducing the cost per unit. Additionally, trains are fuel-efficient and can travel long distances without needing to refuel, further reducing costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>35", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Any activity aimed at creating more markets for a product is", "images": [], "options": {"A": "packaging", "B": "branding", "C": "promotion", "D": "merchandising"}, "answer": "C", "explanation": "The question is about activities aimed at creating more markets for a product. This is typically achieved through promotion. Promotion involves activities such as advertising, sales promotion, public relations, and direct marketing, all aimed at increasing product awareness, creating interest, generating sales, and creating brand loyalty. It is one of the four elements of the marketing mix, also known as the 4Ps (product, price, place, and promotion). Therefore, the correct answer is 'promotion'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>36", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Activities aimed at boosting the image of an organization are regarded as", "images": [], "options": {"A": "sales promotion", "B": "advertising", "C": "public relations", "D": "consumer protection"}, "answer": "C", "explanation": "The question is about activities aimed at boosting the image of an organization. This is typically achieved through public relations. Public relations involves managing the spread of information between an individual or an organization and the public. It may include an organization or individual gaining exposure to their audiences using topics of public interest and news items that do not require direct payment. Therefore, the correct answer is 'public relations'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>37", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "When consumers are unaware of the quality of a product, the best advertising technique to use is", "images": [], "options": {"A": "informative advertising", "B": "competitive advertising", "C": "direct advertising", "D": "indirect advertising"}, "answer": "A", "explanation": "Informative advertising is the best technique to use when consumers are unaware of the quality of a product. This type of advertising is designed to educate the consumer about the product, its features, benefits, and uses. It provides detailed information about the product's quality, which can help consumers make informed purchasing decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>38", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not an obstacle to the achievement of the objectives of ECOWAS?", "images": [], "options": {"A": "lack of capital", "B": "sabotage by other organizations", "C": "lack of commitment of member states", "D": "slow pace of development of member countries"}, "answer": "B", "explanation": "Sabotage by other organizations is not an obstacle to the achievement of the objectives of ECOWAS. The main obstacles to the achievement of the objectives of ECOWAS are internal factors such as lack of capital, lack of commitment of member states, and slow pace of development of member countries. These factors directly affect the functioning and effectiveness of the organization. Sabotage by other organizations, while potentially harmful, is not a primary obstacle to ECOWAS's objectives.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>39", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Musa entered into a contract to supply two cows to Aro. Before the agreed date of supply and without the knowledge of the two parties, thieves stole the cows. This is an example of termination of contract by", "images": [], "options": {"A": "default", "B": "breach", "C": "frustration", "D": "performance"}, "answer": "C", "explanation": "The contract is terminated by frustration. Frustration of a contract occurs when an unforeseen event changes the conditions of the contract, making it impossible to fulfill. In this case, the theft of the cows was an unforeseen event that made it impossible for Musa to fulfill his part of the contract.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>40", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Abuse of monopoly power by industrialists could lead to", "images": [], "options": {"A": "privatization", "B": "commercialization", "C": "nationalization", "D": "indigenization"}, "answer": "C", "explanation": "The abuse of monopoly power by industrialists could lead to government intervention in business which is nationalization. It is the conversion of private-owned business to government-owned business.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>41", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following is an objective of indigenization policy? To", "images": [], "options": {"A": "prevent all foreign interference in business", "B": "encourage local participation in business", "C": "prevent smuggling", "D": "encourage more production"}, "answer": "B", "explanation": "The objective of indigenization policy is to encourage local participation in business. Indigenization policy is a policy that aims to transfer ownership and control of foreign businesses to local citizens. It is designed to foster local participation and growth in the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>42", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the objectives of ECOWAS is to", "images": [], "options": {"A": "promote indigenization policy", "B": "ensure that quality goods are produced", "C": "promote trade within the region", "D": "discourage foreign investors"}, "answer": "C", "explanation": "One of the objectives of ECOWAS (Economic Community of West African States) is to promote trade within the region. ECOWAS is a regional economic union of fifteen countries located in West Africa. It was established to promote economic integration and trade among its member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>43", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The amount of insurance premium to be paid depends on the", "images": [], "options": {"A": "supply and demand of a particular company's service", "B": "extent of the possible loss and the frequency of risk", "C": "number of insurance companies in a place", "D": "amount of profit to be made by the insurer"}, "answer": "B", "explanation": "The amount of insurance premium to be paid depends on the extent of the possible loss and the frequency of risk. This is because insurance is a risk transfer mechanism where the financial burden of potential loss is transferred from the insured to the insurer. The insurer calculates the premium based on the probability of the event happening and the potential loss if the event occurs. This is done using statistical and mathematical calculations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>44", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Which of the following is the main task of the Marketing Manager whose company has adopted the marketing concept? To", "images": [], "options": {"A": "identify and satisfy customers' needs", "B": "maintain the company's share of the market", "C": "recruit more salesmen", "D": "make maximum profit"}, "answer": "A", "explanation": "The main task of a Marketing Manager in a company that has adopted the marketing concept is to identify and satisfy customers' needs. The marketing concept is a business philosophy that holds that the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its selected target customers. Therefore, the Marketing Manager's role is to understand what the customers need and want, and ensure that the company delivers these effectively and efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>45", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "The Money Market is the", "images": [], "options": {"A": "market for long-term loans", "B": "market for short-term loans", "C": "market for government securities", "D": "banking hall of commercial banks"}, "answer": "B", "explanation": "The Money Market is a sector of the financial market in which financial instruments with high liquidity and short-term maturities are traded. The money market is used by participants as a means for borrowing and lending in the short term, with maturities that usually range from overnight to just under a year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>46", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The choice of medium used in advertising is not determined by the", "images": [], "options": {"A": "cost of using a particular medium", "B": "age group to which the medium appeals", "C": "nationality of people using the medium", "D": "number of people reached by the medium"}, "answer": "C", "explanation": "The choice of medium used in advertising is determined by factors such as cost, the target audience, and reach. The nationality of people using the medium is not a primary factor in choosing an advertising medium. The effectiveness of an advertising medium is more about its ability to reach the target audience, regardless of their nationality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>47", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "If a country wishes to discourage imports, it", "images": [], "options": {"A": "removes quotas", "B": "encourages free trade", "C": "imposes tariffs", "D": "subsidizes exports"}, "answer": "C", "explanation": "Tariffs are taxes or duties that are placed on imported goods. When a country imposes tariffs, it increases the cost of imported goods. This makes imported goods more expensive, discouraging imports and encouraging local consumption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>48", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following sources of capital to a business requires mortgaging a specific asset?", "images": [], "options": {"A": "overdraft", "B": "ordinary shares", "C": "fixed debenture", "D": "trade credit"}, "answer": "C", "explanation": "A fixed debenture is a type of debt instrument that is backed by the borrower's assets. If the borrower defaults, the lender can seize the asset to recoup its losses. Therefore, it requires mortgaging a specific asset.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2004>49", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "Which of the following interest holders are settled first in case of a company's liquidation?", "images": [], "options": {"A": "board of directors", "B": "debenture holders", "C": "ordinary shareholders", "D": "preference shareholders"}, "answer": "B", "explanation": "In the event of a company's liquidation, the debenture holders are settled first. This is because debenture holders are creditors of the company and in the event of liquidation, creditors are paid before equity holders (ordinary and preference shareholders).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2004>50", "subject": "Commerce", "year": "2004", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The West African Clearing House (WACH) was establish to", "images": [], "options": {"A": "dredge the rivers in West Africa for easy navigation", "B": "expand the volume of traffic within member countries", "C": "coordinate the efforts to member states to tap their natural resources", "D": "promote the use of currencies of all members for interregional trade"}, "answer": "D", "explanation": "The West African Clearing House (WACH) was established to promote the use of currencies of all members for interregional trade. This is to facilitate trade among member countries and reduce reliance on foreign currencies for trade transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>1", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The form of trade practised by the early men was characterized by", "images": [], "options": {"A": "exchange of goods for money", "B": "efficient distribution system", "C": "exchange of goods for goods", "D": "organized warehousing"}, "answer": "C", "explanation": "The form of trade practiced by early men was characterized by the exchange of goods for goods, a system known as barter trade. In this system, goods were directly exchanged for other goods without the use of money as a medium of exchange. The other options are incorrect because money, efficient distribution systems, and organized warehousing were not features of early trade.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>2", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is an advantage of indigenization?", "images": [], "options": {"A": "Checks exploitation by citizens", "B": "Business risks are shared", "C": "Fosters self-reliance", "D": "Leads to monopoly of power"}, "answer": "C", "explanation": "Indigenization is a policy aimed at promoting local ownership and control of the economy. One of its advantages is that it fosters self-reliance as it encourages the growth of local industries and reduces dependence on foreign goods and services. The other options are incorrect. While indigenization may help check exploitation by citizens and share business risks, these are not its primary advantages. Also, it does not necessarily lead to a monopoly of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>3", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Farming is an activity that falls under", "images": [], "options": {"A": "tertiary occupation", "B": "commercial occupation", "C": "extractive occupation", "D": "secondary occupation"}, "answer": "C", "explanation": "Farming is an activity that falls under extractive occupation. Extractive occupations are those that involve the extraction of raw materials from the earth or sea, such as farming, fishing, mining, and forestry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>4", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following coordinates other factors of production to achieve set objectives?", "images": [], "options": {"A": "Land", "B": "Labour", "C": "Entrepreneur", "D": "Capital"}, "answer": "C", "explanation": "The entrepreneur coordinates other factors of production to achieve set objectives. An entrepreneur is a person who organizes and manages any enterprise, especially a business, usually with considerable initiative and risk. They are responsible for the decision-making processes involved in the operations of the business, including what to produce, how to produce, where to produce and for whom to produce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>5", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Production is defined as", "images": [], "options": {"A": "an industrial undertaking", "B": "creation of utility", "C": "earning ones daily bread", "D": "the changing of raw materials"}, "answer": "B", "explanation": "Production in economics is defined as the process of creating utility. It involves creating goods or services that have utility or value to consumers. This process can involve the transformation of raw materials into finished goods, but the key aspect is the creation of utility, not just the transformation of materials. Therefore, the correct answer is 'creation of utility'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>6", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : ADVANTAGES AND DISADVANTAGES", "question": "An advantage of a public limited company over a private one is the", "images": [], "options": {"A": "limited liability of shareholders", "B": "easy transferability of shares", "C": "access to retained earnings", "D": "less taxation"}, "answer": "B", "explanation": "One of the main advantages of a public limited company over a private one is the easy transferability of shares. In a public limited company, shares can be bought and sold by the public on the stock exchange. This provides liquidity to the shareholders as they can easily sell their shares whenever they want. On the other hand, in a private limited company, the transfer of shares is usually more restricted. Therefore, the correct answer is 'easy transferability of shares'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>7", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : FEATURES AND IMPORTANCE", "question": "The distribution of profits based upon the level of patronage in the business is a common feature of", "images": [], "options": {"A": "partnership firms", "B": "public limited companies", "C": "co-operative societies", "D": "private limited companies"}, "answer": "C", "explanation": "Co-operative societies distribute profits based on the level of patronage in the business. This means that the more a member uses the co-op, the more they receive in patronage dividends. This is different from other types of businesses where profits are distributed based on the amount of capital invested.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>8", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The fee which the bank charges for services rendered to their current account customers is", "images": [], "options": {"A": "commission on turnover", "B": "bank rate", "C": "minimum lending rate", "D": "interest"}, "answer": "A", "explanation": "Banks often charge a commission on turnover for services rendered to their current account customers. This fee is based on the amount of money that passes through the account, rather than a flat rate or a percentage of the balance. Bank rate and minimum lending rate are types of interest rates, not fees. And interest is the cost of borrowing money, not a fee for services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>9", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following would not affect the form of a business unit?", "images": [], "options": {"A": "Availability of raw materials", "B": "The type of business", "C": "Number of persons involved", "D": "The capital size"}, "answer": "A", "explanation": "The form of a business unit is determined by factors such as the type of business, the number of persons involved, and the capital size. These factors determine whether the business will be a sole proprietorship, a partnership, a corporation, etc. The availability of raw materials does not affect the form of the business unit but rather affects the operations of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>10", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Partnership forth of business is mostly", "images": [], "options": {"A": "where professionals are needed", "B": "for non-profit making ventures", "C": "where very large capital is required", "D": "where the liability of members is limited"}, "answer": "A", "explanation": "A partnership form of business is mostly where professionals are needed. This is because in a partnership, each partner brings their unique skills and expertise to the business. This is particularly common in professional fields such as law, accounting, and medicine. The other options are not typically characteristics of a partnership. For instance, partnerships are not usually for non-profit ventures, they do not necessarily require very large capital, and the liability of partners is not limited but rather unlimited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>11", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Use the information below to answer this question  The nominal capital of a public limited company is made up of 400,000 ordinary - shares of 50k each.  The Board of Directors decided to issue 50% of it for subscription by the public.    The authorized share capital is", "images": [], "options": {"A": "₦400,000", "B": "₦200,000", "C": "₦100,000", "D": "₦50,000"}, "answer": "B", "explanation": "The nominal capital of a public limited company is the total value of shares that the company is authorized to issue. In this case, the nominal capital is made up of 400,000 ordinary shares of 50k each, which equals ₦200,000. The Board of Directors decided to issue 50% of it for subscription by the public, which means the authorized share capital is 50% of ₦200,000, which equals ₦100,000. However, the question asks for the authorized share capital, not the amount issued for public subscription. The authorized share capital is the total value of shares that a company can issue, which in this case is ₦200,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>12", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Use the information below to answer this question  The nominal capital of a public limited company is made up of 400,000 ordinary - shares of 50k each.  The Board of Directors decided to issue 50% of it for subscription by the public.  The reserved capital is", "images": [], "options": {"A": "₦300,000", "B": "₦200,000", "C": "₦100,000", "D": "₦50,000"}, "answer": "C", "explanation": "Reserved capital = Authorised capital - Issued capital  Issuedcapital=50100×400,000×0.50  ⇒ ₦100,000  Reserved capital = 200,000 - 100,000  ⇒ ₦100,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>13", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The nominal value of a share is the same as its", "images": [], "options": {"A": "market value", "B": "below par value", "C": "above par value", "D": "face value"}, "answer": "D", "explanation": "The nominal value of a share is also known as its face value. It is the value stated in the corporate charter below which shares of that class cannot be sold upon initial offering and it represents the minimum amount that must be paid for shares of a company. It does not change over time and is not related to market value, which can fluctuate based on supply and demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>14", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Which of the following is an intangible asset of a firm?", "images": [], "options": {"A": "Goodwill", "B": "Reserve", "C": "Skilled personnel", "D": "Rights issue"}, "answer": "A", "explanation": "An intangible asset is an asset that is not physical in nature. Goodwill is an example of an intangible asset as it represents the value of a company's brand name, solid customer base, good customer relations, good employee relations, and any patents or proprietary technology. The other options like Reserve, Skilled personnel, Rights issue are not considered as intangible assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>15", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The net profit of a business is determined by", "images": [], "options": {"A": "deducting cost of goods sold from sales", "B": "deducting purchases from sales", "C": "adding commissions received to gross profit", "D": "deducting all expenses from gross profit and other income"}, "answer": "D", "explanation": "The net profit of a business is determined by deducting all expenses from gross profit and other income. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. Net profit, also referred to as the bottom line, net income, or net earnings is a measure of the profitability of a venture after accounting for all costs and taxes. It is the actual profit, and includes the operating expenses that are excluded from gross profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>16", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An organization formed mainly by traders on the same line of business is known as", "images": [], "options": {"A": "trade union", "B": "co-operative society", "C": "trade association", "D": "chamber of commerce"}, "answer": "C", "explanation": "An organization formed mainly by traders on the same line of business is known as a trade association. A trade association, also known as an industry trade group, business association, sector association or industry body, is an organization founded and funded by businesses that operate in a specific industry. An industry trade association participates in public relations activities such as advertising, education, political donations, lobbying and publishing, but its focus is collaboration between companies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>17", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A bank's undertaking to pay an exporter on behalf of an importer is a", "images": [], "options": {"A": "documentary credit", "B": "letter of a credit", "C": "letter of hypothecation", "D": "bill of exchange"}, "answer": "B", "explanation": "A bank's undertaking to pay an exporter on behalf of an importer is known as a Letter of Credit. A Letter of Credit is a document from a bank guaranteeing that a seller will receive payment in full as long as certain delivery conditions have been met. In the event that the buyer is unable to make payment on the purchase, the bank will cover the outstanding amount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>18", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Who among the following cannot be regarded as an itinerant trader?", "images": [], "options": {"A": "Gypsy", "B": "Barrow boy", "C": "Pedlar", "D": "Stall owner"}, "answer": "D", "explanation": "An itinerant trader is a merchant who does not have a fixed place of business but moves from place to place to trade. Examples include gypsies, barrow boys, and pedlars. A stall owner, on the other hand, has a fixed place of business and therefore cannot be regarded as an itinerant trader.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>19", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following will not be considered in choosing a channel of distribution?", "images": [], "options": {"A": "Nature of product", "B": "Preferences of consumers", "C": "Volume of sales", "D": "Quality of product"}, "answer": "D", "explanation": "The quality of a product is not a factor in choosing a channel of distribution. The channel of distribution is concerned with how the product gets from the producer to the consumer. It involves decisions about which intermediaries to use, such as wholesalers, retailers, or direct marketing. The nature of the product, preferences of consumers, and volume of sales are all factors that can influence these decisions. The quality of the product, however, is determined before the distribution process and is not affected by the choice of distribution channel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>20", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "A manufacturer of goods that are seasonally demanded will be in dire need of a", "images": [], "options": {"A": "wealthy customer", "B": "suitable means of transport", "C": "warehouse", "D": "large shop frontage"}, "answer": "C", "explanation": "A manufacturer of goods that are seasonally demanded will need a warehouse. This is because the goods will not be sold all at once, but rather at specific times of the year. Therefore, the manufacturer will need a place to store the goods until they are needed. A warehouse provides a place for storing goods until they are needed, protecting them from damage and theft. Wealthy customers, suitable means of transport, and large shop frontage are all beneficial for a business, but they do not address the specific need of a manufacturer of seasonally demanded goods to store their products until the appropriate season arrives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>21", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is a feature peculiar to multiple shops?", "images": [], "options": {"A": "Central location", "B": "Self service", "C": "Central buying", "D": "One stop shopping"}, "answer": "C", "explanation": "Multiple shops are a chain of shops owned by a single business entity and spread across different geographical locations. They have a common name, common layout, and common pricing policy. One of the key features of multiple shops is central buying. Central buying means that the purchasing of goods is done centrally for all the shops in the chain. This allows the business to take advantage of economies of scale and negotiate better prices with suppliers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>22", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Terms of trade is the", "images": [], "options": {"A": "rate at which the central bank discounts first class bills", "B": "rate at which a country's exports exchange for its imports", "C": "expected rate of returns on an investment", "D": "rate of payment for goods and services purchased"}, "answer": "B", "explanation": "Terms of trade is an economic concept that refers to the relative price of imports in terms of exports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods. So, it is the rate at which a country's exports exchange for its imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>23", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following encourages trade between regions?", "images": [], "options": {"A": "Differences in currencies of countries", "B": "Difference in national income of countries", "C": "Existence of trade associations", "D": "Differences in natural resources"}, "answer": "D", "explanation": "Trade between regions is encouraged by differences in natural resources. This is because different regions have different natural resources, and they can trade these resources with each other to get what they don't have. This concept is known as comparative advantage in economics, where a region focuses on producing goods that it can produce more efficiently (or at a lower cost) than other goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>24", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "Which of the following is not suitable for hire purchase?", "images": [], "options": {"A": "Textiles", "B": "Furniture", "C": "Refrigeration", "D": "Printing machine"}, "answer": "A", "explanation": "Textiles are generally not suitable for hire purchase because they are consumable items that typically have a shorter lifespan and lower value compared to durable goods like furniture, refrigeration, and printing machines. Hire purchase agreements are more suited to high-value, durable goods that can be used over a longer period, making it practical for the buyer to pay in installments while still deriving value from the item.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>25", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "A seller quoting his goods loco price means that", "images": [], "options": {"A": "all charges are borne by the seller", "B": "all charges are borne by the buyer", "C": "the seller pays carriage as far as the buyers warehouse", "D": "the price includes cost, insurance and freight"}, "answer": "B", "explanation": "Loco price is a term used in commerce which means that the buyer is responsible for the cost of transporting the goods from the seller's location. Therefore, all charges are borne by the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>26", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following is the correct sequence in which the following documents are used?", "images": [], "options": {"A": "Order, delivery note, debit note, invoice, statement", "B": "Order, advice note, debit note, invoice, statement", "C": "Order, statement, delivery note, invoice, debit note", "D": "Order, delivery note, invoice, debit note, statement"}, "answer": "D", "explanation": "The correct sequence of documents used in a typical business transaction is: Order (the buyer places an order), Delivery Note (the seller sends a note confirming the delivery), Invoice (the seller sends an invoice detailing the cost), Debit Note (if there are any adjustments to be made), and Statement (a summary of all transactions).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>27", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "A set of measures pursued by an organisation in order to maintain goodwill in its environment is referred to as", "images": [], "options": {"A": "human relations", "B": "public relations", "C": "personal relations", "D": "organizational set-up"}, "answer": "B", "explanation": "Public relations is a strategic communication process that builds mutually beneficial relationships between organizations and their publics. It involves activities that ensure the company has a strong public image. Public relations activities include helping the public to understand the company and its products.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>28", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following organizations aim at providing relief for countries facing adverse balance of payment?", "images": [], "options": {"A": "A. C. P.", "B": "G. A. T. T", "C": "U. N. C. T. A. D.", "D": "I. M. F."}, "answer": "D", "explanation": "The International Monetary Fund (IMF) is an organization that aims to foster global monetary cooperation, secure financial stability, facilitate international trade, promote high employment and sustainable economic growth, and reduce poverty around the world. One of its primary functions is to provide loans to member countries that are experiencing balance of payments problems.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>29", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "C. O. D. transactions are associated with", "images": [], "options": {"A": "mail order firms", "B": "mobile shops", "C": "supermarkets", "D": "multiple shops"}, "answer": "A", "explanation": "C.O.D. stands for Cash On Delivery. It is a type of transaction where the recipient makes payment for goods at the time of delivery. This type of transaction is most commonly associated with mail order firms where goods are ordered by mail and payment is made upon receipt of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>30", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Postage marks can be printed on letters and parcels using", "images": [], "options": {"A": "teleprinter machine", "B": "facsimile machine", "C": "folding machine", "D": "franking machine"}, "answer": "D", "explanation": "Postage marks can be printed on letters and parcels using a franking machine. A franking machine is a machine that prints postage stamps as well as the logo and date on letters and parcels. It is used as an alternative to traditional stamps, providing a more efficient and streamlined process for sending large volumes of mail.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2005>31", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "If the amount of dividend paid varies according to the level of profit, what type of share is involved?", "images": [], "options": {"A": "Cumulative preference share", "B": "Preference share", "C": "Deferred share", "D": "Ordinary share"}, "answer": "D", "explanation": "Ordinary shares, also known as common shares, are stocks sold on a public exchange. Each share of stock generally gives its owner the right to one vote at a company shareholders' meeting. The dividends of ordinary shares vary according to the level of profit. When a company makes a profit, it may choose to distribute those profits to shareholders as a dividend. The company's board of directors can decide to pay out a certain amount of the profits, or dividends, to shareholders for each share they own.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>32", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail outlet is described as a multiple shop when it", "images": [], "options": {"A": "has many shops under one roof", "B": "sells goods which are not standardized", "C": "sellers through catalogue", "D": "deals in one line of goods"}, "answer": "D", "explanation": "A multiple shop, also known as a chain store, is a type of retail outlet that consists of multiple locations selling the same line of goods, often owned and managed by a single company. This allows the company to standardize products, pricing, and services across all its stores. Unlike department stores (which have many different departments under one roof) or catalog retailers, multiple shops focus on a specific type of product, ensuring consistency and brand recognition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>33", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Time policy in insurance is associated with", "images": [], "options": {"A": "motor vehicles", "B": "ships at sea", "C": "life endowment", "D": "goods in transit"}, "answer": "B", "explanation": "Time policy in insurance is associated with ships at sea. A time policy is a type of marine insurance policy that covers the risk of loss to a ship for a specified period, typically one year. This policy is usually taken by those who own the ship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>34", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "When a quotation is marked 'CWO', it means", "images": [], "options": {"A": "no credit facility is allowed", "B": "no discount is allowed", "C": "the buyer should beware", "D": "the seller should beware"}, "answer": "A", "explanation": "When a quotation is marked 'CWO', it means no credit facility is allowed. CWO stands for Cash With Order, which means the buyer must pay for the goods at the time of placing the order. It is a type of transaction in which the payment for goods is made at the time of order, and not at the time of delivery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>35", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following is a function of a stockbroker?", "images": [], "options": {"A": "Provision of short-term capital", "B": "Giving investment advice", "C": "Regulation of stock exchange practices", "D": "Granting of loans to investors"}, "answer": "B", "explanation": "A stockbroker is a professional who executes buy and sell orders for stocks and other securities on behalf of clients. A stockbroker may also provide investment advice to their clients, helping them navigate the complex world of investing and making decisions about what stocks to buy or sell. Therefore, the function of a stockbroker is giving investment advice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>36", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The people involved in the formation of new companies are called", "images": [], "options": {"A": "members", "B": "directors", "C": "shareholders", "D": "promoters"}, "answer": "D", "explanation": "The people involved in the formation of new companies are called promoters. Promoters are individuals or companies that, in acting to create a company, attract subscribers, acquire initial capital, and apply for the incorporation of the company. They play a crucial role in the establishment of a company, including its registration under the Companies Act. Therefore, the people involved in the formation of new companies are promoters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>37", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Commercial activities among West African countries are greatly hindered by", "images": [], "options": {"A": "nationalization decree", "B": "lack of an acceptable medium of exchange", "C": "good road network", "D": "too many commercial banks"}, "answer": "B", "explanation": "Commercial activities among West African countries are greatly hindered by the lack of an acceptable medium of exchange. This is because different countries have different currencies, and the exchange rates between these currencies can fluctuate, making trade more difficult and unpredictable. Nationalization decree, good road network, and too many commercial banks do not directly hinder commercial activities among West African countries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>38", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following makes it an offence for a trader to make untrue statements about his goods?", "images": [], "options": {"A": "Consumerism", "B": "Consumer Credit Act", "C": "Trade Description Act", "D": "Price Control Act"}, "answer": "C", "explanation": "The Trade Description Act makes it an offence for a trader to make untrue statements about his goods. This Act is designed to prevent traders from misleading consumers about the nature, quality or origin of their goods. Consumerism is a social and economic order that encourages the acquisition of goods and services in ever-increasing amounts. The Consumer Credit Act is designed to protect consumers in credit transactions by requiring clear disclosure of key terms of the lending arrangement and all costs. The Price Control Act is designed to control the prices of certain goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>39", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Which of the following is a means by which a contract of agency could be terminated?", "images": [], "options": {"A": "Mutual agreement", "B": "Lack of consideration", "C": "Failure to insure the contract", "D": "Payment of commission"}, "answer": "A", "explanation": "A contract of agency can be terminated by mutual agreement. This means that both the principal and the agent agree to end the contract. This is not related to consideration, insurance of the contract, or payment of commission. Consideration is something of value exchanged between the parties in a contract, but lack of it does not necessarily terminate a contract of agency. Similarly, failure to insure the contract or payment of commission are not means by which a contract of agency could be terminated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>40", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "Which of the following would be necessary before the introduction of a new product?", "images": [], "options": {"A": "Product differentiation", "B": "Target marketing", "C": "Market research", "D": "Market segmentation"}, "answer": "C", "explanation": "Before introducing a new product, market research would be necessary. Market research involves gathering, analyzing and interpreting information about a market, about a product or service to be offered for sale in that market, and about the past, present and potential customers for the product or service. This helps to identify the needs and preferences of potential customers and the dynamics of the market, which are crucial for the successful introduction of a new product. Product differentiation, target marketing, and market segmentation are strategies that could be employed after the product has been introduced, based on the findings of the market research.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2005>41", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "People who are against advertising claim that it", "images": [], "options": {"A": "widens the market for consumer goods", "B": "encourages consumers to buy what they do not need", "C": "emphasizes the good feature of a particular product", "D": "promotes competition among firms"}, "answer": "B", "explanation": "People who are against advertising often argue that it encourages consumers to buy what they do not need. This is because advertising often creates a perceived need for a product or service in the mind of the consumer, which may not necessarily be a real need. This is done through various techniques such as emotional appeal, creating a sense of urgency, and so on.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>42", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A distinctive feature of personal selling is the", "images": [], "options": {"A": "face to face meeting of seller and buyer", "B": "selling of cheap items only", "C": "sale of industrial goods only", "D": "hawking of goods"}, "answer": "A", "explanation": "A distinctive feature of personal selling is the face to face meeting of seller and buyer. This is because personal selling involves direct communication between the seller and the buyer, which allows for immediate feedback and the ability to address any questions or concerns the buyer may have. This is different from other forms of selling such as online selling or telemarketing, where there is no direct face-to-face interaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>43", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "The practice whereby a firm prepays the postage for the response of its customers is known as", "images": [], "options": {"A": "express delivery", "B": "poste restante", "C": "recorded delivery service", "D": "business reply service"}, "answer": "D", "explanation": "Business reply service is a service provided by the postal services where a business pays for the postage of the mail it receives from its customers. This is done to encourage customers to respond since they do not have to pay for postage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>44", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following is not provided by the post office?", "images": [], "options": {"A": "Recorded delivery service", "B": "Business reply service", "C": "Express delivery service", "D": "After sales service"}, "answer": "D", "explanation": "After sales service is not provided by the post office. After sales service refers to any support provided after a customer has purchased a product. This is typically provided by the company that sold the product, not the post office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>45", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following is not a principle of insurance?", "images": [], "options": {"A": "Indemnity", "B": "Insurable risk", "C": "Subrogation", "D": "Insurable interest"}, "answer": "B", "explanation": "The principles of insurance include indemnity, subrogation, insurable interest, utmost good faith, proximate cause, and contribution. However, 'Insurable risk' is not a principle of insurance. It is a term used to describe a risk that meets the ideal criteria for efficient insurance. The risk must be definable, financially measurable, and non-catastrophic, allowing the insurer to charge a reasonable premium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>46", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following terms is used in marine insurance when the cargo suffers partial loss?", "images": [], "options": {"A": "General Average", "B": "Particular Average", "C": "Floating Policy", "D": "Open Cover"}, "answer": "B", "explanation": "In marine insurance, the term 'Particular Average' is used when the cargo suffers a partial loss. This refers to a partial loss on an individual shipment from one of the risks insured against, regardless of the balance of the cargo. The loss is borne totally by the owner of the item, unless recovered from a carrier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>47", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following is not a function of money?", "images": [], "options": {"A": "Double coincidence of wants", "B": "Medium of exchange", "C": "Measure of value", "D": "Store of wealth"}, "answer": "A", "explanation": "The double coincidence of wants is not a function of money but rather a problem that money solves. In a barter system, for a transaction to occur, both parties must desire what the other has to offer. This is known as the double coincidence of wants. Money, as a medium of exchange, eliminates this problem by providing a common measure of value that everyone accepts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>48", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following is true of rail transport?", "images": [], "options": {"A": "Suitable for perishable goods", "B": "Cheaper over long distances", "C": "It does not require trans-shipment of goods", "D": "Has no fixed route"}, "answer": "B", "explanation": "Rail transport is generally cheaper over long distances compared to other modes of transport like road or air. This is because trains can carry a large volume of goods at once, reducing the cost per unit of goods transported. The other options are incorrect. Rail transport is not suitable for perishable goods because it is slower than air or road transport. It does require trans-shipment of goods when the rail network does not cover the entire route. And it does have a fixed route, unlike road transport which can use different routes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>49", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "The process of dividing market into identifiable sub-markets is known as", "images": [], "options": {"A": "marketing concept", "B": "market segmentation", "C": "market research", "D": "market orientation"}, "answer": "B", "explanation": "Market segmentation is the process of dividing a market of potential customers into groups, or segments, based on different characteristics. The segments created are composed of consumers who will respond similarly to marketing strategies and who share traits such as similar interests, needs, or locations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2005>50", "subject": "Commerce", "year": "2005", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Legal tender consists of", "images": [], "options": {"A": "cheques and coins", "B": "bankdrafts and cheques", "C": "currency notes and coins", "D": "money order and currency notes"}, "answer": "C", "explanation": "Legal tender is a medium of payment recognized by a legal system to be valid for meeting a financial obligation. In many jurisdictions, the two forms of legal tender are currency notes and coins.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>1", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A transporter who offers to carry goods for anyone at a fee is called", "images": [], "options": {"A": "a national carrier", "B": "a common  carrier", "C": "a private carrier", "D": "an independent carrier"}, "answer": "B", "explanation": "A common carrier is a transporter who offers to carry goods for anyone at a fee. This is different from a private carrier who only transports goods for specific clients or an independent carrier who operates independently and not under the control of another carrier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>2", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A dormant partner is one who", "images": [], "options": {"A": "does not work hard", "B": "lent his name to the business", "C": "has limited liability", "D": "does not partake in running the business"}, "answer": "D", "explanation": "A dormant partner is one who does not partake in running the business. They are partners who invest capital into the business but do not participate in its day-to-day operations or management. Their liability is not limited, and they do not necessarily lend their name to the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>3", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The right that a debenture holder has on the earning of a company is", "images": [], "options": {"A": "lien", "B": "dividend", "C": "interest", "D": "rate"}, "answer": "C", "explanation": "The right that a debenture holder has on the earning of a company is interest. A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. The interest is the return earned by the debenture holder for lending money to the company.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>4", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Which of the following does not determine the size of a business unit", "images": [], "options": {"A": "The quality of its products", "B": "The nature of the business", "C": "The size of the market", "D": "The size of the capital"}, "answer": "A", "explanation": "The size of a business unit is determined by factors such as the nature of the business, the size of the market, and the size of the capital. The quality of its products does not determine the size of a business unit. A business can produce high-quality products but still be small in size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>5", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The printing of catalogues is one of the costs associated with the operation of", "images": [], "options": {"A": "tied shops", "B": "mobile shops", "C": "mail order shops", "D": "department stores"}, "answer": "C", "explanation": "The printing of catalogues is a cost associated with the operation of mail order shops. Mail order shops are a type of retail business where the selling and buying of goods or services are conducted through mail delivery. The customers can order the goods or services from a catalogue provided by the shop, hence the need for printing catalogues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>6", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Labour and entrepreneur are examples of", "images": [], "options": {"A": "factors of production", "B": "division of labour", "C": "direct services", "D": "primary production"}, "answer": "A", "explanation": "Labour and entrepreneur are examples of factors of production. Factors of production are the inputs used in the production of goods or services in the attempt to make an economic profit. They include land, labour, capital, and entrepreneurship.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2006>7", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "House builders belong to", "images": [], "options": {"A": "manufacturing industry", "B": "construction industry", "C": "commercial occupation", "D": "tertiary occupation"}, "answer": "B", "explanation": "House builders belong to the construction industry. The construction industry is a sector of the economy that transforms various resources into constructed physical economic and social infrastructure necessary for socio-economic development. The manufacturing industry, on the other hand, is involved in the production and processing of goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2006>8", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following groups of activities are commercial services?", "images": [], "options": {"A": "Manufacturing industry", "B": "constructive industry", "C": "commercial occupation", "D": "tertiary occupation"}, "answer": "D", "explanation": "Commercial services are part of the tertiary sector of the economy, which involves the provision of services to businesses as well as final consumers. Services may involve the transport, distribution, and sale of goods from producer to a consumer, as may happen in wholesaling and retailing, or may involve the provision of a service, such as in pest control or entertainment. The tertiary sector is also known as the service industry/sector.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2006>9", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "The price quotation where the buyer uses his own means to collect goods from the producers warehouse is", "images": [], "options": {"A": "F.O.B", "B": "ex-works", "C": "F.A.S", "D": "F.O.R"}, "answer": "B", "explanation": "Ex-works is a term used in international trade. Under an ex-works agreement, the seller makes the product available at a specific location, and the buyer incurs transport costs. This means the buyer uses his own means to collect goods from the producer's warehouse. F.O.B (Free On Board), F.A.S (Free Alongside Ship), and F.O.R (Free On Rail) are other terms used in international trade, but they involve the seller delivering the goods at a specific location or alongside a vessel.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>10", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is used only in international trade?", "images": [], "options": {"A": "Letter of enquiry", "B": "Certificate of origin", "C": "Pro-forma invoice", "D": "Consignment note"}, "answer": "B", "explanation": "A Certificate of Origin is a document used in international trade. In a globalized world, goods are often manufactured in one country and sold in another. The Certificate of Origin is a document that certifies the country in which the goods were produced. This is important because it can affect the amount of duty that is paid, or whether the goods can be legally imported at all.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>11", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer questions 11 to 13.  The following information relates to Mallam Amidu Kachella for the year ended 31/12/2005  Opening stock ₦ 4 000Purchases ₦ 16 000Sales ₦ 30 000Debtors ₦ 6 500Creditors ₦ 4 200Cash in hand ₦ 800Closing stock ₦ 5 600bank overdraft ₦ 3 000    The average stock is", "images": [], "options": {"A": "₦ 1,600", "B": "₦ 4,800", "C": "₦ 5,600", "D": "₦ 9,600"}, "answer": "B", "explanation": "The average stock is calculated by adding the opening stock and the closing stock, then dividing by 2. In this case, the opening stock is ₦ 4 000 and the closing stock is ₦ 5 600. Therefore, the average stock is (₦ 4 000 + ₦ 5 600) / 2 = ₦ 4 800.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>12", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Use the following information to answer questions 11 to 13.  The following information relates to Mallam Amidu Kachella for the year ended 31/12/2005  Opening stock ₦ 4 000Purchases ₦ 16 000Sales ₦ 30 000Debtors ₦ 6 500Creditors ₦ 4 200Cash in hand ₦ 800Closing stock ₦ 5 600bank overdraft ₦ 3 000  The current liability is", "images": [], "options": {"A": "₦ 1 200", "B": "₦ 3 000", "C": "₦ 4 200", "D": "₦ 7 200"}, "answer": "D", "explanation": "Current liabilities are the company's debts or obligations that are due within one year. In this case, the current liabilities are the creditors (₦ 4 200) and the bank overdraft (₦ 3 000). Therefore, the total current liability is ₦ 4 200 + ₦ 3 000 = ₦ 7 200.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>13", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the following information to answer questions 11 to 13.  The following information relates to Mallam Amidu Kachella for the year ended 31/12/2005  Opening stock ₦ 4 000Purchases ₦ 16 000Sales ₦ 30 000Debtors ₦ 6 500Creditors ₦ 4 200Cash in hand ₦ 800Closing stock ₦ 5 600bank overdraft ₦ 3 000  The cost of goods sold is", "images": [], "options": {"A": "₦ 10,000", "B": "₦ 14,400", "C": "₦ 15,600", "D": "₦ 20,200"}, "answer": "B", "explanation": "The cost of goods sold (COGS) is calculated as the opening stock plus purchases minus closing stock. In this case, COGS = ₦4,000 (opening stock) + ₦16,000 (purchases) - ₦5,600 (closing stock) = ₦14,400. Therefore, the correct option is 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>14", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "When the public wants to buy more of a company's shares than has been offered for sale, the share is said to be", "images": [], "options": {"A": "right issue", "B": "over subscribed", "C": "Refrigerator", "D": "School exercise books"}, "answer": "B", "explanation": "A share is over-subscribed when it is in excess of the number offered for sale.  - Over-valued is when the price sold is higher than what is expected   - quoted at premium is not a means of quoting shares  - Right issue implies that when a company is established, it may raise further capital by offering the shares concerned to existing members on favourable terms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>15", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Which of the following goods has the lowest rate of turnover?", "images": [], "options": {"A": "Staple foods", "B": "Office stationary", "C": "Refrigerator", "D": "School exercise books"}, "answer": "C", "explanation": "The rate of turnover refers to how quickly an item is sold and needs to be replaced. Staple foods and office stationary are typically sold and replaced quickly, while items like refrigerators are sold less frequently due to their higher cost and longer lifespan. Therefore, the correct option is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>16", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following is not a duty of a credit union?", "images": [], "options": {"A": "Helping members to save", "B": "Granting loans", "C": "Advising on the use of funds", "D": "Confirming members indebtedness"}, "answer": "D", "explanation": "A credit union is a member-owned financial cooperative, controlled by its members and operated on the principle of people helping people, providing its members credit at competitive rates as well as other financial services. The duties of a credit union include helping members to save, granting loans, and advising on the use of funds. Confirming members' indebtedness is not a duty of a credit union. It's the responsibility of the individual members to manage their own debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>17", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An association formed to protect the interest of buyers of various commodities is known as", "images": [], "options": {"A": "Chamber of commerce", "B": "Employers Association", "C": "Consumer association", "D": "Manufacturers Association"}, "answer": "C", "explanation": "A consumer association is an organization that protects the interests of consumers, or buyers, of various commodities. They advocate for consumer rights, provide information and advice about products and services, and sometimes take collective action on behalf of consumers. The other options, such as Chamber of Commerce, Employers Association, and Manufacturers Association, are not primarily focused on protecting the interests of buyers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>18", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "An outright prohibition on the important of goods to a country is referred to as", "images": [], "options": {"A": "quota", "B": "tariff", "C": "embargo", "D": "devaluation"}, "answer": "C", "explanation": "An embargo is an official ban on trade or other commercial activity with a particular country. It is an outright prohibition on the import or export of goods to a country. A quota is a limited quantity of a particular product that under official controls can be produced, exported, or imported. A tariff is a tax or duty to be paid on a particular class of imports or exports. Devaluation is the reduction of the value of a currency with respect to those goods, services or other monetary units with which that currency can be exchanged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>19", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following is not concerned about consumer protection?", "images": [], "options": {"A": "Foods and Drugs Act", "B": "Trade Descriptions Act", "C": "Price Control Act", "D": "General Agreement on Tariffs and Trade"}, "answer": "D", "explanation": "The General Agreement on Tariffs and Trade (GATT) is an international trade agreement that aims to promote international trade by reducing or eliminating trade barriers such as tariffs or quotas. It is not directly concerned with consumer protection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>20", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The size of profit of a business is measured by the", "images": [], "options": {"A": "closing stock", "B": "opening stock", "C": "paid-up-capital", "D": "working capital"}, "answer": "D", "explanation": "The working capital of an organization determines the profit of the business. The working capital is calculated as:", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>21", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following assesses duties payable on imports and exports?", "images": [], "options": {"A": "Port Authority", "B": "central bank", "C": "Customs and Excise Authority", "D": "Export Promotional Council"}, "answer": "C", "explanation": "The Customs and Excise Authority is responsible for assessing duties payable on imports and exports. They determine the value of goods and services that are imported or exported and calculate the appropriate duty to be paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>22", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following trends in retailing provides the convenience of shopping without cash", "images": [], "options": {"A": "Automatic vending", "B": "Self-service", "C": "Credit card", "D": "Window display"}, "answer": "C", "explanation": "The trend in retailing that provides the convenience of shopping without cash is the use of credit cards. Credit cards allow consumers to purchase goods or services on credit, meaning they can buy now and pay later. This eliminates the need for carrying cash and provides a convenient and secure method of payment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>23", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "The place where dutiable goods are kept until the duties on them are paid is", "images": [], "options": {"A": "customs warehouse", "B": "public warehouse", "C": "bonded warehouse", "D": "the wharf"}, "answer": "C", "explanation": "A bonded warehouse is a designated area where imported goods can be stored until the required customs duties and taxes are paid. It's essentially a secure storage facility under customs control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>24", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The provision of dredging and dry dock facilities at any sea port is the responsibility of", "images": [], "options": {"A": "Ports Harbour Authority", "B": "Customers and Excise Authority", "C": "National Health Authority", "D": "National Water and Electric Authority"}, "answer": "A", "explanation": "The provision of dredging and dry dock facilities at any sea port is the responsibility of the Ports Harbour Authority. Dredging is the process of removing sediment and debris from the bottom of bodies of water, and dry dock facilities are used for the construction, maintenance, and repair of ships. These are essential services for the operation of a sea port, and are typically managed by the port authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>25", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The time allowed for uploading and loading a ship is referred to as", "images": [], "options": {"A": "demurrage", "B": "lay days", "C": "charter party", "D": "charter by demise"}, "answer": "B", "explanation": "Lay days is the term used to refer to the time allowed for uploading and loading a ship. It is the period agreed between the parties during which the owner will make and keep the vessel available for loading and discharging without payment additional to the freight. Demurrage refers to the charges that the charterer pays to the ship owner for its delayed operations of loading/unloading. Charter party is a contract of affreightment in writing, signed by the shipowner and the charterer, describing the vessel and cargo, the port and the price. Charter by demise is a contract for the hire of a vessel where the charterer takes over the management of the vessel from the shipowner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>26", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following institutions does not belong to the capital market?", "images": [], "options": {"A": "Commercial banks", "B": "Development banks", "C": "Mortgage banks", "D": "Insurance companies"}, "answer": "A", "explanation": "Commercial banks do not belong to the capital market. The capital market is a market for securities (debt or equity), where business enterprises (companies) and governments can raise long-term funds. It is defined as a market in which money is provided for periods longer than a year. Commercial banks, on the other hand, are part of the money market, which provides short term fund. The money market is a component of the financial markets for assets involved in short-term borrowing, lending, buying and selling with original maturities of one year or less.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>27", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The beneficiary of a cheque is called", "images": [], "options": {"A": "acceptor", "B": "drawee", "C": "drawer", "D": "payee"}, "answer": "D", "explanation": "The beneficiary of a cheque is called the payee. In the context of a cheque, the drawer is the party that writes the cheque, the drawee is the bank that the cheque is drawn on and is asked to pay the amount on the cheque to the payee. The payee is the party that receives the amount of the cheque from the drawee bank.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2006>28", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A speculator who applies for a new issue of shares without the intention of keeping them is", "images": [], "options": {"A": "bull", "B": "stag", "C": "bear", "D": "jobber"}, "answer": "B", "explanation": "A speculator who applies for a new issue of shares without the intention of keeping them is known as a 'stag'. This term is used in the stock market to refer to a speculator who buys shares in an initial public offering (IPO) with the intention of selling them immediately after they start trading in order to make a quick profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>29", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "Which of the following is not the duty of an agent to the principal?", "images": [], "options": {"A": "Acting in good faith", "B": "Rendering accurate account", "C": "Disclosing all profits made", "D": "Making secret profit"}, "answer": "D", "explanation": "The duty of an agent to the principal includes acting in good faith, rendering accurate account, and disclosing all profits made. However, making secret profit is not a duty of an agent to the principal. In fact, it is considered unethical and a breach of fiduciary duty for an agent to make a secret profit at the expense of the principal.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>30", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The amount the assured receives if he decide to discontinue the life policy is known as", "images": [], "options": {"A": "refund value", "B": "net value", "C": "surrender value", "D": "sum assured"}, "answer": "C", "explanation": "The amount the assured receives if he decides to discontinue the life policy is known as the 'surrender value'. This is the cash amount payable to a policyholder by the life insurance company upon cancellation of the policy before its maturity or the insured event has occurred.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>31", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A specialized market where stock and shares are bought and sold is", "images": [], "options": {"A": "money market", "B": "commodity exchange market", "C": "perfect market", "D": "stock exchange market"}, "answer": "D", "explanation": "A stock exchange market is a specialized market where securities, such as stocks and shares, are bought and sold. It is a place where buyers and sellers meet to trade in securities. The other options do not accurately describe a market where stocks and shares are traded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>32", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The principal where many insurance companies join together to compensate one policy holder is called", "images": [], "options": {"A": "contribution", "B": "subrogration", "C": "compensation", "D": "indemnity"}, "answer": "A", "explanation": "The principle where many insurance companies join together to compensate one policy holder is called contribution. This is a principle in insurance where, in the event of loss, if more than one insurer is covering the risk, all insurers will contribute towards the loss in proportion to the amount of risk each insurer has taken on. The other options do not accurately describe this principle.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>33", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Demurrage is paid by a vessel for", "images": [], "options": {"A": "overloading", "B": "travelling along unplanned route", "C": "delay at the port", "D": "not using the services at the wharf"}, "answer": "C", "explanation": "Demurrage is a fee paid by a vessel for delay at the port beyond the stipulated time. It is a penalty for exceeding the time allowed for loading or unloading. The other options do not accurately describe the reason for paying demurrage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>34", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "In a limited partnership one of the members must be", "images": [], "options": {"A": "a general partner", "B": "a nominal partner", "C": "an active partner", "D": "a dominant partner"}, "answer": "A", "explanation": "In a limited partnership, one of the members must be a general partner. A general partner is a partner who is actively involved in the day-to-day operations of the business and who has unlimited liability for the debts and obligations of the partnership. This is different from a limited partner, who contributes capital but does not participate in the management of the business and whose liability is limited to the amount of their investment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>35", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "It is safer and quicker to transport petrol and gas by", "images": [], "options": {"A": "rail", "B": "road", "C": "pipeline", "D": "air"}, "answer": "C", "explanation": "It is safer and quicker to transport petrol and gas by pipeline. Pipelines are designed to transport large quantities of gas or liquid over long distances. They are safer because they are less likely to be involved in accidents compared to rail or road transport. They are also quicker because they operate continuously and are not subject to traffic delays.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>36", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The process of taking over the management and control of a privately owned business by government is", "images": [], "options": {"A": "indigenization", "B": "nationalization", "C": "participation", "D": "privatization"}, "answer": "B", "explanation": "The process of taking over the management and control of a privately owned business by government is called nationalization. Nationalization is a process whereby a national government or state takes over the private industry, organization, or assets into public ownership by an Act or ordinance or some other kind of orders. It is the opposite of privatization.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>37", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Who among the following is a middleman?", "images": [], "options": {"A": "Manufacturer", "B": "Agent", "C": "Insurer", "D": "Consumer"}, "answer": "B", "explanation": "An agent is a middleman in commerce. They act as an intermediary between the manufacturer and the consumer, facilitating transactions between the two. Manufacturers produce goods, insurers provide insurance services, and consumers are the end users of goods and services, hence they are not considered middlemen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2006>38", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : MEANING AND TYPES", "question": "The monopoly right granted to an inventor is a", "images": [], "options": {"A": "trademark", "B": "brand name", "C": "patent", "D": "copyright"}, "answer": "C", "explanation": "A patent is a monopoly right granted to an inventor. It gives the inventor exclusive rights to their invention for a certain period of time, preventing others from making, using, selling, or importing the invention without the inventor's permission. Trademarks protect brands and logos, copyrights protect original works of authorship, and brand names are simply the names given to a product or service by a company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>39", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The process of putting goods in attractive packets to arouse the interest of customers is", "images": [], "options": {"A": "collation", "B": "wrapping", "C": "branding", "D": "packaging"}, "answer": "D", "explanation": "The process of putting goods in attractive packets to arouse the interest of customers is known as packaging. Packaging not only protects the product during transportation from the manufacturer to the retailer, but it also prevents damage while the product sits on retail shelves. Moreover, packaging design is also crucial as it is the first thing that the consumer sees and it can directly influence their purchasing decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>40", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is not a reason for nationalization", "images": [], "options": {"A": "Encouraging foreign investors", "B": "Reducing the remittance of profits abroad", "C": "training local entrepreneurs", "D": "Training local hunters"}, "answer": "D", "explanation": "Nationalization refers to the process of a government taking control of a company or industry, which can occur for a variety of reasons. The options provided are generally reasons for nationalization except for 'Training local hunters'. This is not a reason for nationalization as it does not directly relate to the control or management of industries or companies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>41", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Any activity aimed at finding out the wants of consumers and applying them at a profit is referred to as", "images": [], "options": {"A": "promotion", "B": "marketing", "C": "segmentation", "D": "penetration"}, "answer": "B", "explanation": "The activity described in the question is marketing. Marketing involves identifying the needs and wants of consumers and finding ways to meet these needs and wants in a profitable manner. Promotion, segmentation, and penetration are all components or strategies of marketing, but they do not encompass the entire process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>42", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : THE ROLE OF BUREAU DE CHANGE", "question": "The reduction of the value of a country's currency in relation to other country's currencies in", "images": [], "options": {"A": "devaluation", "B": "inflation", "C": "deregulation", "D": "fluctuation"}, "answer": "A", "explanation": "The reduction of the value of a country's currency in relation to other countries' currencies is referred to as devaluation. Devaluation is a monetary policy tool used by governments and central banks to reduce the value of a country's currency relative to other currencies. Inflation refers to the general increase in prices and fall in the purchasing value of money. Deregulation refers to the reduction or elimination of government power in a particular industry. Fluctuation refers to the rise and fall in value or price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2006>43", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Which of the following is the main purpose of a third party insurance? To", "images": [], "options": {"A": "indemnify an injured outsider", "B": "indemnify the insured", "C": "protect the vehicle against theft", "D": "compensate the driver for injuries sustained"}, "answer": "A", "explanation": "Third party insurance is a type of liability insurance purchased by an insured (first-party) from an insurer (second party) for protection against the claims of another (third party). The first party is responsible for their damages or losses, regardless of the cause of those damages. In this case, the third party insurance is meant to indemnify or compensate an injured outsider.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>44", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The term \"utmost good faith\" in insurance requires that the insured must", "images": [], "options": {"A": "not make profit from any loss suffered", "B": "receive his compensation fully in the event of loss", "C": "disclose all relevant facts on what is being insured", "D": "pay his premium regularly"}, "answer": "C", "explanation": "The term 'utmost good faith' in insurance refers to a legal principle that requires both parties to an insurance contract to deal in good faith, particularly in providing all necessary information. Therefore, the insured must disclose all relevant facts on what is being insured.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>45", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Commercial banks usually settle their interbank indebtedness through the", "images": [], "options": {"A": "money market", "B": "clearing house", "C": "discount house", "D": "stock exchange"}, "answer": "B", "explanation": "Commercial banks usually settle their interbank indebtedness through the clearing house. A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>46", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following retail outlets is described as selling without shops?", "images": [], "options": {"A": "Multiple stores?", "B": "Supermarkets", "C": "Mail order business", "D": "Department stores"}, "answer": "C", "explanation": "A mail order business is a type of retail outlet that sells products directly to customers through mail. The customers place orders for the desired products via mail, and the products are then delivered to them. This type of business does not require a physical shop or store.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>47", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following arranges for the conveyance of goods abroad?", "images": [], "options": {"A": "Port Authority", "B": "Customers and Excise Authority", "C": "Airports Authority", "D": "Export Promotion Council"}, "answer": "D", "explanation": "The Export Promotion Council is responsible for arranging the conveyance of goods abroad. They promote a country's exports by providing various services, including export advisory services, export marketing assistance, and organizing trade fairs and exhibitions abroad.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>48", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The difference between the cost of goods sold and the sales value is known as", "images": [], "options": {"A": "net profit", "B": "net loss", "C": "gross profit or loss", "D": "surplus"}, "answer": "C", "explanation": "The difference between the cost of goods sold and the sales value is known as gross profit. Gross profit is a company's total revenue minus the cost of goods sold. It represents the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>49", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : FEATURES/CHARACTERISTICS", "question": "Which of the following is not a feature of a sole trader?", "images": [], "options": {"A": "Quick decision making", "B": "Guaranteed profits", "C": "Unlimited liability", "D": "Bearing losses alone"}, "answer": "B", "explanation": "A sole trader, also known as a sole proprietor, is a type of business entity that is owned and run by one individual and where there is no legal distinction between the owner and the business. While it is true that a sole trader has quick decision making, unlimited liability, and bears losses alone, guaranteed profits is not a feature of a sole trader. Profits are not guaranteed in any business as they depend on various factors such as market conditions, competition, and the business strategy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2006>50", "subject": "Commerce", "year": "2006", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A practice where producers of the same product come together to advertise is known as", "images": [], "options": {"A": "mass advertising", "B": "institutional advertising", "C": "direct advertising", "D": "persuasive advertising"}, "answer": "A", "explanation": "Mass or generic advertising is one in which manufacturers of similar products come together to jointly advertise their products to the consuming public.   Direct Advertisement - is aimed at providing information to a section, target market with relatively similar needs.   - Persuasive advertising is one which tries to persuade customers to buy a particular product as being different from other brands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>1", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following was not used as a medium of exchange by the early Europeans that came to West Africa?", "images": [], "options": {"A": "Pounds and shillings", "B": "Copper manillas", "C": "Iron bars", "D": "Cowries"}, "answer": "A", "explanation": "The early Europeans that came to West Africa used items like copper manillas, iron bars, and cowries as a medium of exchange. However, they did not use pounds and shillings. These are modern forms of currency that were not in use during the early periods of European exploration in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>2", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "The ancillary of trade which ensures that people gain access to facts pertaining to goods is", "images": [], "options": {"A": "insurance", "B": "advertising", "C": "warehousing", "D": "banking"}, "answer": "B", "explanation": "Advertising is the ancillary of trade that ensures that people gain access to facts pertaining to goods. It is a form of communication used to persuade or inform an audience (viewers, readers, or listeners) about a product, service, or idea. Insurance, warehousing, and banking do not directly provide information about goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>3", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following is classified as an extractive industry?", "images": [], "options": {"A": "Digging for minerals", "B": "Digging for road building", "C": "Canning of tomato puree", "D": "Assembling of cars"}, "answer": "A", "explanation": "An extractive industry is one that involves the extraction of raw materials from the earth to be used by consumers. The extracted materials are then converted into finished goods. Digging for minerals is an example of an extractive industry. Digging for road building, canning of tomato puree, and assembling of cars are not extractive industries as they do not involve the extraction of raw materials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>4", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Who among the following does not render direct service?", "images": [], "options": {"A": "Teachers", "B": "Musicians", "C": "Doctors", "D": "Retailers"}, "answer": "D", "explanation": "Retailers do not render direct service. They are intermediaries in the distribution process. They buy goods from manufacturers or wholesalers and sell them to the end consumers. They do not provide a service directly to the consumers, rather they facilitate the process of getting the goods to the consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>5", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partnership cannot raise its capital by", "images": [], "options": {"A": "selling share to the public", "B": "personal contribution of partners", "C": "admission of new partners", "D": "undistributed profits."}, "answer": "A", "explanation": "A partnership cannot raise its capital by selling shares to the public. This is because a partnership is a business entity formed by two or more individuals to carry on a business. The partners contribute capital to the business and share the profits and losses. They cannot sell shares to the public to raise capital as this is a characteristic of a corporation, not a partnership.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>6", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Which of the following is not required in the Mail Order business?", "images": [], "options": {"A": "Warehouse", "B": "Catalogue", "C": "Display room", "D": "Post office"}, "answer": "C", "explanation": "A display room is not required in the Mail Order business. Mail order is a type of business in which customers place orders for products via mail, telephone, or online, and the products are then delivered to them. There is no need for a display room in this type of business because customers do not visit a physical location to view the products. Instead, they rely on catalogs or online descriptions to make their purchasing decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>7", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The staff responsible for the calculation of probability of losses in insurance is the", "images": [], "options": {"A": "Actuary", "B": "Underwriter", "C": "Broker", "D": "Solicitor"}, "answer": "A", "explanation": "An actuary is a business professional who deals with the financial impact of risk and uncertainty. Actuaries use mathematics, statistics, and financial theory to study uncertain future events, especially those of concern to insurance and pension programs. They evaluate the likelihood of those events, design creative ways to reduce the likelihood and decrease the impact of adverse events that actually do occur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>8", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The rate at which the country's import exchanges for its export is known as", "images": [], "options": {"A": "Term of trade", "B": "Balance of trade", "C": "Rate of exchange", "D": "Terms of exchange"}, "answer": "A", "explanation": "The term of trade is the rate at which one country's goods exchange for those of another. It is the ratio of export prices to import prices. It shows the purchasing power of one country's currency in relation to another country's currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>9", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : FEATURES AND IMPORTANCE", "question": "Where a limited partner exists in a partnership,", "images": [], "options": {"A": "no active partner is needed", "B": "other partners must be nominal", "C": "at least one ordinary partner must be there", "D": "at least one partner must be a legal practitioner"}, "answer": "C", "explanation": "In a limited partnership, at least one partner must be a general partner, and at least one partner must be a limited partner. The general partner has the same role as all partners in a general partnership, while the limited partner is not involved in the day-to-day operations and has limited liability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>10", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Which of the following is best organized as a partnership?", "images": [], "options": {"A": "Drilling and marketing of crude oil", "B": "Brewing and distribution of beer", "C": "Designing and building of houses", "D": "Assembling and marketing of vehicles"}, "answer": "C", "explanation": "A partnership is a type of business where two or more people share ownership, each contributing resources such as property, skills, or capital to the business. Designing and building of houses is best organized as a partnership because it involves different skills and resources that can be contributed by different partners. For example, one partner could be an architect (designing) and the other a builder (building).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>11", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Public enterprises are financed mainly by", "images": [], "options": {"A": "the shareholders", "B": "commercial banks", "C": "government grants", "D": "the world bank"}, "answer": "C", "explanation": "Public enterprises are primarily financed by government grants. These are businesses that are owned and operated by the government, and their funding comes from the government's budget, which is raised through taxes and other sources of public revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>12", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Contributing money to buy equipment for making and marketing of product is a feature of", "images": [], "options": {"A": "thrift societies", "B": "public limited companies", "C": "consumer's cooperatives", "D": "producer's cooperatives"}, "answer": "D", "explanation": "Contributing money to buy equipment for making and marketing of product is a feature of producer's cooperatives. A producer's cooperative is a type of cooperative that is owned and operated by its members, who pool their resources to purchase equipment and other necessary items for production and marketing of their products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>13", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The operation of a private company is guided by the", "images": [], "options": {"A": "deed", "B": "certificate trading", "C": "certificate of incorporation", "D": "company's act"}, "answer": "C", "explanation": "The operation of a private company is guided by the 'Certificate of Incorporation'. This is a legal document relating to the formation of a company or corporation. It is a license to form a corporation issued by the state government or, in some jurisdictions, by non-governmental entity/corporation. Its precise meaning depends upon the legal system in which it is used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>14", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The various right attached to different  classes of shares are stated in the", "images": [], "options": {"A": "articles of association", "B": "memorandum of association", "C": "balance sheet", "D": "prospectus"}, "answer": "A", "explanation": "The various rights attached to different classes of shares are stated in the 'Articles of Association'. The Articles of Association is a document that specifies the regulations for a company's operations and defines the company's purpose. The document lays out how tasks are to be accomplished within the organization, including the process for appointing directors and the handling of financial records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>15", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following gets extra dividend after its due fixed rate of dividend?", "images": [], "options": {"A": "Preference shares", "B": "Cumulative preference shares", "C": "Ordinary shares", "D": "Participating preferred shares"}, "answer": "D", "explanation": "The 'Participating Preferred Shares' get extra dividend after its due fixed rate of dividend. Participating Preferred Shares, in addition to their stated dividend, are eligible to receive extra dividends if the company achieves certain financial goals. The holders of these shares will receive their dividends before the common shareholders receive theirs, and these dividends may be higher than the latter.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>16", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "A company may be wound up when", "images": [], "options": {"A": "there is a disagreement among the directors", "B": "there are too many shareholders", "C": "many of the shareholders die", "D": "its product competes with that of the government"}, "answer": "A", "explanation": "Disagreement among directors may bring the company to an end.  - Too many shareholders is not a limit since the number is to infinity.  - Perpetual existence allows for continuity even after the death of shareholders  - Competition is not an hindrance to continuity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>17", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "If the opening is  stock is Le200, cost of goods sold Le2,400, and closing stock Le120, then the rate of turnover", "images": [], "options": {"A": "20 times", "B": "15 times", "C": "12 times", "D": "7.5 times"}, "answer": "B", "explanation": "rate of turn over =   Cost of goods sold/Avg. Stock      Avg. stock =   Opening stock + closing stock/2      Avg. stock = 200 + 120/2      = 320/2 = 160  R.O.T = COGS/Av Stock      2400/160 = 15times.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>18", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The money used by Njie & Co. Ltd in running the day-to-day activities of the business is represented by", "images": [], "options": {"A": "total assets less total liabilities", "B": "total assets less current liabilities", "C": "current assets, less stock", "D": "current assets less current liabilities"}, "answer": "D", "explanation": "The money used by a company in running the day-to-day activities of the business is represented by the working capital. Working capital is calculated as current assets minus current liabilities. Therefore, the correct answer is 'current assets less current liabilities'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>19", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "A limited company has an authorized capital of 20,000,000 shares. If each share capital cost 50k and the company sold 12,000,000 shares. Its issued capital is", "images": [], "options": {"A": "N16,000,000", "B": "N10,000,000", "C": "N6,000,000", "D": "N4,000,000"}, "answer": "C", "explanation": "The issue capital is calculated as:    =  12,000,000 x 0.50k   = ₦6,000,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>20", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A document used to advertise shares for sale is", "images": [], "options": {"A": "prospectus", "B": "annual report", "C": "articles of association", "D": "memorandum of association"}, "answer": "A", "explanation": "A prospectus is a document that companies use to advertise shares for sale. It provides potential investors with detailed information about the company, its operations, and the shares being offered for sale. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>21", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "Which of the following refers to a voluntary association that represents a cross-section of business interest in an area?", "images": [], "options": {"A": "Manufacturer's Association", "B": "Chamber of commerce", "C": "Consumers' Association", "D": "Employers' Association"}, "answer": "B", "explanation": "A Chamber of Commerce is a voluntary association that represents a cross-section of business interests in a particular area. It provides a platform for businesses to network, collaborate, and advocate for their interests. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>22", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is used to show that goods imported were produced in an ECOWAS member country?", "images": [], "options": {"A": "Insurance policy", "B": "Bill of lading", "C": "Certificate of origin", "D": "Bill of exchange"}, "answer": "C", "explanation": "A Certificate of Origin is a document used in international trade. It traditionally states from what country the shipped goods originate, but 'originate' in a CO does not mean the country the goods are shipped from, but the country where the goods are actually made. This is important because it's this 'origin' that determines those 'hidden' costs such as import duty costs. Therefore, a Certificate of Origin is used to show that goods imported were produced in an ECOWAS member country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>23", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Importing goods into a country for re- exporting is known as", "images": [], "options": {"A": "home trade", "B": "retail trade", "C": "entrepot trade", "D": "counter trade"}, "answer": "C", "explanation": "Entrepot trade is a form of international trade which involves importing goods from one country, then re-exporting them to another. This is done to take advantage of price differences between the two markets. The goods are not substantially transformed in the process. Therefore, importing goods into a country for re-exporting is known as entrepot trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>24", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is the function of a small retailer?", "images": [], "options": {"A": "Financing manufacturers", "B": "Warehousing of goods", "C": "Branding of goods", "D": "Selling to consumers"}, "answer": "D", "explanation": "A small retailer's primary function is to sell goods and services to consumers. They purchase goods from wholesalers or directly from manufacturers and sell them in small quantities to the end-users (consumers). Therefore, the function of a small retailer is selling to consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>25", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The content of a bill of lading does not include the", "images": [], "options": {"A": "name of the shipper", "B": "date and place of shipment", "C": "name and destination of the vessel", "D": "demurrage payable"}, "answer": "D", "explanation": "A bill of lading is a legal document between the shipper of goods and the carrier detailing the type, quantity and destination of the goods being carried. It does not include the 'demurrage payable'. Demurrage is a charge payable to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>26", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Who is responsible for the payment of the bill in a documentary credit?", "images": [], "options": {"A": "Exporter", "B": "Importer", "C": "Importers bank", "D": "Exporters bank"}, "answer": "B", "explanation": "In a documentary credit, the importer is responsible for the payment of the bill. A documentary credit is a commitment by a bank on behalf of the buyer (importer) that payment will be made to the beneficiary (exporter), provided that the terms and conditions stated in the credit have been met.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>27", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "A popular product priced low to attract a large number of buyers to a shop is called", "images": [], "options": {"A": "loss leader", "B": "capital goods", "C": "seasonal goods", "D": "price ring"}, "answer": "A", "explanation": "A popular product priced low to attract a large number of buyers to a shop is called a 'loss leader'. A loss leader is a product sold at a low price (at cost or below cost) to stimulate other profitable sales. It is a kind of sales promotion, in other words, a marketing strategy for a store to lead in customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>28", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Centralized buying and decentralized selling are features of", "images": [], "options": {"A": "cooperative wholesalers", "B": "department stores", "C": "mail order business", "D": "multiple stores"}, "answer": "D", "explanation": "Centralized buying and decentralized selling are features of multiple stores. Centralized buying refers to the practice of purchasing all goods for a business (or a network of businesses) from a single, centralized location. Decentralized selling, on the other hand, refers to the practice of selling these goods across multiple, geographically dispersed locations. This is a common practice in multiple stores or chain stores, where all purchasing decisions are made at the head office (centralized buying), and the goods are then sold in stores across different locations (decentralized selling).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>29", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a feature of the self-service store?", "images": [], "options": {"A": "It is found mainly in the urban areas", "B": "It offers steady employment opportunities", "C": "Goods carry price tag", "D": "It operates on a large floor space"}, "answer": "B", "explanation": "The statement 'It offers steady employment opportunities' is not a feature of the self-service store. Self-service stores are characterized by customers serving themselves, which reduces the need for a large number of employees. Therefore, these stores do not necessarily offer steady employment opportunities. Other features of self-service stores include being found mainly in urban areas, goods carrying price tags, and operating on a large floor space.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>30", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "If a share is sold at a price below its face value, it is sold", "images": [], "options": {"A": "above par", "B": "at a discount", "C": "at par", "D": "at premium"}, "answer": "B", "explanation": "If a share is sold at a price below its face value, it is sold at a discount. The face value of a share is its nominal value as stated by the issuing company. When a share is sold for less than this amount, it is said to be sold 'at a discount'. This is different from selling 'at par' (at the face value) or 'above par'/'at premium' (more than the face value).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>31", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Mr. Ojo buys a book from a bookseller and pays cash. The bookseller will issue him a", "images": [], "options": {"A": "debit note", "B": "credit note", "C": "voucher", "D": "receipt"}, "answer": "D", "explanation": "When a customer pays cash for a product or service, the seller issues a receipt. A receipt is a document acknowledging that a person has received money or property in payment following a sale or other transfer of goods or provision of a service. Therefore, the bookseller will issue Mr. Ojo a receipt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>32", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A limited company can raise long term capital through the", "images": [], "options": {"A": "commodity market", "B": "stock exchange market", "C": "export market", "D": "foreign exchange market"}, "answer": "B", "explanation": "A limited company can raise long-term capital through the stock exchange market. The stock exchange market is a marketplace where buyers and sellers trade shares of publicly held companies. Companies can raise capital by issuing shares of stock in a public offering. This capital can then be used for a variety of purposes, including funding operations or acquiring other companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>33", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not a reason of dishonouring a cheque?", "images": [], "options": {"A": "Insufficient funds in the drawer's bank", "B": "When the cheque is stale", "C": "Amount in figure differs from amount in words", "D": "Poor handwriting"}, "answer": "D", "explanation": "Poor handwriting is not a valid reason for a bank to dishonour a cheque. Banks will dishonour a cheque for reasons such as insufficient funds in the drawer's bank, when the cheque is stale (i.e., it is presented for payment six months after the date of issue), or when the amount in figures differs from the amount in words. However, as long as the account number, sort code, and signature are clear, the bank should honour the cheque regardless of the quality of the handwriting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>34", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not the function of the central bank?", "images": [], "options": {"A": "Banker to the government", "B": "Banker's bank", "C": "Issuance of currency notes", "D": "Granting loans to the public"}, "answer": "D", "explanation": "The central bank does not grant loans to the public. The central bank's primary functions include issuing currency, managing the country's money supply and interest rates, and providing a banking service to the government and commercial banks. Granting loans to the public is typically the function of commercial banks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>35", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Treasury bills are bought and sold in the", "images": [], "options": {"A": "Capital market", "B": "Open market", "C": "Commodity market", "D": "Money market"}, "answer": "D", "explanation": "Treasury bills are bought and sold in the money market which is a market for short term loans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>36", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following is a legal tender?", "images": [], "options": {"A": "Bank notes", "B": "Bank drafts", "C": "Central bank cheque", "D": "Traveller's cheque"}, "answer": "A", "explanation": "Bank notes are a legal tender. Legal tender is a medium of payment recognized by a legal system to be valid for meeting a financial obligation. Bank notes, issued by the central bank, are universally accepted as a form of payment, thus making them a legal tender. Other options like bank drafts, central bank cheques, and traveller's cheques are not legal tender as they are not universally accepted for all debts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>37", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is referred to as the oldest form of insurance?", "images": [], "options": {"A": "marine insurance", "B": "Burglary insurance", "C": "Whole life insurance", "D": "Accident insurance"}, "answer": "A", "explanation": "Marine insurance is considered the oldest form of insurance. It originated in the 14th century in northern Italy with the maritime loan, which was an early form of marine insurance. None of the other options predate marine insurance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>38", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "An open cheque is one", "images": [], "options": {"A": "on which the amount is written only in figures", "B": "Which has no name", "C": "Which can be cashed over the counter", "D": "Which has no specific amount written on it"}, "answer": "C", "explanation": "An open cheque is a cheque that is not crossed on the left corner and payable at the counter of the bank. An open cheque may be a bearer cheque or an order one. It means the bank can pay the cheque amount to the person who presents it, even if he is not the drawer or the payee.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>39", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Use the following information to answer the question  Madam Tope insured her shop premises for the sum of D60,000, when insuring the shop, she did not tell the Insurance Company that she cooks in the shop but told the insurance company that she sells second hand clothes. Hence she insured her store against natural causes. Tope's shop got burnt yesterday by fire from the cooking pot.    Which of the following insurance principles was breached by Madam Tope?", "images": [], "options": {"A": "Insurable interest", "B": "Contribution", "C": "Utmost goods faith", "D": "Subrogation"}, "answer": "C", "explanation": "The principle of Utmost Good Faith, also known as Uberrima Fides, is a fundamental principle of insurance. According to this principle, the insurance contract must be signed by both parties (i.e., insurer and insured) in an absolute good faith or belief or trust. The person getting insured must willingly disclose and surrender to the insurer his complete true information regarding the subject matter of insurance. In this case, Madam Tope did not disclose that she cooks in the shop, which is a breach of this principle.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>40", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Use the following information to answer the question  Madam Tope insured her shop premises for the sum of D60,000, when insuring the shop, she did not tell the Insurance Company that she cooks in the shop but told the insurance company that she sells second hand clothes. Hence she insured her store against natural causes. Tope's shop got burnt yesterday by fire from the cooking pot.   Which of the following insurance principle will prevent her from claiming compensation?", "images": [], "options": {"A": "Indemnity", "B": "Insurable interest", "C": "Proximate cause", "D": "Utmost goods faith"}, "answer": "D", "explanation": "The principle of 'Utmost Good Faith' will prevent Madam Tope from claiming compensation. This principle states that all parties in an insurance contract must deal in good faith, making a full declaration of all material facts in the insurance proposal. This means that the insured must disclose all facts about the risk to be insured. In this case, Madam Tope did not disclose that she cooks in the shop, which is a material fact that could affect the risk of fire. Therefore, the insurance company can refuse to pay the claim due to the breach of this principle.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>41", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Use the following information to answer the question  Madam Tope insured her shop premises for the sum of D60,000, when insuring the shop, she did not tell the Insurance Company that she cooks in the shop but told the insurance company that she sells second hand clothes. Hence she insured her store against natural causes. Tope's shop got burnt yesterday by fire from the cooking pot.   The amount of D60,000 quoted represents", "images": [], "options": {"A": "premium", "B": "sum insured", "C": "contribution", "D": "compensation"}, "answer": "B", "explanation": "The amount of D60,000 quoted represents the 'sum insured'. The sum insured is the maximum amount that an insurance company will pay out for a claim. It is the amount for which the policyholder's shop was insured. This is the value that the insurance company would pay out if the shop was completely destroyed, as in this case.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2007>42", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "If the chatter delayed the ship beyond the days, he is asked to pay", "images": [], "options": {"A": "dead freight", "B": "demurrage", "C": "lump sum", "D": "freight"}, "answer": "B", "explanation": "If the charterer delayed the ship beyond the agreed days, he is asked to pay 'demurrage'. Demurrage is a charge payable to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed. So, if the charterer causes delays, they would be liable to pay this charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>43", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following involves the delivery of mails to a traveller without fixed address?", "images": [], "options": {"A": "Speed post", "B": "Replied paid", "C": "Recorded delivery", "D": "Poste restante"}, "answer": "D", "explanation": "Poste restante is a service where the post office holds mail until the recipient calls for it. It is a common method for people traveling abroad, who require a fixed address to receive mail. None of the other options provide this service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>44", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A document showing full details of the goods and passengers carried in a ship or aircraft is", "images": [], "options": {"A": "Bill lading", "B": "Airway bill", "C": "Manifest", "D": "Indent"}, "answer": "C", "explanation": "A manifest is a document listing the cargo, passengers, and crew of a ship, aircraft, or vehicle, for the use of customs and other officials. None of the other options provide a comprehensive list of both goods and passengers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>45", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following is not a means of water transport?", "images": [], "options": {"A": "Liner", "B": "Tanker", "C": "Truck", "D": "Barge"}, "answer": "C", "explanation": "A truck is a means of road transport, not water transport. Liner, Tanker, and Barge are all types of ships, which are means of water transport.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>46", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following provide evidence of receipt of an important document sent through the post?", "images": [], "options": {"A": "Recorded delivery service", "B": "Air mail service", "C": "Letter post", "D": "Express delivery service"}, "answer": "A", "explanation": "A recorded delivery service provides evidence of receipt of an important document sent through the post. This is because the recipient is required to sign upon delivery, and a copy of this signature is kept as proof of delivery. The other options do not necessarily provide this proof.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>47", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "Which of the following is an advantage of transportation by sea?", "images": [], "options": {"A": "Goods can be delivered from door to door", "B": "It is cheaper means of transporting goods", "C": "It is accident free", "D": "It is the fastest means of transport"}, "answer": "B", "explanation": "Transportation by sea is often cheaper than other methods of transportation, especially for large quantities of goods. This is because ships have a large capacity and can carry a lot of cargo at once, reducing the cost per unit. The other options are not necessarily true; for example, sea transport is not the fastest means of transport, and it is not accident-free.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>48", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "Which of the following refers to the division of a market into identifiable sub-markets?", "images": [], "options": {"A": "Market research", "B": "market segmentation", "C": "market penetration", "D": "Marketing mix"}, "answer": "B", "explanation": "Market segmentation refers to the division of a market into identifiable sub-markets or segments. Each segment has similar characteristics and needs, and a company can target its products or services to these specific segments. The other options do not accurately describe this concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2007>49", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A specialist on the stock exchange who buys and sell securities in his own named is a", "images": [], "options": {"A": "Stag", "B": "Bull", "C": "Broker", "D": "Jobber"}, "answer": "D", "explanation": "A Jobber is a trader who buys and sells securities on his own account. Jobbers are specialists in the shares of a few particular companies and sit at particular places on the floor of the stock exchange. They trade on their own account, trying to predict and profit from market movements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2007>50", "subject": "Commerce", "year": "2007", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A document showing that a person has shipped certain goods through a named ship is", "images": [], "options": {"A": "bill of lading", "B": "bill of exchange", "C": "dock warrant", "D": "bill of entry"}, "answer": "A", "explanation": "A Bill of Lading is a document issued by a carrier (or their agent) to acknowledge receipt of cargo for shipment. In British English, the term relates to ship transport only, and in American English, to any type of transportation of goods. It serves as a document of title, a contract of carriage, and a receipt for goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>1", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce can be defined as the", "images": [], "options": {"A": "exchange of goods and services", "B": "distribution and exchange of goods and services", "C": "distribution of services at home", "D": "export of services"}, "answer": "B", "explanation": "Commerce is a broad term that includes all the activities that lead to the exchange of goods and services from the producer to the final consumer. It includes not only the exchange but also the distribution of goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>2", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "Which of the following is not a function of commerce?", "images": [], "options": {"A": "Facilitate mass production of goods", "B": "Assists in raising capital", "C": "Creates goods and services", "D": "Offers employment"}, "answer": "C", "explanation": "Commerce does not create goods and services. The creation of goods and services is a function of production, not commerce. Commerce involves activities that facilitate the exchange and distribution of these goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>3", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Production is defined as", "images": [], "options": {"A": "an industrial activity", "B": "creation of utilities", "C": "exchange of goods and services", "D": "changing of raw materials into finished goods"}, "answer": "D", "explanation": "Production is the process of converting raw materials into finished goods. It involves creating utilities by changing the form, place, and time to add value to the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>4", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Babou penn, a fisherman says he has all necessary materials to go to sea today, except the captain of his boat. Captain here as a factor of production, refers to", "images": [], "options": {"A": "entrepreneur", "B": "capital", "C": "labour", "D": "land"}, "answer": "A", "explanation": "In the context of factors of production, the captain of the boat can be seen as the entrepreneur. The entrepreneur is the individual who takes an idea, product, or service and does the necessary work to create a business around it. This includes taking on the risk of the venture and also managing the enterprise. In this case, the captain would be the one managing the fishing trip, making decisions, and taking on the risk associated with the venture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>5", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "farmers and all other workers concerned with getting raw materials from the earth are engaged in", "images": [], "options": {"A": "commercial occupation", "B": "manufacturing occupation", "C": "constructive occupation", "D": "extractive occupation"}, "answer": "D", "explanation": "Farmers and other workers who extract raw materials from the earth are engaged in extractive occupations. Extractive occupations involve the extraction of raw materials from the earth, such as mining, fishing, forestry, and farming. These occupations are crucial as they provide the raw materials that are used in other sectors of the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>6", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The process of making goods attractive and easy to handle is merchandising", "images": [], "options": {"A": "branding", "B": "merchandising", "C": "packaging", "D": "labelling"}, "answer": "C", "explanation": "The process of making goods attractive and easy to handle is referred to as packaging. Packaging involves enclosing or protecting products for distribution, storage, sale, and use. It also refers to the process of designing and producing the container or wrapper for a product. It plays a key role in a product's marketing mix and can influence consumers' buying decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>7", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The charges imposed by the government on locally manufactured goods is called", "images": [], "options": {"A": "customs duties", "B": "excise duties", "C": "tariffs", "D": "quota"}, "answer": "B", "explanation": "Excise duties are taxes imposed on goods produced within the country. They are indirect taxes that the manufacturers or producers pay to the government, but they recover them from their customers by including them in the price of the goods. Customs duties, on the other hand, are taxes on imports and exports of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>8", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A grocer invoiced a carton of fish valued at N2,500 for N2,000 only. To correct other error, which of the following documents would be sent to the buyer?", "images": [], "options": {"A": "Credit note for N500.00", "B": "Debit note for N500.00", "C": "Credit note for N2,500.00", "D": "Debit note for N2,500.00"}, "answer": "B", "explanation": "Debit note is used to correct an undercharged   - Credit note is used to correct an overcharged.   Since the seller under charged the buyer by ₦500, he would issue a debit note for ₦500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>9", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The exchange of goods and services among many countries is", "images": [], "options": {"A": "multilateral trade", "B": "bilateral trade", "C": "counter trade", "D": "entrepot"}, "answer": "A", "explanation": "Multilateral trade is the exchange of goods and services among many countries. This type of trade allows for the participation of many different countries and is typically managed by international agreements. Bilateral trade, on the other hand, is the exchange of goods between two countries. Counter trade is a system of trading where goods are exchanged for other goods instead of for cash. Entrepot is a port, city, or trading post where merchandise may be imported, stored or traded, usually to be exported again.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>10", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "If a ship overstays its stipulated time at a port, it pays a charge known as", "images": [], "options": {"A": "arbitrate", "B": "demurrage", "C": "dock due", "D": "toll"}, "answer": "B", "explanation": "Demurrage is a charge paid to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed. Therefore, if a ship overstays its stipulated time at a port, it pays a charge known as demurrage.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>11", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A transaction where the buyer of a commodity becomes its legal owner after the payment of the last instalment is", "images": [], "options": {"A": "a credit sale", "B": "factoring", "C": "hire purchase", "D": "leasing"}, "answer": "C", "explanation": "Hire purchase is a system by which a buyer pays for a thing in regular installments while enjoying the use of it. During the repayment period, ownership (title) of the item does not pass to the buyer. Upon the full payment of the last installment, the title passes to the buyer. Therefore, a transaction where the buyer of a commodity becomes its legal owner after the payment of the last installment is hire purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>12", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An agreement whereby the seller transfers or agree to transfer the property in goods for a monetary consideration is a", "images": [], "options": {"A": "contract of sale", "B": "hire purchase", "C": "conditional sale", "D": "party selling"}, "answer": "A", "explanation": "A contract of sale is an agreement whereby the seller transfers or agrees to transfer the property in goods to the buyer for a price. Therefore, an agreement whereby the seller transfers or agrees to transfer the property in goods for a monetary consideration is a contract of sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>13", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "The main purpose of sending delivery notes along with goods is to", "images": [], "options": {"A": "enable the goods to be checked on arrival", "B": "enable the buyer to pay the correct delivery charges", "C": "ensure the safe delivery of the goods", "D": "prevent the goods from being stolen in transit"}, "answer": "A", "explanation": "A delivery note is a document that accompanies a goods shipment and lists details about the goods delivered. The main purpose of sending delivery notes along with goods is to enable the goods to be checked on arrival. This allows the recipient to verify that the correct goods have been delivered in the correct quantities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>14", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A shop that sells only the products of a particular manufacturer, is known as", "images": [], "options": {"A": "mobile shop", "B": "unit shop", "C": "tied shop", "D": "small shop"}, "answer": "C", "explanation": "A shop that sells only the products of a particular manufacturer is known as a tied shop. This is because the shop is 'tied' to the manufacturer, and only sells their products. This is different from a mobile shop (which can move locations), a unit shop (which is a single, standalone shop), or a small shop (which refers to the size of the shop, not what it sells).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>15", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Which of the following statement cannot be found in a partnership deed?", "images": [], "options": {"A": "names of partners", "B": "Nature of business", "C": "payment of tax", "D": "Interest on capital"}, "answer": "C", "explanation": "A partnership deed is a legal document that sets out the terms and conditions of a partnership. It typically includes details such as the names of the partners, the nature of the business, and the interest on capital. However, it does not typically include details about the payment of tax. This is because tax obligations are usually determined by the tax laws of the jurisdiction in which the partnership operates, and not by the partnership agreement itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>16", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Product differentiation is achieved by", "images": [], "options": {"A": "packaging and branding", "B": "packing and grading", "C": "market segmentation", "D": "outdoor advertising"}, "answer": "A", "explanation": "Product differentiation is a marketing strategy that businesses use to distinguish a product from similar offerings on the market. This is achieved by packaging and branding. Packaging refers to the way a product is presented to the consumer. It includes the physical container or wrapping and any graphics or text on the package. Branding, on the other hand, is the process of creating a unique image and name for a product in the consumers' mind, mainly through advertising campaigns with a consistent theme.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>17", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following services is not offered to retailers by wholesalers?", "images": [], "options": {"A": "Keeping them informed of the demands of consumers", "B": "Keeping them informed of new products", "C": "offering a wide range of products", "D": "Granting credit"}, "answer": "A", "explanation": "While wholesalers offer several services to retailers, such as informing them of new products, offering a wide range of products, and granting credit, they do not typically keep retailers informed of the demands of consumers. Understanding consumer demand is usually the retailer's responsibility, as they have direct contact with the end customers and can gather insights on their preferences and purchasing behaviors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>18", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The buying and selling of goods and services within a country is called", "images": [], "options": {"A": "counter trade", "B": "entrepot trade", "C": "foreign trade", "D": "home trade"}, "answer": "D", "explanation": "The buying and selling of goods and services within a country is referred to as home trade. This is also known as domestic trade or internal trade. It involves the exchange of goods and services within the geographical boundaries of a country. This is different from foreign trade which involves trading with other countries, counter trade which involves barter trade, and entrepot trade which involves importing goods to re-export.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>19", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "The relationship between partners is stipulated in the", "images": [], "options": {"A": "Memorandum of Association", "B": "Article of Association", "C": "Partner of Deed", "D": "Certificate of Incorporation"}, "answer": "C", "explanation": "The relationship between partners in a business is stipulated in the 'Partnership Deed'. A partnership deed is a written legal document that provides the terms of partnership among partners. It includes details like profit/loss sharing, salary, interest on capital, drawings, admission of a new partner, retirement of a partner, dissolution of firm, etc. The options 'Memorandum of Association', 'Article of Association', and 'Certificate of Incorporation' are related to a company, not a partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>20", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following cannot be used to regulate importation?", "images": [], "options": {"A": "Import quota", "B": "Import licence", "C": "Imposition of embargo", "D": "Increase of excise duty"}, "answer": "D", "explanation": "Excise duty is a form of tax imposed on goods for their production, licensing, and sale within the country, not on imported goods. Therefore, an increase in excise duty cannot be used to regulate importation. On the other hand, import quota, import license, and imposition of embargo are all tools that can be used to regulate importation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>21", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A firm that accepts, sells and delivers goods by post is a", "images": [], "options": {"A": "supermarket", "B": "multiple store", "C": "department store", "D": "mail order business"}, "answer": "D", "explanation": "A firm that accepts, sells, and delivers goods by post is a 'Mail Order Business'. In this type of business, customers place orders for products through mail, and the products are then delivered to them via post. The other options, such as supermarket, multiple store, and department store, are physical retail establishments and do not primarily operate through post.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>22", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Okoni & Co. law chamber is an example of a", "images": [], "options": {"A": "sole proprietorship", "B": "partnership", "C": "co-operative society", "D": "public limited company"}, "answer": "B", "explanation": "Okoni & Co. law chamber is an example of a partnership. A partnership is a type of business organization where two or more individuals manage and operate the business in accordance with the terms and objectives set out in a Partnership Deed. This is different from a sole proprietorship (which is run by one person), a co-operative society (which is owned and run by its members), and a public limited company (which is owned by shareholders and run by a board of directors).", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>23", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A refund of the duty collected on goods imported into country which are later re-exported is", "images": [], "options": {"A": "excise duty", "B": "ad valorem tax", "C": "customs drawback", "D": "demurrage"}, "answer": "C", "explanation": "A refund of the duty collected on goods imported into a country which are later re-exported is known as a customs drawback. This is a refund given by the government to importers for the import duties paid on goods that are subsequently exported out of the country. Excise duty and ad valorem tax are types of taxes, not refunds. Demurrage is a charge payable to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>24", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following is mostly used by a mail order business to sell goods?", "images": [], "options": {"A": "Poster", "B": "Catalogues", "C": "Journals", "D": "Magazines"}, "answer": "B", "explanation": "A mail order business mostly uses catalogues to sell goods. A catalogue is a printed document or an electronic form (e-catalogue) that lists the goods or services on sale with their description and prices. It is designed to serve as a reference for customers who may not be able to physically see the products. Posters, journals, and magazines can be used for advertising, but they are not the primary sales tools in a mail order business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>25", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Information requested from a bank concerning the credit worthiness of a new customer to a business is", "images": [], "options": {"A": "private enquiry", "B": "status enquiry", "C": "general enquiry", "D": "letter of enquiry"}, "answer": "B", "explanation": "A status enquiry is a request made to a bank or other financial institution to determine the creditworthiness of a potential customer. This is often done when a business is considering extending credit or entering into a financial agreement with a new customer. The bank will provide information on the customer's financial status, including their credit history and current financial situation, which can help the business make an informed decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>26", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The document which gives legal authority to a company to operates as a legal entity is", "images": [], "options": {"A": "Memorandum of Association", "B": "Article of Association", "C": "Share certificate", "D": "Certificate of Incorporation"}, "answer": "D", "explanation": "The Certificate of Incorporation is a legal document that is issued by the government to a company once it has been officially registered. This document gives the company the legal right to conduct business as a separate legal entity. It includes information such as the company's name, the date of incorporation, and the type and number of shares it is authorized to issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>27", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE", "question": "A business that is dependent of its owners is a", "images": [], "options": {"A": "sole proprietorship", "B": "partnership", "C": "limited liability company", "D": "co-operative society"}, "answer": "A", "explanation": "A sole proprietorship is a type of business that is owned and run by one individual. There is no legal distinction between the owner and the business in a sole proprietorship, meaning the owner is personally responsible for all of the business's debts and obligations. This makes the business entirely dependent on its owner.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>28", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The amount paid regularly by the insured to the insurer is", "images": [], "options": {"A": "dividend", "B": "premium", "C": "interest", "D": "indemnity"}, "answer": "B", "explanation": "The amount paid regularly by the insured to the insurer is known as the premium. This is the amount that the insured party pays periodically to the insurance company in return for coverage or protection from specific losses or damages.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>29", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The net profit is calculated as", "images": [], "options": {"A": "sales less purchases", "B": "sales less expenses", "C": "gross profit less expenses", "D": "gross profit less purchases"}, "answer": "C", "explanation": "Net profit is calculated as gross profit less expenses. Gross profit is the profit a company makes after deducting the costs associated with making and selling its products, or the costs associated with providing its services. Expenses include items like administrative costs, interest, taxes, and other costs not included in the cost of goods sold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>30", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following carries specialized goods?", "images": [], "options": {"A": "Liner", "B": "Tramp", "C": "Ferry", "D": "Tanker"}, "answer": "D", "explanation": "A tanker carries specialized goods. In the context of shipping, a tanker is a ship designed to transport or store liquids or gases in bulk. These are often maritime vessels designed to carry oil, gas or other liquid cargo.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>31", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "In sea transport, vessels that operate on fixed routes and schedules are called", "images": [], "options": {"A": "ferries", "B": "yachts", "C": "liners", "D": "tramps"}, "answer": "C", "explanation": "In sea transport, vessels that operate on fixed routes and schedules are called liners. Liners are ships that have a regular schedule and a standard route. They are different from tramps, which do not have a fixed schedule or route. Ferries and yachts do not necessarily operate on fixed routes and schedules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>32", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following advertising media combines the advantages of both sight and sound?", "images": [], "options": {"A": "Television", "B": "Radio", "C": "Neon sign", "D": "Billboard"}, "answer": "A", "explanation": "Television is the advertising medium that combines the advantages of both sight and sound. It allows advertisers to use visual images and sounds to convey their messages, making the advertisement more engaging and memorable. Radio only uses sound, while neon signs and billboards only use sight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>33", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "One disadvantage of advertising to the consumer is that it", "images": [], "options": {"A": "brings confusion on the choice of goods", "B": "increases demand", "C": "persuades the public to buy what they need", "D": "decrease the cost of goods"}, "answer": "A", "explanation": "One disadvantage of advertising to the consumer is that it can bring confusion on the choice of goods. This is because advertising often presents multiple products in the same category as the best, which can make it difficult for consumers to decide which product to purchase. Advertising does not necessarily decrease the cost of goods, persuade the public to buy what they need, or increase demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>34", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following is not a sales promotion method?", "images": [], "options": {"A": "Demonstration", "B": "Exhibition", "C": "Free sample", "D": "Newspaper"}, "answer": "D", "explanation": "Sales promotion methods are marketing strategies businesses use to boost sales and attract new customers. These methods include demonstrations, exhibitions, and free samples. However, a newspaper is not a sales promotion method. It is a medium through which sales promotion methods can be communicated.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>35", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Working capital is", "images": [], "options": {"A": "Current asset less total liabilities", "B": "total assets less total liabilities", "C": "current liabilities plus current assets", "D": "current assets less current liabilities"}, "answer": "D", "explanation": "Working capital is a measure of a company's operational liquidity and short-term financial health. It is calculated as current assets minus current liabilities. Current assets are the assets a company expects to convert to cash within one year. Current liabilities are the company's debts or obligations that are due within one year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>36", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque dated 30th July, 2004 but presented for payment on 28th February, 2005 is", "images": [], "options": {"A": "post-dated", "B": "crossed", "C": "opened", "D": "stale"}, "answer": "D", "explanation": "A cheque is considered stale if it is presented for payment six months after its date of issue. In this case, the cheque was dated 30th July, 2004 but was presented for payment on 28th February, 2005, which is more than six months later. Therefore, the cheque is stale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>37", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer the question    This extract is Eniola Computer Services, Aba.      ₦Sales 200,000.00Stock 1/1/2004 25,000.00Stock 31/12/2004 35,000.00Purchases 145,000.00Returns Inwards 20,000.00Sales and distribution 13,000.00Wages and Salaries 8,000     The average  stock is", "images": [], "options": {"A": "₦60,000.00", "B": "₦35,000.00", "C": "₦30,000.00", "D": "₦25,000.00"}, "answer": "C", "explanation": "Average stock =  Opening stock + Closing stock/2    25000 + 35000/2      60,000/2      = ₦30,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>38", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer the question    This extract is Eniola Computer Services, Aba.      ₦Sales 200,000.00Stock 1/1/2004 25,000.00Stock 31/12/2004 35,000.00Purchases 145,000.00Returns Inwards 20,000.00Sales and distribution 13,000.00Wages and Salaries 8,000   The gross profit is", "images": [], "options": {"A": "₦65,000.00", "B": "₦55,000.00", "C": "₦30,000.00", "D": "₦25,000.00"}, "answer": "A", "explanation": "Gross profit = Sales - Cost of goods sold    Note that the cost of goods sold = Opening stock + Purchases - Closing stock   COGS = 25000 + 145000 - 35000  = 135000    Gross profit = 200000 - 135000  = 65,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>39", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer the question    This extract is Eniola Computer Services, Aba.      ₦Sales 200,000.00Stock 1/1/2004 25,000.00Stock 31/12/2004 35,000.00Purchases 145,000.00Returns Inwards 20,000.00Sales and distribution 13,000.00Wages and Salaries 8,000   The cost of goods sold is", "images": [], "options": {"A": "₦135,000.00", "B": "₦115,000.00", "C": "₦155,000", "D": "₦35,000.00"}, "answer": "A", "explanation": "The cost of goods sold is calculated by adding the opening stock and purchases, and then subtracting the closing stock.    Cost of goods sold =  (₦25,000.00 + ₦145,000.00) - ₦35,000.00   = ₦135,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>40", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following receives dividend based on patronage?", "images": [], "options": {"A": "Preference shareholder", "B": "Co-operative society member", "C": "Cumulative preference shareholder", "D": "Debenture holder"}, "answer": "B", "explanation": "A co-operative society member receives dividend based on patronage. Patronage in this context refers to the amount of business a member does with the cooperative. The more a member patronizes the cooperative, the more dividends they receive. This is different from a typical corporation where dividends are based on the number of shares owned.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>41", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "If a customer opens a deposit account with a bank, he will", "images": [], "options": {"A": "receive a crossed cheque book", "B": "be given a tally", "C": "be given a loan", "D": "receive interest"}, "answer": "D", "explanation": "When a customer opens a deposit account with a bank, they will receive interest. A deposit account is a bank account maintained by a financial institution in which a customer can deposit money and which can be withdrawn. The bank pays interest on the money deposited in the account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>42", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "A chamber of commerce normally consist of", "images": [], "options": {"A": "officials of trade unions of commercial workers", "B": "all the people engage in one aspect of trading and manufacturing", "C": "all the workers in one branch of commerce", "D": "the people who represent a cross-section of business interest in a town"}, "answer": "D", "explanation": "A chamber of commerce normally consists of the people who represent a cross-section of business interest in a town. It is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>43", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A group of musicians can come together to form a", "images": [], "options": {"A": "chamber of commerce", "B": "public corporation", "C": "trade association", "D": "trade union"}, "answer": "C", "explanation": "A group of musicians can come together to form a trade association. A trade association, also known as an industry trade group, is an organization founded and funded by businesses that operate in a specific industry. It is designed to help promote the industry, provide a forum for the formulation and propagation of industry standards, and address any issues that may arise.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>44", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not an advantage of marketing?", "images": [], "options": {"A": "creation of demand", "B": "Ensuring effective distribution of goods", "C": "Implementing government regulations", "D": "Application of marketing techniques"}, "answer": "C", "explanation": "Implementing government regulations is not an advantage of marketing. Marketing is about identifying and meeting human and social needs. It is the activity, set of institutions, and processes for creating, communicating, delivering, and exchanging offerings that have value for customers, clients, partners, and society at large. Implementing government regulations is not a direct function or advantage of marketing, it is rather a requirement that businesses must comply with.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>45", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "One disadvantage of indigenization is that it", "images": [], "options": {"A": "discourages foreign control of an economy", "B": "encourages local retention of profits", "C": "encourages the participation of indigenes in economic development", "D": "discourages foreign investment"}, "answer": "D", "explanation": "The question seems to be incomplete as it does not specify what 'it' refers to. However, based on the options provided, the most logical answer would be that 'it' refers to a policy or practice that discourages foreign investment. Foreign investment can bring a host of advantages to a country, such as economic growth and job creation. However, one potential disadvantage is that it can discourage foreign investment. This is because foreign investors may be wary of investing in a country where they do not have control over their investment or where the majority of profits are retained locally.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>46", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The takeover by government Sanking Sillah and Sons Ltd is referred to as", "images": [], "options": {"A": "privatization", "B": "indigenization", "C": "commercialization", "D": "nationalization"}, "answer": "D", "explanation": "The takeover of a private company by the government is referred to as nationalization. Nationalization is the process of transforming private assets into public assets by bringing them under the public ownership of a national government or state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2008>47", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following economic unions is made up of countries in West Africa only?", "images": [], "options": {"A": "ACP", "B": "ECOWAS", "C": "NATO", "D": "ADB"}, "answer": "B", "explanation": "ECOWAS (Economic Community of West African States) is an economic union comprising of fifteen West African countries. It was established to promote economic integration across countries that could lead to a higher economic growth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2008>48", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "People who sells shares in anticipation of a fall in their value are called", "images": [], "options": {"A": "bears", "B": "bulls", "C": "brokers", "D": "jobbers"}, "answer": "A", "explanation": "People who sell shares in anticipation of a fall in their value are called bears. In stock market terminology, a bear market is a condition in which securities prices fall and widespread pessimism causes the stock market's downward spiral to be self-sustaining.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>49", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a favourable condition under which personal selling can be practiced?", "images": [], "options": {"A": "When advertising entails relatively high costs", "B": "When the market is concentrated", "C": "When the market is dispersed", "D": "When personal touch is needed"}, "answer": "C", "explanation": "Personal selling is a form of direct marketing where a salesperson communicates with potential customers in person. It is most effective when the market is concentrated, as this allows the salesperson to reach a large number of potential customers in a short amount of time. However, when the market is dispersed, personal selling becomes less effective as it is more difficult and time-consuming for the salesperson to reach potential customers. Therefore, a dispersed market is not a favourable condition under which personal selling can be practiced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2008>50", "subject": "Commerce", "year": "2008", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A shareholder who holds 100,000 shares of 50 butts each is given a dividend of 10 per cent less 2 percent tax. What is his net return?", "images": [], "options": {"A": "D10,000.00", "B": "D9,800.00", "C": "D5,000.00", "D": "D4,900.00"}, "answer": "D", "explanation": "The shareholder's gross return is calculated by multiplying the number of shares by the dividend per share.     In this case, the shareholder has 100,000 shares and the dividend per share is 10% of 50 butts, which is 5 butts.     Therefore, the gross return is 100,000 x 5   = 500,000 butts.     The net return is then calculated by subtracting the tax from the gross return.     The tax is 2% of the gross return, which is 0.02 x 500,000   = 10,000 butts.     Therefore, the net return is 500,000 - 10,000   = 490,000 butts.     Assuming 1butts = 10 D  Therefore, 490,000/100  = 4900", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>1", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "A person who invented a new machine for making beverages may protect his exclusive right by", "images": [], "options": {"A": "labeling the product", "B": "obtaining a patent", "C": "choosing a name for the product", "D": "obtaining a trade mark"}, "answer": "B", "explanation": "A patent is a form of intellectual property that gives its owner the legal right to exclude others from making, using, or selling an invention for a limited period of years. In this case, the person who invented a new machine for making beverages can protect his exclusive right by obtaining a patent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>2", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following occupations come under the extractive industry?  I. Cattle-rearing, lumbering, farmer  II. Mining, quarrying, hunting  III. Ship building, road construction, iron bending   IV. Singing, dancing, barbing", "images": [], "options": {"A": "I, II and III only.", "B": "I, II and IV only", "C": "I and II only", "D": "II and III only"}, "answer": "C", "explanation": "Extractive industry refers to any operations that involve the extraction of raw materials from the earth to be used by consumers. This includes all the operations both underground and on the surface. Thus, occupations like cattle-rearing, lumbering, farming, mining, quarrying, and hunting fall under the extractive industry. Therefore, options I and II are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>3", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following is sent by a supplier who does not want to sell on credit?", "images": [], "options": {"A": "Proforma invoice", "B": "Quotation", "C": "Consular invoice", "D": "Advice note"}, "answer": "A", "explanation": "A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is often used to declare the value of the trade. It is not a true invoice because it is not used to record accounts receivable for the seller and accounts payable for the buyer. In this case, a supplier who does not want to sell on credit would send a proforma invoice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>4", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Retail outlets that have identical store design, layout and stock display are", "images": [], "options": {"A": "multiple shops", "B": "tied shops", "C": "mobile shops", "D": "supermarkets"}, "answer": "A", "explanation": "Multiple shops are retail outlets that have identical store design, layout, and stock display. They are usually owned by the same company and operate under the same brand name. This allows the company to maintain a consistent image and shopping experience across all of its locations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>5", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Life assurance premium is determined by the assured's", "images": [], "options": {"A": "educational level", "B": "age", "C": "reputation", "D": "number of children"}, "answer": "B", "explanation": "Life assurance premium is determined by the assured's age. The older a person is, the higher the risk of death, and therefore, the higher the premium. This is because life assurance is a form of insurance that pays out a sum of money either on the death of the insured person or after a set period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>6", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "Which of the following is not a contract of indemnity?", "images": [], "options": {"A": "Marine Insurance", "B": "Fire Insurance", "C": "Life Assurance", "D": "Burglary Insurance"}, "answer": "C", "explanation": "A contract of indemnity is a legal agreement that provides compensation for losses or damages incurred by one party in the event of an unforeseen incident. Examples of contracts of indemnity include marine, fire, theft etc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>7", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A stale cheque is one on which the date for payment is", "images": [], "options": {"A": "overdue", "B": "yet to come", "C": "missing", "D": "due"}, "answer": "A", "explanation": "A stale cheque is a cheque that is not presented for payment within a reasonable amount of time after it is written. It cant be deposited before specific date.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>8", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "When an order cheque is endorsed it becomes a", "images": [], "options": {"A": "confirmed cheque", "B": "bearer cheque", "C": "dishonoured cheque", "D": "cleared cheque"}, "answer": "B", "explanation": "An order cheque becomes a bearer cheque when it is endorsed. This is because an endorsement transfers the rights of the cheque to the new holder (bearer).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>9", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The authority given to a bank to make regular payments on behalf of a customer is", "images": [], "options": {"A": "credit transfer", "B": "bank endorsement", "C": "standing order", "D": "bank overdraft"}, "answer": "C", "explanation": "A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The bank makes these payments on behalf of the customer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>10", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The taking over of private owned business by the government is called?", "images": [], "options": {"A": "indigenization", "B": "commercialization", "C": "nationalization", "D": "privatization"}, "answer": "C", "explanation": "Nationalization refers to the process of taking a private industry or private assets into public ownership by a national government or state. Therefore, the taking over of private owned business by the government is called nationalization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>11", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The rate of turnover is the number of times within a given period that", "images": [], "options": {"A": "stock is sold and replaced", "B": "closing stock is sold and replaced", "C": "purchases are added to stock", "D": "average stock is sold"}, "answer": "A", "explanation": "The rate of turnover refers to how quickly inventory is sold and replaced within a given time period. Therefore, the rate of turnover is the number of times within a given period that stock is sold and replaced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>12", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following will be used when goods are sent through independent carriers?", "images": [], "options": {"A": "Delivery note", "B": "Despatch note", "C": "Consignment note", "D": "Advice note"}, "answer": "C", "explanation": "A consignment note is a document that accompanies goods dispatched by a third party carrier. It serves as proof of the contract of carriage and contains details about the goods and the destination. Therefore, when goods are sent through independent carriers, a consignment note will be used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>13", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : FEATURES/CHARACTERISTICS", "question": "Which of the following is a feature of sole proprietorship", "images": [], "options": {"A": "Legal entity", "B": "Unlimited liability", "C": "Limited liability", "D": "Continuity"}, "answer": "B", "explanation": "In a sole proprietorship, the owner has unlimited liability, meaning they are personally responsible for all losses and debts of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>14", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "If a country devalue its currency, there would be", "images": [], "options": {"A": "reduction in imports", "B": "reduction in export", "C": "increase in production locally", "D": "increase in standard of living"}, "answer": "3~~1", "explanation": "When a country devalues its currency, the following economic effects generally occur:    Reduction in imports: Devaluation makes the country's currency weaker compared to foreign currencies, making imported goods more expensive. This typically leads to a decrease in the volume of imports.    Increase in production locally : Devaluation makes domestic goods cheaper for foreign buyers, potentially increasing exports. This can stimulate local production as domestic producers ramp up to meet the increased demand from abroad.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>15", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Establishing and maintaining mutual understanding between an organization and its customers is known as", "images": [], "options": {"A": "marketing concept", "B": "advertising", "C": "public relations", "D": "sales promotion"}, "answer": "C", "explanation": "Public relations involves managing the spread of information between an individual or an organization and the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>16", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following requires a certificate of trading to start a business?", "images": [], "options": {"A": "Public corporation", "B": "Public limited company", "C": "Cooperative society", "D": "private limited company"}, "answer": "B", "explanation": "A public limited company requires a certificate of trading to start a business. This is because a public limited company is a type of business that offers its shares to the general public. The certificate of trading is a document that gives the company the legal right to start trading (i.e., buying and selling goods or services).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>17", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A document through which the public is invited to subscribe to the shares of a company is a", "images": [], "options": {"A": "Memorandum of Association", "B": "Article of Association", "C": "Prospectus", "D": "Debenture"}, "answer": "C", "explanation": "A prospectus is a document through which the public is invited to subscribe to the shares of a company. It contains details about the company, its business, and the shares being offered. The Memorandum of Association and the Article of Association, on the other hand, are documents that outline the company's constitution and internal rules respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>18", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The tax paid on goods produced within a country is known as", "images": [], "options": {"A": "import duty", "B": "excise duty", "C": "advalorem duty", "D": "customs drawback"}, "answer": "B", "explanation": "Excise duty is a tax paid on goods produced within a country. It is a form of indirect tax that is levied on the manufacturer of the goods and is usually passed on to the consumer as part of the price of the goods. Import duty, on the other hand, is a tax paid on goods imported into a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>19", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The letter R/D on a cheque shown that cheque is", "images": [], "options": {"A": "paid", "B": "dishonoured", "C": "certified", "D": "accepted"}, "answer": "B", "explanation": "The letter R/D on a cheque stands for 'Refer to Drawer'. This is usually written on a cheque to indicate that the cheque has been dishonoured. A cheque is dishonoured when the bank does not allow the withdrawal of the amount written on the cheque. This could be due to insufficient funds in the account, a stop payment instruction from the account holder, or some discrepancy in the cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>20", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The mode of conveying liquid and gases through an underground channel is", "images": [], "options": {"A": "pipeline", "B": "rail transport", "C": "road transport", "D": "sea transport"}, "answer": "A", "explanation": "The mode of conveying liquid and gases through an underground channel is pipeline transport. Pipeline transport is the long-distance transportation of a liquid or gas through a system of pipes—a pipeline—typically to a market area for consumption. The latest data, in 2014, gives a total of slightly less than 2,175,000 miles (3,500,000 km) of pipeline in 120 countries of the world.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>21", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is a source of capital to a sole proprietorship?", "images": [], "options": {"A": "Loans from friends", "B": "Admission of new member", "C": "Issue of shares", "D": "Issue of debenture"}, "answer": "A", "explanation": "A source of capital for a sole proprietorship could be loans from friends. A sole proprietorship is a type of enterprise that is owned and run by one person and in which there is no legal distinction between the owner and the business entity. The owner is in direct control of all elements and is legally accountable for the finances of such business and this may include debts, loans, loss, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>22", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A ship that travels without schedule is called a", "images": [], "options": {"A": "passenger liner", "B": "tramp", "C": "cargo liner", "D": "tanker"}, "answer": "B", "explanation": "A tramp is a ship that does not have a fixed schedule or published ports of call. Unlike a freight liner which follows a schedule and a set route, tramp ships trade on the spot market with no fixed schedule or itinerary/ports-of-call. They go where the cargo is and drop it off where it's supposed to go.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>23", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "For over staying in a port, a ship is charged a liner called", "images": [], "options": {"A": "dock due", "B": "commission", "C": "interest", "D": "demurrage"}, "answer": "D", "explanation": "Demurrage is a charge that a ship pays for overstaying its allotted time at a port. It is a penalty for exceeding the stipulated laytime (the time agreed between the parties for loading or unloading without payment additional to the freight).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>24", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Stock, share and debentures traded in the stock market exchange are called", "images": [], "options": {"A": "bears", "B": "bull", "C": "securities", "D": "collaterals"}, "answer": "C", "explanation": "Securities is the general term for stocks, shares, debentures, bonds, etc., which are tradable financial instruments, used as a form of ownership in a corporation (stocks), or represent a claim on part of a corporation's assets and earnings (bonds).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>25", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following is a reduction in the catalogue price?", "images": [], "options": {"A": "Rebate", "B": "Cash discount", "C": "Commission", "D": "Trade discount"}, "answer": "D", "explanation": "A trade discount is a reduction in the catalogue price. It is given by a seller to the buyer as a deduction in the list price of the product. It is often used in B2B transactions to encourage bulk buying.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>26", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The discount that helps to determine the country from where goods were imported is", "images": [], "options": {"A": "bill of lading", "B": "ship's manifest", "C": "certificate of origin", "D": "share certificate"}, "answer": "C", "explanation": "A certificate of origin is a document that helps to determine the country from where goods were imported. It is a document used in international trade, which traditionally states from what country the shipped goods originate, but 'originate' in a CO does not mean the country the goods are shipped from, but the country where the goods are actually made.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>27", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The internal regulations of a limited company are stated in the", "images": [], "options": {"A": "Memorandum of Association", "B": "Articles of Association", "C": "Certificate of incorporation", "D": "Share certificate"}, "answer": "B", "explanation": "The internal regulations of a limited company are stated in the Articles of Association. The Articles of Association is a document that contains the purpose of the company as well as the duties and responsibilities of its members defined and recorded clearly. It is an important document which needs to be filed with the Registrar of Companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>28", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following features is common to all retailers?", "images": [], "options": {"A": "Operating as sole-proprietors", "B": "Selling to the final consumers", "C": "Operation with small capital", "D": "Selling on hire purchase to consumers"}, "answer": "B", "explanation": "Retailers are businesses or individuals that sell goods directly to the end user or consumer. While some retailers may operate as sole proprietors or sell on hire purchase, not all do. Therefore, the only feature common to all retailers is that they sell to the final consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>29", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A private limited company differs from a public limited company because it", "images": [], "options": {"A": "offers right issues to existing shareholders", "B": "has a separate entity from the owners", "C": "cannot easily transfer shares", "D": "declares dividend"}, "answer": "C", "explanation": "A private limited company differs from a public limited company in several ways, but the most significant difference is that shares in a private limited company cannot be freely transferred or sold to the general public. This is unlike a public limited company, where shares can be bought and sold on a public exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>30", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Exchange is facilitated by", "images": [], "options": {"A": "taxation", "B": "quotas", "C": "specialization", "D": "good supervision"}, "answer": "C", "explanation": "Exchange is facilitated by specialization. Specialization refers to the concept where individuals, businesses, or countries focus on producing a limited scope of products or services to gain greater degrees of productive efficiency. This leads to a surplus of certain goods or services, which can then be exchanged for goods or services that the individual, business, or country does not produce. This is the basis of trade.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>31", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following is not a means of transportation by water?", "images": [], "options": {"A": "Canoes", "B": "Launches", "C": "Tramps", "D": "Carts"}, "answer": "D", "explanation": "Carts are not a means of transportation by water. They are typically used for land transportation. Canoes, Launches, and Tramps are all types of water vessels and therefore are means of transportation by water.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>32", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The nominal value of KCL Ltd's shares is 50k and the market value is 70k. This means that the company's shares are selling", "images": [], "options": {"A": "at par", "B": "ex dividend", "C": "cum dividend", "D": "at premium"}, "answer": "D", "explanation": "The nominal value of a share is its face value, the value stated on the share certificate. The market value is the price at which the share is currently being sold in the market. If the market value is higher than the nominal value, the shares are said to be selling 'at a premium'. In this case, the nominal value is 50k and the market value is 70k, so the shares are selling at a premium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>33", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Those who are engaged in exploiting natural resources are in", "images": [], "options": {"A": "commercial occupation", "B": "constructive occupation", "C": "manufacturing occupation", "D": "extractive occupation"}, "answer": "D", "explanation": "Those who are engaged in exploiting natural resources are in the extractive occupation. This includes activities like mining, fishing, forestry, and oil extraction. Commercial occupation involves trading, constructive occupation involves construction activities, and manufacturing occupation involves converting raw materials into finished goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>34", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A sale agreement whereby the buyer takes possession but not title to the goods is", "images": [], "options": {"A": "credit purchase", "B": "hire purchase", "C": "auction sales", "D": "direct sale"}, "answer": "B", "explanation": "A hire purchase is a method of buying goods through making installment payments over time. The term 'hire purchase' originated in the United Kingdom and is similar to rent-to-own arrangements in the United States. Under a hire purchase contract, the buyer is leasing the goods and does not obtain ownership until the full amount of the contract is paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>35", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is not an example of Marine InSurance?", "images": [], "options": {"A": "Fidelity", "B": "Hull", "C": "Cargo", "D": "Freight"}, "answer": "A", "explanation": "Marine insurance is a type of insurance that covers cargo loss or damage caused to ships, terminals and any transport by which the property is transferred, acquired, or held between the points of origin and the final destination. Fidelity insurance is a form of protection that covers policyholders for losses that they incur as a result of fraudulent acts by specified individuals. It usually insures a business for losses caused by the dishonest acts of its employees. Therefore, Fidelity insurance is not an example of Marine Insurance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>36", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The owner of a public limited company are", "images": [], "options": {"A": "board of directors", "B": "management team", "C": "shareholders", "D": "government"}, "answer": "C", "explanation": "The owners of a public limited company are its shareholders. A public limited company (PLC) is a company that has offered shares to the general public and maintains limited liability. Shareholders have the right to vote on major company decisions, such as the board of directors and whether to approve proposed mergers. They also receive dividends relative to the number of shares they own.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>37", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following justifies the existence of public enterprise?", "images": [], "options": {"A": "Making quick decision", "B": "Creating monopoly", "C": "making profit for government", "D": "Providing essential services."}, "answer": "D", "explanation": "Public enterprises exist primarily to provide essential services to the public. These services may include utilities like water and electricity, transportation, healthcare, and education. While public enterprises may also make decisions, create monopolies, or generate profit for the government, these are not their primary justifications. Their main purpose is to ensure that all citizens have access to certain basic necessities, regardless of their ability to pay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>38", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Who among the following has no voting right?", "images": [], "options": {"A": "Preferred ordinary shareholders", "B": "Ordinary shareholders", "C": "Deferred shareholders", "D": "Debenture holders"}, "answer": "D", "explanation": "Debenture holders are creditors of a company, not shareholders. They lend money to the company and in return, they receive a document called a debenture that acknowledges the company's debt and promises to repay it with interest. However, because they are not shareholders, they do not have voting rights in the company. Shareholders, on the other hand, are owners of the company and therefore have voting rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>39", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "One of the main objectives of International Bank for Reconstruction and Development (IBRD) is to", "images": [], "options": {"A": "settle interbank indebtedness", "B": "lend to poor countries", "C": "oversee the activities of bank broad", "D": "encourage trade liberalization among members."}, "answer": "B", "explanation": "The International Bank for Reconstruction and Development (IBRD) is one of the constituent organizations of the World Bank Group. Its primary goal is to reduce poverty and improve living standards in developing countries by providing loans, guarantees, risk management products, and advisory services. While it initially focused on reconstructing Europe after World War II, its mandate has expanded to address the development challenges faced by middle-income and creditworthy low-income countries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>40", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is not a function of a commercial bank?", "images": [], "options": {"A": "Collection of deposit", "B": "Safe custody services", "C": "Issuing of currency", "D": "Agents of payment"}, "answer": "C", "explanation": "Commercial banks do not issue currency. This is the function of the central bank or the government. Commercial banks can distribute the currency, but the issuance is done by the central bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>41", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Use this diagram to answer this question.       \"P\"  in the diagram above represent", "images": ["Commerce/imgs/2009/41.png"], "options": {"A": "commerce", "B": "home trade", "C": "Retail trade", "D": "Commercialization"}, "answer": "B", "explanation": "Commerce is divided into home or domestic trade and foreign trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>42", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Use this diagram to answer this question.    What does  'V'  represent in the diagram?", "images": ["Commerce/imgs/2009/41.png"], "options": {"A": "Trade", "B": "Home trade", "C": "Retail trade", "D": "Commerce"}, "answer": "C", "explanation": "V is Retail trade, the other being Wholesale trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>43", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "The police and army are engaged in", "images": [], "options": {"A": "direct service occupation", "B": "indirect service occupation", "C": "industrial occupation", "D": "primary occupation"}, "answer": "B", "explanation": "All civil servants render indirect service.  Indirect service are services provided without person-to-person contact.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2009>44", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following are exclusive function of marketing?", "images": [], "options": {"A": "Buying, pricing, selling and promotion", "B": "Risk-bearing, storage, production and transporting", "C": "Organizing, risk-bearing, transportation and storage", "D": "Production, promotion, distribution and recruiting"}, "answer": "A", "explanation": "The exclusive functions of marketing include buying, pricing, selling, and promotion. These activities are directly related to the marketing of a product or service. Production is a function of the production department, not marketing. Similarly, recruiting is a function of the human resources department, not marketing.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>45", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "A type of life policy where the assured or his dependents will not get anything if he did not die within the period of the policy is known as", "images": [], "options": {"A": "group policy", "B": "whole life policy", "C": "endowment policy", "D": "term policy"}, "answer": "D", "explanation": "A term policy is a type of life insurance policy where the assured or his dependents will not get anything if he did not die within the period of the policy. This is because term life insurance provides coverage for a certain period of time, and if the policyholder does not die during this term, no death benefit is paid out.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2009>46", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following note would be sent to a buyer to inform him that the goods he ordered have been dispatched?", "images": [], "options": {"A": "Advice Note", "B": "Delivery Note", "C": "Credit Note", "D": "Consignment Note"}, "answer": "A", "explanation": "An Advice Note is a document sent to a customer to inform them that their goods have been dispatched. It usually includes details such as the quantity of goods and how they have been sent. The other options, Delivery Note, Credit Note, and Consignment Note, are used in different contexts. A Delivery Note is a document that accompanies a goods shipment and lists details about the delivery. A Credit Note is a document sent by a seller to a buyer to reduce the amount that the buyer owes to the seller under the terms of an earlier invoice. A Consignment Note is a document that accompanies goods but is not an indication of goods dispatch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>47", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "The post office services that allows a traveller without a fixed address to collect his letter is known as", "images": [], "options": {"A": "post restante", "B": "recorded delivery", "C": "speed post", "D": "express service"}, "answer": "A", "explanation": "Poste restante (French: 'post remaining' or 'mail remaining'), known in various countries as general delivery in North America, poste restante in many European countries (including in France), and list for general delivery in the UK and in international mail, is a service where the post office holds mail until the recipient calls for it. It is a common destination for mail for people who are visiting a particular location and have no need, or no way, of having mail delivered directly to their place of residence at that time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>48", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES", "question": "Which of the following is not a function of an entrepreneur?", "images": [], "options": {"A": "Co-ordination", "B": "Risk-bearing", "C": "Entertaining", "D": "Making Decision"}, "answer": "C", "explanation": "An entrepreneur is a person who organizes and operates a business or businesses, taking on greater than normal financial risks in order to do so. The functions of an entrepreneur include coordination of business activities, risk-bearing, and decision-making. Entertaining is not a function of an entrepreneur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>49", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "A place where dutiable goods are kept until duties on them are paid is known as", "images": [], "options": {"A": "private warehouse", "B": "public warehouse", "C": "bonded warehouse", "D": "manufacturer's warehouse"}, "answer": "C", "explanation": "A bonded warehouse is a secured warehouse facility that is covered by customs rules. Companies use these facilities to store goods until duties are paid or goods are cleared through customs. Therefore, the place where dutiable goods are kept until duties on them are paid is known as a bonded warehouse.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2009>50", "subject": "Commerce", "year": "2009", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "The cost of advertising is ultimately borne by the", "images": [], "options": {"A": "manufacturer", "B": "consumer", "C": "wholesaler", "D": "retailer"}, "answer": "B", "explanation": "The cost of advertising is ultimately borne by the consumer. This is because the cost of advertising is factored into the price of the product or service. When a consumer purchases a product or service, they are paying for not only the product or service itself, but also for the cost of advertising it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>1", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "A bonded warehouse is a place for keeping", "images": [], "options": {"A": "contraband goods", "B": "dutiable goods", "C": "tax free goods", "D": "smuggled goods"}, "answer": "B", "explanation": "A bonded warehouse is a place where dutiable goods are stored until the duty is paid or the goods are exported. Dutiable goods are goods on which customs duty has to be paid. They are stored in a bonded warehouse to ensure that the duty is paid before they are released.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>2", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following can quote its shares on the stock exchange", "images": [], "options": {"A": "Partnership", "B": "Sole proprietorship", "C": "Co-operative society", "D": "Public Limited Company"}, "answer": "D", "explanation": "A Public Limited Company is the only type of business entity among the given options that can quote its shares on the stock exchange. This is because it is a type of company that offers its securities (stock/shares, bonds/loans, etc.) for sale to the general public, typically through a stock exchange. Other types of businesses like partnerships, sole proprietorships, and co-operative societies do not have shares to be quoted on a stock exchange.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>3", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "If a business man wants to insure against dishonesty of the cashier, he will take", "images": [], "options": {"A": "a burglary policy", "B": "an employer's liability cover", "C": "a fidelity guarantee cover", "D": "a consequential loss policy"}, "answer": "C", "explanation": "If a businessman wants to insure against the dishonesty of the cashier, he will take a fidelity guarantee cover. This type of insurance policy covers the policyholder for losses that they incur as a result of fraudulent acts by specified individuals. It usually insures a business for losses caused by the dishonest acts of its employees.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>4", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following describes the reason for international trade?", "images": [], "options": {"A": "Balance of payment", "B": "Comparative cost advantage", "C": "Absolute cost advantage", "D": "Balance of trade"}, "answer": "B", "explanation": "International trade is primarily driven by the concept of comparative cost advantage. This economic theory suggests that countries should specialize in producing goods for which they have a lower opportunity cost and trade for goods that other countries produce at a lower opportunity cost. This allows for efficient use of resources and increases the total output and consumption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>5", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Small scale retailer continue to survive inspite of serious competition from large scale retailers because they", "images": [], "options": {"A": "buy from many manufacturers", "B": "Maintain personal relationship with customers", "C": "Stock only one line of goods in their stalls", "D": "do not separate business money from personal money"}, "answer": "B", "explanation": "Small scale retailers often survive in the face of competition from large scale retailers due to their ability to maintain personal relationships with customers. This can lead to customer loyalty and repeat business. Large scale retailers often cannot provide the same level of personal service due to their size.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>6", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following factors is not to be considered in starting a retailer trade?", "images": [], "options": {"A": "Size of the business", "B": "Nature of business", "C": "Amount of capital required", "D": "Level of tax payable"}, "answer": "D", "explanation": "The level of tax payable is not a primary factor to be considered when starting a retail trade. The main factors to consider are the size of the business, the nature of the business, and the amount of capital required. Taxes are a consequence of doing business and vary depending on the jurisdiction and the nature of the business, but they are not a deciding factor in starting a retail trade.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>7", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The import of foreign produced goods to be re-exported is known as", "images": [], "options": {"A": "domestic trade", "B": "wholesale trade", "C": "entreport trade", "D": "counter trade"}, "answer": "C", "explanation": "Entreport trade involves the importation of goods and commodities from other countries with the intention of re-exporting them to other countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>8", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "One roof containing a number of shops is a", "images": [], "options": {"A": "tied shop", "B": "mail order firm", "C": "department store", "D": "chain store"}, "answer": "C", "explanation": "A department store is a large retail establishment that sells a wide variety of goods. These goods are separated into departments, each of which specializes in a type of merchandise.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>9", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The selling of articles from place to place on foot is", "images": [], "options": {"A": "mail order", "B": "itinerant trading", "C": "barter", "D": "self service"}, "answer": "B", "explanation": "Itinerant trading refers to a type of retailing where the retailer does not have a fixed place of business. Instead, they move from place to place, selling their goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>10", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A company whose shares are not easily transferable is a", "images": [], "options": {"A": "private limited company", "B": "public limited company", "C": "public corporation", "D": "company limited"}, "answer": "A", "explanation": "A private limited company is a type of business entity in which ownership is restricted. In this type of entity, the transfer of shares is not easily done because it requires the agreement of other shareholders. This is in contrast to a public limited company, where shares can be freely traded on a public exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>11", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following must be stated in the article of association?", "images": [], "options": {"A": "The objects of the company", "B": "The registered office address of the company", "C": "The method of issues and transfer of shares", "D": "Statement that liabilities are limited"}, "answer": "C", "explanation": "The articles of association of a company detail the regulations for a company's operations and defines the company's purpose. They set out how tasks are to be accomplished within the organization, including the process for appointing directors and the handling of financial records. The method of issues and transfer of shares is one of the key elements that must be stated in the articles of association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>12", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following insurance principles state that a person must be in a position to suffer financially in the event of a loss?", "images": [], "options": {"A": "Proximate cause", "B": "Indemnity", "C": "Insurable interest", "D": "Subrogation"}, "answer": "C", "explanation": "The principle of insurable interest states that the person getting insured must have a legitimate interest in the preservation of the life or property insured. That is, they must stand to suffer a financial loss in the event of a loss or damage to the life or property insured. This principle is fundamental to insurance contracts to establish that the purchaser of the insurance policy is actually subject to risk and has something to lose if the insured event occurs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>13", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Catalogues are mostly used by", "images": [], "options": {"A": "chain stores", "B": "department stores", "C": "mail order firm", "D": "supermarkets"}, "answer": "C", "explanation": "Catalogues are mostly used by mail order firms. A mail order firm is a retail establishment that sells products through a catalogue. Customers can browse through the catalogue and place orders for the items they want to purchase. The items are then shipped directly to the customer. This method of retailing allows customers to shop from the comfort of their own homes, without having to visit a physical store.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>14", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The main function of a thrift and credit cooperative society is to", "images": [], "options": {"A": "encourage members to buy cheaply", "B": "enable members get the highest profit", "C": "help members get legal redress", "D": "encourages members to save"}, "answer": "D", "explanation": "The main function of a thrift and credit cooperative society is to encourage members to save. A thrift and credit cooperative society is a type of financial institution that is owned and operated by its members. The primary purpose of these societies is to provide their members with a safe place to save money and access to loans on reasonable terms. They encourage members to save by offering them a share in the profits of the society in the form of dividends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>15", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The exchange of goods in home trade is known as", "images": [], "options": {"A": "entrepot trade", "B": "trade by barter", "C": "commodity trade", "D": "distributive trade"}, "answer": "D", "explanation": "The exchange of goods in home trade is known as distributive trade. Distributive trade involves the distribution of goods from producers to consumers within the same country. It includes all the activities involved in the transfer of goods from the point of production to the point of consumption. This includes activities such as transportation, warehousing, and retailing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>16", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following is the safest way of sending important documents through the post?", "images": [], "options": {"A": "Registered mail", "B": "Parcel post", "C": "Letter post", "D": "Express mail"}, "answer": "A", "explanation": "Registered mail is the safest way of sending important documents through the post. This is because registered mail requires the recipient's signature upon delivery, providing proof that the document was received. Additionally, registered mail can be tracked, ensuring that the sender knows exactly where the document is at all times.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>17", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following is not true of the stock exchange?", "images": [], "options": {"A": "It is a commodity market", "B": "It provides market for trading on shares", "C": "Government and companies raise fund through it", "D": "It provides professional advice on investment"}, "answer": "A", "explanation": "The stock exchange is not a commodity market. A commodity market is a physical or virtual marketplace for buying, selling, and trading raw or primary products. On the other hand, the stock exchange is a marketplace for buying and selling securities such as stocks and bonds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>18", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque issued in January 1997 which the holder failed to present until September 1997 is called a", "images": [], "options": {"A": "cross-cheque", "B": "traveller's cheque", "C": "post-date cheque", "D": "stale cheque"}, "answer": "D", "explanation": "A cheque that is not presented within a reasonable time (usually six months) after its issue date is called a stale cheque. In this case, the cheque was issued in January 1997 but was not presented until September 1997, making it a stale cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>19", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "When the buyer of an existing share is to receive the pending dividend, the price is", "images": [], "options": {"A": "cum div", "B": "ex-div", "C": "at par", "D": "at a discount"}, "answer": "A", "explanation": "When the buyer of an existing share is to receive the pending dividend, the price is 'cum div'. 'Cum div' is a Latin term that means 'with dividends'. The term is used to signify that a buyer will receive the current dividend that has been declared, but not yet paid. The other options do not correctly describe this situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>20", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "What is the name of the service where a bank makes regular payment on behalf of its customers?", "images": [], "options": {"A": "Direct debit", "B": "Credit transfer", "C": "Standing order", "D": "Bank draft"}, "answer": "C", "explanation": "The service where a bank makes regular payments on behalf of its customers is known as a 'Standing order'. A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The other options do not correctly describe this service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>21", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The enterprise whose main objective is to provide the public with essential services is known as", "images": [], "options": {"A": "cooperative society", "B": "partnership", "C": "private company", "D": "public corporation"}, "answer": "D", "explanation": "The enterprise whose main objective is to provide the public with essential services is known as a 'public corporation'. A public corporation is a company that is publicly owned and operates for the benefit of the public. The other options do not correctly describe this type of enterprise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>22", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following is a more suitable medium for advertising a new tractor?", "images": [], "options": {"A": "Radio", "B": "Poster", "C": "Neon sign", "D": "Trade fair"}, "answer": "D", "explanation": "A trade fair is the most suitable medium for advertising a new tractor. This is because a trade fair allows for a physical demonstration of the product, which is important for a product like a tractor that has many features and specifications that potential buyers would want to see and understand before making a purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>23", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is an advertising function?", "images": [], "options": {"A": "Packaging", "B": "Persuading", "C": "Grading", "D": "Segmenting"}, "answer": "B", "explanation": "Persuading is an advertising function. The main goal of advertising is to persuade consumers to buy a product or service. This is achieved by creating awareness about the product or service, highlighting its benefits, and convincing consumers that it is the best option available.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>24", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document of title to goods being shipped abroad is known as", "images": [], "options": {"A": "consignment note", "B": "ship manifest", "C": "bill of entry", "D": "bill of lading"}, "answer": "D", "explanation": "The document of title to goods being shipped abroad is known as a bill of lading. A bill of lading is a legal document issued by a carrier to a shipper that details the type, quantity, and destination of the goods being carried. It serves as a shipment receipt when the carrier delivers the goods at a predetermined destination. This document also serves as evidence of a contract between the shipper and the carrier.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>25", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The practice whereby customers purchase goods without being attended to by shop assistants is", "images": [], "options": {"A": "pre sales service", "B": "after sale service", "C": "self service", "D": "impulse buying"}, "answer": "C", "explanation": "The practice whereby customers purchase goods without being attended to by shop assistants is known as self-service. This is a common practice in many modern retail stores where customers pick items from the shelves themselves, then pay at the checkout. Pre-sales service and after-sales service refer to services provided before and after a purchase respectively, while impulse buying refers to unplanned or spontaneous purchases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>26", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "In which of the following organizations are members entitled to one vote, irrespective of the number of shares held?", "images": [], "options": {"A": "Public corporation", "B": "Partnership", "C": "Limited company", "D": "Co-operative society"}, "answer": "D", "explanation": "In a co-operative society, members are entitled to one vote, irrespective of the number of shares held. This is based on the principle of 'one member, one vote' which is fundamental to the operation of co-operatives. In contrast, in public corporations, partnerships, and limited companies, voting rights are usually determined by the number of shares a person holds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>27", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Mobile Shopping involves selling", "images": [], "options": {"A": "from motor van", "B": "at a particular spot in the city", "C": "in multiple shops only", "D": "from vending machine"}, "answer": "A", "explanation": "Mobile shopping involves selling from a motor van. This is a form of non-store retailing where goods are sold from a vehicle that moves around different locations. Selling at a particular spot in the city would be a fixed location, not mobile. Selling in multiple shops only would be a form of store retailing, and selling from a vending machine is another form of non-store retailing, but not mobile.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>28", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The provision of adequate number of berth by which ships can off-load and off-load is the function of the", "images": [], "options": {"A": "Department of customer & Excise", "B": "Ports Authority", "C": "Shipping and Forwarding Agent", "D": "National Shipping Line"}, "answer": "B", "explanation": "The provision of adequate number of berths by which ships can off-load is the function of the Ports Authority. The Ports Authority is responsible for the management and operation of ports, including the provision of berthing facilities for ships.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>29", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "Which of the following is not a disadvantage of a one-man-business?", "images": [], "options": {"A": "Unlimited liability of owner", "B": "Life of business limited to life of owner", "C": "Personal control of business", "D": "Difficulty in raising additional capital"}, "answer": "C", "explanation": "Personal control of business is not a disadvantage of a one-man-business. In fact, it is often seen as an advantage because the owner has full control over all decisions and operations of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>30", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "Unlimited liability in business implies that the", "images": [], "options": {"A": "risk of the owner is limited only to the amount invested", "B": "debts are paid with subventions", "C": "property of the owners should not be used to secure loans", "D": "owners private property can be used to settle the business debts"}, "answer": "D", "explanation": "Unlimited liability implies that the owner's private property can be used to settle the business debts. In a business with unlimited liability, the owner is personally responsible for all the business's debts, which means their personal assets can be used to pay off the business's debts if the business itself doesn't have enough assets to cover them.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>31", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE", "question": "Sole proprietorship is a form of business owned by", "images": [], "options": {"A": "an individual", "B": "two or more persons", "C": "a registered business subsidiary", "D": "the government"}, "answer": "A", "explanation": "A sole proprietorship is a type of business that is owned and run by one individual. There is no legal distinction between the owner and the business entity in this type of business structure. Therefore, the correct answer is 'an individual'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>32", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "Which of these qualities guaranty the keeping of money for a long period?", "images": [], "options": {"A": "Acceptability", "B": "Divisibility", "C": "Durability", "D": "Homogeneity"}, "answer": "C", "explanation": "Durability is the quality that guarantees the keeping of money for a long period. Durability refers to the ability of money to withstand wear and tear and last over time. This is important because money is often used and exchanged many times. Therefore, it needs to be durable to maintain its value and usefulness over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>33", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is not a source of fund for sole proprietorship?", "images": [], "options": {"A": "Personal savings", "B": "Borrowing from friends and relatives", "C": "Borrowing from financial institution", "D": "Government bonds"}, "answer": "D", "explanation": "A sole proprietorship is a type of business that is owned and run by one individual. The sources of funds for a sole proprietorship typically include personal savings, borrowing from friends and relatives, and borrowing from financial institutions. Government bonds, however, are not a source of funds for a sole proprietorship. Government bonds are debt securities issued by a government to support government spending and obligations. Investors buy these bonds, effectively lending money to the government. Therefore, the correct answer is 'Government bonds'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>34", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is not an advantage of partnership?", "images": [], "options": {"A": "Diversified managerial talents", "B": "Greater financial resources", "C": "Freedom to terminate business", "D": "Account is not made public"}, "answer": "C", "explanation": "The statement 'Freedom to terminate business' is not an advantage of partnership. In fact, it can be a disadvantage as the sudden withdrawal or death of a partner can lead to the dissolution of the partnership. The other options are advantages of a partnership: 'Diversified managerial talents' refers to the fact that partners can bring different skills and expertise to the business. 'Greater financial resources' refers to the fact that more partners can contribute more capital. 'Account is not made public' refers to the fact that unlike public companies, partnerships do not have to disclose their financial statements to the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>35", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is used for a single payment of many people at the same time through a bank instead of writing separate cheque?", "images": [], "options": {"A": "Debit transfer", "B": "Credit transfer", "C": "Certified cheque", "D": "Crossed cheque"}, "answer": "B", "explanation": "The term 'Credit transfer' is used for a single payment of many people at the same time through a bank instead of writing separate cheques. This is a method of payment where the payer instructs their bank to send money directly to the payee's bank account. The other options do not accurately describe this process. A 'Debit transfer' is when funds are withdrawn from one account and deposited into another. A 'Certified cheque' is a type of cheque for which the bank verifies that sufficient funds exist in the account to cover the cheque, and so it does not bounce. A 'Crossed cheque' is a cheque that has been marked specifying an instruction about the way it is to be redeemed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>36", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "The legal document that gives an individual power to protect his own piece of invention is called", "images": [], "options": {"A": "copy right", "B": "license", "C": "patent right", "D": "trade mark"}, "answer": "C", "explanation": "The legal document that gives an individual power to protect his own piece of invention is called a 'Patent right'. A patent is a form of intellectual property that gives its owner the legal right to exclude others from making, using, or selling an invention for a limited period of years. The other options do not accurately describe this. A 'Copy right' is a legal right that grants the creator of an original work exclusive rights to its use and distribution. A 'License' is a legal instrument granting someone permission to use or access something. A 'Trade mark' is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>37", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A mortage bank is primarily concerned with financing the acquisition of", "images": [], "options": {"A": "motor vehicle", "B": "research equipment", "C": "computer machine", "D": "dwelling houses"}, "answer": "D", "explanation": "A mortgage bank is a financial institution that specializes in originating and/or servicing mortgage loans. In the US, it is a state-licensed banking entity that makes mortgage loans directly to consumers. The primary purpose of a mortgage bank is to provide loans to those looking to purchase real estate, such as dwelling houses. Therefore, the correct answer is 'dwelling houses'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>38", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The work of actuaries is to", "images": [], "options": {"A": "underwrite insurance risks", "B": "calculate insurance premiums", "C": "settle insurance claims", "D": "assess profits for insurance companies"}, "answer": "B", "explanation": "Actuaries use mathematics, statistics, and financial theory to study uncertain future events, especially those of concern to insurance and pension programs. They evaluate the likelihood of those events, design creative ways to reduce the likelihood and decrease the impact of adverse events that actually do occur. One of their main responsibilities is to calculate insurance premiums, which is the amount of money an individual or business pays for an insurance policy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>39", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Government financial grants is a source of capital to a", "images": [], "options": {"A": "partnership", "B": "public limited company", "C": "public corporation", "D": "co-operative society"}, "answer": "C", "explanation": "Government financial grants are typically provided to public corporations. A public corporation is a company that has sold all or a portion of itself to the public via an initial public offering. This means that shareholders have claim to part of the company's assets and profits. Government grants are non-repayable funds or products disbursed or given by one party, often a government department, corporation, foundation or trust, to a recipient, often a nonprofit entity, educational institution, business or an individual.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>40", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : FEATURES AND IMPORTANCE", "question": "Which of the following is not a feature of a cooperative society?", "images": [], "options": {"A": "Owners are the customers", "B": "Capital can be repaid to a member", "C": "Votes are according to the shares held", "D": "Dividend is based on patronage"}, "answer": "C", "explanation": "In a cooperative society, votes are not according to the shares held. This is because a cooperative society operates on the principle of 'one man, one vote'. This means that each member has equal voting rights irrespective of the number of shares held by them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>41", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The practice of selling a product below the cost price to attract customers to a shop is known as", "images": [], "options": {"A": "hedging", "B": "loss leader", "C": "skimming", "D": "under-invoicing"}, "answer": "B", "explanation": "The practice of selling a product below the cost price to attract customers to a shop is known as 'loss leader'. This is a marketing strategy where a product is sold at a price below its market cost to stimulate other sales of more profitable goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>42", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "Which of the following is not contained in a deed of partnership?", "images": [], "options": {"A": "Names and address of partners", "B": "Ratio for sharing profits and losses", "C": "Investment of each partner", "D": "Rate of taxation"}, "answer": "D", "explanation": "The rate of taxation is not contained in a deed of partnership. A deed of partnership typically includes the names and addresses of partners, the ratio for sharing profits and losses, and the investment of each partner. The rate of taxation is determined by the government and not agreed upon in the partnership agreement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>43", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The publication of facts on a firm's product is called", "images": [], "options": {"A": "merchandizing", "B": "exhibition", "C": "feature articles", "D": "mass advertizing"}, "answer": "C", "explanation": "The publication of facts on a firm's product is called feature articles. Feature articles are in-depth pieces that explore a range of topics about a product. They provide detailed information about the product, its uses, benefits, and other relevant facts. This is different from merchandising, exhibition, and mass advertising which are more about promoting the product rather than providing detailed facts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>44", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is not a function of a retailer?", "images": [], "options": {"A": "Providing after sales service", "B": "Stocking variety of goods", "C": "Selling in small units to the consumers", "D": "Financing manufacturers"}, "answer": "D", "explanation": "Financing manufacturers is not a function of a retailer. Retailers are primarily involved in selling goods to the end consumers. They may provide after-sales service, stock a variety of goods, and sell in small units to consumers. However, providing finance to manufacturers is typically a function of financial institutions, not retailers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>45", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A firm on the stock exchange which agrees to buy shares not bought after a public offer is", "images": [], "options": {"A": "a broker", "B": "a stag", "C": "a jobber", "D": "an underwriter"}, "answer": "D", "explanation": "A firm on the stock exchange which agrees to buy shares not bought after a public offer is an underwriter. Underwriters are typically investment banks that agree to buy any shares not purchased by the public in an initial public offering (IPO). This provides a safety net for the company making the IPO, as it ensures they will raise the capital they need. A broker, stag, and jobber have different roles in the stock exchange.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2010>46", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following ancillary services makes it possible for goods to be where they are required?", "images": [], "options": {"A": "Communication", "B": "Banking", "C": "Transportation", "D": "Insurance"}, "answer": "C", "explanation": "Transportation is the ancillary service that makes it possible for goods to be where they are required. Ancillary services are those that support the primary activities of a business or an economy. In this case, transportation supports the movement of goods from one place to another, ensuring they reach the required destination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2010>47", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer 47 to 49.   Ojo bought a bicycle for ₦20,000, and repaired it at a cost of ₦5,000. He then sold the bicycle for ₦30,000    What was his net profit?", "images": [], "options": {"A": "₦35,000", "B": "₦25,000", "C": "₦15,000", "D": "₦5,000"}, "answer": "D", "explanation": "The net profit is calculated by subtracting the total cost (purchase price + repair cost) from the selling price. In this case, Ojo bought the bicycle for ₦20,000 and spent ₦5,000 on repairs, making the total cost ₦25,000. He then sold the bicycle for ₦30,000. Therefore, his net profit is ₦30,000 - ₦25,000 = ₦5,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>48", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer 47 to 49.   Ojo bought a bicycle for ₦20,000, and repaired it at a cost of ₦5,000. He then sold the bicycle for ₦30,000   What is the percentage of expenses over cost?", "images": [], "options": {"A": "50%", "B": "33%", "C": "25%", "D": "17%"}, "answer": "C", "explanation": "% of expenses over cost =  500/20,000 x 100      = 25%", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>49", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the following information below to answer 47 to 49.   Ojo bought a bicycle for ₦20,000, and repaired it at a cost of ₦5,000. He then sold the bicycle for ₦30,000   What is the cost of goods sold?", "images": [], "options": {"A": "₦30,000", "B": "₦25,000", "C": "₦20,000", "D": "₦15,000"}, "answer": "B", "explanation": "The cost of goods sold is the total cost that a company incurs to produce a product or service. In this case, Ojo bought a bicycle for ₦20,000 and repaired it at a cost of ₦5,000. Therefore, the cost of goods sold is ₦20,000 + ₦5,000 = ₦25,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2010>50", "subject": "Commerce", "year": "2010", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following mode of transport involves the use of tramps?", "images": [], "options": {"A": "Land transport", "B": "Sea transport", "C": "Air transport", "D": "Pipeline"}, "answer": "B", "explanation": "Tramps are ships that have no fixed schedules or ports of call. They go where the cargo is and drop it off where it's needed. Therefore, the mode of transport that involves the use of tramps is sea transport.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>1", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "When the government gives up its ownership and control of a business to individuals, this is known as", "images": [], "options": {"A": "nationalization", "B": "commercialization", "C": "privatization", "D": "indigenization"}, "answer": "C", "explanation": "Privatization is the process by which a government-owned business or property becomes owned by private, non-government parties. This process can involve either selling government-owned property or businesses to private individuals or allowing the private sector to engage in functions that were previously controlled by the government. Therefore, the correct answer is 'privatization'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>2", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "The reward received by a party in a correct agreement is known as", "images": [], "options": {"A": "consideration", "B": "acceptance", "C": "offer", "D": "warranty"}, "answer": "A", "explanation": "In contract law, consideration is the benefit that each party gets or expects to get from the contractual deal. It is an essential element for the formation of a contract. It can be anything of value, such as an item or a service, which each party gives as a sign of agreement to the terms of the contract. Therefore, the correct answer is 'consideration'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>3", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Payment to a ship owner for carrying one's cargo is", "images": [], "options": {"A": "demurrage", "B": "fare", "C": "dock due", "D": "freight"}, "answer": "D", "explanation": "Freight is the term used to describe the cost of transporting goods from one place to another by any mode of transport, including sea, air, or land. The payment made to a ship owner for carrying one's cargo is referred to as 'freight'. Therefore, the correct answer is 'freight'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>4", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is not pre-sale service?", "images": [], "options": {"A": "Repair and maintenance work", "B": "Providing detailed information about the goods to be purchased", "C": "Demonstrating the use and performance of the product to be sold", "D": "Setting up facilities for storing the product to be bought"}, "answer": "A", "explanation": "Pre-sale services are those services that are provided before the purchase of the product. Repair and maintenance work is a post-sale service, not a pre-sale service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>5", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "Which of the following is used to inform the addressee that he has a registered parcel for collection?", "images": [], "options": {"A": "Counterfoil", "B": "Express label", "C": "Slip", "D": "Telegram"}, "answer": "C", "explanation": "A slip is typically left at the addressee's address to inform them of a registered parcel for collection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>6", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The co-operative society that perform a combination of the function of other types of cooperative is called", "images": [], "options": {"A": "consumer cooperative", "B": "multipurpose cooperative", "C": "producer cooperative", "D": "thrift and credit cooperative"}, "answer": "B", "explanation": "A multipurpose cooperative is a type of co-operative society that performs a combination of the functions of other types of cooperatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>7", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "That portion of the share capital which the company has asked the shareholders to pay for is known as", "images": [], "options": {"A": "authorised capital", "B": "paid-up capital", "C": "issued capital", "D": "called-up capital"}, "answer": "D", "explanation": "Called-up capital is the portion of share capital that a company has asked its shareholders to pay. Authorised capital is the maximum amount of share capital that a company can issue. Paid-up capital is the amount of money a company has received from shareholders in exchange for shares. Issued capital is the total value of the shares that a company has issued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>8", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "One of the advantages of air transport over other forms of transport is", "images": [], "options": {"A": "safety", "B": "flexibility", "C": "cost", "D": "speed"}, "answer": "D", "explanation": "Air transport is significantly faster than other forms of transport, especially for long distances. Safety, flexibility, and cost are also factors, but they are not the primary advantage of air transport. Safety can vary depending on the specific circumstances, flexibility is limited by factors such as airport locations and flight schedules, and cost is generally higher for air transport compared to other forms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>9", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Which of the following are elements of valid contract?", "images": [], "options": {"A": "Discharge and performance", "B": "Offer and acceptance", "C": "Age and maturity", "D": "Promise and capacity"}, "answer": "B", "explanation": "The elements of a valid contract include offer and acceptance, intention to create legal relations, consideration, capacity to contract, and legality of the object. Discharge and performance are stages in the life of a contract, not elements of a contract. Age and maturity relate to the capacity to contract, but they are not elements in themselves. Promise and capacity are also related to contract formation, but they are not standalone elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>10", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The last link in the channel of distribution is the", "images": [], "options": {"A": "retailer", "B": "consumer", "C": "wholesaler", "D": "producer"}, "answer": "B", "explanation": "The last link in the channel of distribution is the consumer. The channel of distribution refers to the path or route along which goods move from producers or manufacturers to ultimate consumers or industrial users. It starts with the producer and ends with the consumer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>11", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Taxes on imported foreign goods are known as", "images": [], "options": {"A": "excise duties", "B": "tariffs", "C": "ad valorem taxes", "D": "dock dues"}, "answer": "B", "explanation": "Taxes on imported foreign goods are known as tariffs. Tariffs are a type of tax imposed on imported goods (and sometimes exported goods) by the domestic government. They are used to increase the price of imported goods and services, making them more expensive for consumers and thus less competitive with domestic goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>12", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "If Karamos who lives in The Gambia imports goods from Senegal and later sells them in Guinea Bissau: Karamo is engaged in", "images": [], "options": {"A": "multi-lateral trade", "B": "counter trade", "C": "barter trade", "D": "entrepot trade"}, "answer": "D", "explanation": "If Karamos who lives in The Gambia imports goods from Senegal and later sells them in Guinea Bissau, Karamo is engaged in entrepot trade. Entrepot trade is a form of international trade in which goods are imported from one country and then re-exported to another country, often after some processing or re-packaging.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>13", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Manufacturer may sell directly to the consumers where goods are   i. made to customer's specification   ii. advertised by the manufacturer   iii.perishable   iv. highly technical.", "images": [], "options": {"A": "I, III and IV only", "B": "I and III only", "C": "III, IV and V only", "D": "III and IV only"}, "answer": "A", "explanation": "Manufacturers may sell directly to consumers when goods are made to customer's specification, are perishable, or are highly technical. This is because these types of goods often require direct interaction between the manufacturer and the consumer. Goods made to customer's specification need direct interaction to ensure the product meets the customer's needs. Perishable goods need to be sold quickly, which can often be done more efficiently by the manufacturer. Highly technical goods may require the manufacturer's knowledge to explain and sell the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>14", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following is a means of payment?", "images": [], "options": {"A": "I.O.U", "B": "Postal order", "C": "Promissory note", "D": "C.I.F"}, "answer": "B", "explanation": "A postal order is a means of payment. It is a financial instrument usually intended for sending money through the mail. It is purchased at a post office and is payable at another post office to the named recipient. An I.O.U is a document that acknowledges a debt but it is not a means of payment. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date. A promissory note typically contains all the terms pertaining to the indebtedness, such as the principal amount, interest rate, maturity date, date and place of issuance, and issuer's signature. CIF (Cost, Insurance, and Freight) is a term used in international trade for the point at which responsibility for goods transfers from the seller to the buyer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>15", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Shipping services rendered by Nigeria to The Gambia would be classified by The Gambia as", "images": [], "options": {"A": "invisible imports", "B": "invisible exports", "C": "visible imports", "D": "visible export"}, "answer": "A", "explanation": "Shipping services rendered by Nigeria to The Gambia would be classified by The Gambia as invisible imports. In the balance of payments, invisible imports are services bought from foreign countries. These services do not result in the physical movement of tangible goods and are not visible. They include services like transportation, banking, insurance, tourism, and technology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>16", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The main division of production are", "images": [], "options": {"A": "industry, direct and indirect services", "B": "extraction, manufacturing and construction", "C": "industry, commerce and direct services", "D": "industry, commerce and trading"}, "answer": "B", "explanation": "The main divisions of production are extraction, manufacturing, and construction. These are the primary stages of production where raw materials are extracted, then manufactured into goods, and finally, construction involves building infrastructure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>17", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000.  What is the cost of goods sold?", "images": [], "options": {"A": "D28,000", "B": "D27,000", "C": "D8,000", "D": "D5,000"}, "answer": "B", "explanation": "The cost of goods sold (COGS) is calculated by adding the opening stock and purchases, then subtracting the closing stock. In this case, COGS = D28,000 (Purchases) + D2,000 (Opening Stock) - D3,000 (Closing Stock) = D27,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>18", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000.  The average stock is", "images": [], "options": {"A": "D5,000", "B": "D3,000", "C": "D2,500", "D": "D2,000"}, "answer": "C", "explanation": "The average stock is calculated by adding the opening and closing stock and dividing by 2.     In this case, Average Stock = (D2,000 (Opening Stock) + D3,000 (Closing Stock)) / 2     = D2,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>19", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000. What is the rate of turnover?", "images": [], "options": {"A": "13.5 times", "B": "10.8 times", "C": "9 times", "D": "5.4 times"}, "answer": "B", "explanation": "The rate of turnover is calculated by dividing the cost of goods sold by the average inventory. The cost of goods sold is calculated by adding the opening stock to purchases and then subtracting the closing stock. In this case, the cost of goods sold is D36,000 + D28,000 - D3,000 = D61,000. The average inventory is the average of the opening and closing stock, which is (D2,000 + D3,000) / 2 = D2,500. Therefore, the rate of turnover is D61,000 / D2,500 = 10.8 times.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>20", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "In marine insurance when a particular cargo is thrown into the sea in order to prevent the ship from sinking, the type of marine loss is", "images": [], "options": {"A": "Particular average loss", "B": "general average loss", "C": "total average loss", "D": "constructive average loss"}, "answer": "B", "explanation": "In marine insurance, a general average loss refers to a loss resulting from a voluntary sacrifice of any part of the ship or cargo, or an expenditure, to safeguard the ship and the rest of its cargo. If a particular cargo is thrown into the sea to prevent the ship from sinking, it is a voluntary sacrifice made for the safety of the ship and the rest of the cargo, hence it is a general average loss.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>21", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The turnover of a trade is the", "images": [], "options": {"A": "number of times the stock is sold", "B": "total sales made during a period", "C": "profit made during the period", "D": "total purchases made during the period"}, "answer": "B", "explanation": "The turnover of a trade refers to the total sales made during a period. It is the total amount of goods or services sold by a business during a certain period. It does not refer to the number of times the stock is sold, the profit made during the period, or the total purchases made during the period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>22", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The total assets of a business less its total liability is known as", "images": [], "options": {"A": "capital owned", "B": "share capital", "C": "issued capital", "D": "working capital"}, "answer": "A", "explanation": "The total assets of a business less its total liability is known as capital owned. This is because the capital owned by a business is essentially the net worth of the business, which is calculated by subtracting the total liabilities from the total assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>23", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A document is issued to the public by a company to advertise its share is known as", "images": [], "options": {"A": "prospectus", "B": "tender", "C": "share certificate", "D": "trading certificate"}, "answer": "A", "explanation": "A document issued to the public by a company to advertise its share is known as a prospectus. A prospectus is a legal document that institutions and businesses use to describe the securities they are offering for participants and buyers. It provides details about the financial health of the company offering the securities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>24", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "An overdraft is the", "images": [], "options": {"A": "amount permitted to be withdrawn in excess of one's deposit", "B": "excess cash withdrawn by commercial banks from the Central Bank", "C": "credit balance standing in the name of a customer", "D": "special deposit made by commercial banks"}, "answer": "A", "explanation": "An overdraft is the amount permitted to be withdrawn in excess of one's deposit. It is a type of short-term loan that allows you to continue withdrawing money even if your account has no funds in it or not enough to cover the withdrawal. Banks may permit this as a form of credit to trusted customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>25", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following is NOT a principle of insurance?", "images": [], "options": {"A": "Insurable interest", "B": "Subrogation", "C": "Surrender value", "D": "proximate cause"}, "answer": "C", "explanation": "The principles of insurance include insurable interest, subrogation, and proximate cause. However, surrender value is not a principle of insurance. Surrender value is the amount the policyholder will receive from the insurance company if he/she decides to exit the policy before maturity. It is a term associated with life insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>26", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "The par value of a share is also known as its", "images": [], "options": {"A": "premium price", "B": "market price", "C": "discount price", "D": "nominal price"}, "answer": "D", "explanation": "The par value of a share is also known as its nominal price. The par value is the face value of a bond or stock as stated by the issuer. It is the value at which the share was originally issued and it remains constant over time, regardless of the market price of the share.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>27", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque dated 15th March, 2012 will become stale on", "images": [], "options": {"A": "6th June, 2012", "B": "16th July, 2012", "C": "16th August, 2012", "D": "16th September 2012"}, "answer": "D", "explanation": "A cheque becomes stale after a period of six months from the date written on it. Therefore, a cheque dated 15th March, 2012 will become stale on 16th September, 2012. A stale cheque is not honored by the bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>28", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Bank settle their indebtedness in the", "images": [], "options": {"A": "discount house", "B": "stock exchange market", "C": "commercial bank", "D": "clearing house"}, "answer": "D", "explanation": "Banks settle their indebtedness in the clearing house. A clearing house is a financial institution formed to facilitate the exchange (clearing) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>29", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following distinguishes home trade from foreign trade?", "images": [], "options": {"A": "Payments are easily arranged", "B": "Taxes are levied", "C": "Goods have to be warehoused", "D": "Middlemen are not required"}, "answer": "A", "explanation": "The main difference between home trade and foreign trade is that in home trade, payments are easily arranged. This is because the buyer and seller are in the same country and use the same currency. In foreign trade, payments can be more complex due to differences in currency and banking regulations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>30", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Before the advent of legal tender and credit instrument, which of the following was used as a medium of exchange?", "images": [], "options": {"A": "Currency note", "B": "Cowries", "C": "Cheques", "D": "Bank drafts"}, "answer": "B", "explanation": "Before the advent of legal tender and credit instruments, cowries were used as a medium of exchange. Cowries are a type of shell which were used as currency in some cultures. They were used in many parts of Africa, Asia, and the Americas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>31", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "When C.I.F is quoted on an invoice, it means that the price includes the", "images": [], "options": {"A": "cost of goods only", "B": "cost of insurance only", "C": "cost of carriage only", "D": "cost, insurance and carriage"}, "answer": "D", "explanation": "C.I.F stands for Cost, Insurance, and Freight. It is a term used in international trade that means the seller of the goods is responsible for arranging and paying for transportation of the goods to the port of destination, including the cost of insurance. Therefore, when C.I.F is quoted on an invoice, it means that the price includes the cost of the goods, the cost of insurance, and the cost of carriage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>32", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Encouraging a high quality of member's products through the circulation of research information is a function of", "images": [], "options": {"A": "Manufacturers Association", "B": "Trade Union", "C": "Employers' Association", "D": "Consumers' Association"}, "answer": "A", "explanation": "The function of encouraging a high quality of member's products through the circulation of research information is typically performed by a Manufacturers Association. This is because a Manufacturers Association is a group of businesses in the same industry that collaborate to promote their common interests, including the improvement of product quality and the sharing of research information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>33", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "A voluntary association of business executives within a locality is known as", "images": [], "options": {"A": "Trade union", "B": "consumers' Association", "C": "Chamber of commerce", "D": "Trade Association"}, "answer": "C", "explanation": "A voluntary association of business executives within a locality is known as a Chamber of Commerce. A Chamber of Commerce is a local organization of businesses whose goal is to further the interests of businesses in a locality. They often offer networking opportunities, training, and other resources to help local businesses succeed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>34", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following is NOT a function of the ports authority?", "images": [], "options": {"A": "Providing facilities for loading and off-loading of vessels", "B": "Collecting dock dues", "C": "Providing enough ships for the country", "D": "Dredging of harbours"}, "answer": "C", "explanation": "The function of the ports authority is to manage and operate the ports. This includes providing facilities for loading and off-loading of vessels, collecting dock dues, and dredging of harbours. However, providing enough ships for the country is not a function of the ports authority. This is typically the responsibility of the shipping companies or the government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>35", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Using symbol, letters, name or combination of these by a company to distinguish its products is", "images": [], "options": {"A": "product cycle", "B": "marketing mix", "C": "trading mark", "D": "market segmentation"}, "answer": "C", "explanation": "A trading mark, also known as a trademark, is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others. The trademark owner can be an individual, business organization, or any legal entity. It is not a product cycle, marketing mix or market segmentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>36", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Trade as a division of commerce is usually classified into", "images": [], "options": {"A": "retail and wholesale", "B": "import and export", "C": "home and foreign", "D": "visible and invisible"}, "answer": "C", "explanation": "Trade is divided into home or domestic or internal trade and foreign/external/international trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>37", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "The box marked 'X' stands for", "images": ["Commerce/imgs/2011/comm1.png"], "options": {"A": "indirect services", "B": "industry", "C": "occupation", "D": "aids to trade"}, "answer": "B", "explanation": "The main divisions of production: industry, commerce & direct services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>38", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The box marked 'Y' stands for", "images": ["Commerce/imgs/2011/comm1.png"], "options": {"A": "wholesale", "B": "direct services", "C": "Aids to trade", "D": "foreign trade"}, "answer": "C", "explanation": "The aids to trade include transport, communication, banking etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>39", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The box marked 'Z' stands for", "images": ["Commerce/imgs/2011/comm1.png"], "options": {"A": "warehousing", "B": "Home trade", "C": "Foreign trade", "D": "Marketing"}, "answer": "A", "explanation": "Warehousing is one of the aids to trade and it involves the act of storing goods ahead of demand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>40", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Liquid capital in a business means the", "images": [], "options": {"A": "movable assets of the business", "B": "authorised capital", "C": "issued capital", "D": "assets easily convertible to cash"}, "answer": "D", "explanation": "Liquid capital in a business refers to assets that can be easily converted into cash. These assets are highly liquid and can be sold or exchanged for cash without affecting their market value. This is important for businesses as it allows them to quickly access funds to meet short-term obligations or make quick investments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>41", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "The \"relationship which subsists between two or more persons carrying on a business with a view of profit is", "images": [], "options": {"A": "cooperative society", "B": "partnership", "C": "Public limited company", "D": "credit union"}, "answer": "B", "explanation": "The statement describes a partnership. A partnership is a type of business organization where two or more individuals pool money, skills, and other resources, and share profit and loss in accordance with terms of the partnership agreement. In absence of such agreement, a partnership is assumed to exist where the participants in an enterprise agree to share the associated risks and rewards proportionately.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>42", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "\"Right issues\" is the", "images": [], "options": {"A": "individual's right to be issued shares on subscription", "B": "right of shareholders to vote on issues", "C": "preferential right to return to shares", "D": "shares offered to existing shareholders at a cheaper price"}, "answer": "D", "explanation": "\"Right issues\" refers to the shares offered to existing shareholders at a cheaper price. This is a way for companies to raise additional equity capital. With the help of rights issues, the company asks the existing shareholders to buy additional new shares in proportion to their existing holdings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>43", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "In limited partnership the partners'", "images": [], "options": {"A": "capital is limited", "B": "liability is limited", "C": "participation is limited", "D": "ownership is unlimited"}, "answer": "B", "explanation": "In a limited partnership, the liability of at least one partner is limited. This means that they are only liable for the amount of capital they have invested into the business and their personal assets are not at risk. This is different from a general partnership where all partners have unlimited liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>44", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following pieces of information would be found in a typical debit note?", "images": [], "options": {"A": "Customer code", "B": "Date of invoice", "C": "Brief reason for the debit", "D": "E & O.E"}, "answer": "C", "explanation": "Debit notes usually all include the same general information: the date of the note, a serial number, a brief description of the prior business transaction, details of items returned (including sales taxes and a reference to the invoice), and the signatures of appropriate company authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>45", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "The completion of the production process by grading and branding of goods is a function of the", "images": [], "options": {"A": "transporter", "B": "wholesaler", "C": "retailer", "D": "consumer"}, "answer": "B", "explanation": "The completion of the production process by grading and branding of goods is a function of the wholesaler. Wholesalers often sort goods into different grades, depending on their quality. They also often label the goods with their own brand or the manufacturer's brand. This is part of the value-added services that wholesalers provide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>46", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The development of commerce was encouraged by the desire to", "images": [], "options": {"A": "get goods and services to others", "B": "work with others", "C": "create wealth for the nation", "D": "satisfy all wants and needs"}, "answer": "A", "explanation": "The development of commerce was primarily encouraged by the desire to get goods and services to others. Commerce involves the exchange of goods and services, and its development was driven by the need to facilitate this exchange, making goods and services available to those who need them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2011>47", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following countries is NOT a member of the Lake Chad Basin Commission?", "images": [], "options": {"A": "Nigeria", "B": "Chad", "C": "Gabon", "D": "Cameroun"}, "answer": "C", "explanation": "Gabon is not a member of the Lake Chad Basin Commission. The Lake Chad Basin Commission (LCBC) is a regional body established in May 22,1964 by Cameroon, Chad, Niger, and Nigeria. Other countries, such as the Central African Republic and Libya, joined later. However, Gabon is not a member of this commission.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>48", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "A false statement made by one party with an intention of inducing the other party to enter into a contract with him is known as", "images": [], "options": {"A": "misrepresentation", "B": "legal capacity", "C": "consensus ad idem", "D": "consideration"}, "answer": "A", "explanation": "A false statement made by one party with an intention of inducing the other party to enter into a contract with him is known as misrepresentation. Misrepresentation is a concept in contract law where a false or misleading statement is made that convinces another party to enter into an agreement. The statement could be a fact that is not true, or could be a promise made without any intention of performing it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2011>49", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The essence of adopting the marketing concept by a firm is the recognition that goods and services have no value unless they are", "images": [], "options": {"A": "desirable to customers", "B": "company oriented", "C": "beautiful packaged", "D": "profit oriented"}, "answer": "A", "explanation": "The marketing concept is a business philosophy that holds the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets. Therefore, the essence of adopting the marketing concept by a firm is the recognition that goods and services have no value unless they are desirable to customers. This is because the value of a product or service is determined by the customer's perception of its worth, not by the cost of production or the price set by the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2011>50", "subject": "Commerce", "year": "2011", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "When consumers engage in action that express dissatisfaction with the quantity, price and quality of goods available, such action is termed", "images": [], "options": {"A": "Consumer behaviour", "B": "Consumerism", "C": "Consumer education", "D": "Consumer orientation"}, "answer": "B", "explanation": "Consumerism is a social and economic order that encourages the acquisition of goods and services in ever-increasing amounts. When consumers engage in action that express dissatisfaction with the quantity, price and quality of goods available, such action is termed Consumerism. This is because consumerism involves advocating for the rights and interests of consumers, including the right to information, the right to choose, the right to safety, and the right to be heard.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>1", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The development of trade in West Africa was aided by the", "images": [], "options": {"A": "emergence of traditional rules", "B": "arrival of the Portuguese", "C": "introduction of tax payment", "D": "introduction of money"}, "answer": "B", "explanation": "The development of trade in West Africa was significantly aided by the arrival of the Portuguese. The Portuguese were among the first Europeans to explore Africa. They established trade routes and began trading goods, which boosted the economy and development of trade in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>2", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "An issuing house is an outlet for", "images": [], "options": {"A": "new shares and bonds", "B": "non listed companies shares", "C": "existing shares and bonds", "D": "only gilt-edged securities"}, "answer": "A", "explanation": "An issuing house is a financial institution that acts as an intermediary between a company seeking to issue new shares and the public. The issuing house helps the company in the process of issuing new shares or bonds to raise capital. Therefore, an issuing house is an outlet for new shares and bonds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>3", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following is quoted when the buyer is responsible for the cost of loading the goods from the seller's warehouse up to his own warehouse?", "images": [], "options": {"A": "F.O.R", "B": "C.I.F", "C": "F.A.S", "D": "Loco"}, "answer": "D", "explanation": "The term 'Loco' is used in trade when the buyer is responsible for the cost of loading the goods from the seller's warehouse up to his own warehouse. It is a trade term indicating that the seller delivers the goods to the buyer at the seller's location or shipping point. In a 'Loco' contract, all expenses and risks related to the goods are transferred from the seller to the buyer at the seller's premises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>4", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The relationship between all imports and exports of a country is known as", "images": [], "options": {"A": "terms of trade", "B": "balance of trade", "C": "balance of payment", "D": "terms of payment"}, "answer": "B", "explanation": "The balance of trade is the difference between the value of a country's imports and exports for a given period. It is the largest component of a country's balance of payments. The terms of trade, on the other hand, refer to the relative price of imports in terms of exports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>5", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is an example of large-scale retailing?", "images": [], "options": {"A": "Hawking", "B": "Mobile shops", "C": "kiosks", "D": "Department stores"}, "answer": "D", "explanation": "Large-scale retailing refers to a retail business that operates on a large scale, such as a department store. Department stores are large retail establishments that sell a wide variety of goods. They are usually part of a retail chain and sell a broad range of merchandise, including clothing, furniture, appliances, toys, cosmetics, housewares, and food. Hawking, mobile shops, and kiosks are examples of small-scale retailing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2012>6", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque drawn by a bank on itself is an/a", "images": [], "options": {"A": "direct debit", "B": "bank draft", "C": "bank transfer", "D": "overdraft"}, "answer": "B", "explanation": "A bank draft is a type of check where the payment is guaranteed to be available by the issuing bank. It is a payment on behalf of a payer that is guaranteed by the issuing bank. Direct debit is a financial transaction in which one person withdraws funds from another person's bank account. Formally, the person who directly draws the funds instructs his or her bank to collect an amount directly from another's bank account designated by the payer and pay those funds into a bank account designated by the payee. Bank transfer is a method of electronic funds transfer from one person or entity to another. An overdraft occurs when money is withdrawn from a bank account and the available balance goes below zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>7", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A voluntary body formed by people in the same line of business for the purpose of protecting their interest is a", "images": [], "options": {"A": "trade association", "B": "trade union", "C": "chamber of commerce", "D": "trading partnership"}, "answer": "A", "explanation": "A trade association is a voluntary group of business people in the same industry who join together to further their collective interests, particularly in negotiating with governments, unions, and other businesses. They are formed to protect the interests of the members. Trade unions, on the other hand, are organizations of workers who have banded together to achieve common goals such as better working conditions. The chamber of commerce is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. A trading partnership is a business run by two or more individuals who share the profits and losses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2012>8", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Those who are engaged in the distribution of goods belong to", "images": [], "options": {"A": "commercial occupation", "B": "extractive industry", "C": "manufacturing industry", "D": "construction industry"}, "answer": "A", "explanation": "Commercial occupation refers to activities related to the buying and selling of goods and services. Those who are engaged in the distribution of goods belong to commercial occupations. Extractive industry refers to businesses that revolve around different forms of extraction, mining, and quarrying. Manufacturing industry refers to businesses that produce finished goods from raw materials by using various processes and tools. Construction industry refers to businesses involved in the construction of buildings or engineering projects.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2012>9", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "When an insurance policy is declared void because of a false declaration, the principle involved is ?", "images": [], "options": {"A": "indemnity", "B": "subrogation", "C": "proximate cause", "D": "utmost good faith"}, "answer": "D", "explanation": "The principle of utmost good faith, also known as Uberrima fides, is a legal doctrine which stipulates that all parties to an insurance contract must deal in good faith, making a full declaration of all material facts in the insurance proposal. This means that the insured must disclose all facts about the risk to be insured. If an insurance policy is declared void because of a false declaration, the principle involved is utmost good faith. The other options refer to different principles of insurance. Indemnity is a principle that states that the insured may not be compensated by the insurance company in an amount exceeding the insured's economic loss. Subrogation refers to the right of an insurer to pursue the party that caused an insurance loss to the insured in an attempt to recover funds paid in the claim. Proximate cause is an event sufficiently related to a legally recognizable injury to be held to be the cause of that injury.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>10", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Buildings and machinery used in running of a business are examples of", "images": [], "options": {"A": "current assets", "B": "intangible assets", "C": "liquid assets", "D": "fixed assets"}, "answer": "D", "explanation": "Buildings and machinery used in running a business are examples of fixed assets. Fixed assets, also known as long-term assets or property, plant, and equipment (PP&E), are assets that are expected to provide benefits for more than one year, such as buildings, land, equipment, machinery, and vehicles. They are used in the production of goods and services, rental to third parties, or for administrative purposes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2012>11", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Which of the following is classified as invisible item in balance payment?", "images": [], "options": {"A": "import of goods", "B": "salaries of expatriates", "C": "export of groundnuts", "D": "sales of equipment"}, "answer": "B", "explanation": "Salaries of expatriates are classified as invisible items in balance of payments. Invisible items in balance of payments refer to non-physical or non-tangible items that still have a value, such as services, royalties, and income from foreign investments. The salaries of expatriates fall under the category of services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>12", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "Collecting information on the taste of consumers and the extent of demand for a product is", "images": [], "options": {"A": "market research", "B": "market segmentation", "C": "marketing mix", "D": "marketing concept"}, "answer": "A", "explanation": "Collecting information on the taste of consumers and the extent of demand for a product is market research. Market research is the process of gathering, analyzing, and interpreting information about a market, a product or service to be offered for sale in that market, and about the past, present, and potential customers for the product or service. It includes research into the characteristics, spending habits, location, and needs of your business's target market, the industry as a whole, and the particular competitors you face.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>13", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is not an insurance of indemnity?", "images": [], "options": {"A": "Life", "B": "Marine", "C": "Burglary", "D": "Fire"}, "answer": "A", "explanation": "Insurance of indemnity refers to a type of insurance that seeks to restore the insured party to the position they were in before the loss or damage occurred. It applies to most types of insurance, such as fire, marine, and burglary insurance. However, life insurance is not an insurance of indemnity because the value of a human life cannot be measured in monetary terms. Therefore, the insurer does not restore the insured to their previous position but instead pays a predetermined amount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>14", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The entitlement of a debenture holder from a company's income is known as", "images": [], "options": {"A": "commission", "B": "interest", "C": "lien", "D": "dividend"}, "answer": "B", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. The entitlement of a debenture holder from a company's income is known as interest. This is because the company is obligated to pay a fixed rate of interest before any dividend is paid to the shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>15", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The collection of tariffs on imported goods is the function of", "images": [], "options": {"A": "Port Authority", "B": "Customs and Excise Authority", "C": "Clearing and Forwarding Agents", "D": "Export Promotion Council"}, "answer": "B", "explanation": "The collection of tariffs on imported goods is the function of the Customs and Excise Authority. Tariffs are a type of tax imposed on imported goods, and the Customs and Excise Authority is responsible for enforcing these tariffs and collecting the revenue. The other options, such as the Port Authority, Clearing and Forwarding Agents, and Export Promotion Council, do not have the authority to collect tariffs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>16", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "A licensed person who is authorized to sell to the highest bidder is", "images": [], "options": {"A": "principal", "B": "factor", "C": "broker", "D": "auctioneer"}, "answer": "D", "explanation": "An auctioneer is a person who is licensed and authorized to sell items to the highest bidder. This is typically done in an auction setting where multiple parties bid on the item and the highest bid wins. The other options, principal, factor, and broker, do not fit the description given in the question.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>17", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "An efficient transport system enables a trader to", "images": [], "options": {"A": "widen the market for his products", "B": "avoid customs examination of goods", "C": "adopt better price policy", "D": "reduce cost of production"}, "answer": "A", "explanation": "An efficient transport system enables a trader to widen the market for his products. This is because an efficient transport system allows for goods to be transported quickly and efficiently to different areas, thus expanding the potential market. The other options, such as avoiding customs examination of goods, adopting a better price policy, and reducing cost of production, are not directly related to an efficient transport system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>18", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "The Central Bank's monetary policy instrument by which it buys and sells Treasury bills is known as", "images": [], "options": {"A": "Open Market Operation", "B": "Bank rate", "C": "Cash reserve ratio", "D": "Special Deposit"}, "answer": "A", "explanation": "The Central Bank's monetary policy instrument by which it buys and sells Treasury bills is known as Open Market Operation. Open Market Operations (OMO) is a tool used by central banks to implement monetary policy. It involves the buying and selling of government securities in the open market in order to control the money supply in the economy. The other options, Bank rate, Cash reserve ratio, and Special Deposit, are other tools used by the central bank but they do not involve the buying and selling of Treasury bills.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>19", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following acted as the Central Bank for West African countries before their independence?", "images": [], "options": {"A": "The West Africa Clearing House", "B": "The British Bank for West Africa", "C": "The West African Currency Board", "D": "The African Development Bank"}, "answer": "C", "explanation": "The West African Currency Board acted as the Central Bank for West African countries before their independence. It was established by the colonial masters to issue currency notes and coins in the West African region. The other options did not serve as a central bank.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>20", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Current account holders withdraw money by means of", "images": [], "options": {"A": "credit card", "B": "draft", "C": "withdraw form", "D": "cheque"}, "answer": "D", "explanation": "Current account holders withdraw money by means of a cheque. A cheque is a document that orders a bank to pay a specific amount of money from a person's account to the person in whose name the cheque has been issued. The other options are not the primary means of withdrawing money from a current account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>21", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is a feature of mail order business?", "images": [], "options": {"A": "Employs many shop assistants", "B": "Practice self service", "C": "Provide attractive shop front", "D": "Rent large warehouse"}, "answer": "D", "explanation": "A feature of mail order business is that they rent large warehouses. Mail order is a term which describes the buying of goods or services by mail delivery. The buyer places an order for the desired products with the merchant through some remote method such as through a telephone call or web site. Then, the products are delivered to the customer. The merchandise is typically delivered directly to an address supplied by the customer, such as a home address, but occasionally the orders are delivered to a nearby retail location for the customer to pick up. Some merchants also allow the goods to be shipped directly to a third party consumer, which is an effective way to send a gift to an out-of-town recipient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>22", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Bonded warehouse is a place where", "images": [], "options": {"A": "duty free goods are kept", "B": "perishable goods are kept", "C": "home-made goods are kept", "D": "dutiable goods are kept"}, "answer": "D", "explanation": "A bonded warehouse is a secured area where imported dutiable goods are kept until the duty owed is paid. The goods are 'in bond' meaning under the control of customs authorities. Once the duty is paid, the goods can be released.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>23", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Which of the following is concerned with promoting favourable image of an organization?", "images": [], "options": {"A": "Consumer sovereignty", "B": "Public relations", "C": "Marketing research", "D": "Market segmentation"}, "answer": "B", "explanation": "Public relations is the practice of managing and disseminating information from an individual or an organization to the public in order to affect public perception and create a favorable image. It involves activities that help to create a good image of the organization and maintain a good relationship with the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>24", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The document issued by the registrar of companies to permit a public limited company to commence business is", "images": [], "options": {"A": "Memorandum of Association", "B": "Certificate of Incorporation", "C": "Article of Association", "D": "Trading certificate"}, "answer": "D", "explanation": "A trading certificate is a document issued by the registrar of companies to a public limited company, allowing it to commence business and borrow capital. It is issued after the company has met certain requirements, including having a minimum allotted share capital.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>25", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is NOT an economic grouping?", "images": [], "options": {"A": "Lake Chad basin Commission", "B": "Economic Community of West Africa State", "C": "European Union", "D": "International Monetary Fund"}, "answer": "D", "explanation": "The International Monetary Fund (IMF) is not an economic grouping. It is an international financial institution that provides monetary cooperation and financial stability to its members. On the other hand, the Lake Chad Basin Commission, Economic Community of West Africa State, and the European Union are all examples of economic groupings, which are groups of countries that have joined together to promote economic integration and cooperation among their members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>26", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "One of the principles of insurance is", "images": [], "options": {"A": "Consequential loss", "B": "fidelity guarantee", "C": "proximate cause", "D": "surrender value"}, "answer": "C", "explanation": "One of the principles of insurance is 'proximate cause'. This principle states that the loss of an insured risk must be caused by the risk insured against. It means that the cause of the loss should be a direct cause, and not just a remote or incidental cause. The other options, 'Consequential loss', 'fidelity guarantee', and 'surrender value' are not principles of insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>27", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A written instruction by a current account holder to his bank to debit his account at regular intervals with a specified amount for a given period is known as", "images": [], "options": {"A": "standing order", "B": "money order", "C": "bank draft", "D": "over draft"}, "answer": "A", "explanation": "A 'standing order' is a written instruction by a current account holder to his bank to debit his account at regular intervals with a specified amount for a given period. A 'money order' is a payment order for a pre-specified amount of money, a 'bank draft' is a payment on behalf of a payer that is guaranteed by the issuing bank, and an 'overdraft' is a deficit in a bank account caused by drawing more money than the account holds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>28", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "A collective bundle of shares is called", "images": [], "options": {"A": "debenture", "B": "stock", "C": "bond", "D": "share"}, "answer": "B", "explanation": "A collective bundle of shares is called a stock. A stock represents ownership in a corporation and constitutes a claim on part of the corporation's assets and earnings. There are two main types of stock: common and preferred.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>29", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The assets of a business that is available as cash or near cash is called", "images": [], "options": {"A": "equity", "B": "capital employment", "C": "reserved capital", "D": "liquid capital"}, "answer": "D", "explanation": "The assets of a business that are available as cash or near cash are called liquid capital. Liquid capital refers to cash or other assets that can be easily converted into cash without losing value. These assets are considered 'liquid' because they can be sold or consumed quickly to meet debt obligations or pay for goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>30", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The bank on which a cheque is drawn is known as the", "images": [], "options": {"A": "drawer", "B": "drawee", "C": "cashier", "D": "payee"}, "answer": "B", "explanation": "The bank on which a cheque is drawn is known as the drawee. In the context of a cheque, the drawee is the bank or other financial institution that pays the amount of the cheque to the payee from the drawer's account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>31", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A percentage reduction from the quoted-price of goods given to a buyer to encourage bulk purchase is called", "images": [], "options": {"A": "cash discount", "B": "trade discount", "C": "commission", "D": "bonus"}, "answer": "B", "explanation": "A trade discount is a reduction in price given by the wholesaler/manufacturer to the retailer at the list price or catalogue price. This is done to encourage the retailer to buy more quantities. Therefore, a percentage reduction from the quoted-price of goods given to a buyer to encourage bulk purchase is called a trade discount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>32", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The difference between the cost price and selling price of an article is", "images": [], "options": {"A": "commission", "B": "mark-up", "C": "rebate", "D": "discount"}, "answer": "B", "explanation": "The difference between the cost price and selling price of an article is known as the mark-up. Mark-up is the amount added to the cost price of goods to cover overheads and profit. It is the difference between the cost of a product and its selling price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>33", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A ceiling on the quantity of commodity to be imported into the country is called", "images": [], "options": {"A": "ban", "B": "tariff", "C": "price unit", "D": "quota"}, "answer": "D", "explanation": "A quota is a government-imposed trade restriction that limits the number or monetary value of goods that a country can import or export during a particular period. Therefore, a ceiling on the quantity of a commodity to be imported into the country is called a quota.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>34", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "The buyer in a hire purchase contract becomes the legal owner of the goods by paying", "images": [], "options": {"A": "initial deposit", "B": "the last instalment", "C": "half of the purchase price", "D": "two-third of the purchase price"}, "answer": "B", "explanation": "In a hire purchase contract, the buyer does not become the legal owner of the goods until the final payment (the last instalment) is made. This is because the hire purchase agreement is essentially a hire agreement with an option to purchase at the end of the agreement, once all payments have been made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>35", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document which helps in ascertaining the correct value of imports in order to assess the custom duty is", "images": [], "options": {"A": "bill of laden", "B": "consular invoice", "C": "bill of insight", "D": "ship manifest"}, "answer": "B", "explanation": "A consular invoice is a document that represents a statement of the nature, quantity, and value of goods being shipped. This document is certified by the consular official of the importing country stationed in the foreign country and is used by the country's customs officials to verify the value, quantity, and nature of the shipment. Therefore, it helps in ascertaining the correct value of imports in order to assess the custom duty.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>36", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The combination of product, price, promotion and distribution decision employed by a company is referred to as its", "images": [], "options": {"A": "pricing policy", "B": "marketing mix", "C": "product mix", "D": "marketing concept"}, "answer": "B", "explanation": "The combination of product, price, promotion, and distribution decisions employed by a company is referred to as its marketing mix. The marketing mix is a business tool used in marketing and by marketers. The marketing mix is often crucial when determining a product or brand's offer, and is often associated with the four P's: price, product, promotion, and place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>37", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document which specified the manufacturer from whom goods are to be imported is", "images": [], "options": {"A": "closed indent", "B": "open indent", "C": "export invoice", "D": "consignment note"}, "answer": "A", "explanation": "A closed indent is a document that specifies the manufacturer from whom goods are to be imported. It is a type of purchase order that provides detailed specifications about the goods to be imported. An open indent, on the other hand, does not specify the manufacturer. Export invoice is a document that the exporter sends to the importer, while a consignment note is a document that accompanies goods being shipped.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>38", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Who among the following generally has no capacity to enter into a valid contract?", "images": [], "options": {"A": "School principals", "B": "Infants", "C": "Agents", "D": "Religious ministers"}, "answer": "B", "explanation": "According to contract law, infants or minors generally do not have the capacity to enter into a valid contract. This is because they are considered not to have the legal ability to understand the implications of the contract. School principals, agents, and religious ministers, being adults, generally have the capacity to enter into contracts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>39", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The satisfaction of consumers in all business activities is emphasized by", "images": [], "options": {"A": "market research", "B": "marketing concept", "C": "marketing mix", "D": "product differentiation"}, "answer": "B", "explanation": "The marketing concept emphasizes the satisfaction of consumers in all business activities. It is a business philosophy that holds that the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value. Market research is a component of the marketing concept, but it is not the concept itself. The marketing mix refers to the set of actions, or tactics, that a company uses to promote its brand or product in the market. Product differentiation is the process of distinguishing a product or service from others, to make it more attractive to a particular target market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>40", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document which is used when a country imposes ad valorem duties is", "images": [], "options": {"A": "bill of laden", "B": "consular invoice", "C": "certificate of origin", "D": "open indent"}, "answer": "B", "explanation": "Ad valorem duties are taxes that are based on the assessed value of a product, service, or property. The consular invoice is a document that is used when a country imposes ad valorem duties. This document is prepared by the consular official of the country to which goods are being shipped. It is used to verify the quantity, nature, and value of the goods being shipped. This is important for the calculation of ad valorem duties.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>41", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "An activity involving buying, selling and contribution of goods and services is known as", "images": [], "options": {"A": "trade", "B": "marketing mix", "C": "exchange", "D": "commerce"}, "answer": "D", "explanation": "Commerce is the activity of buying, selling, and exchanging goods and services. It includes all those activities which are necessary for maintaining the free flow of goods and services. It is a broader term than trade as it includes trade and aids-to-trade. Therefore, the correct answer is commerce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2012>42", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following arrangement of document is the correct sequences as used in the detail trade?     I. Quotation   II. Enquiry   III. Order   IV. Invoice", "images": [], "options": {"A": "I, II, III, IV", "B": "II, I, III, IV", "C": "I, IV, III only", "D": "I, III, IV only"}, "answer": "B", "explanation": "The correct sequence of documents used in detail trade is: Enquiry, Quotation, Order, and Invoice. Initially, an enquiry is made about the goods or services. Then, a quotation is provided by the seller. If the buyer agrees with the terms and conditions, they place an order. Finally, an invoice is issued by the seller to the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>43", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Mr. Lou who assured his life with XYZ Assurance Company, was involved in an accident and had a broken leg; the sum of N80,000 was paid to Mr. Lou for his broken leg. The money received is known as", "images": [], "options": {"A": "Premium", "B": "Payment", "C": "Credit", "D": "Compensation"}, "answer": "D", "explanation": "The money received by Mr. Lou is known as Compensation. In insurance terms, compensation is the money paid to a policyholder after a covered loss. In this case, Mr. Lou's accident and broken leg were presumably covered by his insurance policy with XYZ Assurance Company, hence the payment of N80,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>44", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The size of profit of a business is measured by the", "images": [], "options": {"A": "closing stock", "B": "opening stock", "C": "total purchase", "D": "rate of turnover"}, "answer": "D", "explanation": "The size of profit of a business is measured by the rate of turnover. The rate of turnover refers to the speed at which a company can sell its goods. It is calculated by dividing the cost of goods sold by the average inventory. The higher the rate of turnover, the more profit a business is likely to make as it means the business is selling its goods quickly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>45", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Industrial occupation does not involve the", "images": [], "options": {"A": "growing and extraction of raw materials", "B": "use of machinery", "C": "construction and manufacturing of goods", "D": "movement of people and goods"}, "answer": "D", "explanation": "An industrial occupation involves those who engage in the physical production of goods or changing of raw materials into finished or semi- finished products. Examples are extraction, construction and manufacturing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>46", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "The abbreviation E & O.E. on an invoice seeks to", "images": [], "options": {"A": "draw the attention of the buyer to the contents of the document", "B": "show that there is no error about prices quoted on the invoice", "C": "protect the seller against any error on the document", "D": "draw the attention of the seller to the contents of the document"}, "answer": "C", "explanation": "E & O.E. stands for 'Errors and Omissions Excepted'. This is a disclaimer that is used in an attempt to reduce legal liability for potentially incorrect or incomplete information supplied in a contractually related document such as an invoice or quotation. It is used to protect the seller against any error on the document.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>47", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The function of credit and thrift society does not include", "images": [], "options": {"A": "charging low interest on loan", "B": "providing savings facilities", "C": "encourage mutual co-operation of members", "D": "providing security for members' property"}, "answer": "D", "explanation": "The function of credit and thrift society includes providing savings facilities, charging low interest on loans, and encouraging mutual co-operation of members. However, providing security for members' property is not a function of credit and thrift society. This is because the primary purpose of these societies is to promote savings and provide loans to members, not to provide security for their property.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2012>48", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Throwing cargo over board in order to save a ship from sinking is", "images": [], "options": {"A": "jettison", "B": "abandonment", "C": "piracy", "D": "flotsam"}, "answer": "A", "explanation": "Throwing cargo overboard in order to save a ship from sinking is known as 'jettison'. This is a maritime practice that is done in extreme circumstances to lighten the ship's load and prevent it from sinking. The other options, 'abandonment', 'piracy', and 'flotsam', do not accurately describe this action.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>49", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The document in which the full details of goods and the ship carrying the goods are contained is known as", "images": [], "options": {"A": "bill of exchange", "B": "bill of sight", "C": "certificate of origin", "D": "shipping advice note"}, "answer": "D", "explanation": "The document that contains the full details of goods and the ship carrying the goods is known as a 'Shipping Advice Note'. This document is used in international trade and is issued by the carrier to the shipper as proof that the goods have been received for shipment. It contains details such as the description and quantity of the goods, the vessel's name, the port of loading and discharge, etc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2012>50", "subject": "Commerce", "year": "2012", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "The exclusive right of an author over his book is", "images": [], "options": {"A": "Trademark", "B": "Brand name", "C": "Copyright", "D": "Patent right"}, "answer": "C", "explanation": "The exclusive right of an author over his book is known as 'Copyright'. Copyright is a legal term used to describe the rights that creators have over their literary and artistic works. Works covered by copyright range from books, music, paintings, sculpture, and films, to computer programs, databases, advertisements, maps, and technical drawings.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>1", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A document used as a polite way of refusing credit is", "images": [], "options": {"A": "advice note", "B": "quotation", "C": "proforma invoice", "D": "invoice"}, "answer": "C", "explanation": "A proforma invoice is a document that is sent to a buyer in certain circumstances, usually before all details of the sale are known. It provides a detailed breakdown of what the seller intends to charge the buyer, but it is not an official demand for payment. It is often used as a polite way of refusing credit to a customer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>2", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Carriage forward on an invoice means", "images": [], "options": {"A": "carriage will be paid next time", "B": "carriage will be paid by seller", "C": "carriage will be paid by buyer", "D": "carriage had been paid"}, "answer": "C", "explanation": "Carriage forward, also known as freight collect, on an invoice means that the buyer is responsible for the freight charges. In other words, the buyer pays the freight charges to the carrier when the goods are delivered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>3", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is not contained in a consignment note?", "images": [], "options": {"A": "Name of the buyer", "B": "Name of the seller", "C": "Description of goods", "D": "Cost of goods"}, "answer": "D", "explanation": "A consignment note, also known as a bill of lading, is a document issued by a carrier to a shipper, acknowledging that specified goods have been received on board as cargo for conveyance to a named place for delivery to the consignee. It contains the name of the buyer, the name of the seller, and a description of the goods, but it does not contain the cost of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>4", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The PW Company Ltd achieved the following result in 2012.    ................... Le    Sales ............. 100,000   Profit ............ 5,000   Capital employed .. 20,000   The return on capital employed is", "images": [], "options": {"A": "25%", "B": "20%", "C": "15%", "D": "5%"}, "answer": "A", "explanation": "The return on capital employed (ROCE) is a financial ratio that measures a company's profitability and the efficiency with which its capital is used. In other words, the ratio measures how well a company is generating profits from its capital. The formula for calculating ROCE is: ROCE = Net Profit / Capital Employed * 100%. In this case, the net profit is 5,000 and the capital employed is 20,000. Therefore, the ROCE is (5,000 / 20,000) * 100% = 25%. Hence, the correct option is 1 (25%).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>5", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "Which of the following will be suitable for hire purchase sale?", "images": [], "options": {"A": "Shares", "B": "Refrigerator", "C": "Shoes", "D": "Textile"}, "answer": "B", "explanation": "Hire purchase is a method of buying goods through making installment payments over time. The term 'hire purchase' originated in the United Kingdom and is similar to what are called 'installment plans' in the United States. It's typically used for the purchase of high-value items such as cars and electrical goods where the purchaser does not have the funds to pay upfront. Among the given options, a refrigerator is a high-value item that can be bought through hire purchase. Hence, the correct option is 2 (Refrigerator).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>6", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A person who earns extra commission for guaranteeing debts is a", "images": [], "options": {"A": "factor", "B": "broker", "C": "commission agent", "D": "del-credere agent"}, "answer": "D", "explanation": "A del-credere agent is a type of principal-agent relationship wherein the agent acts as a guarantor for the credit extended to the buyer. If the buyer is unable to pay, the agent pays the amount to the seller. This is a special type of arrangement and for this, the agent receives an extra commission known as del credere commission. Hence, the correct option is 4 (del-credere agent).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>7", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "An insurance principle that prevents a person from insuring what he does not stand to lose financially if the insured risk occurs is", "images": [], "options": {"A": "indemnity", "B": "insurable interest", "C": "proximate cause", "D": "subrogation"}, "answer": "B", "explanation": "The principle of insurable interest states that the person getting an insurance policy must have a legitimate interest in the preservation of the life or property insured. That is, they stand to lose financially if the insured risk occurs. This principle prevents people from taking out insurance policies on things they do not own or have no financial stake in.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>8", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Voyage policy insurance is associated with", "images": [], "options": {"A": "fire", "B": "life", "C": "marine", "D": "burglary"}, "answer": "C", "explanation": "A voyage policy is a type of insurance policy that covers the risks of a particular journey, typically by sea, hence it is associated with marine insurance. It covers the insured goods from the start of the journey to its completion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>9", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "If a share is quoted ex-div, it means the new buyer would", "images": [], "options": {"A": "get the next dividend", "B": "not get the next dividend", "C": "get a fixed dividend", "D": "not get any dividend"}, "answer": "B", "explanation": "When a share is quoted as 'ex-div', it means that the buyer of that share is not entitled to receive the next dividend payment. The term 'ex-div' is short for 'excluding dividend'. This means that the right to receive the next dividend payment remains with the seller.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>10", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "Which of the following is the function of commerce?", "images": [], "options": {"A": "The conversion of raw materials into semi-finished products", "B": "The conversion of semi-finished products into end products", "C": "Provision of services to customers", "D": "The exchange and distribution of goods and services"}, "answer": "D", "explanation": "Commerce is concerned with the exchange and distribution of goods and services. It involves all the activities that facilitate the transfer of goods and services from the producer to the consumer. The other options are related to the production process, not commerce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2013>11", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Who among the following does not render direct service?", "images": [], "options": {"A": "Teachers", "B": "Musicians", "C": "Doctors", "D": "Retailers"}, "answer": "D", "explanation": "A retailer does not render direct service. A retailer is involved in the business of selling goods to the consumer. They are part of the distribution chain, unlike teachers, musicians, and doctors who provide direct services to individuals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2013>12", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The last link in the production process is the ......", "images": [], "options": {"A": "transporter", "B": "wholesaler", "C": "consumer", "D": "retailer"}, "answer": "C", "explanation": "The last link in the production process is the consumer. The production process starts with raw materials and ends with the consumer who uses the final product. The transporter, wholesaler, and retailer are all intermediaries in the distribution process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>13", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The Board of Director of Public corporation is appointed by the", "images": [], "options": {"A": "government", "B": "shareholders", "C": "management", "D": "employees"}, "answer": "A", "explanation": "The Board of Directors of a Public Corporation is appointed by the government. A Public Corporation is a company that is owned by the government, and its board of directors is appointed by the government to oversee its operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>14", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The object clause of a limited liability company is stated in the", "images": [], "options": {"A": "Memorandum of Association", "B": "Article of Association", "C": "Certificate of incorporation", "D": "Trading certificate"}, "answer": "A", "explanation": "The object clause of a limited liability company is stated in the Memorandum of Association. The Memorandum of Association is a document that sets out the constitution of the company and includes the company's object clause, which outlines the scope of activities that the company can engage in.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>15", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A market which deals in the purchase and sale of second-hand securities is the", "images": [], "options": {"A": "Stock Exchange", "B": "Building Society", "C": "Shippers Council", "D": "Co-operation Society"}, "answer": "A", "explanation": "A market which deals in the purchase and sale of second-hand securities is the Stock Exchange. The Stock Exchange is a market where stock brokers and traders can buy and sell securities, such as shares of stock and bonds and other financial instruments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>16", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "To endorse a cheque means to", "images": [], "options": {"A": "write and sign one's name at the back of the cheque", "B": "write \"pay cash\" on the cheque", "C": "cross the cheque", "D": "stop the payment of the cheque"}, "answer": "A", "explanation": "Endorsing a cheque means to sign one's name on the back of the cheque. This is usually done by the payee (the person to whom the cheque is made out) to authorize the bank to process the cheque. It is a way of transferring the ownership of the cheque to another person or entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>17", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "An insurance policy that covers the body of the ship only is called", "images": [], "options": {"A": "Haulage insurance", "B": "Voyage insurance", "C": "Hull insurance", "D": "Cargo insurance"}, "answer": "C", "explanation": "Hull insurance is a type of marine insurance that covers the hull and machinery of a ship. It provides indemnity for loss of or damage to the ship itself, as opposed to the cargo (which would be covered by cargo insurance) or potential liabilities from accidents (covered by P&I clubs).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>18", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following protects consumers against poor quality goods?", "images": [], "options": {"A": "Chambers of Commerce", "B": "Standard Organization", "C": "Trade Association", "D": "Manufacturers Association"}, "answer": "B", "explanation": "The Standard Organization is responsible for setting and enforcing standards for goods and services. This includes ensuring that goods are of high quality and fit for consumption. They protect consumers by ensuring that products meet certain safety and quality standards before they are sold in the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>19", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Mr Biu has been paying the premium of a straight Life Assurance policy for several years. The surrender value of the policy is the amount that", "images": [], "options": {"A": "would be paid to Mr. Biu if he should discontinue with the policy", "B": "would be paid to Mr. Bui's beneficiary if he dies", "C": "is paid annually by Mr. Biu's to the insurance company", "D": "the amount Mr. Biu has paid plus interest"}, "answer": "A", "explanation": "The surrender value of a life insurance policy is the amount that the insurance company would pay to the policyholder if they decide to voluntarily terminate the policy before its maturity or if the insured event does not occur. This means that if Mr. Biu discontinues his policy, he would receive the surrender value.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>20", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The use of current account in business is convenient because", "images": [], "options": {"A": "withdrawer can be made at any time", "B": "deposit earn higher interest", "C": "loans are always available", "D": "notices are necessary before withdrawals"}, "answer": "A", "explanation": "A current account in business is a type of deposit account that allows for unlimited number of deposits and withdrawals at any time. It is convenient for businesses because it provides liquidity, meaning businesses can access their funds whenever they need to cover their expenses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>21", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE", "question": "The cost of telephone conversation is determined by the", "images": [], "options": {"A": "number of words spoken", "B": "person sending the message", "C": "duration of the conversation", "D": "urgency of the message conveyed"}, "answer": "C", "explanation": "The cost of a telephone conversation is typically determined by the duration of the conversation. The longer the call, the more it costs. This is because telecommunication companies usually charge based on the amount of time you spend on the phone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>22", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "'Not negotiable' on a cheque means", "images": [], "options": {"A": "ownership can be transferred to the third party by mere delivery", "B": "the cheque can be paid over the counter on endorsement", "C": "the holder has no better title than the person who transfer it", "D": "ownership rest with the one who issued the cheque"}, "answer": "C", "explanation": "The term 'Not negotiable' on a cheque means that the holder of the cheque has no better title than the person who transferred it. This means that if the cheque was stolen, the holder cannot claim ownership of the funds. This is a legal concept that protects the rightful owner of the cheque.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>23", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The type of transport a manufacturer will use will be influenced by", "images": [], "options": {"A": "type of sales", "B": "the tax on the goods", "C": "the customer's age", "D": "nature of goods"}, "answer": "D", "explanation": "The type of transport a manufacturer will use is primarily influenced by the nature of the goods. For instance, perishable goods might require refrigerated transport, while large or heavy goods might require a specific type of vehicle or container. The other options listed do not directly influence the choice of transport.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>24", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A contract made between a ship owner and a merchant for the carriage of cargo is", "images": [], "options": {"A": "ships' manifested", "B": "charter party", "C": "freight forward", "D": "cargo service"}, "answer": "B", "explanation": "A contract made between a ship owner and a merchant for the carriage of cargo is known as a 'charter party'. This is a legal term for a contract between the owner of a vessel and the charterer who rents use of the vessel or a part of its cargo space. The other options listed do not accurately describe this type of contract.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>25", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Advertising effort geared towards a particular audience is known as", "images": [], "options": {"A": "mass advertising", "B": "direct advertising", "C": "persuasive advertising", "D": "indirect advertising"}, "answer": "B", "explanation": "Direct advertising is a type of advertising which is directed towards a particular audience. It is a targeted form of advertising where the messages are directed at specific consumers. The other options do not accurately describe advertising efforts geared towards a particular audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>26", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Trade fairs and exhibitions are media of", "images": [], "options": {"A": "sales promotion", "B": "customer service", "C": "market segmentation", "D": "advertising"}, "answer": "A", "explanation": "Trade fairs and exhibitions are media of sales promotion. They are used to promote products and services, attract new customers, and increase brand awareness. They are not typically used for customer service, market segmentation, or advertising.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>27", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The concept which says that a company's production policy should be centered on the ultimate user of the product is known as", "images": [], "options": {"A": "market segmentation", "B": "consumer sovereignty", "C": "marketing mix", "D": "marketing research"}, "answer": "B", "explanation": "The concept which says that a company's production policy should be centered on the ultimate user of the product is known as consumer sovereignty. This concept emphasizes that the consumer is the king and the success of any product is determined by the acceptance of the consumer. The other options do not accurately describe this concept.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>28", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The various rights attached to different classes of shares are stated in the", "images": [], "options": {"A": "articles of association", "B": "memorandum of association", "C": "balance sheet", "D": "prospectus"}, "answer": "A", "explanation": "The rights attached to different classes of shares are stated in the Articles of Association. The Articles of Association is a document that specifies the regulations for a company's operations and defines the company's purpose. It lays out how tasks are to be accomplished within the organization, including the process for appointing directors and the handling of financial records.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>29", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is a feature of supermarkets?", "images": [], "options": {"A": "Gives credit to reliable customers", "B": "Specializes in one line of product", "C": "Goods are on display with price tag", "D": "Does not have to provide storage facilities"}, "answer": "C", "explanation": "A feature of supermarkets is that goods are on display with price tags. This allows customers to easily see the price of items and make purchasing decisions accordingly. Supermarkets typically do not specialize in one line of product, do not give credit to customers, and they do have to provide storage facilities for the goods they sell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>30", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Public enterprises are financed mainly by", "images": [], "options": {"A": "the shareholders", "B": "commercial banks", "C": "government grants", "D": "mortgage banks"}, "answer": "C", "explanation": "Public enterprises are mainly financed by government grants. A public enterprise is a business organization wholly or partly owned by the state and controlled through a public authority. Some are fully owned by the government while others have both the government and the private sector as its shareholders. However, the government holds majority of the shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>31", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "A personal computer on sale in an office equipment shop is an example of", "images": [], "options": {"A": "stock", "B": "fixed asset", "C": "liability", "D": "fixed capital"}, "answer": "A", "explanation": "A personal computer on sale in an office equipment shop is an example of stock. In the context of a retail business, stock refers to the goods or merchandise kept on the premises of a business or warehouse and available for sale or distribution. The personal computer is part of the shop's inventory that is intended to be sold, hence it is considered as stock.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>32", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The difference between current assets and current liabilities is", "images": [], "options": {"A": "issued capital", "B": "capital employment", "C": "working capital", "D": "nominal capital"}, "answer": "C", "explanation": "The difference between current assets and current liabilities is known as working capital. Working capital is a measure of a company's operational liquidity and short-term financial health. It is calculated as current assets minus current liabilities. Current assets are the assets that a company expects to convert into cash within one fiscal year, while current liabilities are the company's debts or obligations that are due within one fiscal year.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>33", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A Ltd company has an authorized capital of 2,000,000 shares of D5 each. If the company issued 1,200,000 shares, its issued capital is", "images": [], "options": {"A": "D10,000,000", "B": "D6,000,000", "C": "D4,000,000", "D": "D2,000,000"}, "answer": "B", "explanation": "The issued capital of a company is the total of a company's shares of stock that have been sold and are held by shareholders. In this case, the company has issued 1,200,000 shares, each with a value of D5. Therefore, the issued capital is 1,200,000 shares * D5/share = D6,000,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>34", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The money used by Ola Maro and Co. Ltd. in running the day-to-day activities of the business is represented by", "images": [], "options": {"A": "fixed capital", "B": "capital employed", "C": "paid-up-capital", "D": "working capital"}, "answer": "D", "explanation": "Working capital is the money used by a company to run its day-to-day operations. It is calculated as current assets minus current liabilities. Current assets are resources that a company expects to convert to cash within one year, while current liabilities are the company's debts or obligations that are due within one year. Therefore, the money used by Ola Maro and Co. Ltd. in running the day-to-day activities of the business is represented by working capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>35", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "Which of the following is an advantage to a sole trader?", "images": [], "options": {"A": "Guaranteed profit", "B": "Quick decision making", "C": "Unlimited liability", "D": "Buying on credit"}, "answer": "B", "explanation": "A sole trader, also known as a sole proprietor, is a type of business structure where one person owns and runs the business. One of the advantages of being a sole trader is the ability to make quick decisions. This is because there are no other owners or board of directors to consult before making decisions. Therefore, a sole trader can respond quickly to business situations, which can be a competitive advantage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2013>36", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A country's deliberate decision to reduce the value of her currency is called", "images": [], "options": {"A": "deregulation", "B": "inflation", "C": "devaluation", "D": "revaluation"}, "answer": "C", "explanation": "Devaluation is a deliberate downward adjustment to the value of a country's currency relative to another currency, group of currencies, or standard. Devaluation is a monetary policy tool of countries that have a fixed exchange rate or semi-fixed exchange rate. It is often used to correct a trade imbalance, which may help to reduce a nation's trade deficit. Therefore, a country's deliberate decision to reduce the value of her currency is called devaluation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>37", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following is not a function of warehousing?", "images": [], "options": {"A": "Creating scarcity of goods", "B": "Stabilization of price", "C": "Production ahead of demand", "D": "Storage of goods"}, "answer": "A", "explanation": "Warehousing serves several functions such as storage of goods, production ahead of demand, and stabilization of price. However, creating scarcity of goods is not a function of warehousing. Warehouses are meant to store goods and not to create artificial scarcity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>38", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Ad valorem duties are based on the", "images": [], "options": {"A": "importance of the goods imported", "B": "value of the goods imported", "C": "weight of the goods imported", "D": "nature of the goods imported"}, "answer": "B", "explanation": "Ad valorem is a Latin term that means 'according to value.' Therefore, ad valorem duties are taxes that are based on the value of the goods imported, not on their importance, weight, or nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>39", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A tariff refers to", "images": [], "options": {"A": "fees imposed on contraband goods", "B": "fees paid on exports", "C": "taxes imposed on imported goods", "D": "taxes paid on home made goods"}, "answer": "C", "explanation": "A tariff is a tax or duty to be paid on a particular class of imports or exports. In this context, a tariff refers to taxes imposed on imported goods, not on contraband goods, exports, or homemade goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>40", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The selling of goods in small units is normally performed by", "images": [], "options": {"A": "chambers of commerce", "B": "wholesalers", "C": "distributors", "D": "retailers"}, "answer": "D", "explanation": "The selling of goods in small units is typically performed by retailers. Retailers are businesses or individuals that sell goods directly to the end user or consumer. They purchase goods in large quantities from manufacturers or wholesalers and then sell smaller quantities to consumers for a profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2013>41", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Direct sales to consumers by manufacturers is a means of eliminating", "images": [], "options": {"A": "wholesalers only", "B": "retailers only", "C": "middlemen", "D": "agents"}, "answer": "C", "explanation": "Direct sales to consumers by manufacturers is a means of eliminating middlemen. Middlemen are intermediaries between the manufacturer and the consumer. They can include wholesalers, distributors, brokers, and retailers. By selling directly to consumers, manufacturers can avoid the costs and complications of dealing with these intermediaries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>42", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A physical restriction placed on the quantity of goods that can be imported is", "images": [], "options": {"A": "a ban", "B": "a quota", "C": "an exercise duty", "D": "an import tax"}, "answer": "B", "explanation": "A physical restriction placed on the quantity of goods that can be imported is a quota. A quota is a government-imposed trade restriction that limits the number or monetary value of goods that a country can import or export during a particular period.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>43", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "A country is said to achieve a trade surplus when total", "images": [], "options": {"A": "visible exports exceeds total visible imports", "B": "invisible exports exceeds total invisible import", "C": "visible exports exceeds total invisible import", "D": "visible imports exceeds total visible export"}, "answer": "A", "explanation": "A trade surplus occurs when the value of a country's exports of goods (visible exports) exceeds the value of its imports of goods (visible imports). Therefore, a country achieves a trade surplus when total visible exports exceed total visible imports.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>44", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "The process of winding up a public limited company by a court order is known as", "images": [], "options": {"A": "termination", "B": "dissolution", "C": "voluntary liquidation", "D": "compulsory liquidation"}, "answer": "D", "explanation": "The process of winding up a public limited company by a court order is known as compulsory liquidation. This is a legal process where a company is brought to an end, and its assets are redistributed. Voluntary liquidation is initiated by the company's shareholders, while compulsory liquidation is initiated by a court order.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>45", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A person who undertakes responsibility for forming a new company is", "images": [], "options": {"A": "auditor", "B": "solicitor", "C": "registrar", "D": "promoter"}, "answer": "D", "explanation": "A promoter is a person who undertakes the responsibility for forming a new company. They are involved in the initial setup of the company, including its registration, legal procedures, and the arrangement of capital. An auditor, solicitor, and registrar have different roles in a company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>46", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "A term which describe the value of business connections made by a company over the years is known as", "images": [], "options": {"A": "patent", "B": "copyright", "C": "goodwill", "D": "trade mark"}, "answer": "C", "explanation": "Goodwill is a term that describes the value of business connections made by a company over the years. It is an intangible asset that includes brand reputation, customer loyalty, and other non-physical items that add value to a business. Patents, copyrights, and trademarks are forms of intellectual property, but they do not describe the value of business connections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>47", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "The ancillary to trade which ensures that people have access to information pertaining to goods is", "images": [], "options": {"A": "insurance", "B": "advertising", "C": "warehouse", "D": "banking"}, "answer": "B", "explanation": "Advertising is the ancillary to trade that ensures that people have access to information pertaining to goods. It is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea. Insurance, warehousing, and banking are also ancillaries to trade, but they do not primarily provide information about goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2013>48", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The insurance principle of indemnity does not apply to", "images": [], "options": {"A": "fire insurance", "B": "life assurance", "C": "burglary insurance", "D": "marine insurance"}, "answer": "B", "explanation": "The insurance principle of indemnity does not apply to life assurance. The principle of indemnity is a key aspect of many types of insurance and asserts that an insured may not be compensated by the insurance company in an amount exceeding the insured's economic loss. In life assurance, the value of a human life cannot be measured in terms of money, and therefore, the principle of indemnity does not apply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2013>49", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following questions requires the buyer to take delivery at the manufacturer's warehouse?", "images": [], "options": {"A": "Ex-works", "B": "F.O.R", "C": "F.O.B", "D": "F.A.S"}, "answer": "A", "explanation": "Ex-works is a term in international commercial law, specifying at the point at which sellers are responsible for goods. The term 'Ex-works' means that the seller delivers when it places the goods at the disposal of the buyer at the seller's premises or at another named place (i.e., works, factory, warehouse, etc.). The seller does not need to load the goods on any collecting vehicle, nor does it need to clear the goods for export, where such clearance is applicable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2013>50", "subject": "Commerce", "year": "2013", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "To take an insurance policy, an applicant must first complete a/an", "images": [], "options": {"A": "proposal form", "B": "cover note", "C": "certificate of insurance", "D": "advice note"}, "answer": "A", "explanation": "Before taking an insurance policy, an applicant must first complete a proposal form. The proposal form contains details about the applicant and the risk to be insured. The insurance company uses the information provided in the proposal form to decide whether to accept the risk and determine the premium to be charged.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>1", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A price quotation which includes all the expenses involved in loading the goods into a ship is", "images": [], "options": {"A": "Free on Board (FOB)", "B": "Free Alongside(FAS)", "C": "Cost, Insurance, Freight(C.I.F)", "D": "Ex-ship"}, "answer": "C", "explanation": "The term 'Cost, Insurance, Freight (C.I.F)' refers to a type of contract where the seller pays for the costs associated with transporting goods until the buyer receives them. This includes the cost of the goods, the cost of insurance, and the cost of freight to transport the goods to the buyer's location. Therefore, it includes all the expenses involved in loading the goods into a ship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>2", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Shares, bond, Stocks and debentures traded on the stock exchange are collectively called", "images": [], "options": {"A": "collaterals", "B": "commodities", "C": "resources", "D": "securities"}, "answer": "D", "explanation": "Shares, bonds, stocks, and debentures traded on the stock exchange are collectively referred to as 'securities'. Securities are financial instruments that hold some type of monetary value. They represent an ownership position in a publicly-traded corporation (via stock), a creditor relationship with a governmental body or a corporation (represented by owning that entity's bond), or rights to ownership as represented by an option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>3", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "In a hire purchase contract, the customer becomes the legal owner of the goods by", "images": [], "options": {"A": "paying the last instalment", "B": "paying the first instalment", "C": "taking possession of goods", "D": "paying half the purchase price"}, "answer": "A", "explanation": "In a hire purchase contract, the customer becomes the legal owner of the goods by paying the last instalment. A hire purchase agreement is a type of installment plan where the buyer makes an initial deposit and pays the balance plus interest in installments. The ownership of the goods passes to the buyer only after the final installment is paid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>4", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "Which of the following is engaged in commercial occupation?", "images": [], "options": {"A": "A brick layer", "B": "An engineer", "C": "An Insurance broker", "D": "A barber"}, "answer": "C", "explanation": "A commercial occupation is one that involves the buying and selling of goods and services. An insurance broker fits this description as they sell insurance policies to clients. A brick layer, an engineer, and a barber provide services but do not engage in the buying and selling of goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>5", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "\"Net 3 months\" on an invoice means the buyer will", "images": [], "options": {"A": "pay interest after 3 months", "B": "get discount if he pays within 3 months", "C": "pay full invoice amount after 3 months", "D": "have discount if he pays after 3 months"}, "answer": "C", "explanation": "\"Net 3 months\" on an invoice means that the buyer is expected to pay the full invoice amount within 3 months. It does not imply any interest or discount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>6", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The ratio between a country's export and her imports price is the", "images": [], "options": {"A": "balance of trade", "B": "balance of payments", "C": "terms of trade", "D": "exchange rate"}, "answer": "C", "explanation": "The ratio between a country's export and her imports price is known as the terms of trade. The terms of trade is an economic concept that refers to the relative price of exports in terms of imports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>7", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The charge paid to a ship owner for the unused part of a ship is known as", "images": [], "options": {"A": "penalty", "B": "dock dues", "C": "dead freight", "D": "demurrage"}, "answer": "C", "explanation": "Dead freight is the charge paid to a ship owner for the unused part of a ship. This is usually paid by the charterer when they have not fully utilized the space they have booked on the ship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>8", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Fidelity guarantee insurance will only cover", "images": [], "options": {"A": "cashier's fraud", "B": "daylight robbery", "C": "loss of profit", "D": "unpaid loan"}, "answer": "A", "explanation": "Fidelity guarantee insurance is a type of insurance that covers businesses for the loss of money or property due to employee dishonesty. It is specifically designed to cover the fraudulent acts of employees, such as a cashier's fraud.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>9", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "In the absence of the bill of lading, which of the following is used to clear the goods?", "images": [], "options": {"A": "Bill of sight", "B": "Dock warrant", "C": "Certificate of origin", "D": "mate's receipt"}, "answer": "D", "explanation": "In the absence of the bill of lading, a mate's receipt can be used to clear the goods. A mate's receipt is a document issued by the commandant of the ship when the cargo is loaded onto the ship. It is then exchanged for a bill of lading.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>10", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A system of sales, where goods are sold to the highest bidder is known as", "images": [], "options": {"A": "credit sale", "B": "hire purchase", "C": "clearance sale", "D": "auction sale"}, "answer": "D", "explanation": "Auction sale is a system where goods are sold to the highest bidder. The other options do not fit the description. Credit sale is a sale where the payment is made at a later date. Hire purchase is a system where the buyer pays for goods in regular installments while having the use of them. Clearance sale is a discount sale to clear old stock.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>11", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "The term \"fiduciary issue\" means", "images": [], "options": {"A": "money issued without gold backing", "B": "money issue with gold backing", "C": "money issued as currency note", "D": "gold reserve"}, "answer": "A", "explanation": "Fiduciary issue refers to money issued without gold backing. It is a system where the currency is not based on a physical commodity like gold or silver, but rather on the trust and confidence of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>12", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "An insurance principle which prevents an insured from making profit when compensated is known as", "images": [], "options": {"A": "proximate cause", "B": "indemnity", "C": "insurable interest", "D": "utmost good faith"}, "answer": "B", "explanation": "The principle of indemnity in insurance prevents an insured from making a profit when compensated. It ensures that the insured is returned to the same financial position as before the loss occurred. Proximate cause refers to the first event in a chain of events leading to damage. Insurable interest is the interest that a person has in a property which is insured. Utmost good faith is a principle that requires all parties to reveal any information that could influence the other's decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>13", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail outlet with many branches all dealing in similar line of goods is described as a", "images": [], "options": {"A": "department store", "B": "supermarket", "C": "chain store", "D": "hypermarket"}, "answer": "C", "explanation": "A chain store is a retail outlet that has multiple locations. These stores sell similar goods and are typically owned and operated by a single organization. Department stores, supermarkets, and hypermarkets can all be types of chain stores, but they can also exist as single, standalone stores. Therefore, the most accurate answer is 'chain store'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>14", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The person who gave his building as a security for loan is known as a", "images": [], "options": {"A": "trustee", "B": "mortgage", "C": "mortgagor", "D": "guarantor"}, "answer": "C", "explanation": "A mortgagor is a person who borrows money from a lender (usually a bank) and gives his property as a security for the loan. If the mortgagor fails to repay the loan, the lender has the right to sell the property to recover the loan amount. In this context, the property is usually a building or land, and the loan is known as a mortgage loan. Therefore, the correct answer is 'mortgagor'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>15", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A firm that specializes in packing and shipping of goods is known as a", "images": [], "options": {"A": "forwarding agent", "B": "general agent", "C": "del credere agent", "D": "cargo banding company"}, "answer": "A", "explanation": "A forwarding agent, also known as a freight forwarder, is a firm that specializes in arranging storage and shipping of goods on behalf of its shippers. It usually provides a full range of services including tracking inland transportation, preparation of shipping and export documents, warehousing, booking cargo space, negotiating freight charges, freight consolidation, cargo insurance, and filing of insurance claims. Therefore, the correct answer is 'forwarding agent'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>16", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Which of the following is a function of marketing department in a firm?", "images": [], "options": {"A": "Add value to goods and services", "B": "Protect those who engage in business transactions", "C": "Initiate general policies in the organization", "D": "Handle all staff matter in the business"}, "answer": "A", "explanation": "The marketing department in a firm is responsible for adding value to goods and services. This is done through various strategies such as branding, packaging, advertising, and other promotional activities. These strategies help to increase the perceived value of the product or service in the eyes of the consumers, thereby making them more willing to purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>17", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "An individual or company that encourages in the transaction of any type of goods for a fee is called a", "images": [], "options": {"A": "common carrier", "B": "hawker", "C": "porter", "D": "clearing agent"}, "answer": "D", "explanation": "A clearing agent is an individual or company that facilitates the transaction of goods for a fee. They are involved in the process of clearing goods through customs barriers for importers and exporters. This involves the preparation of documents, calculation of transaction taxes and duties, and facilitating communication between the importer/exporter and governmental authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>18", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Debenture which are secured by the fixed assets of a company are called", "images": [], "options": {"A": "Mortgaged Debentures", "B": "Naked Debentures", "C": "Redeemable Debentures", "D": "Irredeemable Debenture"}, "answer": "A", "explanation": "Mortgaged Debentures are debentures that are secured by the fixed assets of a company. This means that if the company fails to pay the debenture holders, they have the right to sell the mortgaged assets to recover their money. This is different from Naked Debentures, which are not secured by any asset.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>19", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The Central Bank sometimes called for special deposits from the commercial banks in order to", "images": [], "options": {"A": "reduce bank lending", "B": "increase bank lending", "C": "withdraw defaced currencies", "D": "issue new notes and coins"}, "answer": "A", "explanation": "The Central Bank can control the amount of money in circulation by adjusting the reserve requirements of commercial banks. By calling for special deposits, the Central Bank effectively increases the reserve requirements, which reduces the amount of money that commercial banks can lend out. This is a monetary policy tool used to control inflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>20", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A principal member of the stock exchange who buys and sell securities on his own is a", "images": [], "options": {"A": "Jobber", "B": "Promoter", "C": "Broker", "D": "Speculator"}, "answer": "A", "explanation": "A Jobber is a trader who buys and sells securities on his own account. Jobbers are market-makers in the securities industry, they make their profits from the spread between the buy and sell prices of the securities they deal in. They do not deal with the public directly but through brokers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>21", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Consumer protection places an obligation on producers to ensure that their products", "images": [], "options": {"A": "are wholesome and safe", "B": "are cheap", "C": "do not evade customs examination", "D": "are branded"}, "answer": "A", "explanation": "Consumer protection laws are designed to ensure fair trade competition and the free flow of truthful information in the marketplace. The laws are designed to prevent businesses that engage in fraud or specified unfair practices from gaining an advantage over competitors and may provide additional protection for the weak and those unable to take care of themselves. Hence, producers are obligated to ensure that their products are wholesome and safe for consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>22", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The target for all marketing activities is the", "images": [], "options": {"A": "consumer", "B": "middlemen", "C": "producer", "D": "distributor"}, "answer": "A", "explanation": "The target for all marketing activities is the consumer. Marketing activities are designed to meet the needs and wants of the consumer. They involve creating, communicating, delivering, and exchanging offerings that have value for customers, clients, partners, and society at large.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>23", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Small scale retailers continue to exist in spite of the dominance of large firms because they", "images": [], "options": {"A": "render personal service", "B": "employ few salesmen", "C": "can raise large capital from relatives", "D": "deal in specific goods"}, "answer": "A", "explanation": "Small scale retailers continue to exist in spite of the dominance of large firms because they render personal service. Small scale retailers often have a closer relationship with their customers, which allows them to provide a more personalized service. This can include understanding their customers' preferences and needs, providing advice, and offering a more personal shopping experience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>24", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Building and machinery purchased for use in business are examples of", "images": [], "options": {"A": "current assets", "B": "fixed assets", "C": "capital employed", "D": "paid up capital"}, "answer": "B", "explanation": "Building and machinery purchased for use in business are examples of fixed assets. Fixed assets, also known as tangible assets or property, plant, and equipment (PP&E), are long-term assets that a company plans to use in its business operations to generate income. Fixed assets are not intended for sale but are to be used or held by the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>25", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "Olamide bought shares in a company with the following information    Authorised capital #500,000  Issued capital #450,000  Nominal value #1.00  Market price #1.20    If the share are offered to him at ₦1.15, the share is sold at", "images": [], "options": {"A": "par value", "B": "a discount", "C": "face value", "D": "a premium"}, "answer": "D", "explanation": "When shares are sold at a price higher than their face value, they are said to be sold at a premium. In this case, if the face value of the share is ₦1 and it is being sold at ₦1.15, it is being sold at a premium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>26", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "Olamide bought shares in a company with the following information    Authorised capital #500,000  Issued capital #450,000  Nominal value #1.00  Market price #1.20  Calculate the number of unissued shares of the company", "images": [], "options": {"A": "950,000 shares", "B": "500,000 shares", "C": "450,000 shares", "D": "50,000 shares"}, "answer": "D", "explanation": "The unissued share is the difference between the authorised capital and the issued capital i.e    500,000 - 450, 000    = 50, 000 shares.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>27", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The throwing of goods over board to prevent a ship from sinking is known as", "images": [], "options": {"A": "float sam", "B": "abandonment", "C": "jettison", "D": "particular average"}, "answer": "C", "explanation": "The act of throwing goods overboard to lighten a ship and prevent it from sinking is known as jettison. This is a maritime practice done in extreme situations to save the ship and the remaining cargo.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>28", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "In insurance, risk that have no statistics for their calculations are", "images": [], "options": {"A": "insurable risks", "B": "certain risks", "C": "un-insurable risks", "D": "un-certain risks"}, "answer": "C", "explanation": "In insurance, risks that have no statistics for their calculations are referred to as un-insurable risks. This is because insurance companies rely on statistical data to calculate the probability of a risk occurring and to determine the premium to be charged. If there are no statistics available, the insurance company cannot accurately assess the risk and therefore, it becomes un-insurable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>29", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The practice of selling goods in foreign countries at lower prices than obtainable in the exporting country is known as", "images": [], "options": {"A": "entreport trade", "B": "dumping", "C": "hedging", "D": "counter trade"}, "answer": "B", "explanation": "The practice of selling goods in foreign countries at lower prices than obtainable in the exporting country is known as dumping. This is a type of predatory pricing, often used in international trade, where a company exports a product to another country at a price lower than the price it normally charges in its own home market.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>30", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "The entertainment industry is classified under", "images": [], "options": {"A": "extractive industry", "B": "manufacturing industry", "C": "constructive industry", "D": "commercial industry"}, "answer": "D", "explanation": "The entertainment industry is classified under the commercial industry. Commercial industries are those that trade, transport, distribute, or sell goods or services. The entertainment industry falls under this category as it involves the sale and distribution of entertainment products and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>31", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Buying on impulse is encouraged by", "images": [], "options": {"A": "co-operative shops", "B": "hawkers", "C": "supermarkets", "D": "mail order firms"}, "answer": "C", "explanation": "Supermarkets often use strategies such as product placement, attractive packaging, and sales promotions to encourage impulse buying. This is because supermarkets have a wide variety of products displayed in a manner that encourages customers to make unplanned purchases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>32", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A fixed deposit account is beneficial to its holders because", "images": [], "options": {"A": "cheque can be used to settle huge debts", "B": "customers can become shareholders of the bank", "C": "it attracts higher interest rate", "D": "it allows customers to overdraw their account"}, "answer": "C", "explanation": "A fixed deposit account is beneficial to its holders because it attracts a higher interest rate. This is because the money deposited in a fixed deposit account is held for a fixed term, during which the bank can use the money. As a result, banks offer higher interest rates on fixed deposit accounts compared to regular savings accounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>33", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "An amount paid by a bull who wishes to defer the purchase of shares to the next account period is", "images": [], "options": {"A": "brokerage", "B": "backwardation", "C": "contango", "D": "commissional"}, "answer": "C", "explanation": "Contango is a situation where the futures price of a commodity is higher than the spot price. It is an amount paid by a bull who wishes to defer the purchase of shares to the next account period. This is because the bull expects the price of the shares to rise in the future, and is therefore willing to pay a premium (the contango) to defer the purchase.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>34", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Foreign trade is concerned with", "images": [], "options": {"A": "exchange of goods and services among companies", "B": "buying and selling of imported goods", "C": "exchange of goods and services among citizens", "D": "buying and selling goods and services among countries"}, "answer": "D", "explanation": "Foreign trade is concerned with the buying and selling of goods and services among countries. It involves the import and export of goods and services between different countries, which is a key aspect of global economic activity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>35", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The distribution of goods create", "images": [], "options": {"A": "time utility", "B": "place utility", "C": "form utility", "D": "possession utility"}, "answer": "B", "explanation": "The distribution of goods creates place utility. Place utility refers to the value or usefulness that a consumer receives by having access to a product or service in a location that is convenient for them. When goods are distributed to various locations where consumers can easily access them, it creates place utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>36", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : REGISTRATION OF BUSINESS", "question": "The documents issued by the registrar of companies which allows a public company to commence business is called", "images": [], "options": {"A": "trading certificate", "B": "properties", "C": "certificate of incorporation", "D": "memorandum of association"}, "answer": "A", "explanation": "The document issued by the registrar of companies which allows a public company to commence business is called a trading certificate. A trading certificate is a document issued by the registrar of companies to a public limited company, allowing it to start business operations. This is after the company has complied with the legal requirement of having a minimum allotted share capital.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>37", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque bearing a date showing that it was issued more than six months ago is termed a", "images": [], "options": {"A": "blank cheque", "B": "bearer cheque", "C": "stale cheque", "D": "order cheque"}, "answer": "C", "explanation": "A cheque that is presented for payment after six months from the date it was issued is termed a 'stale cheque'. This is because, by banking standards, a cheque is considered valid for six months from the date of issue. After this period, it becomes stale and banks will typically not honor it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>38", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "A system of buying products from a machine is known as", "images": [], "options": {"A": "impulse buying", "B": "branding", "C": "automatic vending", "D": "loss leader"}, "answer": "C", "explanation": "Automatic vending refers to the system of buying products from a machine. These machines, known as vending machines, dispense items such as snacks, beverages, cigarettes, lottery tickets to customers automatically, after the customer inserts currency or credit into the machine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>39", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Carpentry is an activity classified under", "images": [], "options": {"A": "extractive occupation", "B": "tertiary occupation", "C": "commercial occupation", "D": "constructive occupation"}, "answer": "D", "explanation": "Carpentry is a constructive occupation. It involves the cutting, shaping and installation of building materials during the construction of buildings, ships, timber bridges, concrete formwork, etc. It is therefore classified under constructive occupation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2014>40", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A system of buying goods by an agent where the supplier is determined by the principal is", "images": [], "options": {"A": "tied shop", "B": "closed indent", "C": "open indent", "D": "ring trading"}, "answer": "B", "explanation": "Closed indent enables a principal to determine the supplier of the goods i.e to buy from a specific person.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>41", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "One of the functions of a central bank is to", "images": [], "options": {"A": "perform supervisory role over all the banks in the country", "B": "provide the means of payment to individuals", "C": "ensure the smooth transfer of shares", "D": "accept private deposits"}, "answer": "A", "explanation": "One of the primary functions of a central bank is to perform a supervisory role over all the banks in the country. This involves monitoring and regulating the activities of commercial banks to ensure they are in line with the country's financial and economic policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>42", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "The issue of Certificate of Incorporation to a company means that it has", "images": [], "options": {"A": "started production", "B": "legally come into being", "C": "appointed a board of directors", "D": "merged with another company"}, "answer": "B", "explanation": "The issue of a Certificate of Incorporation to a company means that it has legally come into being. This certificate is a legal document that is issued by the government to a company to confirm its existence and to give it the right to operate as a business entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>43", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The part of authorized capital of a company sold to share holders is", "images": [], "options": {"A": "paid-up capital", "B": "called-up capital", "C": "issued capital", "D": "a nominal partner"}, "answer": "C", "explanation": "The part of authorized capital of a company sold to shareholders is known as issued capital. Authorized capital is the maximum amount of share capital that the company is authorized by its constitutional documents to issue to shareholders. Parts of this capital may be issued by the company to shareholders, which is then referred to as issued capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>44", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A person who contributes money to a partnership business and is also involved in its general supervision is called", "images": [], "options": {"A": "an active partner", "B": "a limited partner", "C": "a dormant partner", "D": "a nominal partner"}, "answer": "A", "explanation": "A person who contributes money to a partnership business and is also involved in its general supervision is called an active partner. An active partner is not only an investor in the business but also participates in its day-to-day operations and management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>45", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A business obtains part of its short-term capital from", "images": [], "options": {"A": "bond", "B": "debentures", "C": "trade credit", "D": "ordinary shares"}, "answer": "C", "explanation": "A business obtains part of its short-term capital from trade credit. Trade credit is the credit extended by one trader to another for the purchase of goods and services. Trade credit facilitates the purchase of supplies without immediate payment. Trade credit is commonly used by business organisations as a source of short-term financing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>46", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A postal service that allows a company's customers to reply to its advertisement at the expense of company is", "images": [], "options": {"A": "recorded delivery service", "B": "post restante", "C": "express delivery service", "D": "business reply service"}, "answer": "D", "explanation": "A business reply service is a service provided by many postal operators that allows a sender to distribute pre-printed and pre-paid items to their customers, who can then reply using these items without needing to pay postage. The original sender pays the postage fees, not the customer. Therefore, this is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>47", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "A voluntary association which consist of people who represent a cross section of business interest in an area is a", "images": [], "options": {"A": "Trade Association", "B": "Trade Union", "C": "Chamber of Commerce", "D": "Consumers' Association"}, "answer": "C", "explanation": "A Chamber of Commerce is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community. They represent a wide range of business interests in a particular area, hence the correct answer is 'Chamber of Commerce'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>48", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "When a ship overstays the allowed number of days at the port, it is made to pay", "images": [], "options": {"A": "interest", "B": "tariff", "C": "demurrage", "D": "commission"}, "answer": "C", "explanation": "Demurrage is a charge payable to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed. In other words, when a ship overstays the allowed number of days at the port, it is made to pay demurrage. Therefore, the correct answer is 'demurrage'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2014>49", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The place where bankers meet daily to exchange cheque drawn on each other is known as", "images": [], "options": {"A": "capital market", "B": "money market", "C": "clearing house", "D": "discount house"}, "answer": "C", "explanation": "A clearing house is a financial institution formed to facilitate the exchange of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations. In the context of banking, a clearing house is a place where bankers meet daily to exchange cheques drawn on each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2014>50", "subject": "Commerce", "year": "2014", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "An advertising campaign designed to sell one's own products at the expense of other brands is", "images": [], "options": {"A": "competitive", "B": "persuasive", "C": "direct", "D": "informative"}, "answer": "A", "explanation": "Competitive advertising is a method of attracting buyers by comparing your products to those of your competitors. Companies use competitive advertising to differentiate their product from other similar products in the market. The main goal of this type of advertising is to show potential customers that their product is better than their competitors' product. In this case, the advertising campaign is designed to sell one's own products at the expense of other brands, which is the definition of competitive advertising.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>1", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The practice of giving a particular name to a product by a manufacturer is", "images": [], "options": {"A": "branding", "B": "standardization", "C": "publicity", "D": "advertizing"}, "answer": "A", "explanation": "Branding is the practice of giving a particular name to a product by a manufacturer. It helps in distinguishing the goods of one producer from those of another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>2", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "An extra commission paid to an agent who guarantees credit sales made by him is", "images": [], "options": {"A": "del-credere", "B": "guarantor's fee", "C": "jobber's turn", "D": "brokerage"}, "answer": "A", "explanation": "Del-credere is an extra commission paid to an agent who guarantees credit sales made by him. It is a type of agreement whereby the agent guarantees to the principal that the third party (buyer) will fulfill the contract. The agent is liable to the principal if the third party fails to perform.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>3", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "A professional in insurance who evaluate the level of loss for claims is an", "images": [], "options": {"A": "adjuster", "B": "assessor", "C": "underwriter", "D": "actuary"}, "answer": "A", "explanation": "An adjuster is a professional in insurance who evaluates the level of loss for claims. They investigate insurance claims by interviewing the claimant and witnesses, consulting police and hospital records, and inspecting property damage to determine the extent of the company's liability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>4", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "The insurance services rendered to a foreign shipping company are treated as", "images": [], "options": {"A": "invisible export", "B": "invisible import", "C": "visible export", "D": "balance trade"}, "answer": "A", "explanation": "The insurance services rendered to a foreign shipping company are treated as invisible export. Invisible export refers to the sale of services and other intangible goods to foreign countries. In this case, the insurance service is the intangible good being sold to the foreign shipping company.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>5", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "Dividing the market for a product according to potential buyer who have common characteristics is", "images": [], "options": {"A": "market analysis", "B": "market penetration", "C": "market segmentation", "D": "market research"}, "answer": "C", "explanation": "Dividing the market for a product according to potential buyers who have common characteristics is known as market segmentation. Market segmentation is a marketing strategy which involves dividing a broad target market into subsets of consumers, businesses, or countries that have, or are perceived to have, common needs, interests, and priorities, and then designing and implementing strategies to target them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>6", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following aids to trade facilities production ahead of demand?", "images": [], "options": {"A": "Insurance", "B": "Transportation", "C": "Advertising", "D": "Warehousing"}, "answer": "D", "explanation": "Warehousing aids to trade facilities production ahead of demand. Warehousing refers to the activities involving storage of goods on a large-scale in a systematic and orderly manner and making them available conveniently when needed. In other words, warehousing means holding or preserving goods in huge quantities from the time of their purchase or production till their actual use or sale. Warehousing is one of the important auxiliaries to trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>7", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "When a government acquires business enterprise formally owned by individuals, it is termed", "images": [], "options": {"A": "Commercialization", "B": "Indigenization", "C": "Privatization", "D": "Nationalization"}, "answer": "D", "explanation": "When a government acquires a business enterprise formerly owned by individuals, it is termed Nationalization. Nationalization is the process of transforming privately owned assets into public assets by bringing them under the public ownership of a national government or state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>8", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "How many countries make up the River Niger Basin Commission?", "images": [], "options": {"A": "16", "B": "12", "C": "10", "D": "9"}, "answer": "D", "explanation": "The River Niger Basin Commission is made up of 9 countries. These countries are Benin, Burkina Faso, Cameroon, Chad, Côte d'Ivoire, Guinea, Mali, Niger, and Nigeria. They are all part of the Niger River Basin.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>9", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following means of payment makes the bank both the drawer and drawee?", "images": [], "options": {"A": "Standing order", "B": "Bill of exchange", "C": "Bank draft", "D": "Open cheque"}, "answer": "C", "explanation": "A Bank Draft is a means of payment where the bank is both the drawer and drawee. A bank draft is a payment on behalf of a payer that is guaranteed by the issuing bank. Essentially, the bank guarantees the payment of the amount to the payee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>10", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An association that protects the interest of members in the same line of business is a", "images": [], "options": {"A": "Consumer Association", "B": "Trade Union", "C": "Trade Association", "D": "Chamber of Commerce"}, "answer": "C", "explanation": "A Trade Association is an organization founded and funded by businesses that operate in a specific industry. An industry trade association participates in public relations activities such as advertising, education, political donations, lobbying and publishing, but its main focus is collaboration between companies. Associations may offer other services, such as producing conferences, networking or charitable events or offering classes or educational materials.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>11", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Bamidele co ltd has authorized capital of 40,000,000 ordinary shares of #4 each. Shares issues and fully paid are 25,000,000    The value of Bamidele Co. Ltd's authorized share capital is", "images": [], "options": {"A": "N160,000,000", "B": "N10,000,000", "C": "N65,000,000", "D": "N40,000,000"}, "answer": "A", "explanation": "Authorized capital = 40,000,000 x 4    = ₦160, 000, 000", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>12", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Bamidele co ltd has authorized capital of 40,000,000 ordinary shares of #4 each. Shares issues and fully paid are 25,000,000  The value of the issued capital of the company is", "images": [], "options": {"A": "N160,000,000", "B": "N100,000,000", "C": "N60,000,000", "D": "N15,000,000"}, "answer": "B", "explanation": "Issued capital = 25, 000, 000 x 4    = ₦ 100,000,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>13", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Bamidele co ltd has authorized capital of 40,000,000 ordinary shares of #4 each. Shares issues and fully paid are 25,000,000  The unissued capital amount to", "images": [], "options": {"A": "N160,000,000", "B": "N100,000,000", "C": "N60,000,000", "D": "N15,000,000"}, "answer": "C", "explanation": "Unissued Capital = 40, 000, 000 - 25, 000, 000    = 15,000,000    = 15, 000,000 x 4    = ₦ 60,000,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>14", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following aids to trade is used to stimulate demand for goods?", "images": [], "options": {"A": "Banking", "B": "Transport", "C": "Insurance", "D": "Advertising"}, "answer": "D", "explanation": "Advertising helps to create awareness about the existence of a product thereby stimulating demand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>15", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The term consumer sovereignty means that the", "images": [], "options": {"A": "seller is the king", "B": "product is supreme", "C": "buyer is the king", "D": "producer is the king"}, "answer": "C", "explanation": "Consumer sovereignty is an economic concept where the consumer has the power to decide what goods and services are produced based on their demands. Therefore, the correct answer would be 'buyer is the king'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>16", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following activities is classified under extractive industry?", "images": [], "options": {"A": "Exploration of minerals", "B": "Construction of roads", "C": "Canning of tomato purees", "D": "Assembling of cars"}, "answer": "A", "explanation": "Extractive industry refers to any processes that involve extracting raw materials from the earth to be used by consumers. The term extractive industry encompasses not only the extraction of minerals, but also the extraction of oil, natural gas, and even water. In this case, the exploration of minerals falls under the extractive industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>17", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "BYX Enterprise has the following balances at the end of March 2010:  Opening stock D6,000Purchases  D23,000Salaries and wages  D12,000Closing stock  D8,000Sales  D30,000    Calculate the gross profit of BYX Enterprise", "images": [], "options": {"A": "D13,000", "B": "D9,000", "C": "D5,000", "D": "D1,000"}, "answer": "B", "explanation": "Gross profit  = Sales - Cost of goods sold  Note that: COGS = Opening stock + Purchases - Closing stock    COGS = 6000 + 23000 - 8000  = 21000    GP = 30000 - 21000  = D9000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>18", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "BYX Enterprise has the following balances at the end of March 2010:  Opening stock D6,000Purchases  D23,000Salaries and wages  D12,000Closing stock  D8,000Sales  D30,000  What is the rate turnover of BYX Enterprise?", "images": [], "options": {"A": "5.0 times", "B": "3.5 times", "C": "3.0 times", "D": "1.5 times"}, "answer": "C", "explanation": "R.O.T = cost of goods sold / average stock   Note that COGS = 21000    Therefore, Average stocki = Opening stock + Closing stock/2  = 6000 + 8000/2  = 14000/2  = 7000    RST = 21000/7000  = 3 times", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>19", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following workers is engaged in construction occupation?", "images": [], "options": {"A": "Mason", "B": "Shop Assistant", "C": "Farmer", "D": "Train Driver"}, "answer": "A", "explanation": "A mason is a worker who builds with, or dresses, hard units such as brick, stone, or concrete. This is a type of construction occupation, as it involves the creation or assembly of structures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>20", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque which the bank refuse to pay because the drawer had insufficient funds in his account is", "images": [], "options": {"A": "a bounced cheque", "B": "a bearer cheque", "C": "a crossed cheque", "D": "an order cheque"}, "answer": "A", "explanation": "A bounced cheque is a cheque that the bank has returned (bounced back) to the payee (the person who received the cheque) because the payer (the person who wrote the cheque) has insufficient funds in their account. The other options are types of cheques but they are not related to insufficient funds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>21", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is a function of the retailer to the wholesaler?", "images": [], "options": {"A": "Providing after sales service", "B": "Providing information on market trends", "C": "Sale of variety of goods", "D": "Sale of goods in smaller quantities"}, "answer": "B", "explanation": "Retailers often provide wholesalers with information on market trends. This is because retailers are in direct contact with consumers and can therefore provide valuable insights into consumer behavior and emerging trends. The other options are functions of the retailer to the consumer, not to the wholesaler.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>22", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The term utmost good faith in insurance means", "images": [], "options": {"A": "both the insured and insurer must disclose all information", "B": "only the insurer must disclose all information", "C": "the beneficiary must disclose all information", "D": "only the insured must disclose all information"}, "answer": "A", "explanation": "The term 'utmost good faith' in insurance refers to a legal principle that requires both parties to an insurance contract, the insurer and the insured, to deal honestly with each other and to not withhold any important information. Therefore, both the insured and insurer must disclose all information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>23", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following business unit enjoys government subsidies?", "images": [], "options": {"A": "Private Limited company", "B": "Limited partnership", "C": "Public Limited company", "D": "Public corporation"}, "answer": "D", "explanation": "A public corporation is a company that is owned by the government and therefore, it is the type of business unit that enjoys government subsidies. Private Limited companies, Limited partnerships, and Public Limited companies are typically not eligible for government subsidies as they are privately owned.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>24", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Duty drawer refers to duties paid on", "images": [], "options": {"A": "exported goods produced with local content", "B": "re-exported goods previously imported", "C": "imported goods for sale locally", "D": "locally manufactured goods for sale locally"}, "answer": "C", "explanation": "Duty drawer refers to the duties paid on imported goods for sale locally. This is a type of tax that is imposed on imported goods to protect local industries from foreign competition, to raise revenue for the government, and to control the volume of goods coming into the country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>25", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The capital that is used in the day-to-day running of a business is", "images": [], "options": {"A": "nominal capital", "B": "working capital", "C": "paid capital", "D": "authorized capital"}, "answer": "B", "explanation": "Working capital is the capital that is used in the day-to-day running of a business. It is the difference between a company's current assets, like cash, accounts receivable, and inventories of raw materials and finished goods, and its current liabilities, like accounts payable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>26", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is classified under current asset?", "images": [], "options": {"A": "Machinery", "B": "Motor vehicle", "C": "Stock", "D": "Fittings"}, "answer": "C", "explanation": "Stock is classified under current assets. Current assets are all assets that a company expects to convert to cash within one year. They are commonly used to measure the liquidity of a company. A company's assets on its balance sheet are split into two categories - current assets and long-term assets. Stock, or inventory, falls into the current assets category.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>27", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The reduction in value of a country's currency in relation to others is", "images": [], "options": {"A": "predomination", "B": "devaluation", "C": "inflation", "D": "deflation"}, "answer": "B", "explanation": "The reduction in value of a country's currency in relation to others is called devaluation. Devaluation is a monetary policy tool of countries that have a fixed exchange rate or semi-fixed exchange rate. It is often used to correct a trade imbalance. Devaluation reduces the cost of a country's exports, rendering them more competitive in the global market, and increases the cost of importing goods, encouraging consumers to buy domestic goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>28", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Retail outlets which sell from specialized vans are called", "images": [], "options": {"A": "supermarkets", "B": "multiple shops", "C": "mail order firms", "D": "mobile shops"}, "answer": "D", "explanation": "Retail outlets which sell from specialized vans are called mobile shops. This is because they are not fixed in one location but move around to reach their customers. Supermarkets, multiple shops, and mail order firms are all stationary and do not move around.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>29", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Which of the following is an aspect of marketing concept?", "images": [], "options": {"A": "Product differentiation", "B": "Sales orientation", "C": "Consumer orientation", "D": "Price differentiation"}, "answer": "C", "explanation": "The marketing concept is a business philosophy that prioritizes identifying the needs and wants of consumers and creating a product that satisfies them. Therefore, consumer orientation is an aspect of the marketing concept. Product differentiation and price differentiation are strategies used in marketing, but they are not concepts. Sales orientation, on the other hand, is a different business philosophy that prioritizes selling existing products rather than identifying and satisfying consumer needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>30", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The practice of selling goods in foreign markets at a price lower than the cost price is", "images": [], "options": {"A": "fair trading", "B": "under invoicing", "C": "hedging", "D": "dumping"}, "answer": "D", "explanation": "The practice of selling goods in foreign markets at a price lower than the cost price is called dumping. This is a strategy used by companies to gain a competitive edge in foreign markets by selling their products at a lower price. Fair trading, under invoicing, and hedging are not related to this practice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>31", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque made payable to a named person is", "images": [], "options": {"A": "a crossed cheque", "B": "a certified cheque", "C": "an order cheque", "D": "a confirmed cheque"}, "answer": "C", "explanation": "A cheque made payable to a named person is an order cheque. An order cheque is a type of cheque that is payable to a specific person or entity. The name of the person or entity is written on the cheque, and only that person or entity can cash or deposit the cheque. This is different from a bearer cheque, which is payable to whoever is in possession of the cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>32", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "A house insured against damage by flood was burnt down and the owner had no claim. Which of the following principles prevented him from making a claim?", "images": [], "options": {"A": "Indemnity", "B": "Contribution", "C": "Insurable interest", "D": "Proximate cause"}, "answer": "D", "explanation": "The principle that prevented the owner from making a claim is 'Proximate cause'. The principle of proximate cause states that the loss must be directly caused by the peril insured against. In this case, the house was insured against damage by flood, but it was burnt down. Since the cause of the loss (fire) is not the peril insured against (flood), the owner cannot make a claim.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>33", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "The market for short term capital is called", "images": [], "options": {"A": "community market", "B": "discount market", "C": "money market", "D": "stock market"}, "answer": "C", "explanation": "The market for short term capital is called the money market. The money market is a segment of the financial market in which financial instruments with high liquidity and short maturities are traded. The money market is used by participants as a means for borrowing and lending in the short term, with maturities that usually range from overnight to just under a year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>34", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Which of the following principles of insurance stipulates that the insured must be in a position to suffer financial loss?", "images": [], "options": {"A": "Indemnity", "B": "Proximate cause", "C": "Insurable interest", "D": "Subrogation"}, "answer": "C", "explanation": "The principle of 'Insurable Interest' stipulates that the insured must be in a position to suffer financial loss. This principle is based on the concept that insurance is for compensation and not for making profit. The insured must have a legal relationship with the subject matter of insurance and stands to lose financially if a loss occurs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>35", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "When share are sold 'ex-div' it means the", "images": [], "options": {"A": "buyer is not entitled to the next dividend", "B": "shares are sold at par", "C": "shares are sold above par", "D": "seller has right to the next dividend"}, "answer": "A", "explanation": "EX-DIV: Means the shareholder (buyer) will not be entitled to the next dividend", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>36", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Turnover could be increased by", "images": [], "options": {"A": "increasing price and products differentiation", "B": "advertising and cutting prices", "C": "refusing credits and customer services", "D": "increasing the mark up and margin"}, "answer": "B", "explanation": "Turnover, which refers to the total sales of a company, could be increased by advertising and cutting prices. Advertising helps to increase the visibility of the company's products or services, thereby attracting more customers. Cutting prices, on the other hand, makes the products or services more affordable, which can also attract more customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>37", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce started as a result of", "images": [], "options": {"A": "speculation", "B": "competition", "C": "specialization", "D": "nationalization"}, "answer": "C", "explanation": "Commerce started as a result of specialization. Specialization refers to the method of production where a business or area focuses on the production of a limited scope of products or services to gain greater degrees of productive efficiency within an overall system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2015>38", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Which of the following is used for making payments to many people in a single cheque?", "images": [], "options": {"A": "Debit transfer", "B": "Certified cheque", "C": "Bank draft", "D": "Credit transfer"}, "answer": "D", "explanation": "Credit transfer is used for making payments to many people in a single cheque. It is a direct payment of money from one bank account into another. It's a way of sending money between accounts without exchanging physical money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>39", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Equity interest in a company is represented by", "images": [], "options": {"A": "preference share", "B": "dividend", "C": "debenture", "D": "ordinary share"}, "answer": "D", "explanation": "Equity interest in a company is represented by ordinary shares. Ordinary shares, also known as common shares, provide the owner with a stake in the company and often come with voting rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>40", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "When two insurers are liable under a given common policy, the principle of insurance that applies is", "images": [], "options": {"A": "indemnity", "B": "subrogation", "C": "proximate cause", "D": "contribution"}, "answer": "D", "explanation": "The principle of insurance that applies when two insurers are liable under a given common policy is 'contribution'. The principle of contribution is a sub-principle of the principle of indemnity. It is applicable when the insured has taken out more than one policy on the same subject matter. In such a case, the insured cannot make a profit by claiming the loss from all the insurers. The loss is distributed among all the insurers in proportion to the amount assured by them.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>41", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "All activities aimed at creation of a good image for an organization are referred to as", "images": [], "options": {"A": "market segmentation", "B": "market research", "C": "public relation", "D": "consumer orientation"}, "answer": "C", "explanation": "All activities aimed at creation of a good image for an organization are referred to as 'public relation'. Public relations is a strategic communication process that builds mutually beneficial relationships between organizations and their publics. It involves managing the spread of information between an individual or an organization and the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>42", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Which of the following is a disadvantage of foreign trade?", "images": [], "options": {"A": "It encourages dumping", "B": "It widens the world market", "C": "It encourages specialization", "D": "It provides variety of goods"}, "answer": "A", "explanation": "A disadvantage of foreign trade is that 'It encourages dumping'. Dumping is a term used in the context of international trade. It's when a country or company exports a product at a price that is lower in the foreign importing market than the price in the exporter's domestic market. The biggest advantage of dumping is that it can help a company gain a competitive advantage in a new market. But it's a disadvantage for the country where the products are being dumped, as it can hurt its domestic industries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>43", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "A study to discover consumer's preference and needs is called", "images": [], "options": {"A": "market segmentation", "B": "consumer orientation", "C": "market research", "D": "marketing mix"}, "answer": "C", "explanation": "Market research is the process of determining the viability of a new service or product through research conducted directly with potential customers. It allows a company to discover the target market and get opinions and other feedback from consumers about their interest in the product or service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>44", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following is a disadvantage of retailing?", "images": [], "options": {"A": "Selling on credit", "B": "Lower price of goods", "C": "Selling in smaller quantities", "D": "Location at convenient places"}, "answer": "A", "explanation": "Selling on credit can be a disadvantage of retailing because it involves the risk of bad debts and delayed payments, which can impact cash flow and financial stability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>45", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A private limited liability company differs from a public limited liability company because it", "images": [], "options": {"A": "does not issue its shares to the public", "B": "has a separate entity", "C": "has many directors", "D": "is a going concern"}, "answer": "A", "explanation": "The main difference between a private limited liability company and a public limited liability company is that a private limited company does not offer its shares to the general public. This means that the company's shares can only be owned by a limited number of people, such as the company's management and its employees.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>46", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "A tax charged in proportion to the value of imported goods is", "images": [], "options": {"A": "specific duty", "B": "ad valorem duty", "C": "custom duty", "D": "excise duty"}, "answer": "B", "explanation": "An ad valorem duty is a type of tax charged on the value of an item, such as an import, in proportion to its value. The term 'ad valorem' is Latin for 'according to value', which means that it is flexible and depends on the assessed value of an asset, product or service.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>47", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is a reason for the failure of public corporations?", "images": [], "options": {"A": "Legal requirements", "B": "Inadequate funding", "C": "Political stability", "D": "Lack of competition"}, "answer": "B", "explanation": "Inadequate funding is a common reason for the failure of public corporations. Public corporations are typically funded by the government, and if the government does not allocate enough resources to them, they may not be able to operate effectively or achieve their objectives.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>48", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The factor that is not considered when determining the means of transport suitable for cargo is", "images": [], "options": {"A": "size", "B": "weight", "C": "manufacturer", "D": "perishability"}, "answer": "C", "explanation": "The manufacturer of the cargo is not a factor that is considered when determining the means of transport suitable for cargo. Factors such as size, weight, and perishability of the cargo are considered because they directly affect the type of transportation that can be used. For example, perishable goods may require refrigerated transport, while heavy goods may require a certain type of vehicle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2015>49", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following is a document of title to goods?", "images": [], "options": {"A": "Bill of exchange", "B": "Bill of entry", "C": "Letter of hypothecation", "D": "Bill of lading"}, "answer": "D", "explanation": "A document of title to goods is a document that provides evidence of a person's entitlement to the possession of goods. The Bill of Lading is a document issued by a carrier (or their agent) to acknowledge receipt of cargo for shipment. It serves three purposes: it is a receipt for the goods shipped, evidence of the contract of carriage, and a document of title to the goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2015>50", "subject": "Commerce", "year": "2015", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The fee paid for transporting goods by ship is called", "images": [], "options": {"A": "far", "B": "freight", "C": "durage", "D": "wages"}, "answer": "B", "explanation": "The fee paid for transporting goods by ship is called freight. Freight is the price paid for the transportation of goods in a ship or on a train, truck, or airplane. It is the charge for carrying goods from one place to another either by land, sea, or air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>1", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Where a number of insurance companies are liable under one Policy, the principle applicable is", "images": [], "options": {"A": "Subrogation", "B": "Contribution", "C": "Indemnity", "D": "Utmost good faith"}, "answer": "B", "explanation": "The principle of Contribution is applicable where a number of insurance companies are liable under one policy. This principle is a corollary of the principle of indemnity. It applies when the insured has taken out more than one policy on the same subject matter. According to this principle, each insurer is liable to pay only his proportion of the loss. If one insurer pays more than his share of the loss, he has the right to recover the excess amount from the other insurers who are liable for the same loss.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>2", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Buying and selling stocks in the stock exchange in anticipation of changes in the share prices is", "images": [], "options": {"A": "hedging", "B": "projection", "C": "forecasting", "D": "speculation"}, "answer": "D", "explanation": "Speculation is the buying and selling of stocks in the stock exchange in anticipation of changes in the share prices. Speculators aim to make a profit from price changes. They buy stocks when they anticipate prices will rise and sell when they anticipate prices will fall. This is different from hedging, which is a strategy used to offset potential losses that may be incurred by a companion investment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>3", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Another term for a dishonoured cheque is", "images": [], "options": {"A": "an order cheque", "B": "a bounced cheque", "C": "a bearer cheque", "D": "an open cheque"}, "answer": "B", "explanation": "A dishonoured cheque is also known as a bounced cheque. This happens when the bank does not honour the payment of the cheque due to insufficient funds in the account of the person who issued the cheque, or due to other reasons such as a mismatch of signatures, overwriting, post-dated cheque, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>4", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is an example of life assurance?", "images": [], "options": {"A": "Third party policy", "B": "Comprehensive policy", "C": "Fidelity guarantee policy", "D": "Endowment policy"}, "answer": "D", "explanation": "Life assurance is a contract between an insurance policy holder and an insurer, where the insurer promises to pay a designated beneficiary a sum of money upon the death of the insured person. Endowment policy is a type of life insurance contract designed to pay a lump sum after a specific term or on death. Hence, the correct answer is 'Endowment policy'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>5", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The main concern of commerce is to", "images": [], "options": {"A": "Create wealth", "B": "buy and sell goods and services", "C": "exchange and distribute goods and services", "D": "satisfy all human wants"}, "answer": "C", "explanation": "Commerce is concerned with the exchange and distribution of goods and services. It includes all those activities which directly or indirectly facilitate that exchange. This includes trade and aids to trade. Hence, the correct answer is 'exchange and distribute goods and services'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>6", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "The organized effort of consumers to protect themselves against the unfair practices of businessmen is", "images": [], "options": {"A": "strike", "B": "consumerism", "C": "picketing", "D": "demonstration"}, "answer": "B", "explanation": "Consumerism is a social and economic order that encourages the acquisition of goods and services in ever-increasing amounts. It is the organized effort of consumers to protect themselves against the unfair practices of businessmen. Hence, the correct answer is 'consumerism'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>7", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following legislation aims primarily at protection of consumers?", "images": [], "options": {"A": "Law of Contract", "B": "Trade Description Act", "C": "Company's Act", "D": "Partnership Act"}, "answer": "B", "explanation": "The Trade Description Act is a legislation that primarily aims at the protection of consumers. It prevents manufacturers, retailers or service industry providers from misleading consumers as to what they are spending their money on. This act requires that products and services are accurately described, and penalties are imposed for false or misleading descriptions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>8", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "In a law of contract, a counter offer operates as", "images": [], "options": {"A": "an acceptance", "B": "consensus ad idem", "C": "a rejection", "D": "a contract"}, "answer": "C", "explanation": "In the law of contract, a counter offer operates as a rejection of the original offer. When a counter offer is made, the original offer is terminated and cannot be accepted thereafter. The counter offer becomes the new offer, which the original offeror can now accept or reject.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>9", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "An economic policy which encourages government ownership of business is called", "images": [], "options": {"A": "Privatization", "B": "Nationalization", "C": "Indigenization", "D": "Commercialization"}, "answer": "B", "explanation": "Nationalization is an economic policy which encourages government ownership of businesses. It involves the transfer of a major sector of the economy from private to public sector. This is done with the aim of managing and controlling resources, providing employment, preventing exploitation, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>10", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Lack of permanent record for the message receiver is a disadvantage of", "images": [], "options": {"A": "television", "B": "direct mail", "C": "catalogue", "D": "magazine"}, "answer": "A", "explanation": "Television is a form of communication that does not provide a permanent record for the message receiver. Unlike direct mail, catalogues, and magazines, which are physical forms of communication that can be kept and referred back to, television broadcasts are ephemeral and cannot be referred back to unless recorded.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>11", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following occupations are classified under the extractive industry?   i. cattle-rearing , lumbering and farming  ii. mining, quarrying and hunting  iii. ship building, road construction and iron bending  iv. singing, dancing and tailoring", "images": [], "options": {"A": "i and iii only", "B": "i, ii and iv only", "C": "i and ii only", "D": "ii, iii and iv only"}, "answer": "C", "explanation": "The extractive industry involves the extraction of raw materials from the earth. This includes activities like mining, quarrying, hunting, cattle-rearing, lumbering, and farming. Therefore, options i and ii (cattle-rearing, lumbering, farming, mining, quarrying, and hunting) are classified under the extractive industry. The other options involve manufacturing or service industries, not extractive industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>12", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following abbreviations allows the drawer of a document to correct any error?", "images": [], "options": {"A": "C. T. F", "B": "I. O. U", "C": "C. W. O", "D": "E. & O. E."}, "answer": "D", "explanation": "E. & O. E. stands for 'Errors and Omissions Excepted'. This abbreviation is used to indicate that while every effort has been made to ensure accuracy, the drawer of a document is not liable for any errors or omissions. This allows the drawer to correct any errors that may have been made in the document.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>13", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Use the following information relating to Bala Enterprises to answer this question  ₦Premises  Motor vehicle  Debtors  Stock  Creditors32,000  15,000  15,000  20,000  10,000    The value of current assets is", "images": [], "options": {"A": "₦35,000", "B": "₦32,000", "C": "₦25,000", "D": "₦10,000"}, "answer": "A", "explanation": "The value of current assets is calculated by adding the value of debtors and stock. In this case, it is ₦15,000 (Debtors) + ₦20,000 (Stock) = ₦35,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>14", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Use the following information relating to Bala Enterprises to answer this question  ₦Premises  Motor vehicle  Debtors  Stock  Creditors32,000  15,000  15,000  20,000  10,000  What is the value of the working capital?", "images": [], "options": {"A": "₦47,000", "B": "₦35,000", "C": "₦25,000", "D": "₦10,000"}, "answer": "C", "explanation": "The value of the working capital is calculated by subtracting the value of creditors from the value of current assets. In this case, it is ₦35,000 (Current Assets) - ₦10,000 (Creditors) = ₦25,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>15", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Use the following information relating to Bala Enterprises to answer this question  ₦Premises  Motor vehicle  Debtors  Stock  Creditors32,000  15,000  15,000  20,000  10,000  The value of fixed assets is", "images": [], "options": {"A": "₦72,000", "B": "₦47,000", "C": "₦35,000", "D": "₦25,000"}, "answer": "B", "explanation": "Fixed assets₦premises32,000motor vehicle15,000 47,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>16", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A clean bill of lading is so called because", "images": [], "options": {"A": "it shows record of damaged goods", "B": "it is not a stained bill", "C": "it is a document of authority", "D": "it shows no record of damaged goods"}, "answer": "D", "explanation": "A clean bill of lading is a document issued by a carrier that certifies that goods were received in an appropriate condition, without any damages. Therefore, it shows no record of damaged goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>17", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "When an importer has been overcharged for goods supplied, the exporter issues him with a", "images": [], "options": {"A": "debit note", "B": "proforma invoice", "C": "letter of credit", "D": "credit note"}, "answer": "D", "explanation": "When an importer has been overcharged for goods supplied, the exporter issues him with a credit note. A credit note is a document sent by a seller to its buyer, or, in other words, a vendor to the customer, notifying that a credit has been provided to their account against the goods returned by the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>18", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Fidelity guarantee insurance is a cover against loss arising from", "images": [], "options": {"A": "Trade debt", "B": "Personal accident", "C": "Dishonest staff", "D": "Fire disaster"}, "answer": "C", "explanation": "Fidelity guarantee insurance is a type of insurance cover that protects a business against losses, such as theft of cash or stock, committed by employees in the course of their employment. Therefore, it is a cover against loss arising from dishonest staff.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>19", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "When a cheque is paid by the bank on which it is drawn, the cheque is", "images": [], "options": {"A": "discounted", "B": "credited", "C": "debited", "D": "cleared"}, "answer": "D", "explanation": "When a cheque is paid by the bank on which it is drawn, it is said to be 'cleared'. This means that the bank has confirmed there are sufficient funds in the account and those funds have been moved from the account to the payee. The other options such as 'discounted', 'credited', and 'debited' do not accurately describe this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>20", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "The process of buying, selling and distribution of goods and services is", "images": [], "options": {"A": "retails trade", "B": "commerce", "C": "marketing concept", "D": "marketing"}, "answer": "B", "explanation": "The process of buying, selling, and distribution of goods and services is best described as 'commerce'. Commerce involves the exchange of goods, services or something of value, between businesses or entities. From a broad perspective, nations are concerned about managing commerce in a way that enhances the well-being of citizens, by providing jobs and producing beneficial goods and services. 'Retail trade', 'marketing concept', and 'marketing' are all components of commerce, but they do not encompass the entire process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>21", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE", "question": "Risk bearing in business organization is a function of the", "images": [], "options": {"A": "employees", "B": "entrepreneur", "C": "customers", "D": "manager"}, "answer": "B", "explanation": "Risk bearing in a business organization is a function of the 'entrepreneur'. The entrepreneur is the individual who undertakes the risks of a business or enterprise. The entrepreneur is often the proprietor of the business and is responsible for its success or failure. The 'employees', 'customers', and 'manager' do not bear the overall risk of the business, although they may have their own individual risks associated with the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>22", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The worth of a life assurance policy before its maturity date is", "images": [], "options": {"A": "residual value", "B": "surrender value", "C": "accrued value", "D": "assured value"}, "answer": "B", "explanation": "The worth of a life assurance policy before its maturity date is known as the surrender value. This is the amount the policyholder will receive from the life insurance company if they choose to exit the policy before its maturity date. The surrender value is usually a percentage of the total premiums paid.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>23", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "One disadvantage of advertising is that it", "images": [], "options": {"A": "could be misleading", "B": "decreases sales", "C": "reduces profit", "D": "causes over stocking"}, "answer": "A", "explanation": "One disadvantage of advertising is that it could be misleading. Some advertisements may exaggerate the benefits or features of a product or service, leading consumers to make purchases based on false or misleading information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>24", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The business unit that applies the principle of one man, one vote is", "images": [], "options": {"A": "Sole proprietorship", "B": "Partnership", "C": "Public company", "D": "Co-operative society"}, "answer": "D", "explanation": "The business unit that applies the principle of one man, one vote is a Co-operative society. In a co-operative society, each member has one vote, regardless of the number of shares they hold. This is to ensure democratic control and equal rights for all members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>25", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The Water Corporation is an example of", "images": [], "options": {"A": "Co-operative Society", "B": "Public Enterprise", "C": "Private Enterprise", "D": "Limited Company"}, "answer": "B", "explanation": "Public enterprises are owned and managed by the government. They provide services that are of public interest like water, electricity, etc. The Water Corporation, being a provider of water services, is a public enterprise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>26", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : DISSOLUTION AND LIQUIDATION", "question": "A partnership is dissolved due to", "images": [], "options": {"A": "liquidity of the firm", "B": "death of an employee", "C": "insanity of a partner", "D": "resignation of an employee"}, "answer": "C", "explanation": "In a partnership, the mental capacity of the partners is crucial for the functioning of the business. If a partner becomes insane, it can lead to the dissolution of the partnership.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>27", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : REGISTRATION OF BUSINESS", "question": "A document that contains the relationship between the company and outsiders is", "images": [], "options": {"A": "Certificate of Incorporation", "B": "Memorandum of Association", "C": "Article of Association", "D": "Certificate of Trading"}, "answer": "B", "explanation": "The Memorandum of Association is a document that sets out the constitution of a company. It contains the rights, responsibilities, and powers of the company in relation to the outside world.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>28", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An organization formed mainly by traders and manufacturers to cater for interest of members is", "images": [], "options": {"A": "Trade Union", "B": "Co-operative Society", "C": "Trade Association", "D": "Chamber of Commerce"}, "answer": "C", "explanation": "A Trade Association is an organization founded and funded by businesses that operate in a specific industry. They participate in public relations activities such as advertising, education, political donations, lobbying and publishing, but their main focus is collaboration between companies. They may offer other services, such as producing conferences, networking or charitable events or offering classes or educational materials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>29", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "An insurance broker is involved in", "images": [], "options": {"A": "industrial occupation", "B": "distributive occupation", "C": "commercial occupation", "D": "constructive occupation"}, "answer": "C", "explanation": "An insurance broker sells, solicits, or negotiates insurance for compensation. An insurance broker is a specialist in insurance and risk management. Brokers act on behalf of their clients and provide advice in the interests of their clients.     Commercial Occupation: This refers to all the people involved in the distribution and exchange of goods produced by the industrial sector. Examples ocommercial workers are: bankers, transporters, insurers, traders, etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>30", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An agreement that is enforceable in law is", "images": [], "options": {"A": "a contract", "B": "an offer", "C": "an acceptance", "D": "a consideration"}, "answer": "A", "explanation": "A contract is an agreement that is enforceable by law. It is a legally binding agreement that recognises and governs the rights and duties of the parties to the agreement. A contract is legally enforceable because it meets the requirements and approval of the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>31", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The size of an enterprise is determined by the", "images": [], "options": {"A": "number of customers of the enterprise", "B": "length of the time the firm has been in operation", "C": "amount of capital invested", "D": "type of work done"}, "answer": "C", "explanation": "The size of an enterprise is typically determined by the amount of capital invested. This is because the amount of capital invested often determines the scale of operations, the number of employees, the size of the production facility, and other aspects of the business. The number of customers, the length of time the firm has been in operation, and the type of work done can all vary greatly and do not necessarily reflect the size of the enterprise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>32", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following function is not performed by trade association?", "images": [], "options": {"A": "Research and development", "B": "Standardization of product", "C": "Credit facilities", "D": "Technical Information"}, "answer": "C", "explanation": "Trade associations typically do not provide credit facilities. Their main functions include promoting the interests of their members, providing a platform for the exchange of ideas and information, lobbying for favorable policies, and sometimes conducting research and development and standardizing products. Credit facilities, on the other hand, are typically provided by financial institutions like banks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>33", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The fees charged on postal order by the post office is", "images": [], "options": {"A": "interest", "B": "brokerage", "C": "poundage", "D": "premium"}, "answer": "C", "explanation": "The fees charged on postal orders by the post office is known as poundage. Poundage is a type of service charge that is levied to cover the costs of processing the postal order. It is not interest, brokerage, or premium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>34", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "The document issued by a warehouse keeper for goods taken into the store is", "images": [], "options": {"A": "mate receipt", "B": "bill of sight", "C": "ship manifest", "D": "dock warrant"}, "answer": "D", "explanation": "A dock warrant is a document issued by a warehouse keeper for goods taken into the store. It is a receipt given for goods received into a dock or warehouse, which can be transferred by endorsement and delivery of the receipt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>35", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following is a verbal means of communication?", "images": [], "options": {"A": "Telex", "B": "Express mail", "C": "Business reply service", "D": "Telephone"}, "answer": "D", "explanation": "Telephone is a verbal means of communication. It allows for direct, real-time communication between the caller and receiver, and it involves speaking and listening, which are verbal forms of communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>36", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "The production of goods in anticipation of demand is made possible by", "images": [], "options": {"A": "Packaging", "B": "Warehousing", "C": "Branding", "D": "Advertising"}, "answer": "B", "explanation": "The production of goods in anticipation of demand is made possible by warehousing. Warehousing allows businesses to store goods and products until they are needed. This means that production can continue even if the demand is not immediate, as the goods can be stored safely until they are required.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>37", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "Regarding the consumer as the King who must be satisfied is the main emphasis of", "images": [], "options": {"A": "marketing research", "B": "marketing mix", "C": "consumerism", "D": "marketing concept"}, "answer": "D", "explanation": "The marketing concept is a business philosophy that holds the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets. It emphasizes that the consumer is the king and must be satisfied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>38", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE AND FUNCTIONS", "question": "Which of the following is a function of marketing?", "images": [], "options": {"A": "Branding", "B": "Planning", "C": "Organising", "D": "Manufacturing"}, "answer": "A", "explanation": "Branding is a function of marketing. It involves creating a unique name and image for a product in the consumers' mind, mainly through advertising campaigns with a consistent theme. Branding aims to establish a significant and differentiated presence in the market that attracts and retains loyal customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>39", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "A component of marketing mix that is put in consumable form a satisfy the consumer is", "images": [], "options": {"A": "product", "B": "promotion", "C": "place", "D": "price"}, "answer": "A", "explanation": "In the marketing mix, the product is the item that is put in consumable form to satisfy the consumer. It can be a tangible good or an intangible service that fulfills a need or want of consumers. It's the item that the business has created to meet the identified customer needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>40", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "Goods become the property of the buyer on the transfer of liability and possession without immediate payment under the", "images": [], "options": {"A": "hire purchase agreement", "B": "credit sale agreement", "C": "auction sales agreement", "D": "conditional sales agreement"}, "answer": "B", "explanation": "In a credit sale agreement, the goods become the property of the buyer upon the transfer of liability and possession, even if immediate payment is not made. The buyer agrees to pay the seller the purchase price at a later date. This is different from a hire purchase agreement, where the buyer does not own the goods until the final payment is made.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>41", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The value at which one country obtains another country's currency is", "images": [], "options": {"A": "terms of trade", "B": "exchange rate", "C": "bank rate", "D": "terms of payment"}, "answer": "B", "explanation": "The value at which one country obtains another country's currency is known as the exchange rate. It is the rate at which one currency can be exchanged for another. Terms of trade, bank rate, and terms of payment do not refer to the value of one country's currency in terms of another's.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>42", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Specializing in the sale of one line of goods is the main feature of", "images": [], "options": {"A": "supermarkets", "B": "chain stores", "C": "mail order firms", "D": "mobile shops"}, "answer": "B", "explanation": "Chain store is a group of retail stores of essentially the same type centrally owned with some degree of centralised control of operation and selling the same range of products. It is a chain of similar shops with identical store design, layout and stock display, each selling limited cohesive range of products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>43", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One objective of the European Union is to", "images": [], "options": {"A": "fight the guilty nation in time of war", "B": "eliminate drug addiction among member countries", "C": "eliminate all tariffs and quotas among member countries", "D": "fight against child abuse in member countries"}, "answer": "C", "explanation": "The European Union (EU) is a political and economic union of 27 member states that are located primarily in Europe. One of its main objectives is to promote economic cooperation among member countries. This includes the elimination of tariffs and quotas among member countries to promote free trade. Tariffs and quotas are trade barriers that restrict the free flow of goods and services. Eliminating these barriers allows for a more efficient allocation of resources, leading to increased economic growth and prosperity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>44", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Which of the following persons is a part of a business internal environment?", "images": [], "options": {"A": "Employee", "B": "Supplier", "C": "Creditor", "D": "Customer"}, "answer": "A", "explanation": "The internal environment of a business refers to the factors within the organization that affect its operations. This includes employees, management, corporate culture, organizational structure, and other internal factors. Employees are a part of a business's internal environment because they directly contribute to the business's operations and performance. Suppliers, creditors, and customers, on the other hand, are part of the business's external environment because they exist outside the organization and interact with the business in various ways.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>45", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A person or a firm to whom a sum of money is owed is", "images": [], "options": {"A": "banker", "B": "guarantor", "C": "debtor", "D": "creditor"}, "answer": "D", "explanation": "A creditor is a person or institution to whom money is owed. The term is used broadly in finance and accounting to refer to any party that has provided resources (like goods, services, or money) to another party with the expectation of being repaid. In contrast, a debtor is a person or firm that owes money. A banker is a person who works at a bank, while a guarantor is a person who guarantees to pay for someone else's debt if he or she defaults on a loan obligation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>46", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "A general tax which applies at each point of exchange of goods and services is", "images": [], "options": {"A": "a specific tax", "B": "an ad valorem tax", "C": "a value added tax", "D": "a direct tax"}, "answer": "C", "explanation": "A value added tax (VAT) is a type of general tax that is applied at each point of exchange of goods and services. It is based on the increase in value of a product or service at each stage of production or distribution. VAT is usually implemented as a destination-based tax, where the tax rate is based on the location of the customer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>47", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "If a business uses part of its profit to develop the area where it operates, the business is fulfilling its.", "images": [], "options": {"A": "economic responsibility", "B": "marketing responsibility", "C": "social responsibility", "D": "managerial responsibility"}, "answer": "C", "explanation": "When a business uses part of its profit to develop the area where it operates, it is fulfilling its social responsibility. Social responsibility is an ethical framework that suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. It is a duty every individual or organization has to perform so as to maintain a balance between the economy and the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2016>48", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Production ends when goods and services", "images": [], "options": {"A": "reach the final user", "B": "are used for manufacturing", "C": "are packed and labelled", "D": "are sold to the middlemen"}, "answer": "A", "explanation": "Production ends when goods and services reach the final user. This is because the final user is the end point of the production process, where the product is finally consumed and no further economic activity is generated by this specific product. The other options refer to intermediate stages in the production and distribution process, not the end point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2016>49", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The process of converting a non-profit making organization to a profit making business is", "images": [], "options": {"A": "indigenization", "B": "privatization", "C": "deregulation", "D": "commercialization"}, "answer": "D", "explanation": "The process of converting a non-profit making organization to a profit making business is commercialization. Commercialization is the process of bringing new products or services to the market. The term is used in several fields like technology, marketing, and business startups. In the context of this question, it refers to the process of transforming a non-profit organization into a profit-making one by introducing revenue-generating activities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2016>50", "subject": "Commerce", "year": "2016", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "A distinctive symbol, title or design that readily identifies the company and its products is", "images": [], "options": {"A": "Patent right", "B": "Trade mark", "C": "Trade name", "D": "Brand name"}, "answer": "B", "explanation": "A distinctive symbol, title or design that readily identifies the company and its products is a Trade mark. A trademark is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others. It is a type of intellectual property consisting of a recognizable sign, design, or expression which distinguishes products or services of a particular source from those of others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>1", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Commercial activities received a great boost in West Africa due to contact with", "images": [], "options": {"A": "Asians", "B": "Europeans", "C": "American", "D": "Africans"}, "answer": "B", "explanation": "Commercial activities in West Africa received a significant boost due to contact with Europeans. This is because the Europeans introduced new forms of trade and commerce, including the transatlantic slave trade and later legitimate trade in raw materials and finished goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>2", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "The job of the police in keeping law and order in the society is", "images": [], "options": {"A": "a commercial services", "B": "an indirect service", "C": "a direct service", "D": "a self service"}, "answer": "B", "explanation": "While the police work to maintain law and order, their role is considered indirect because they are not directly providing a tangible product or service to individuals. Instead, they create an environment where citizens can safely engage in commercial, social, and other activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>3", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "A business which becomes insolvent may result in", "images": [], "options": {"A": "continuity", "B": "expansion", "C": "liquidation", "D": "re-incorporation"}, "answer": "C", "explanation": "When a business becomes insolvent, it may result in liquidation. Insolvency is a state of financial distress in which a business is unable to pay its debts as they come due. Liquidation is the process of selling off all the assets of an insolvent business to pay off its debts. Therefore, insolvency often leads to liquidation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>4", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following activities does not belong to extractive occupation?", "images": [], "options": {"A": "Quarrying", "B": "Carving", "C": "Mining", "D": "Agriculture"}, "answer": "B", "explanation": "Extractive occupations are those that involve extracting or taking out resources from nature. This includes activities like mining, quarrying, and agriculture. Carving, on the other hand, is a form of art or craft and does not involve extracting resources from nature. Therefore, it does not belong to extractive occupations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>5", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "The major divisions of Commerce are", "images": [], "options": {"A": "import, export and transportation", "B": "trade, communication and warehousing", "C": "import, trade and production", "D": "trade and auxiliaries to trade"}, "answer": "D", "explanation": "The major divisions of commerce are trade and auxiliaries to trade. Trade involves the buying and selling of goods and services. Auxiliaries to trade, also known as aids to trade, include activities that help to facilitate trade. These include transportation, banking, insurance, warehousing, advertising, and communication.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>6", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A memorandum of Association is a document", "images": [], "options": {"A": "defining a company's relationship with the public", "B": "inviting the public to buy a company's share", "C": "governing the affairs of the partnership", "D": "regulating a company's internal affairs"}, "answer": "A", "explanation": "A Memorandum of Association is a document that sets out the constitution of a company and defines the scope of the company's activities and its relationship with the outside world. It is one of the fundamental documents required to incorporate a company and typically includes the following information:    Company Name: The name under which the company will operate.  Registered Office: The address of the company's registered office.  Objects Clause: The purpose and range of activities the company can undertake.  Liability Clause: The extent of the liability of the company's members.  Capital Clause: Details about the company's share capital and the division of shares.  Association Clause: A declaration that the subscribers wish to form a company and agree to take at least one share each.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>7", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The main purpose of branding is to", "images": [], "options": {"A": "increase the quantity of goods demanded", "B": "increase the selling price of goods", "C": "differentiate goods from other similar goods", "D": "enhance turnover of goods"}, "answer": "C", "explanation": "Branding is a marketing practice in which a company creates a name, symbol or design that is easily identifiable as belonging to the company. This helps to identify a product and distinguish it from other products and services. Branding is important because not only is it what makes a memorable impression on consumers but it allows your customers and clients to know what to expect from your company. Therefore, the main purpose of branding is to differentiate goods from other similar goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>8", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The facility which is not provided by the ports authority is", "images": [], "options": {"A": "berth", "B": "warehouse", "C": "tarmac", "D": "cranes"}, "answer": "C", "explanation": "The Ports Authority is responsible for providing facilities that aid in the loading, unloading, storage and movement of goods at the port. These facilities include berths for ships to dock, warehouses for storage of goods, and cranes for loading and unloading of goods. However, a tarmac, which is a material used for surfacing roads or other outdoor areas, is not a facility provided by the Ports Authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>9", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque could be dishonoured as a result of", "images": [], "options": {"A": "insufficient funds", "B": "same amount in words and figures", "C": "general crossing", "D": "regular signature"}, "answer": "A", "explanation": "A cheque can be dishonoured for a number of reasons, one of which is insufficient funds in the account of the person who wrote the cheque. If there is not enough money in the account to cover the amount of the cheque, the bank will not honour the cheque and it will be returned to the person who tried to cash it. The other options listed do not typically result in a cheque being dishonoured. Having the same amount in words and figures, a general crossing, and a regular signature are all requirements for a valid cheque, not reasons for a cheque to be dishonoured.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>10", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "When a company sells shares to existing share-holders at preferential rates, this is", "images": [], "options": {"A": "right issue", "B": "bonus issue", "C": "private placing", "D": "issue by introduction"}, "answer": "A", "explanation": "A right issue is a way by which a company can sell new shares to existing shareholders, usually at a preferential rate. This is done to raise additional capital for the company. The shareholders have the 'right' to buy the new shares before they are offered to the public.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>11", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The conversion of raw materials into finished goods is performed by", "images": [], "options": {"A": "the extractive industry", "B": "service occupations", "C": "commercial occupations", "D": "the manufacturing industry"}, "answer": "D", "explanation": "The manufacturing industry is responsible for the conversion of raw materials into finished goods. This process involves various stages such as design, production, quality control, and distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>12", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is not a factor of production?", "images": [], "options": {"A": "capital", "B": "Labour", "C": "Exchange", "D": "Entrepreneurship"}, "answer": "C", "explanation": "The traditional factors of production include land, labor, capital, and entrepreneurship. Exchange is not considered a factor of production. It is rather a process or mechanism through which the products produced or services rendered are traded or swapped.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>13", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Adama's opening stock is D5,000. He purchased goods worth D30,000. His closing stock was D7,000 and sales D55,000.    What is the average stock?", "images": [], "options": {"A": "D12,000", "B": "D7,000", "C": "D6,000", "D": "D5,000"}, "answer": "C", "explanation": "Opening stock is D5,000   Closing Stock is D7,000   Average stock value = (5,000 + 7,000) x 0.5   = 12,000 x 0.5 = 6,000  = D6,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>14", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Adama's opening stock is D5,000. He purchased goods worth D30,000. His closing stock was D7,000 and sales D55,000.  What is the cost of goods sold?", "images": [], "options": {"A": "D55,000", "B": "D42,000", "C": "D32,000", "D": "D28,000"}, "answer": "D", "explanation": "Cost of goods sold: Opening stock  + Purchases - Closing Stock  = 5000 + 30000 - 7000  = 28000", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>15", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Adama's opening stock is D5,000. He purchased goods worth D30,000. His closing stock was D7,000 and sales D55,000.  What is the rate of stock turnover?", "images": [], "options": {"A": "11 times", "B": "6 times", "C": "4.7 times", "D": "4 times"}, "answer": "C", "explanation": "Rateofstockturnover=Cost of goods soldAverage stock holding    =D28,000D6,000=4.6667≏4.6667≏4.7times", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>16", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is a source of short term capital?", "images": [], "options": {"A": "Trade credit", "B": "Shares", "C": "Leasing", "D": "Debenture"}, "answer": "A", "explanation": "Trade credit is a source of short term capital. It is an agreement where a customer can purchase goods on account (without paying cash), paying the supplier at a later date. Usually when the goods are delivered, a trade credit is given for a few days (30, 60, 90 days etc.) Shares, leasing, and debentures are typically sources of long-term capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>17", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The most suitable channel for the sale of an aircraft is", "images": [], "options": {"A": "manufacturer - wholesaler - retailer - consumer", "B": "manufacturer - wholesaler - consumer", "C": "manufacturer - retailer - consumer", "D": "manufacturer - consumer"}, "answer": "D", "explanation": "The most suitable channel for the sale of an aircraft is directly from the manufacturer to the consumer. This is because aircrafts are highly specialized and expensive products that are typically not sold through intermediaries like wholesalers or retailers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>18", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The duty payable on goods produced locally is", "images": [], "options": {"A": "export duty", "B": "excise duty", "C": "import duty", "D": "advalorem duty"}, "answer": "B", "explanation": "Excise duty is a tax that is levied on goods that are produced locally. It is a form of indirect tax that is paid by the manufacturer of the goods, who then usually passes the cost onto the consumer. Export duty is charged on goods leaving the country, import duty is charged on goods coming into the country, and ad valorem duty is a type of tax based on the value of a transaction or property.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>19", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "An overdraft is granted to holder of", "images": [], "options": {"A": "savings accounts", "B": "loan accounts", "C": "deposit accounts", "D": "current accounts"}, "answer": "D", "explanation": "An overdraft is a facility often provided to current account holders by banks. It allows the account holder to withdraw money from their account even if their account balance is zero, up to a certain limit. This is not typically provided to savings, loan, or deposit account holders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>20", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The amount of capital used in the day - to day running of a company is", "images": [], "options": {"A": "working capital", "B": "capital employed", "C": "share capital", "D": "fixed capital"}, "answer": "A", "explanation": "Working capital refers to the funds used in the day-to-day operations of a company. It is calculated as current assets minus current liabilities. Capital employed, share capital, and fixed capital are all types of capital but they are not specifically used for the day-to-day operations of a company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>21", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "An example of in invisible item of trade is", "images": [], "options": {"A": "oil", "B": "shipping", "C": "machinery", "D": "textile"}, "answer": "B", "explanation": "Invisible items of trade refer to services and other non-tangible items that are traded internationally. Shipping is a service and therefore an example of an invisible item of trade. Oil, machinery, and textiles are all tangible goods, so they are not considered invisible items of trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>22", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "In a hire purchase agreement, the buyer is the", "images": [], "options": {"A": "agent", "B": "hirer", "C": "lessee", "D": "lessor"}, "answer": "B", "explanation": "In a hire purchase agreement, the buyer is referred to as the hirer. The hirer is the person who hires the goods from the owner (lessor) and has an option to buy the goods by paying installments. The hirer has the right to terminate the agreement at any time in the course of the payment period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>23", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Which of the following terms is not used in price quotation for goods?", "images": [], "options": {"A": "E & O. E", "B": "C. I. F", "C": "Ex works", "D": "F.A.S"}, "answer": "A", "explanation": "E & O. E (Errors and Omissions Excepted) is not a term used in price quotation for goods. It is a phrase used in business to reduce legal liability for potentially incorrect or incomplete information supplied in a contractually related document such as a quotation or specification. On the other hand, C.I.F (Cost, Insurance, and Freight), Ex works, and F.A.S (Free Alongside Ship) are all terms used in international commercial law, specifying at what point respective obligations, costs, and risk involved in the delivery of goods shift from the seller to the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>24", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "Mr. Ojo paid Noak the sum of ₦3,000 for a piece of land without signing a deed of sale. The element of contract which is lacking in the transaction is", "images": [], "options": {"A": "valuable consideration", "B": "formality", "C": "offer and acceptance", "D": "capacity"}, "answer": "B", "explanation": "The element of contract which is lacking in the transaction is formality. A contract for the sale of land is one of the contracts that must be in writing and signed by both parties according to the Statute of Frauds. This is to prevent fraudulent transactions and misunderstandings. In this case, Mr. Ojo paid Noak the sum of ₦3,000 for a piece of land without signing a deed of sale, hence the contract lacks formality.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>25", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Which of the following document is used in home trade only?", "images": [], "options": {"A": "Bill of lading", "B": "Airway bill", "C": "Certificate of origin", "D": "Proforma invoice"}, "answer": "D", "explanation": "A proforma invoice is a document that is used in home trade only. It is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. The invoice will typically describe the purchased items and other important information such as the shipping weight and transport charges. Other options like Bill of lading, Airway bill, and Certificate of origin are used in international trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>26", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The Central Bank carries out its monetary policy through", "images": [], "options": {"A": "discounting bills", "B": "credit ceiling", "C": "replacement of worn-out notes", "D": "bank rate"}, "answer": "B", "explanation": "The Central Bank carries out its monetary policy through credit ceiling. A credit ceiling is a limit that restricts the amount a person can borrow from a bank. It is one of the tools used by central banks to control the money supply in the economy. Other options like discounting bills, replacement of worn-out notes, and bank rate are also methods used by the central bank but they are not the primary methods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>27", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The expert responsible for the calculation of probability of risk in insurance is", "images": [], "options": {"A": "an actuary", "B": "an underwriter", "C": "a broker", "D": "a solicitor"}, "answer": "A", "explanation": "The expert responsible for the calculation of probability of risk in insurance is an actuary. An actuary is a business professional who deals with the financial impact of risk and uncertainty. Actuaries use mathematics, statistics, and financial theory to study uncertain future events, especially those of concern to insurance and pension programs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>28", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "A disadvantage of rail transport is that", "images": [], "options": {"A": "it carries bulky goods only", "B": "the cost of carriage is high", "C": "it is not flexible", "D": "it travels on schedule"}, "answer": "C", "explanation": "Rail transport is not flexible because it operates on a fixed schedule and routes. It cannot be adjusted or redirected easily based on individual needs or changes in circumstances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>29", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The advertising medium that makes only audio impression is", "images": [], "options": {"A": "cinema", "B": "radio", "C": "television", "D": "hoardings"}, "answer": "B", "explanation": "Radio is an advertising medium that makes only audio impressions. Unlike television or cinema, it does not provide visual content. And unlike hoardings, it does not provide static visual content.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>30", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A speculator in the stock exchange market who sells securities in anticipation of a fall in their prices is a", "images": [], "options": {"A": "broker", "B": "bull", "C": "bear", "D": "stag"}, "answer": "C", "explanation": "In stock exchange market terminology, a 'bear' is a speculator who sells securities in anticipation that the price will fall, allowing them to buy back the securities at a lower price for a profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>31", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following activities aims at increasing sales?", "images": [], "options": {"A": "Insurance", "B": "Banking", "C": "Warehousing", "D": "Advertising"}, "answer": "D", "explanation": "Advertising is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea. It aims at increasing sales by making the product or service known to potential customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>32", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "A machine supplied by the post office to organizations to imprint stamps on their letters is", "images": [], "options": {"A": "vending machine", "B": "shredding machine", "C": "automated teller machine", "D": "franking machine"}, "answer": "D", "explanation": "A franking machine is a machine that imprints stamps on letters or packages, typically for large quantities of mail. It is supplied by the post office to organizations to facilitate the process of mailing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>33", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An agreement between two parties which can be embraced is", "images": [], "options": {"A": "a warranty", "B": "an offer", "C": "consideration", "D": "a contract"}, "answer": "D", "explanation": "A contract is an agreement between two or more parties that is intended to be enforceable by law. The key elements of a contract are offer, acceptance, consideration, and the intention to create legal relations. Therefore, a contract can be embraced by two parties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>34", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The marketing mix element which ensures that goods are available when and where needed is", "images": [], "options": {"A": "place", "B": "price", "C": "product", "D": "promotion"}, "answer": "A", "explanation": "The marketing mix is a combination of factors that can be controlled by a company to influence consumers to purchase its products. It consists of the 4Ps: Product, Price, Place, and Promotion. 'Place' in the marketing mix refers to the distribution channel of a product. It ensures that goods are available when and where they are needed by the consumer. Therefore, the correct answer is 'place'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>35", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "An example of a computer's output device is a", "images": [], "options": {"A": "keyboard", "B": "mouse", "C": "monitor", "D": "scanner"}, "answer": "C", "explanation": "In computing, an output device is any piece of computer hardware equipment used to communicate the results of data processing carried out by an information processing system (such as a computer) to the outside world. Examples of output devices include monitors, printers, speakers, etc. In this case, a 'monitor' is an output device because it displays information in visual form, using text and graphics. Therefore, the correct answer is 'monitor'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>36", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Ocean liners are vessels that", "images": [], "options": {"A": "sail at scheduled times on fixed routes", "B": "sail any time to any place where there is cargo", "C": "carry only cargo", "D": "cary only liquid"}, "answer": "A", "explanation": "Ocean liners are large ships that transport people and goods across the sea. They are designed for scheduled service on specific routes on specific schedules. This is different from a cruise ship, which is primarily focused on the passenger experience, or a cargo ship, which is primarily focused on carrying cargo. Therefore, the correct answer is 'sail at scheduled times on fixed routes'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>37", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The process of placing the right people in the right position is an organization is", "images": [], "options": {"A": "planning", "B": "motivating", "C": "staffing", "D": "directing"}, "answer": "C", "explanation": "The process of placing the right people in the right position in an organization is referred to as staffing. Staffing is a managerial function that involves the process of acquiring, deploying, and retaining a workforce of sufficient quantity and quality to create positive impacts on the organization's effectiveness. It is not planning, motivating or directing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>38", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "The right of an unpaid seller does not include", "images": [], "options": {"A": "declaring the buyer bankrupt", "B": "retaining the possession of the goods", "C": "stopping the goods while in transit", "D": "reselling the goods"}, "answer": "A", "explanation": "The right of an unpaid seller does not include declaring the buyer bankrupt. The rights of an unpaid seller, according to the Sale of Goods Act, include the right of lien or retaining the possession of the goods, the right of stoppage in transit, and the right of resale. Declaring the buyer bankrupt is a legal process that the seller does not have the authority to initiate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>39", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "The coming together of people who engage in trade and industry in a particular area is", "images": [], "options": {"A": "an employer's association", "B": "a trade association", "C": "a chamber of commerce", "D": "a trade union"}, "answer": "C", "explanation": "The coming together of people who engage in trade and industry in a particular area is a chamber of commerce. A chamber of commerce is a form of business network, such as a local organization of businesses whose goal is to further the interests of businesses. It is not an employer's association, a trade association, or a trade union.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2017>40", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "The term which enjoins the buyer to examine goes thoroughly before making a purchase is", "images": [], "options": {"A": "uberimae fidel", "B": "caveat venditor", "C": "consumer sovereignty", "D": "caveat emptor"}, "answer": "D", "explanation": "The term 'caveat emptor' is a Latin term that means 'let the buyer beware'. It is a principle that the buyer alone is responsible for checking the quality and suitability of goods before a purchase is made. Hence, it enjoins the buyer to examine goods thoroughly before making a purchase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>41", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a tool for sales promotion?", "images": [], "options": {"A": "Publicity", "B": "Exhibition", "C": "Competition", "D": "Free samples"}, "answer": "C", "explanation": "Sales promotion is a marketing strategy where the product is promoted using short-term attractive initiatives to stimulate its demand and increase its sales. This includes methods like free samples, exhibitions, and publicity. However, competition is not a tool for sales promotion. It is a market condition which affects the selling environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>42", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "The organization of local and international trade fair is the responsibility of", "images": [], "options": {"A": "trade associations", "B": "labour unions", "C": "chambers of commerce", "D": "customs and excise authorities"}, "answer": "C", "explanation": "The organization of local and international trade fairs is typically the responsibility of chambers of commerce. A chamber of commerce is a form of business network, e.g., a local organization of businesses whose goal is to further the interests of businesses. They often organize trade fairs to promote businesses and stimulate economic activity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>43", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "Under the principle of subrogation, the insurer has the right to", "images": [], "options": {"A": "abrogate the contract", "B": "re-insure the property", "C": "take over any legal rights of the insured", "D": "take over all the liabilities of the insured"}, "answer": "C", "explanation": "The principle of subrogation in insurance means that the insurer, after compensating the insured for the loss, acquires all the legal rights and remedies that the insured had against a third party with respect to the loss. Therefore, the insurer has the right to take over any legal rights of the insured.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2017>44", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "The law that protects a musician's work from piracy is", "images": [], "options": {"A": "usury law", "B": "copyright", "C": "trademark", "D": "hire purchase"}, "answer": "B", "explanation": "Copyright law protects original works of authorship, including musical works. Therefore, the law that protects a musician's work from piracy is copyright.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>45", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following countries is a member of the Lake Chad Basin Commission?", "images": [], "options": {"A": "Libya", "B": "Cameroon", "C": "Ghana", "D": "Guinea"}, "answer": "D", "explanation": "The Lake Chad Basin Commission (LCBC) is a regional body established in May 22,1964 by Cameroon, Chad, Niger, and Nigeria. Other countries, such as the Central African Republic and Libya, joined later.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>46", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following is a type of marine insurance?", "images": [], "options": {"A": "Endowment", "B": "Hull", "C": "Accident", "D": "Fidelity"}, "answer": "B", "explanation": "Marine insurance is a type of insurance that covers the loss or damage of ships, cargo, terminals, and any transport by which the property is transferred, acquired, or held between the points of origin and the final destination. Hull insurance is a type of marine insurance, and it specifically covers the hull and body of a ship against damages and losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>47", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The transfer of ownership of government business to individuals is", "images": [], "options": {"A": "commercialisation", "B": "deregulation", "C": "privatization", "D": "nationalization"}, "answer": "C", "explanation": "The transfer of ownership of government business to individuals is known as privatization. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The public sector is the part of the economic system that is run by government agencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>48", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the aims of ECOWAS is to", "images": [], "options": {"A": "discourage foreign investors", "B": "promote privatization policy", "C": "ensure production of quality products", "D": "promote trade within the region"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. One of its main aims is to promote trade within the region. This is done by removing trade barriers and promoting free trade, which allows for the easy movement of goods and services between member countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>49", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following business relies on government subvention for its operation?", "images": [], "options": {"A": "Public Corporation", "B": "Public Limited Company", "C": "Co-operative society", "D": "Private Limited Company"}, "answer": "A", "explanation": "A Public Corporation is a company that is publicly owned and operated by the government. It relies on government subvention for its operation. Government subvention refers to the financial aid or support that a government provides to a particular entity, in this case, a Public Corporation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2017>50", "subject": "Commerce", "year": "2017", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "Balance of payment deficits may be caused by", "images": [], "options": {"A": "revaluation of currency", "B": "sales of foreign reserves", "C": "unrestricted exports", "D": "unrestricted imports"}, "answer": "D", "explanation": "Balance of payment deficits occur when a country imports more goods, services, and capital than it exports. Unrestricted imports can lead to an increase in imports, thereby causing a deficit in the balance of payments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>1", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Activities which facilitate commerce include", "images": [], "options": {"A": "engaging youths in environmental sanitation.", "B": "funding political campaigns.", "C": "providing recreational facilities in communities.", "D": "improving road networks."}, "answer": "D", "explanation": "Activities that facilitate commerce are those that make the process of buying and selling goods and services easier. This includes improving infrastructure such as road networks which makes transportation of goods easier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>2", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A document through which invitation is extended to the public to subscribe to shares is", "images": [], "options": {"A": "article of association.", "B": "prospectus.", "C": "memorandum of association.", "D": "quotation."}, "answer": "B", "explanation": "A prospectus is a legal document issued by companies that are offering securities for sale. It contains details about the company, its operations, and the securities being offered.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>3", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "One example of a product of the construction industry is", "images": [], "options": {"A": "chair.", "B": "bag of cement.", "C": "piece of cloth.", "D": "television"}, "answer": "B", "explanation": "The construction industry involves the building and assembly of infrastructure, and cement is a key material used in this process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>4", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION", "question": "A person authorized to sell the property of a company in a winding up is", "images": [], "options": {"A": "an auctioneer.", "B": "an agent.", "C": "a liquidator.", "D": "a bailee"}, "answer": "C", "explanation": "In the context of a company winding up, a liquidator is the person who is authorized to sell the property of the company. A liquidator is appointed when a company goes into liquidation or winding up. Their main role is to sell the company's assets, settle the claims of creditors, and distribute any remaining assets to the shareholders. An auctioneer, agent, and bailee do not have the same level of authority or responsibility in a company winding up.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>5", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The space marked A represents", "images": ["Commerce/imgs/2018/commerce18ssce233ds.png"], "options": {"A": "trading.", "B": "industry.", "C": "occupation.", "D": "advertising."}, "answer": "C", "explanation": "The space represent occupation or division of production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>6", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The space marked X represents", "images": ["Commerce/imgs/2018/commerce18ssce233ds.png"], "options": {"A": "industry.", "B": "foreign trade.", "C": "home trade.", "D": "production."}, "answer": "A", "explanation": "The space represent industry based on division of occupation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>7", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "What does the space marked M represent?", "images": ["Commerce/imgs/2018/commerce18ssce233ds.png"], "options": {"A": "quarrying", "B": "manufacturing", "C": "agriculture", "D": "trade"}, "answer": "D", "explanation": "The space represent trade based on division of commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>8", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The purchase and sale of goods over electronic system is", "images": [], "options": {"A": "E-payment", "B": "E-commerce", "C": "E-mail", "D": "E-transfer"}, "answer": "B", "explanation": "The purchase and sale of goods over an electronic system is referred to as E-commerce. E-commerce, or electronic commerce, refers to transactions conducted via the internet. Every time individuals and companies are buying or selling products and services online they're engaging in e-commerce. The term e-commerce also encompasses other activities including online auctions, internet banking, payment gateways, and online ticketing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>9", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "One disadvantage of a sole proprietorship is", "images": [], "options": {"A": "quick decision making", "B": "unlimited liability", "C": "pride of ownership", "D": "unlimited sources of capital"}, "answer": "B", "explanation": "One disadvantage of a sole proprietorship is unlimited liability. In a sole proprietorship, the owner is personally liable for all the debts and obligations of the business. This means that if the business incurs a debt or is sued, the owner's personal assets can be used to satisfy these obligations. Quick decision making, pride of ownership, and unlimited sources of capital are generally considered advantages, not disadvantages, of a sole proprietorship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>10", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Which of the following is a source of short-term finance to a business", "images": [], "options": {"A": "Hire purchase", "B": "Overdraft", "C": "Lease", "D": "Debenture"}, "answer": "B", "explanation": "An overdraft is a type of short-term finance where a bank allows a company to withdraw more money than it has in its account, up to a certain limit. This is a form of short-term finance because it is typically meant to cover a company's immediate financial needs and is expected to be paid back quickly. The other options, such as hire purchase, lease, and debenture, are typically forms of long-term finance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>11", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The portion of share capital which the company has asked shareholders to pay is", "images": [], "options": {"A": "called-up capital", "B": "authorized capital", "C": "paid-up capital", "D": "unpaid capital"}, "answer": "A", "explanation": "Called-up capital is the portion of share capital that a company has asked its shareholders to pay. Authorized capital is the maximum amount of share capital that a company is allowed to issue, while paid-up capital is the amount of money a company has received from shareholders in exchange for shares. Unpaid capital is the part of the issued capital of a company which has not yet been paid by the shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>12", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Multilateral trade is carried out", "images": [], "options": {"A": "between two countries only", "B": "within many countries", "C": "among many countries", "D": "between neighbouring countries only"}, "answer": "C", "explanation": "Multilateral trade is trade that is conducted among many countries, without discrimination. It is carried out through international agreements, where all signatories treat each other equally. This is different from bilateral trade, which is trade between two countries, and does not necessarily involve many countries or neighboring countries only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>13", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "An association of businesses engaged in both trade and industry is a", "images": [], "options": {"A": "co-operative society", "B": "trade union", "C": "trust fund", "D": "chamber of commerce"}, "answer": "D", "explanation": "A chamber of commerce is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>14", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Which of the following statements is true of a debenture?", "images": [], "options": {"A": "Its holders receive interest", "B": "It forms part of a company's authorized capital", "C": "Its holders are co-owners of the company", "D": "Its holders control the company"}, "answer": "A", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. The holders of debentures are paid interest for their investment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>15", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The path through which a product moves from the manufacturer to the consumer is a", "images": [], "options": {"A": "channel of communication", "B": "line of production", "C": "means of transportation", "D": "channel of distribution"}, "answer": "D", "explanation": "The path through which a product moves from the manufacturer to the consumer is known as the channel of distribution. It includes all the entities involved in getting the product from the producer to the consumer, including wholesalers, retailers, and distributors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>16", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "If the share stock of Ali Ltd is #40,000, cost of goods sold is #48,000 and closing stock is #24,000, its rate of turnover will be", "images": [], "options": {"A": "1.2 times", "B": "1.5 times", "C": "2.0 times", "D": "7.5 times"}, "answer": "C", "explanation": "The rate of turnover is calculated by dividing the cost of goods sold by the average inventory. In this case, the average inventory is not given, but we can assume that the closing stock is the average inventory. Therefore, the rate of turnover is 48000/24000 = 2.0 times.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>17", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "A business which requires a certificate of trading in order to commence operation is a", "images": [], "options": {"A": "co-operative society", "B": "private company", "C": "sole proprietorship", "D": "public company"}, "answer": "D", "explanation": "A public company is a type of business that requires a certificate of trading in order to commence operation. This is because public companies are allowed to sell shares to the public and are therefore subject to more regulations than other types of businesses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>18", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Exchange of goods in international market which does not involve the use of money is", "images": [], "options": {"A": "barter trade", "B": "entrepot trade", "C": "counter trade", "D": "bilateral trade"}, "answer": "C", "explanation": "Counter trade is a form of international trade in which goods or services are exchanged for other goods or services rather than the use of hard currency.    Countries that engage in countertrade have limited foreign exchange or credit facilities, and it is most common in developing countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>19", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "Which of the following features is not associated with a chamber of commerce? It is", "images": [], "options": {"A": "democratically administered", "B": "an independent association", "C": "open only to entrepreneurs", "D": "a voluntary association"}, "answer": "C", "explanation": "A chamber of commerce is a local association to promote and protect the interests of the business community in a particular place. It is democratically administered, an independent association, and a voluntary association. However, it is not open only to entrepreneurs. It is open to all businesses, big or small, entrepreneur or corporation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>20", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "The reason for sending a proforma invoice to a potential customer is that it is", "images": [], "options": {"A": "an indication of the seller's willingness to grant credit", "B": "a polite way of telling the customer to return the goods", "C": "an invitation to the buyer to buy on hire purchase", "D": "a polite way of refusing to sell on credit"}, "answer": "A", "explanation": "A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is an indication of the seller's willingness to sell the goods or services to the buyer. It is not a polite way of telling the customer to return the goods, an invitation to the buyer to buy on hire purchase, or a polite way of refusing to sell on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>21", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "The insurance policy taken to cover dishonesty of accounts personnel of an organization is", "images": [], "options": {"A": "employees's liability", "B": "fidelity guarantee", "C": "life endowment", "D": "marine insurance"}, "answer": "B", "explanation": "Fidelity guarantee insurance is a type of insurance policy that covers businesses for the loss of money or property sustained as a direct result of acts of fraud, theft or dishonesty by an employee in the course of employment. It is not employees's liability, life endowment, or marine insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>22", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following document is used when goods are being sent by a common carrier?", "images": [], "options": {"A": "Delivery note", "B": "Consignment note", "C": "Advice note", "D": "Credit note"}, "answer": "B", "explanation": "A consignment note is a document that accompanies goods being transported by a common carrier and describes the goods, the details of the consignor and consignee. It serves as a proof that the carrier has received the goods and has a contract from the consignor to carry them. The other options are not specifically used for goods being sent by a common carrier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>23", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A put option in the stock exchange is an option", "images": [], "options": {"A": "to sell", "B": "not to sell", "C": "to buy", "D": "not to buy"}, "answer": "A", "explanation": "A put option in the stock exchange is an option to sell a specified amount of an underlying security at a specified price within a specified time. This is a financial contract between the buyer and the seller of the put option. The buyer of the put option has the right, but not the obligation, to sell an agreed quantity of a particular commodity or financial instrument (the underlying) to the seller of the option at a certain time for a certain price (the strike price).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>24", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "The function of money do not include", "images": [], "options": {"A": "store of value", "B": "medium of exchange", "C": "double coincidence of wants", "D": "means of deferred payment"}, "answer": "C", "explanation": "The functions of money include serving as a medium of exchange, a store of value, and a unit of account. Money does not include the function of 'double coincidence of wants'. This term refers to the situation where the supplier of good A wants good B and the supplier of good B wants good A. This is a situation that money helps to avoid by providing a common medium of exchange.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>25", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A document of title of goods written by the ship owner,specifying that certain goods are being conveyed in the ship is a", "images": [], "options": {"A": "bill of sale", "B": "bill of sight", "C": "bill of entry", "D": "bill of lading"}, "answer": "D", "explanation": "A bill of lading is a document issued by a carrier (or their agent) to acknowledge receipt of cargo for shipment. In British English, the term relates to ship transport only, and in American English, to any type of transportation of goods. It serves three main purposes: it is a conclusive receipt, i.e., an acknowledgement that the goods have been loaded; and, which operates as a document of title to the goods, subject to the nemo dat quod non habet rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>26", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Information advertising is aimed at", "images": [], "options": {"A": "giving advice on the use of a product", "B": "influencing customers to buy a product", "C": "giving gifts to attract customers", "D": "encouraging specific customers to buy a product"}, "answer": "A", "explanation": "Information advertising is a type of advertising that is used to inform consumers about a product or feature. This type of advertising is often used to introduce a new product or feature, or to promote a new use for an existing product. It is designed to educate the consumer and create a better understanding of the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>27", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A cheap means of carrying bulky goods over a distance is by", "images": [], "options": {"A": "rail", "B": "road", "C": "air", "D": "pipeline"}, "answer": "A", "explanation": "Rail transport is known for being a cost-effective way to move large and heavy cargo over long distances. Trains can carry a significant amount of goods in a single trip, reducing the cost per unit of what's being transported.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>28", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "A contract terminated by the occurrence of an event which makes performance impossible is discharged by", "images": [], "options": {"A": "breach", "B": "agreement", "C": "frustration", "D": "performance"}, "answer": "C", "explanation": "A contract is discharged by frustration when an event occurs that makes the performance of the contract impossible, illegal, or radically different from that contemplated by the parties at the time of the contract. This is not a breach, which is a failure to perform a contractual obligation, nor an agreement, which is a mutual decision to end the contract, nor performance, which is the completion of the contractual obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>29", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "An individual employed to act on behalf of another within a specific guideline is", "images": [], "options": {"A": "a jobber", "B": "an agent", "C": "a broker", "D": "a distributor"}, "answer": "B", "explanation": "An agent is an individual employed to act on behalf of another (the principal) within specific guidelines. The agent can make decisions and take actions that legally bind the principal. A jobber is a trader who buys goods from manufacturers and sells them to retailers. A broker is an intermediary who arranges transactions between a buyer and a seller, and a distributor is an entity that buys non-competing products or product lines and sells them direct to end users or customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>30", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a component of the marketing mix", "images": [], "options": {"A": "price", "B": "place", "C": "population", "D": "product"}, "answer": "C", "explanation": "The marketing mix, also known as the 4Ps of marketing, consists of Product, Price, Place (distribution), and Promotion. These are the controllable elements of a marketing program and are used to help a business reach its target market. Population is not a component of the marketing mix.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>31", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A method of buying in anticipation of price fluctuation in the commodity market is", "images": [], "options": {"A": "speculation", "B": "arbitrage", "C": "contango", "D": "hedging"}, "answer": "A", "explanation": "Speculation is the practice of engaging in risky financial transactions in an attempt to profit from fluctuations in the market value of a tradable good such as a financial instrument, rather than attempting to profit from the underlying financial attributes embodied in the instrument such as capital gains, interest, or dividends. This involves buying commodities in anticipation of price fluctuation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>32", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A shipping document detailing the charges for carrying a particular cargo for a specified voyage is", "images": [], "options": {"A": "dock warrant", "B": "freight note", "C": "bill of lading", "D": "mate's receipt"}, "answer": "B", "explanation": "A freight note is a shipping document that details the charges for carrying a particular cargo for a specified voyage. It is issued by a carrier and it specifies the type, quantity and destination of the goods being carried. A freight note also includes the charges, rate of freight and total freight chargeable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>33", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Commercial agent who are authorized to keep goods untill they are sold are", "images": [], "options": {"A": "factors", "B": "distributors", "C": "brokers", "D": "auctioneers"}, "answer": "A", "explanation": "Factors are commercial agents who are authorized to keep goods until they are sold. They are entrusted with the possession of goods to be sold in their own name but on behalf of their principals. They have control over the goods and can sell them on credit, receive payment and even sue the buyer in their own name.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>34", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "An advertisement method whose objective is to convince customers to buy a product is", "images": [], "options": {"A": "informative advertisement", "B": "persuasive advertisement", "C": "competitive advertisement", "D": "mass advertisement"}, "answer": "B", "explanation": "Persuasive advertisement is a type of advertisement whose main goal is to convince customers to buy a product. It uses emotional appeal, logical arguments, and moral or ethical values to persuade customers to make a purchase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>35", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "A government legislation which ensures that quality goods and services are available to customers is", "images": [], "options": {"A": "hire purchase Act", "B": "copy right Act", "C": "price control Act", "D": "Standard organization Act"}, "answer": "D", "explanation": "The Standard Organization Act is a government legislation that ensures quality goods and services are available to customers. It sets and enforces standards for products and services to ensure they meet certain safety and quality requirements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>36", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A bank draft is a cheque drawn by a bank on", "images": [], "options": {"A": "another bank", "B": "itself", "C": "creditors", "D": "customers deposits"}, "answer": "A", "explanation": "A bank draft is a type of check where the payment is guaranteed to be available by the issuing bank. It is a check drawn by a bank on another bank, not on itself or on customers' deposits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>37", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A company is quoted on the stock exchange when its share are", "images": [], "options": {"A": "put under private placement", "B": "not for sale to the public", "C": "listed for sale on the stock exchange", "D": "owned by the government"}, "answer": "C", "explanation": "A company is quoted on the stock exchange when its shares are listed for sale on the stock exchange. This means that the company's shares are publicly traded and anyone can buy them. The stock exchange is a marketplace where buyers and sellers meet to trade stocks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>38", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "Which of the following functions is not performed by the export promotion council?", "images": [], "options": {"A": "prevention of importation of harmful goods", "B": "provision of credit facilities to exporters", "C": "provision of technical advice to exporters", "D": "creation of export free zones"}, "answer": "A", "explanation": "The function of the export promotion council is to promote and support export activities. This includes providing credit facilities to exporters, providing technical advice, and creating export free zones. However, preventing the importation of harmful goods is not a function of the export promotion council. This function is typically performed by customs and other regulatory bodies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>39", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Activities undertaken to create awareness of a product by giving out samples or gifts is", "images": [], "options": {"A": "marketing mix", "B": "marketing concept", "C": "window display", "D": "sales promotion"}, "answer": "D", "explanation": "Sales promotion is a marketing strategy where a company tries to get more customers by offering them special deals, discounts, or incentives. This can include giving out samples or gifts to create awareness of a product. The other options, marketing mix, marketing concept, and window display, are all different aspects of marketing but they do not specifically refer to the activity of giving out samples or gifts to promote a product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>40", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "An advantage of privatizing a firm is that it", "images": [], "options": {"A": "become more efficient", "B": "sells good at low prices", "C": "employ more workers", "D": "attracts more customers"}, "answer": "A", "explanation": "Privatization often leads to increased efficiency due to the profit motive, which drives firms to cut costs and innovate. Privatization eliminates bureaucratic red tape that can slow down decision making, and allows firms to respond more quickly to market forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>41", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The transformation of authority by a superior officer to his subordinate in an organization", "images": [], "options": {"A": "controlling", "B": "decentralization", "C": "delegation", "D": "directing"}, "answer": "C", "explanation": "Delegation is the process of assigning responsibility or authority to another person to carry out specific activities. It allows a person to move from what they've been doing to what they should be doing. It increases efficiency and allows for better management in an organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>42", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "The provision of scholarships by a firm to needy students is part of its", "images": [], "options": {"A": "political responsibility", "B": "economic responsibility", "C": "social responsibility", "D": "legal responsibility"}, "answer": "C", "explanation": "Providing scholarships to needy students is part of a firm's social responsibility. Social responsibility is an ethical framework that suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. It is a duty every individual or organization has to perform so as to maintain a balance between the economy and the ecosystem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>43", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "How many countries form ECOWAS", "images": [], "options": {"A": "17", "B": "16", "C": "15", "D": "14"}, "answer": "C", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. It was founded on May 28, 1975, with the signing of the Treaty of Lagos. Its mission is to promote economic integration across the region.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>44", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following is a modern means of communication?", "images": [], "options": {"A": "Grape vine", "B": "E-mail", "C": "Whistles", "D": "Town crier"}, "answer": "B", "explanation": "E-mail is a modern means of communication. It is a method of exchanging messages between people using electronic devices. Invented by Ray Tomlinson, email first entered limited use in the 1960s and by the mid-1970s had taken the form now recognized as email.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2018>45", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "A system of issuing new shares to selected investors instead of the general public is", "images": [], "options": {"A": "public offer", "B": "issue by tender", "C": "offer for sale", "D": "private placement"}, "answer": "D", "explanation": "Private placement is a method of issuing new shares to selected investors instead of the general public. It is a funding round of securities which are sold not through a public offering, but rather through a private offering, mostly to a small number of chosen investors.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>46", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the aims of the European Union is to", "images": [], "options": {"A": "ease trade among members countries", "B": "enhance better trade with Africa", "C": "enhance free trade with America", "D": "offer financial assistance to poor countries"}, "answer": "A", "explanation": "The European Union (EU) is a political and economic union of 27 member states that are located primarily in Europe. One of its main aims is to promote peace, its values and the well-being of its citizens. It also aims to offer freedom, security and justice without internal borders. An important aspect of this is the ease of trade among member countries. This is achieved through a single market which allows goods, services, money and people to move freely.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>47", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The purpose of commercialization is to", "images": [], "options": {"A": "encourage the participation of private sector", "B": "make state-owned firms more efficient", "C": "encourage the flow of foreign capital", "D": "enable state-owned firms pay tax"}, "answer": "B", "explanation": "Commercialization is the process of introducing a new product or production method into commerce—making it available on the market. The purpose of commercialization is to make state-owned firms more efficient. This is achieved by introducing competition, which forces the firms to improve their efficiency in order to survive. It also often involves the participation of the private sector, but the main aim is to improve efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>48", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The time allowed for loading and unloading a ship at the harbour is", "images": [], "options": {"A": "demurrage", "B": "tenure", "C": "lay days", "D": "dead freight"}, "answer": "C", "explanation": "In shipping, lay days are the days allowed by the charterer for loading and unloading the cargo. If the ship is detained beyond this period, demurrage is charged. Therefore, the time allowed for loading and unloading a ship at the harbour is referred to as lay days.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2018>49", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Inter-bank indebtedness is settled at the", "images": [], "options": {"A": "clearing house", "B": "money market", "C": "discount house", "D": "stock exchange"}, "answer": "A", "explanation": "Inter-bank indebtedness is settled at the clearing house. A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2018>50", "subject": "Commerce", "year": "2018", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The concern of a marketing manager whose company has adopted the marketing concept is to", "images": [], "options": {"A": "recruit more salesmen", "B": "make maximum profit", "C": "identify and satisfy customers needs", "D": "maintain the company's share of the market"}, "answer": "C", "explanation": "The concern of a marketing manager whose company has adopted the marketing concept is to identify and satisfy customers needs. The marketing concept is a business philosophy that holds that the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>1", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "A firm which turns timber into wooden office desks belongs to the", "images": [], "options": {"A": "extractive industry", "B": "direct service industry", "C": "indirect service industry", "D": "construction industry"}, "answer": "D", "explanation": "While it might seem like manufacturing, in the broader context, especially in relation to sectors directly dealing with physical goods and their utilization, such firms are often categorized under the construction industry. This is because they produce items used in the construction of office spaces and other buildings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>2", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "E-commerce is an activity which involves", "images": [], "options": {"A": "trading in products through the post office", "B": "trading in products through the internet", "C": "buying and selling of products through telegram messages", "D": "buying and selling of products through fax messages"}, "answer": "B", "explanation": "E-commerce refers to the buying and selling of goods or services using the internet, and the transfer of money and data to execute these transactions. Therefore, the correct answer is 'trading in products through the internet'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>3", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Rent is the return on", "images": [], "options": {"A": "a loan", "B": "labour", "C": "land", "D": "a share"}, "answer": "C", "explanation": "In economics, rent is the income derived from the ownership of land and other rental properties. It is the return on land. Therefore, the correct answer is 'land'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2019>4", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partner whose only contribution to the partnership is his name and goodwill is", "images": [], "options": {"A": "an active partner", "B": "a limited partner", "C": "a nominal partner", "D": "a sleeping partner"}, "answer": "C", "explanation": "A nominal partner is a partner who does not invest any capital or share in the profits or losses of a business, but lends his name to the firm. His name gives the firm a certain reputation and goodwill. This is different from an active partner who takes part in the management of the business, a limited partner who has limited liability and a sleeping partner who invests capital but does not participate in the management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>5", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Computer manufacturers in an area could form a", "images": [], "options": {"A": "producer association", "B": "thrift society", "C": "chamber of commerce", "D": "consumer association"}, "answer": "A", "explanation": "Computer manufacturers in an area could form a producer association. A producer association is a group of manufacturers or businesses that produce similar products or services and come together to collaborate on business matters, such as setting standards, sharing research, or lobbying government. This is different from a thrift society which is a savings and loan organization, a chamber of commerce which is a network of local businesses, or a consumer association which is a group that advocates for consumer rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>6", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The problem of double coincidence of wants is that", "images": [], "options": {"A": "it is hard to determine the exchange rate for goods", "B": "it does not encourage purchase of large quantities and varieties", "C": "deferred payment is not possible because goods exchanged are not durable", "D": "one has to find someone who wants his surplus and also has what he needs"}, "answer": "D", "explanation": "The problem of double coincidence of wants refers to the difficulty in barter trade where one has to find someone who wants his surplus and also has what he needs. This is because in barter trade, for a transaction to occur, both parties must desire what the other has to offer. This is different from the other options which refer to other problems associated with barter trade such as determining the exchange rate for goods, encouraging purchase of large quantities and varieties, or making deferred payment possible.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>7", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The type of business where management is separated from ownership is a", "images": [], "options": {"A": "sole proprietorship", "B": "public company", "C": "partnership", "D": "cooperative society"}, "answer": "B", "explanation": "A public company is a type of business where management is separated from ownership. This is because the owners (shareholders) do not participate in the day-to-day running of the company. Instead, they elect a board of directors to manage the company on their behalf.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>8", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : FEATURES AND IMPORTANCE", "question": "Where there is no deed of partnership, members share profit on", "images": [], "options": {"A": "the basis of participation", "B": "the basis of shares held", "C": "patronage basis", "D": "equal basis"}, "answer": "D", "explanation": "In the absence of a partnership deed, the law assumes that all partners share profits and losses equally, regardless of their capital contribution or level of involvement in the business. This is a legal principle in partnership law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>9", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The factor of production that is fixed in nature is", "images": [], "options": {"A": "land", "B": "labour", "C": "entrepreneurship", "D": "capital"}, "answer": "A", "explanation": "In the context of economics, land is considered a fixed factor of production. This is because the quantity of land is fixed and cannot be increased or decreased by human effort. It includes all natural resources that are used in the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2019>10", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A means of payment through the post office is", "images": [], "options": {"A": "standing order", "B": "money order", "C": "debit card", "D": "credit card"}, "answer": "B", "explanation": "A means of payment through the post office is a money order. A money order is a payment order for a specific amount of money. It is more trusted than a cheque as it is prepaid. The money is received by the post office at the time of issuance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>11", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "A stock exchange broker is engaged in", "images": [], "options": {"A": "construction occupation", "B": "commercial occupation", "C": "extractive occupation", "D": "manufacturing occupation"}, "answer": "B", "explanation": "A stock exchange broker is engaged in a commercial occupation. They are involved in buying and selling of securities on behalf of their clients on the stock exchange. This is a commercial activity as it involves trade and commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>12", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "A group of companies formed to carry out an activity that is beyond the ability of any individual company is", "images": [], "options": {"A": "a subsidiary", "B": "a merger", "C": "a consortium", "D": "an acquisition"}, "answer": "C", "explanation": "A group of companies formed to carry out an activity that is beyond the ability of any individual company is a consortium. A consortium is an association of two or more companies, organizations, or governments (or any combination of these entities) with the objective of participating in a common activity or pooling their resources for achieving a common goal.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>13", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The share capital of a company stated in the Memorandum of Association and approved by the registrar of companies is", "images": [], "options": {"A": "working capital", "B": "paid-up capital", "C": "nominal capital", "D": "called-up capital"}, "answer": "C", "explanation": "The share capital of a company stated in the Memorandum of Association and approved by the registrar of companies is the nominal capital. Nominal capital, also known as authorized capital, is the maximum amount of share capital that a company is authorized to issue to shareholders. It is a notional value and the company may not issue the entire amount of nominal capital.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>14", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE ASSOCIATION : OBJECTIVES , MERIT & DEMERIT", "question": "One of the aims of a trade association is to", "images": [], "options": {"A": "liaise with other trade associations in other countries", "B": "organize trade fairs and exhibitions", "C": "provide quality goods and services", "D": "promote commercial activities in their business"}, "answer": "D", "explanation": "One of the aims of a trade association is to promote commercial activities in their business. Trade associations are organizations founded and funded by businesses that operate in a specific industry. They participate in public relations activities such as advertising, education, political donations, lobbying and publishing, but their main focus is collaboration between companies, or standardization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>15", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Retail outlets which sell from vehicles are", "images": [], "options": {"A": "supermarkets", "B": "mobile shops", "C": "departmental stores", "D": "chain stores"}, "answer": "B", "explanation": "Retail outlets which sell from vehicles are mobile shops. Mobile shops are a type of retail outlet that operates from a vehicle or moving transport. They are able to change their location and serve customers in different areas, providing convenience and accessibility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>16", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "Cash in hand and at bank, plus debtors are components of", "images": [], "options": {"A": "intangible assets", "B": "current assets", "C": "current liabilities", "D": "depleting assets"}, "answer": "B", "explanation": "Cash in hand and at bank, plus debtors are components of current assets. Current assets are all assets of a business that are expected to be used up or converted into cash within one business operating cycle – typically 12 months. They include cash, stocks, debtors, and prepaid expenses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>17", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "Goods sold under a distinctive trademark are", "images": [], "options": {"A": "branded goods", "B": "unsought goods", "C": "perishable goods", "D": "public goods"}, "answer": "A", "explanation": "Goods sold under a distinctive trademark are branded goods. A brand is a name, term, design, symbol, or any other feature that identifies one seller's good or service as distinct from those of other sellers. Branded goods are those that are associated with a specific, well-known brand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>18", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A firm which imports goods with the view of re-exporting them is engaged in", "images": [], "options": {"A": "bilateral trade", "B": "entrepot trade", "C": "multilateral trade", "D": "counter trade"}, "answer": "B", "explanation": "A firm which imports goods with the view of re-exporting them is engaged in entrepot trade. Entrepot trade is a form of international trade in which goods are imported for the purpose of re-exporting them, rather than for domestic consumption. The goods are often stored, repackaged or processed in some way before being re-exported.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>19", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "A risk whose probability of occurrence is impossible to estimate is", "images": [], "options": {"A": "uninsurable risk", "B": "pure risk", "C": "particular risk", "D": "insurable risk"}, "answer": "A", "explanation": "An uninsurable risk is a risk that is not insurable, typically because the likelihood of the risk occurring is unknown or it's so high that insuring it would be impractical. This is the case when the probability of occurrence is impossible to estimate.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>20", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "An instruction to a bank to make regular payment to a third party on behalf of a customer is", "images": [], "options": {"A": "standing order", "B": "money order", "C": "money transfer", "D": "credit transfer"}, "answer": "A", "explanation": "A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The other options do not involve regular payments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>21", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram above to answer this question    The diagram above shows a", "images": ["Commerce/imgs/2019/img1.png"], "options": {"A": "standing order", "B": "receipt", "C": "cheque", "D": "bill of exchange"}, "answer": "C", "explanation": "The diagram above depicts(represent) a cheque. It is a negotiable instrument.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>22", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram above to answer this question  XYZ Bank of Commerce PLC is the", "images": ["Commerce/imgs/2019/img1.png"], "options": {"A": "payee", "B": "endorser", "C": "drawer", "D": "drawee"}, "answer": "D", "explanation": "XYZ Bank of Commerce PLC is the drawee, the person whose name is on the cheque such payer said y is payee and the person who write the cheque is known as Drawer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>23", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram above to answer this question  Oki Williams is the", "images": ["Commerce/imgs/2019/img1.png"], "options": {"A": "payee", "B": "endorser", "C": "drawer", "D": "drawee"}, "answer": "C", "explanation": "Oki williams is drawer, his the owner of the account and who issue the cheque.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>24", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "An international trade practice where goods are exchanged for other good is", "images": [], "options": {"A": "entrepot trade", "B": "bilateral trade", "C": "barter trade", "D": "counter trade"}, "answer": "C", "explanation": "Barter trade is a system in the economy that involves the exchange of goods and services for other goods and services. This is an ancient method of trade and exchange. The other options involve monetary transactions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>25", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A proportion of the total deposit that a commercial bank must keep as cash and convertible papers is", "images": [], "options": {"A": "special deposit", "B": "liquidity ratio", "C": "interest rate", "D": "bank rate"}, "answer": "B", "explanation": "The proportion of the total deposit that a commercial bank must keep as cash and convertible papers is known as the liquidity ratio. This is a financial metric used to determine a bank's ability to pay off its short-term debts obligations. The liquidity ratio shows the proportion of a company's short-term assets available to cover its short-term liabilities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>26", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The principle that applies when Greene and Sunwar Insurance Companies jointly indemnified Fatou for the destruction of her storey building by fire is", "images": [], "options": {"A": "contribution", "B": "insurable interest", "C": "proximate cause", "D": "subrogation"}, "answer": "A", "explanation": "The principle that applies when two insurance companies jointly indemnify a person for a loss is known as the principle of contribution. This principle is used when the insured has taken out more than one insurance policy on the same subject matter. In such a case, each insurer contributes proportionately to the loss.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>27", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "The charge paid by a specular for non-settlement of his account within the specified period is", "images": [], "options": {"A": "backwardation", "B": "brokerage", "C": "commission", "D": "contango"}, "answer": "B", "explanation": "This refers to the fee or commission charged by a broker for executing transactions or providing services. In some contexts, it can include additional charges for non-settlement or late settlement of accounts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>28", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque for which payment is refused due to insufficient funds is a", "images": [], "options": {"A": "bearer cheque", "B": "crossed cheque", "C": "dishonoured cheque", "D": "stale cheque"}, "answer": "C", "explanation": "A dishonoured cheque is a cheque that the bank has refused to honour as there is insufficient funds in the account, or there is some other problem with the cheque. A bearer cheque is a cheque that is payable to whoever presents it at the bank. A crossed cheque is a cheque that is marked specifying an instruction about the way it is to be redeemed. A stale cheque is a cheque that is presented for payment six months after its date of issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>29", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "The keyboard of a computer is classified as", "images": [], "options": {"A": "an input device", "B": "a memory device", "C": "an output device", "D": "a storage device"}, "answer": "A", "explanation": "The keyboard of a computer is an input device. It is used to input data into the computer. A memory device is a device that is used to store data or information. An output device is a device that outputs data from the computer. A storage device is a device that is used to store data or information for a long period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2019>30", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "A communication equipment which is stationed in space for sending signals is", "images": [], "options": {"A": "data processor", "B": "internet", "C": "satellite", "D": "telex machine"}, "answer": "C", "explanation": "A satellite is a communication equipment which is stationed in space for sending signals. A data processor is a system which processes data. The internet is a global network of computers. A telex machine is a communication device that was used to send and receive messages over long distances.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2019>31", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "One of the factors which determines the choice of transport for goods is the", "images": [], "options": {"A": "cost of purchasing the mode of transport", "B": "maintenance cost of the mode of transport", "C": "number of users of the mode of transport", "D": "nature of the goods to be transported"}, "answer": "D", "explanation": "The nature of the goods to be transported is a key factor in determining the choice of transport. Different goods require different modes of transport based on their size, weight, perishability, and other factors. For instance, perishable goods like fruits and vegetables might require refrigerated transport, while large, heavy goods might require transport by ship or train.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>32", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following activities increase demand for goods and services?", "images": [], "options": {"A": "Advertising", "B": "Banking", "C": "Transportation", "D": "Warehousing"}, "answer": "A", "explanation": "Advertising is a marketing activity that increases demand for goods and services. It does this by making consumers aware of a product or service, highlighting its benefits, and persuading consumers to purchase it. Banking, transportation, and warehousing are all important aspects of commerce, but they do not directly increase demand for goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2019>33", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "A diagram showing the positions of the structure of a company is", "images": [], "options": {"A": "span of control", "B": "organizational chart", "C": "vertical integration", "D": "flow chart"}, "answer": "B", "explanation": "An organizational chart is a diagram that shows the structure of a company, including the positions and relationships between different parts of the organization. It provides a visual representation of the hierarchy within the company and can help employees understand their role within the larger structure. A span of control refers to the number of subordinates a manager or supervisor can effectively manage. Vertical integration is a strategy where a company takes control of more than one stage in the production or distribution of a product. A flow chart is a type of diagram that represents a process, showing the steps as boxes of various kinds, and their order by connecting them with arrows.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>34", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "Good consumer service practise requires", "images": [], "options": {"A": "charging high prices so as to make profit", "B": "hanging up customers' phone calls when busy", "C": "patience towards ill-mannered customers", "D": "promoting hard working employees"}, "answer": "C", "explanation": "Good consumer service practice requires patience towards ill-mannered customers. This is because customer service is about dealing with customers in a polite, respectful, and helpful manner, regardless of their behavior. It's about understanding and meeting their needs and expectations, and handling complaints and problems effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>35", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "The elements of a contract are offer ,", "images": [], "options": {"A": "acceptance and performance", "B": "consideration and performance", "C": "legality and formality", "D": "acceptance and consideration"}, "answer": "D", "explanation": "The elements of a contract are offer, acceptance, and consideration. An offer is a proposal by one party to another to enter into a contract. Acceptance is the agreement by the other party to the offer. Consideration is something of value that is given in exchange for something else. It is the price paid for the promise of the other party.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>36", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following types of advertising is aimed at taking away existing buyers from their suppliers?", "images": [], "options": {"A": "Negative", "B": "Competitive", "C": "Informative", "D": "Mass"}, "answer": "B", "explanation": "Competitive advertising is aimed at taking away existing buyers from their suppliers. This type of advertising is used by companies to differentiate their products or services from those of their competitors. It is designed to highlight the unique features and benefits of a company's product or service, and to persuade customers to switch from their current supplier to the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>37", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The marketing concept emphasizes the need to", "images": [], "options": {"A": "identify and satisfy customer wants", "B": "maximize foreign investment", "C": "maximise profit for the company", "D": "build a strong and solid brand"}, "answer": "A", "explanation": "The marketing concept is a business philosophy that emphasizes the importance of creating value for customers. It involves identifying the needs and wants of the target market and delivering the desired satisfactions more effectively and efficiently than competitors. Therefore, the correct answer is 'identify and satisfy customer wants'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>38", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "An agent whose authority, as conferred by the principal, has no limit is a", "images": [], "options": {"A": "del credere agent", "B": "general agent", "C": "special agent", "D": "universal agent"}, "answer": "D", "explanation": "An agent whose authority, as conferred by the principal, has no limit is a universal agent. A universal agent can perform all acts that can be lawfully delegated to an agency. This is different from a general agent who can only perform acts related to a business or employment, and a special agent who is authorized to conduct a single transaction or a series of transactions not involving continuity of service.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>39", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "An agreement in which Philip paid half the price of a car and accepted to pay the rest in installments is a", "images": [], "options": {"A": "conditional sale contract", "B": "credit sale contract", "C": "hire purchase contract", "D": "haulage contract"}, "answer": "C", "explanation": "A hire purchase contract is a type of agreement where a customer agrees to pay for goods in parts or a percentage at a time. In this case, Philip paid half the price of a car and accepted to pay the rest in installments, which is a characteristic of a hire purchase contract. A conditional sale contract would involve the transfer of ownership after certain conditions are met, and a credit sale contract would involve the immediate transfer of ownership with payment to be made in the future. A haulage contract is unrelated to this scenario as it involves the transportation of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>40", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "A new offer of contract that terminates the original offer is", "images": [], "options": {"A": "a void contract", "B": "a counter offer", "C": "an invalid offer", "D": "quasi contract"}, "answer": "B", "explanation": "A counter offer is a response given to an initial offer. It means the original offer has been rejected and replaced by a new one. Therefore, it terminates the original offer. A void contract is a contract that is not legally enforceable. An invalid offer is an offer that does not meet the legal requirements for a valid contract. A quasi contract is a contract created by a court in the interests of fairness and justice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2019>41", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "Which of the following roles is performed by middle management in an organization?", "images": [], "options": {"A": "Formulation of objectives and strategies", "B": "Review of master plans, programmes and budgets", "C": "Review and appraisal of operational results", "D": "Implementation of organizational plans and objectives"}, "answer": "D", "explanation": "Middle management in an organization is responsible for implementing the plans and objectives set by the top management. They do not formulate objectives and strategies, this is the role of top management. Review of master plans, programmes and budgets is also a role of top management. Review and appraisal of operational results is a role of both middle and top management, but it is not the primary role of middle management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>42", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The management term which refers to the number of staff a superior officer can efficiently supervise is", "images": [], "options": {"A": "delegation of authority", "B": "division of labour", "C": "unity of command", "D": "span of control"}, "answer": "D", "explanation": "Span of control refers to the number of subordinates that a manager or supervisor can effectively manage. This number varies depending on the complexity of tasks, the abilities of the manager and the abilities of the workers. Delegation of authority is the process of distributing and entrusting work to other members of an organization. Division of labour refers to the assignment of different parts of a manufacturing process or task to different individuals. Unity of command is a principle that suggests that an individual should only report to one manager.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>43", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following business units could be commercialized?", "images": [], "options": {"A": "Public corporation", "B": "Cooperative society", "C": "Private company", "D": "Sole proprietorship"}, "answer": "A", "explanation": "A public company and a private company can be commercialized. However, the term \"commercialized\" typically refers to the process of bringing a product or service to market. In the context of business units, the term might be more relevant to the activities they engage in rather than their classification as public or private.    Public Company: A company whose shares are traded publicly on stock exchanges. These companies are already commercialized in the sense that they offer their shares to the public and engage in business activities to generate profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>44", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The restructuring of a government enterprise with the intention of making it profit oriented is", "images": [], "options": {"A": "privatization", "B": "nationalization", "C": "commercialization", "D": "deregulation"}, "answer": "C", "explanation": "Commercialization is the process of converting a government owned company to profit oriented. It is the restructuring of a government enterprise with the intention of making it profit oriented.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>45", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "The headquarters of the Mano River Union is in", "images": [], "options": {"A": "Freetown", "B": "Monrovia", "C": "Conakry", "D": "Abidjan"}, "answer": "A", "explanation": "The headquarters of the Mano River Union is in Free town, Sierra Leone. The Mano River Union (MRU) is an international association initially established between Liberia and Sierra Leone in 1973 for economic and social development. Guinea joined in 1980 and Côte d'Ivoire in 2008. The MRU is named for the Mano River which begins in the Guinea highlands and forms a border between Liberia and Sierra Leone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>46", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A source of capital to a public company which attracts a fixed rate of interest is", "images": [], "options": {"A": "an ordinary share", "B": "a subvention", "C": "a debenture", "D": "an overdraft"}, "answer": "C", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. Both corporations and governments frequently issue this type of bond to secure capital. Like other types of bonds, debentures are documented in an indenture. Debentures have a fixed rate of interest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>47", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not an economic grouping in West Africa?", "images": [], "options": {"A": "Lake Chad Basin Commission", "B": "Economic Community of West African States", "C": "European Union", "D": "Niger Basin Commission"}, "answer": "C", "explanation": "The European Union is not an economic grouping in West Africa. It is a political and economic union of 27 member states that are located primarily in Europe. The other options, Lake Chad Basin Commission, Economic Community of West African States, and Niger Basin Commission, are all economic groupings in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>48", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A customer who wishes to withdraw an amount greater than the balance in his current account would apply for", "images": [], "options": {"A": "a standing order", "B": "an overdraft", "C": "a loan", "D": "a credit transfer"}, "answer": "B", "explanation": "An overdraft is a facility provided by the bank to its customers that allows the customer to withdraw money from their account even if the account balance is zero, or less than the amount they want to withdraw. This is a form of short-term borrowing facility provided by the bank to its customers. A loan, on the other hand, is a long-term borrowing. A standing order is an instruction to the bank to make regular fixed payments to a particular person or organization, and a credit transfer is a deposit of funds directly into a bank account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>49", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "The combination of business activities of Abbas Ltd and Denko Ltd to form one large company is", "images": [], "options": {"A": "an amalgamation", "B": "a consortium", "C": "an acquisition", "D": "a cartel"}, "answer": "A", "explanation": "Amalgamation is the process of combining two or more companies into a larger single company. In this case, Abbas Ltd and Denko Ltd are combining to form one large company, which is a clear example of an amalgamation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2019>50", "subject": "Commerce", "year": "2019", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The difference between commercialization and privatization is that commercialized businesses", "images": [], "options": {"A": "are government-owned while privatized businesses are owned by individuals", "B": "are non-profit marking ventures while privatized businesses are profit oriented", "C": "can sell shares while privatized businesses cannot", "D": "employed more workers than privatized businesses"}, "answer": "A", "explanation": "Commercialization and privatization are two different concepts. Commercialization refers to the process of managing or running something principally for financial gain, or the process of incorporating an activity into the economy. These businesses are typically government-owned. On the other hand, privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The businesses are owned by individuals or a group of individuals.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>1", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce is defined as", "images": [], "options": {"A": "buying and selling of goods and services only", "B": "all activities in the distribution and exchange of goods and services", "C": "all activities involved in the production of goods and services", "D": "transporting and warehousing of goods only"}, "answer": "B", "explanation": "Commerce involves all activities in the distribution and exchange of goods and services, not just buying and selling. It includes transportation, warehousing, insurance, and finance that are involved in the process of transferring goods from the producer to the consumer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>2", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "The type of occupation that a broker belongs to is", "images": [], "options": {"A": "commercial", "B": "construction", "C": "extraction", "D": "manufacturing"}, "answer": "A", "explanation": "A broker is involved in commercial activities as they facilitate transactions between two parties, typically buyers and sellers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>3", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "A form of money which was not used in the early days of trade is", "images": [], "options": {"A": "tobacco", "B": "metal bars", "C": "cowries", "D": "coins"}, "answer": "D", "explanation": "Before the invention of coins, people used various forms of commodity money such as tobacco, metal bars, and cowries for trade. Coins were introduced later as a more standardized and convenient form of money.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>4", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following activities is not an example of the extractive industry", "images": [], "options": {"A": "weaving", "B": "quarrying", "C": "hunting", "D": "fishing"}, "answer": "A", "explanation": "The extractive industry involves the extraction of raw materials from the earth to be used by consumers. The extracted materials are then used to produce goods and services. Examples of extractive industries include mining, quarrying, fishing, and hunting. Weaving, on the other hand, is a part of the manufacturing industry where raw materials are transformed into finished goods. Therefore, weaving is not an example of the extractive industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>5", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The factor of production which bears all the risks of the business is", "images": [], "options": {"A": "capital", "B": "entrepreneurship", "C": "labour", "D": "land"}, "answer": "B", "explanation": "In the context of business, the entrepreneur is the factor of production that bears all the risks. An entrepreneur is an individual who, rather than working as an employee, runs a small business and assumes all the risks and rewards of a given business venture, idea, or good or service offered for sale. The entrepreneur is commonly seen as an innovator, a source of new ideas, goods, services, and business/or procedures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>6", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION", "question": "Production is completed when products reach the", "images": [], "options": {"A": "warehouse", "B": "users", "C": "retailers", "D": "shops"}, "answer": "B", "explanation": "Production is considered complete when products reach the users or consumers. The production process involves creating goods and services with the desired quality and quantity and making them available for users or consumers at the right time and place. Therefore, the production process is completed when the products reach the users.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>7", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partner whose name is used to boost the image of the business and does not contribute capital is a", "images": [], "options": {"A": "dormant partner", "B": "general partner", "C": "limited partner", "D": "nominal partner"}, "answer": "D", "explanation": "A nominal partner is a partner who lends his or her name to a partnership without contributing any capital and without participating in its management. This type of partner is often used to boost the image or credibility of the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>8", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "One of the advantage of sole proprietorship is that", "images": [], "options": {"A": "access to large capital is easy", "B": "decisions are made promptly", "C": "business risks are spread", "D": "continuity of business is assured"}, "answer": "B", "explanation": "One of the advantages of a sole proprietorship is that decisions can be made promptly. This is because the business is owned and managed by one person, so there is no need for consultation or agreement with other partners or shareholders before decisions can be made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>9", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A business unit in which savings of members are lent to others is a", "images": [], "options": {"A": "consumer cooperative society", "B": "producer cooperative society", "C": "credit and thrift society", "D": "wholesale cooperative society"}, "answer": "C", "explanation": "A credit and thrift society is a type of cooperative society where the savings of members are pooled together and lent to other members. This type of society is designed to promote savings and provide loans to members at low interest rates.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>10", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The document issued by a public company allowing it to commence business is the", "images": [], "options": {"A": "Articles of Association", "B": "Certificate of Incorporation", "C": "Memorandum of Association", "D": "Certificate of Trading"}, "answer": "D", "explanation": "The Certificate of Trading is the document that gives a public company the legal permission to commence business.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>11", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following is not a function of a consumer association?", "images": [], "options": {"A": "Ensuring that consumers buy quality goods", "B": "Educating consumers on their rights", "C": "Penalizing importers of fake goods", "D": "Ensuring that fair prices are charged"}, "answer": "C", "explanation": "Consumer associations do not have the authority to penalize importers of fake goods. This is the responsibility of regulatory bodies and law enforcement agencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>12", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An association formed by computer distributors to safeguard and promote their interest is a", "images": [], "options": {"A": "chamber of commerce", "B": "cooperative society", "C": "trade association", "D": "trade union"}, "answer": "C", "explanation": "A trade association is an organization formed by businesses in the same industry to promote their interests and influence public policy in favor of their industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>13", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The issue of prospectus by a company is an invitation to members of the public to", "images": [], "options": {"A": "subscribe to the company's shares", "B": "attend the company's Annual general Meeting", "C": "buy the company's products", "D": "attend the company's board meeting"}, "answer": "A", "explanation": "A prospectus is a legal document issued by companies that are offering securities for sale. It is an invitation to the public to subscribe to the company's shares. It contains details about the company, its business, and the securities being offered.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>14", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Examples of current assets are", "images": [], "options": {"A": "cash and trade debtors", "B": "cash and trade creditors", "C": "trade debtors, trade creditors and cash", "D": "trade creditors and trade debtors"}, "answer": "A", "explanation": "Current assets are assets that a company expects to convert to cash or use up within one year or its operating cycle, whichever is longer. Examples of current assets include cash and trade debtors (accounts receivable). Trade creditors (accounts payable) are not assets but liabilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>15", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "When the cost of sales is divided by the average stock, the result is", "images": [], "options": {"A": "gross profit", "B": "net profit", "C": "rate of turnover", "D": "working capital"}, "answer": "C", "explanation": "When the cost of sales is divided by the average stock, the result is the rate of turnover. The rate of turnover is a measure of how quickly a company sells its goods. It is calculated by dividing the cost of goods sold by the average inventory for the period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>16", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The part of issued share capital that the company has asked the subscribers to pay for", "images": [], "options": {"A": "authorised capital", "B": "called-up capital", "C": "nominal capital", "D": "paid-up capital"}, "answer": "B", "explanation": "The part of issued share capital that the company has asked the subscribers to pay for is called the called-up capital. This is the portion of a company's share capital that has been called for payment. It is the value of shares that a company has issued and investors have promised to pay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>17", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The last link in a channel of distribution is the", "images": [], "options": {"A": "wholesaler", "B": "retailer", "C": "consumer", "D": "agent"}, "answer": "C", "explanation": "The last link in a channel of distribution is the consumer. The channel of distribution refers to the path or route along which goods move from producers or manufacturers to ultimate consumers or users. It ends with the consumer who is the final user of the product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>18", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The difference between a country's imports and exports of goods in a particular year is", "images": [], "options": {"A": "terms of trade", "B": "terms of payment", "C": "balance of payment", "D": "balance of trade"}, "answer": "D", "explanation": "The difference between a country's imports and exports of goods in a particular year is the balance of trade. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>19", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "Goods bought into the country for sale are the country's", "images": [], "options": {"A": "invisible imports", "B": "invisible exports", "C": "visible imports", "D": "visible exports"}, "answer": "C", "explanation": "Goods bought into a country for sale are referred to as visible imports. This is because they are tangible goods that can be seen and touched, and they are being imported into the country, not exported.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>20", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A feature of supermarkets which distinguishes it from other large scale retail outlets is that items sold are", "images": [], "options": {"A": "mainly household goods", "B": "mainly industrial goods", "C": "delivered by post", "D": "one line of products"}, "answer": "A", "explanation": "Supermarkets are distinguished from other large scale retail outlets by the fact that they sell mainly household goods. These include food items, cleaning supplies, and other goods typically used in a household.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>21", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "One advantage of small scale retail outlets is", "images": [], "options": {"A": "availability of self service facilities", "B": "ability to buy in bulk", "C": "easy acess to large amount of capital", "D": "personal attention to customers"}, "answer": "D", "explanation": "One advantage of small scale retail outlets is the personal attention to customers. Because these outlets are smaller, the staff can provide more personalized service to each customer, which can improve the shopping experience and customer satisfaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>22", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "A discount deducted from the invoice price of goods to enable the retailer to make profit", "images": [], "options": {"A": "cash discount", "B": "functional discount", "C": "trade discount", "D": "seasonal discount"}, "answer": "C", "explanation": "A trade discount is a reduction in price given by a manufacturer or wholesaler to a retailer. The purpose of a trade discount is to allow the retailer to make a profit when selling the goods to the end consumer. It is deducted from the invoice price of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>23", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A document issued by the seller's own courier and signed by the customer to acknowledge receipt of the goods is", "images": [], "options": {"A": "advice note", "B": "consignment note", "C": "delivery note", "D": "freight note"}, "answer": "C", "explanation": "A delivery note is a document that is included with a shipment of goods sent out for delivery to a customer. It lists the description and quantity of the goods delivered. The customer signs the note to acknowledge receipt of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>24", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A request for goods from another country by an importer would be made using", "images": [], "options": {"A": "an invoice", "B": "an indent", "C": "an order", "D": "a quotation"}, "answer": "B", "explanation": "An indent is a purchase order placed by an importer with a foreign exporter or agent for the supply of goods. It is a formal request for goods from another country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>25", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The right to buy or sell stock in the stock exchange within a stipulated period is", "images": [], "options": {"A": "option", "B": "contango", "C": "backwardation", "D": "brokerage"}, "answer": "A", "explanation": "Option is a financial contract that gives the buyer the right, but not the obligation, to buy (call option) or sell (put option) a specific underlying asset (like a stock) at a predetermined price (strike price) by a certain time (expiration date).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>26", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "The share value stated on a share certificate is", "images": [], "options": {"A": "above par value", "B": "below par value", "C": "market value", "D": "nominal value"}, "answer": "D", "explanation": "The share value stated on a share certificate is the 'nominal value'. The nominal value of a share, also known as the par value, is its face value as stated in the company's constitution. This is not necessarily the price at which the shares are issued or the market value of the shares.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>27", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "The bank which acts as the lender of last resort is the", "images": [], "options": {"A": "Central bank", "B": "Commercial bank", "C": "Merchant bank", "D": "Mortegage bank"}, "answer": "A", "explanation": "The bank which acts as the lender of last resort is the 'Central bank'. The central bank is a financial institution given privileged control over the production and distribution of money and credit for a nation or a group of nations. In modern economies, the central bank is usually responsible for the formulation of monetary policy and the regulation of member banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>28", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The issue of shares which allows existing shareholder's to buy shares at a preferential price is", "images": [], "options": {"A": "bonus issue", "B": "offer for sale", "C": "public offer", "D": "rights issue"}, "answer": "D", "explanation": "A rights issue is an invitation to existing shareholders to purchase additional new shares in the company. This type of issue gives existing shareholders securities called rights. With the rights, the shareholder can purchase new shares at a discount to the market price on a stated future date. The company is giving shareholders a chance to increase their exposure to the stock at a discount price. But until that date, the rights can often be traded to other investors.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>29", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "The finanacial market where existing shares and bonds are bought and sold in the", "images": [], "options": {"A": "forex market", "B": "stock market", "C": "money market", "D": "commodity market"}, "answer": "B", "explanation": "The stock market is a public market for the trading of company stock and derivatives at an agreed price. It is a place where buyers and sellers meet to trade in securities. The securities traded on the stock market include: shares issued by companies, unit trusts, derivatives, pooled investment products and bonds. The stock market is different from the forex market (where currencies are traded), the money market (where short-term debt instruments are traded), and the commodity market (where commodities are traded).", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>30", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "An insurance policy which is not a contract of indemnity is", "images": [], "options": {"A": "burglary insurance", "B": "fire insurance", "C": "life insurance", "D": "motor insurance"}, "answer": "C", "explanation": "Life insurance is not a contract of indemnity because the value of a human life cannot be measured in terms of money. The insurer does not pay the actual loss suffered by the insured. Instead, the insurer pays a fixed sum mentioned in the policy on the happening of the event insured against. In contracts of indemnity, such as fire and burglary insurance, the insurer undertakes to compensate the actual loss suffered by the insured on the occurrence of an event.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>31", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "When a company insures the lives of all its employees collectively, the policy is", "images": [], "options": {"A": "accident insurance", "B": "fleet insurance", "C": "fidelity guarantee insurance", "D": "group insurance"}, "answer": "D", "explanation": "Group insurance is a type of insurance that covers a group of people, usually who are the members of societies, employees of a common employer, or professionals in a common group. In this case, when a company insures the lives of all its employees collectively, it is referred to as group insurance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>32", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque that could be cashed over the counter by the payee is", "images": [], "options": {"A": "certified cheque", "B": "crossed cheque", "C": "open cheque", "D": "bank draft"}, "answer": "C", "explanation": "An open cheque is a type of cheque that is not crossed on the left corner and payable at the counter of the bank. An open cheque may be a bearer cheque or an order one. It is also known as an uncrossed cheque. The cheque is payable over the counter of the bank. You can collect the money for the cheque from the bank counter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>33", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A specially-designed mode of transport for conveying liquid and gas is a", "images": [], "options": {"A": "coaster", "B": "tanker", "C": "liner", "D": "ferry"}, "answer": "B", "explanation": "A tanker is a ship designed to transport or store liquids or gases in bulk. Major types of tankship include the oil tanker, the chemical tanker, and gas carrier. Tankers also carry commodities such as vegetable oils, molasses and wine. In this case, a specially-designed mode of transport for conveying liquid and gas is a tanker.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>34", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "The safe keeping of goods produced until they are needed is", "images": [], "options": {"A": "hoarding", "B": "marketing", "C": "packaging", "D": "warehousing"}, "answer": "D", "explanation": "The safe keeping of goods produced until they are needed is referred to as warehousing. Warehousing involves the storage of goods in a commercial building for the purpose of handling, storage and retrieval. It is not hoarding, which is the accumulation of items in excess, or marketing, which is the promotion and selling of products or services, or packaging, which is the process of designing and producing packages for products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>35", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the objectives of the Niger Basin Commission is to", "images": [], "options": {"A": "regulate the movement of citizens across borders", "B": "improve tariff and quota on non-members", "C": "regulate the movement of cargo along the river", "D": "streaming the construction of dams on the river"}, "answer": "D", "explanation": "The Niger Basin Commission works to manage and develop the resources of the Niger River Basin, including the coordination of infrastructure projects like dams and water management.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>36", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "A paid presentation about a product with a view to encouraging purchases by an identifiable sponsor is", "images": [], "options": {"A": "publicity", "B": "personal selling", "C": "sales promotion", "D": "advertisement"}, "answer": "D", "explanation": "A paid presentation about a product with a view to encouraging purchases by an identifiable sponsor is an advertisement. Advertising is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea. It is not publicity, which is the public visibility or awareness for any product, service or company, or personal selling, which involves a salesperson directly selling to a prospective buyer, or sales promotion, which are activities that supplement and coordinate personal selling and advertising to attract customers to buy immediately.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>37", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "The face-to-face meeting of the seller with the buyer for the purpose of making sales is", "images": [], "options": {"A": "mass selling", "B": "impulse buying", "C": "personal selling", "D": "sale promotion"}, "answer": "C", "explanation": "Personal selling involves a face-to-face interaction between the seller and the buyer for the purpose of making a sale. It is a form of direct marketing where the salesperson uses his or her skills and abilities to build a personal relationship with the buyer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>38", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The activity which improves the appearance of a product and also aimed at protecting it is", "images": [], "options": {"A": "advertising", "B": "grading", "C": "labelling", "D": "packaging"}, "answer": "D", "explanation": "Packaging is the activity that improves the appearance of a product and also aimed at protecting it. It involves designing and producing the container or wrapper for a product. It serves to protect the product from damage during transportation, while also improving its appearance to attract customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>39", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a component of the marketing mix?", "images": [], "options": {"A": "product", "B": "production", "C": "promotion", "D": "place"}, "answer": "B", "explanation": "The marketing mix, also known as the 4Ps of marketing, includes Product, Price, Place, and Promotion. Production is not a component of the marketing mix. The marketing mix is a business tool used in marketing and by marketers to strategize and implement their marketing plan.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>40", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The marketing term which regards the consumer as king that must be satisfied is", "images": [], "options": {"A": "market segmentation", "B": "market research", "C": "marketing concept", "D": "marketing mix"}, "answer": "C", "explanation": "The marketing concept is a business philosophy that holds the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets. It regards the consumer as the king that must be satisfied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>41", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An agreement that is enforceable in law is", "images": [], "options": {"A": "an offer", "B": "a consideration", "C": "a contract", "D": "an acceptance"}, "answer": "C", "explanation": "A contract is a legally binding agreement that recognises and governs the rights and duties of the parties to the agreement. It is enforceable by law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>42", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : REMEDIES FOR A BREACH OF CONTRACT", "question": "A contract will not be discharge through", "images": [], "options": {"A": "acceptance", "B": "agreement", "C": "breach", "D": "performance"}, "answer": "A", "explanation": "A contract is not discharged through acceptance. Acceptance is a part of the formation of a contract, not its termination. A contract is discharged or terminated through performance, agreement, breach, or other legal means.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>43", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "A person engaged for the purpose of bringing his principal and a third party into a contractual relation is", "images": [], "options": {"A": "an arbiter", "B": "an auctioneer", "C": "an agent", "D": "a middlemen"}, "answer": "C", "explanation": "An agent is a person who is employed to bring his principal into contractual relations with third parties. He is an intermediary with the power to create legal relationships between a principal and a third party. An arbiter is a person who settles a dispute or has ultimate authority in a matter. An auctioneer is a person who conducts auctions by accepting bids and declaring goods sold. A middleman is a person who buys goods from producers and sells them to retailers or consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>44", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "The additional commission paid to agents for guaranteeing payment is", "images": [], "options": {"A": "brokerage", "B": "del credere", "C": "drawback", "D": "demurrage"}, "answer": "B", "explanation": "Del credere is a Latin term that translates as 'of trust'. It is a type of commission that is paid to an agent for providing a guarantee that the principal will receive payment from the third party. If the third party fails to pay, the agent is liable. Brokerage is a fee paid to a broker for executing a transaction. Drawback is a refund on taxes or duties paid on goods that are later exported. Demurrage is a charge payable to the owner of a chartered ship on failure to load or discharge the ship within the time agreed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>45", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The transfer of ownership of a business from government to the public is", "images": [], "options": {"A": "communication", "B": "deregulation", "C": "privatization", "D": "merger"}, "answer": "C", "explanation": "Privatization is the transfer of ownership, property or business from the government to the private sector. The government ceases to be the owner of the entity or business. Communication is the exchange of information or news. Deregulation is the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry. Merger is a combination of two things, especially companies, into one.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>46", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "One of the disadvantages of privatization is that it", "images": [], "options": {"A": "promotes inefficiency of staff", "B": "brings about economic decline", "C": "reduces government revenue", "D": "causes increase in the prices of products"}, "answer": "C", "explanation": "Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The government loses control of the entity, which often results in a reduction of its revenue. This is because the profits that the entity generates go to private individuals or groups instead of the government treasury.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2020>47", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The management function which involves measuring outcomes and taking corrective action to reduce error is", "images": [], "options": {"A": "staffing", "B": "organizing", "C": "directing", "D": "controlling"}, "answer": "D", "explanation": "Controlling is the management function that involves measuring actual performance, comparing it against standards, and taking corrective action if necessary. It's the process of monitoring progress towards goal achievement and taking corrective action when progress isn't being made. This includes setting performance standards, measuring actual performance, comparing actual performance with established standards, and taking corrective action if needed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>48", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "In delegation of authority, the subordinate officer is", "images": [], "options": {"A": "accountable to his immediate superior", "B": "responsible for his superiors actions", "C": "only answerable to top management", "D": "expected to replace his superior"}, "answer": "A", "explanation": "In delegation of authority, the subordinate officer is accountable to his immediate superior. Delegation of authority is a process in which the authority and powers are divided and shared amongst the subordinates. When the work of a manager gets beyond his capacity, there should be some system of sharing the work. That is why delegation of authority becomes an important tool in organization function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2020>49", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "A medium for intra-departmental communication is all except", "images": [], "options": {"A": "intercom", "B": "notice board", "C": "radiophone", "D": "circular"}, "answer": "C", "explanation": "Intra-departmental communication refers to communication within a specific department in an organization. Intercom, notice board, and circulars are all common mediums for this type of communication. However, a radiophone is typically used for long-distance communication or in fields where immediate communication is necessary, such as in the military or emergency services. It is not a common medium for intra-departmental communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2020>50", "subject": "Commerce", "year": "2020", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not an objective of ECOWAS?", "images": [], "options": {"A": "promotion of a common language", "B": "improvement of infrastructural facilities", "C": "encouragement of free movement of people", "D": "encouragement of trade among member countries"}, "answer": "A", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Its mission is to promote economic integration in all fields of economic activity, particularly industry, transport, telecommunications, energy, agriculture, natural resources, commerce, monetary and financial issues, social and cultural matters. However, the promotion of a common language is not one of its objectives. The other options, such as improvement of infrastructural facilities, encouragement of free movement of people, and encouragement of trade among member countries, are all objectives of ECOWAS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>1", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "Commerce started as a result of", "images": [], "options": {"A": "competition", "B": "distribution", "C": "privatization", "D": "specialization"}, "answer": "D", "explanation": "Commerce started as a result of specialization. Specialization refers to the concept where individuals, businesses, or countries focus on producing a limited scope of products or services to gain efficiencies. This leads to the need for trade or commerce, as no one individual or region can produce everything they need.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>2", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The process of changing raw materials into finished goods is", "images": [], "options": {"A": "construction", "B": "extraction", "C": "manufacturing", "D": "marketing"}, "answer": "C", "explanation": "The process of changing raw materials into finished goods is manufacturing. Manufacturing involves the conversion of raw materials into finished goods using tools, human labor, and chemical or biological processing or formulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>3", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "An example of a primary product is", "images": [], "options": {"A": "textile", "B": "palm oil", "C": "flour", "D": "cocoa"}, "answer": "B", "explanation": "An example of a primary product is palm oil. Primary products are goods that are available from cultivating raw materials without a manufacturing process. Palm oil is a primary product because it is obtained directly from the palm fruit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>4", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "All activities geared towards the distribution and exchange of goods and services is", "images": [], "options": {"A": "commerce", "B": "market survey", "C": "personal selling", "D": "trade"}, "answer": "A", "explanation": "Commerce involves all activities geared towards the distribution and exchange of goods and services. It includes trade and aids to trade. Trade involves buying and selling of goods and services while aids to trade include banking, insurance, transportation, warehousing, and advertising.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>5", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "The word \"limited\" written after the name of a company means that", "images": [], "options": {"A": "it has a democratic system of management", "B": "members are liable to the extent of their shareholdings only", "C": "the company is a going concern", "D": "profit is determined by management"}, "answer": "B", "explanation": "The word 'limited' written after the name of a company means that the liability of the shareholders of the company is limited to the extent of the face value of shares held by them. This means that if the company goes into liquidation, the maximum amount that they will be required to contribute will be the unpaid amount on their shares.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>6", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which type of occupation is a carpenter engaged in?", "images": [], "options": {"A": "Commercial", "B": "Construction", "C": "Extraction", "D": "Manufacturing"}, "answer": "B", "explanation": "A carpenter is primarily involved in the construction industry. Carpenters work on building and assembling structures made of wood, such as frames, cabinets, and furniture, as well as repairing and installing wooden components in buildings. Their work is crucial in the construction and renovation of buildings and other structures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>7", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward for land as a factor of production is", "images": [], "options": {"A": "wage", "B": "rent", "C": "profit", "D": "interest"}, "answer": "B", "explanation": "In economics, the four factors of production are land, labor, capital, and entrepreneurship. Each factor is rewarded for its contribution to the production process: land is rewarded with rent, labor with wages, capital with interest, and entrepreneurship with profit. Therefore, the reward for land as a factor of production is rent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>8", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Which of the following businesses can raise capital through the stock exchange?", "images": [], "options": {"A": "Sole proprietorship", "B": "Private company", "C": "Public company", "D": "Cooperative society"}, "answer": "C", "explanation": "A public company is a company that has issued securities through an initial public offering (IPO) and is traded on at least one stock exchange or in the over the counter market. Public companies have a much larger ability to raise capital as they can issue more shares to the public. Therefore, among the given options, only a public company can raise capital through the stock exchange.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>9", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "A group of people representing a cross-section of business interests in an area is", "images": [], "options": {"A": "chamber of commerce", "B": "consumer's association", "C": "employer's association", "D": "manufacturers' association"}, "answer": "A", "explanation": "A Chamber of Commerce is a form of business network, for example, a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community. Therefore, a group of people representing a cross-section of business interests in an area is a chamber of commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>10", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "One of the disadvantages of selling on credit is", "images": [], "options": {"A": "reduction in turnover", "B": "reduction in profit", "C": "increase in liquidity", "D": "increase in bad debts"}, "answer": "D", "explanation": "Selling on credit can lead to an increase in bad debts. This is because when a business sells on credit, it is essentially lending money to its customers. If these customers fail to pay back this money, the business incurs bad debts. None of the other options accurately represent a disadvantage of selling on credit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>11", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A number of shops under one roof is a", "images": [], "options": {"A": "chain store", "B": "department store", "C": "discount store", "D": "unit store"}, "answer": "B", "explanation": "A number of shops under one roof is a department store. A department store is a retail establishment offering a wide variety of merchandise, organized into different departments or sections. Each department specializes in a type of product, such as clothing, home appliances, electronics, etc. The other options do not accurately describe a number of shops under one roof.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>12", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An organization of producers of similar products, which controls output with the intention to fix price is a", "images": [], "options": {"A": "trust", "B": "syndicate", "C": "consortium", "D": "cartel"}, "answer": "D", "explanation": "An organization of producers of similar products, which controls output with the intention to fix price is a cartel. A cartel is a group of independent market participants who collude with each other in order to improve their profits and dominate the market. They do this by controlling the production and price of a product or service. The other options do not accurately describe this type of organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>13", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE ASSOCIATION : OBJECTIVES , MERIT & DEMERIT", "question": "One of the functions of a trade association is to", "images": [], "options": {"A": "provide infrastructure for members", "B": "provide employment for members", "C": "promote members' welfare", "D": "pay member's salaries"}, "answer": "C", "explanation": "Trade associations are organizations founded and funded by businesses that operate in a specific industry. Their main function is to promote the interests of their members. They do this by advocating for policies that will benefit the industry, providing educational opportunities for members, and promoting the welfare of members. They do not provide infrastructure or employment for members, nor do they pay members' salaries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>14", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "The practice of selling goods to a foreign country at lower prices than obtainable in the exporting country is", "images": [], "options": {"A": "speculattion", "B": "skimming", "C": "hedging", "D": "dumping"}, "answer": "D", "explanation": "The practice of selling goods to a foreign country at lower prices than obtainable in the exporting country is known as dumping. This is often done to increase market share in the foreign country or to offload excess production. It is not speculation, skimming, or hedging. Speculation involves making high-risk investments with the hope of high returns, skimming is a pricing strategy where a high price is set for a new product, and hedging is a risk management strategy used in limiting or offsetting probability of loss from fluctuations in the prices of commodities, currencies, or securities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>15", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A foreign order which instructs an agent to buy certain goods from a particular supplier is", "images": [], "options": {"A": "closed indent", "B": "open indent", "C": "letter of credit", "D": "letter of enquiry"}, "answer": "A", "explanation": "A closed indent is a foreign order which instructs an agent to buy certain goods from a particular supplier. It is a type of trade document used in international commerce. An open indent, on the other hand, gives the agent discretion in the choice of supplier. A letter of credit is a letter from a bank guaranteeing that a buyer's payment to a seller will be received on time and for the correct amount, while a letter of enquiry is a formal method of requesting information.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>16", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : DISSOLUTION AND LIQUIDATION", "question": "Which of the following is not a condition for dissolution of a partnership?", "images": [], "options": {"A": "Continuous disagreement among partners", "B": "Expiration of a business year", "C": "Mutual consent of the partners", "D": "Termination of the venture"}, "answer": "B", "explanation": "Expiration of a business year is not a condition for dissolution of a partnership. A partnership can continue to operate indefinitely as long as the partners agree to do so. The other options, such as continuous disagreement among partners, mutual consent of the partners, and termination of the venture, can all lead to the dissolution of a partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>17", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "A country's balance of trade of -$20 million shows that its", "images": [], "options": {"A": "import volume is greater than export", "B": "import and export volumes are equal", "C": "export volume is greater than imports", "D": "exports are mainly primary products"}, "answer": "A", "explanation": "A country's balance of trade of -$20 million shows that its import volume is greater than export. The balance of trade is the difference between the value of a country's imports and its exports. When a country's imports exceed its exports, it has a trade deficit, which is represented by a negative balance of trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>18", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "The collection of import duty is a function of the", "images": [], "options": {"A": "ports authority", "B": "marketing boards", "C": "clearing and forwarding agents", "D": "customs and excise authority"}, "answer": "D", "explanation": "The collection of import duty is a function of the customs and excise authority. Import duty is a tax collected on imports and some exports by the customs authorities of a country. It is usually based on the value of the goods that are imported.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>19", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "An error on an invoice may be rectified by issuing", "images": [], "options": {"A": "an advice note", "B": "a consignment note", "C": "a credit note", "D": "a delivery note"}, "answer": "C", "explanation": "An error on an invoice can be rectified by issuing a credit note. A credit note is a document sent by a seller to its buyer, or, in other words, a vendor to the customer, notifying that a credit has been provided to their account. The reasons could be many including error on the invoice, incorrect goods sent, goods in bad condition, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>20", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the information below to answer questions below .       \t#\tOpening stock \t4000\tClosing stock \t12000\tPurchases \t17000\t    What is the average stock?", "images": [], "options": {"A": "#10,500", "B": "#8,500", "C": "#8,000", "D": "#6,000"}, "answer": "C", "explanation": "Average stock = Opening stock + Closing stock / 2   = 4000 + 12,000 / 2   = 16,000 / 2   = 8,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>21", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the information below to answer questions below .       \t#\tOpening stock \t4000\tClosing stock \t12000\tPurchases \t17000\t  - The cost of goods sold is", "images": [], "options": {"A": "#4,000", "B": "#9,000", "C": "#16,000", "D": "#21,000"}, "answer": "B", "explanation": "Cost of goods sold = Opening stock + Purchases - Closing stock   = 4,000 + 17,000 - 12,000   = 21,000 - 12,000   = 9000", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>22", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "The expected response from the recipient of a quotation is to send", "images": [], "options": {"A": "an advice note", "B": "a cheque for payment", "C": "an invoice", "D": "an order"}, "answer": "D", "explanation": "The expected response from the recipient of a quotation is to send an order. A quotation is a document that a seller provides to a buyer to offer goods or services at a stated price, under specified conditions. If the buyer agrees with the conditions and the price, they will send an order to the seller to proceed with the transaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>23", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : THE ROLE OF BUREAU DE CHANGE", "question": "The main function of a bureau-de-exchange is", "images": [], "options": {"A": "buying and selling foreign currency", "B": "buying and selling securities", "C": "providing trade information", "D": "selling goods and services"}, "answer": "A", "explanation": "The main function of a bureau-de-exchange is buying and selling foreign currency. A bureau de change is a business where people can exchange one currency for another. They buy a currency from individuals or businesses at one rate (the bid price), and sell it to others at a higher rate (the ask price). The difference between the bid price and the ask price is how the bureau de change makes a profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>24", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE", "question": "The right of a seller to make correction on invoices is expressed by the term", "images": [], "options": {"A": "errors and omissions excepted", "B": "errors and omissions excluded", "C": "errors and omissions exempted", "D": "errors and omissions expected"}, "answer": "A", "explanation": "The right of a seller to make correction on invoices is expressed by the term 'errors and omissions excepted'. This term, often abbreviated as 'E&OE', is used in an attempt to reduce legal liability for potentially incorrect or incomplete information supplied in a contractually related document such as a quotation or specification.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>25", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Speed is an important factor to be considered for choice of means of transport where goods are", "images": [], "options": {"A": "perishable", "B": "inferior", "C": "fragile", "D": "bulky"}, "answer": "A", "explanation": "Perishable goods are items that can spoil or decay quickly, such as fruits, vegetables, meat, dairy, and seafood. These goods need to be transported quickly to prevent them from spoiling. Therefore, speed is an important factor to be considered for the choice of means of transport where goods are perishable.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>26", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The practice by which insurance companies share risks with other insurance companies is", "images": [], "options": {"A": "contribution", "B": "re-insurance", "C": "under insurance", "D": "underwriting"}, "answer": "B", "explanation": "Re-insurance is a practice where insurance companies share risks with other insurance companies to reduce their potential losses. This is done by purchasing insurance policies from other insurance companies to limit the total loss the original insurer would experience in case of disaster. The other options do not accurately describe this practice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>27", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "One of the functions of the ports authority is", "images": [], "options": {"A": "checking the activities of smugglers", "B": "collecting import duties", "C": "enforcing law and order in harbors", "D": "providing warehousing services"}, "answer": "D", "explanation": "Ports authorities are responsible for providing various services, including warehousing services. Warehousing services involve the storage of goods and commodities in a safe and secure environment before they are transported to their final destination. The other options are not primary functions of the ports authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>28", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "Which of the following means of payment requires acceptance by the debtor to make it valuable?", "images": [], "options": {"A": "Bearer's cheque", "B": "Bill of exchange", "C": "Postal order", "D": "Promissory note"}, "answer": "B", "explanation": "A bill of exchange requires acceptance by the debtor to make it valuable. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>29", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The purpose for which the Central Bank sells securities is to", "images": [], "options": {"A": "reduce the interest rate", "B": "reduce cash in the economy", "C": "increase cash in the economy", "D": "increase the interest rate"}, "answer": "B", "explanation": "The Central Bank sells securities to reduce cash in the economy. This is a monetary policy tool known as open market operations. When the Central Bank sells securities, it is taking money out of the economy, thereby reducing the amount of cash available in the economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>30", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "The amount a current holder is allowed to withdraw in excess of the balance in his account is", "images": [], "options": {"A": "standing order", "B": "overdraft", "C": "interest", "D": "credit transfer"}, "answer": "B", "explanation": "The amount a current holder is allowed to withdraw in excess of the balance in his account is an overdraft. An overdraft is a credit facility that allows an account holder to withdraw more than the current balance in their account, up to a certain limit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>31", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Which of the following business risks would an insurance firm not cover for an entrepreneur?", "images": [], "options": {"A": "Theft", "B": "Fire", "C": "Loss of goods in transit", "D": "Change in consumers' taste"}, "answer": "D", "explanation": "Insurance firms cover risks that are accidental and unforeseeable. They do not cover risks that are a result of changes in market conditions or consumer behavior. A change in consumers' taste is a business risk that is influenced by market trends and consumer behavior, and therefore, it is not something an insurance firm would cover.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>32", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "One of the qualities of tradable goods is", "images": [], "options": {"A": "divisibility", "B": "heterogeneity", "C": "homogeneity", "D": "perishability"}, "answer": "A", "explanation": "Divisibility is one of the qualities of tradable goods. It refers to the ability of a good to be divided into smaller units without losing its value. For example, a bar of gold can be divided into smaller pieces and each piece will still retain its value. This is an important quality for tradable goods as it allows for flexibility in trading.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>33", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following instruments of payment could be used in international trade?", "images": [], "options": {"A": "Promissory note", "B": "Postal order", "C": "I.O.U.", "D": "Bill of exchange"}, "answer": "D", "explanation": "A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party on demand or at a predetermined date. It is commonly used in international trade because it provides a secure method of payment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>34", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE", "question": "Bonded warehouses are supervised by", "images": [], "options": {"A": "clearing and forwarding agents", "B": "customs and excise authorities", "C": "immigration officers", "D": "ports authorities"}, "answer": "B", "explanation": "Bonded warehouses are supervised by customs and excise authorities. A bonded warehouse is a secured area where imported goods are stored until the import duties are paid. They are under the jurisdiction of the customs authorities, who ensure that the duties are paid before the goods are released.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>35", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "An advertising campaign by a chicken seller designed to sell his products at the expense of a beef seller is", "images": [], "options": {"A": "competitive", "B": "direct", "C": "informative", "D": "persuasive"}, "answer": "A", "explanation": "An advertising campaign by a chicken seller designed to sell his products at the expense of a beef seller is competitive. Competitive advertising is a method of attracting customers by communicating the unique attributes of a product and how it is superior to competitor products.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>36", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The main idea of the marketing concepts is that all the firm's plans and operations should be", "images": [], "options": {"A": "product oriented", "B": "price oriented", "C": "consumer oriented", "D": "company oriented"}, "answer": "C", "explanation": "The main idea of the marketing concept is that all the firm's plans and operations should be consumer oriented. This means that the company focuses on meeting the needs and wants of its customers in order to achieve its business goals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>37", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "A person who is employed for the purpose of bringing his principal into contractual relationship with the third parties is", "images": [], "options": {"A": "a merchant", "B": "a consignee", "C": "a consignor", "D": "an agent"}, "answer": "D", "explanation": "An agent is a person who is employed to bring his principal into contractual relationship with third parties. This is because an agent acts on behalf of the principal in business transactions with third parties. A merchant is a person who buys and sells goods. A consignee is a person or company to whom goods are shipped. A consignor is a person or company who ships goods to another.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>38", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "The transfer of a government company to the public is", "images": [], "options": {"A": "commercialization", "B": "localization", "C": "deregulation", "D": "privatization"}, "answer": "D", "explanation": "The transfer of a government company to the public is known as privatization. Privatization is the process of transferring ownership of a business, enterprise, agency, public service, or public property from the public sector (a government) to the private sector, either to a business that operates for a profit or to a nonprofit organization. Commercialization is the process of introducing a new product or production method into commerce. Localization is the adaptation of a product or service to meet the needs of a particular language, culture or desired population's 'look-and-feel'. Deregulation is the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>39", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "One of the roles performed by middle managers is", "images": [], "options": {"A": "formulation of objectives and strategies", "B": "implementation of organizational plans and objectives", "C": "review and appraisal of operational results", "D": "review of master plans, programmes and budgets"}, "answer": "B", "explanation": "Middle managers are responsible for implementing the organizational plans and objectives that are set by top management. They translate the strategic goals set by upper management into actionable plans for their teams. Formulation of objectives and strategies is typically the role of top management. Review and appraisal of operational results and review of master plans, programmes and budgets can be part of the roles of both middle and top management, but they are not the primary role of middle managers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>40", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "Which of the following is responsible for protecting consumers against poor quality goods?", "images": [], "options": {"A": "Industrial tribunals", "B": "Manufacturers association", "C": "Standard organizations", "D": "Trade associations"}, "answer": "C", "explanation": "Standard organizations are responsible for protecting consumers against poor quality goods. They set and enforce quality standards for products and services to ensure they are safe, reliable and of good quality. They also provide certification to products and services that meet their standards.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>41", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The saying that the 'consumer is always right' describes the doctrine of", "images": [], "options": {"A": "caveat emptor", "B": "consumer sovereignty", "C": "consumer protection", "D": "proximate cause"}, "answer": "B", "explanation": "The saying that the 'consumer is always right' describes the doctrine of consumer sovereignty. This doctrine suggests that consumers dictate what goods and services are produced in the market based on their demands. Therefore, businesses must cater to these demands to be successful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>42", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "A disadvantage of privatization is that", "images": [], "options": {"A": "there is reduction in the quality of goods", "B": "there is inefficiency in the supply of goods", "C": "the existence of monopoly is high", "D": "the profit motive outweighs public interest"}, "answer": "D", "explanation": "A disadvantage of privatization is that the profit motive outweighs public interest. This is because private companies are primarily driven by profit. As a result, they may neglect the public interest in favor of actions that increase their profits. For example, they may increase prices, reduce quality, or cut corners in ways that harm the public.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>43", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "The act of placing goods in glass shields in front of shops to attract passers by is", "images": [], "options": {"A": "window display", "B": "trade fair", "C": "personal selling", "D": "sales promotion"}, "answer": "A", "explanation": "Window display is a marketing strategy where goods are placed in glass shields in front of shops to attract passers-by. It is a form of visual merchandising that aims to attract, engage, and motivate the customer towards making a purchase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2021>44", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The practice of making a state firm more profit-oriented is", "images": [], "options": {"A": "privatization", "B": "nationalization", "C": "deregulation", "D": "commercialization"}, "answer": "D", "explanation": "Commercialization is the process of managing or running something principally for financial gain. It is the practice of making a state firm more profit-oriented. It involves the transformation of a public sector organization into a business enterprise in the private sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>45", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Trade fairs and exhibitions are media of", "images": [], "options": {"A": "sales promotion", "B": "market segmentation", "C": "market research", "D": "customer service"}, "answer": "A", "explanation": "Trade fairs and exhibitions are media of sales promotion. They are used by companies to introduce new products, attract potential customers, and to get feedback from the market. They are a promotional strategy where goods and services are displayed for the attendees to see and buy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>46", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE", "question": "The income generated from tourism forms part of the country's", "images": [], "options": {"A": "visible imports", "B": "visible exports", "C": "invisible imports", "D": "invisible exports"}, "answer": "D", "explanation": "The income generated from tourism is considered as part of the country's invisible exports. Invisible exports are services that are sold to foreign countries, which includes tourism, banking, insurance, etc. These are called 'invisible' because they do not result in the shipment of physical goods unlike visible exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>47", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "An objective of the European Union is to", "images": [], "options": {"A": "eliminate drug addiction in member countries", "B": "eliminate tariffs and quotas among member countries", "C": "encourage migrant workers from developing countries", "D": "fight against child abuse in developing countries"}, "answer": "B", "explanation": "One of the main objectives of the European Union is to eliminate tariffs and quotas among member countries. This is to promote free trade and economic integration among the member countries. Tariffs and quotas are trade barriers that restrict the free flow of goods and services.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2021>48", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT", "question": "An inventor of a new machine for canning tomatoes can protect his product by", "images": [], "options": {"A": "obtaining a trade mark", "B": "obtaining a patent", "C": "labeling the product", "D": "choosing a brand name"}, "answer": "B", "explanation": "An inventor of a new machine for canning tomatoes can protect his product by obtaining a patent. A patent is a legal document that gives the inventor the exclusive right to produce, sell, and use the invention for a certain period of time. This prevents others from copying, manufacturing, selling, or importing the invention without the inventor's permission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>49", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The concept of determining the objectives of a business and stating how they can be actualized is", "images": [], "options": {"A": "directing", "B": "motivating", "C": "organizing", "D": "planning"}, "answer": "D", "explanation": "The concept of determining the objectives of a business and stating how they can be actualized is planning. Planning involves setting goals and determining the best way to achieve them. It involves selecting a course of action from a set of alternatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2021>50", "subject": "Commerce", "year": "2021", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the aims of ECOWAS is to", "images": [], "options": {"A": "provide a market for stocks and shares", "B": "have a common political system", "C": "foster exchange of goods and services", "D": "create a common transport policy."}, "answer": "C", "explanation": "One of the aims of ECOWAS (Economic Community of West African States) is to foster exchange of goods and services among member states. This is done to promote economic integration and development in the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>1", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "An article used as a means of exchange in the early days of trade in West Africa was", "images": [], "options": {"A": "cedis", "B": "cowrie", "C": "dalasi", "D": "naira"}, "answer": "B", "explanation": "Cowries were used as a form of currency in West Africa before the introduction of coins and notes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2022>2", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "The provision of services is classified under", "images": [], "options": {"A": "batch production", "B": "flow production", "C": "secondary production", "D": "tertiary production"}, "answer": "D", "explanation": "Tertiary production involves the provision of services in the economy. These services include transportation, banking, insurance, and tourism among others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>3", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "The growth of commerce is not enhanced by", "images": [], "options": {"A": "development of modern forms of production", "B": "government participation in business", "C": "high population growth", "D": "low per capita income"}, "answer": "D", "explanation": "Low per capita income means that the average income per person is low. This implies that people have less disposable income to spend on goods and services, which can hinder the growth of commerce.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>4", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "One of the products of the construction industry is a", "images": [], "options": {"A": "piece of cloth", "B": "bag of cement", "C": "television", "D": "chair"}, "answer": "B", "explanation": "The construction industry is involved in the production of infrastructure and buildings, which includes the use of materials like cement. A bag of cement is therefore a product of the construction industry. A piece of cloth, television, and chair are not products of the construction industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>5", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The service of a retailer is part of production because it", "images": [], "options": {"A": "creates a link between consumers and producers", "B": "enables finished goods to reach consumers", "C": "increases consumers standard of living", "D": "is a commercial occupation"}, "answer": "A", "explanation": "Retailers create a link between consumers and producers by selling goods produced by manufacturers to consumers. They do not produce goods themselves, but their service is part of the production process because they facilitate the distribution of goods from producers to consumers. The other options, while they may be effects or aspects of retail, do not directly explain why the service of a retailer is part of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>6", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The resources put together to create goods and services are", "images": [], "options": {"A": "working capital", "B": "producer goods", "C": "factors of production", "D": "consumer goods"}, "answer": "C", "explanation": "The resources put together to create goods and services are known as factors of production. These include land, labor, capital, and entrepreneurship. Working capital is a type of capital used in the day-to-day operations of a business, producer goods are goods used in the production of other goods, and consumer goods are the end products bought by consumers, none of these options fully encompass all the resources used to create goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>7", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Which of the following organizations provide essential goods and services at low cost to citizens?", "images": [], "options": {"A": "Thrift societies", "B": "Public enterprises", "C": "Private companies", "D": "Cooperative societies"}, "answer": "B", "explanation": "Public enterprises are organizations that are owned and operated by the government. They provide essential goods and services at low cost to citizens. This is because they are not primarily driven by profit motives but are established to meet the social and economic objectives of the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>8", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A group of buyers who pool their resources to buy goods in large quantities and sell to its members is a", "images": [], "options": {"A": "wholesaler cooperative society", "B": "thrift and credit society", "C": "consumer cooperative society", "D": "chamber of commerce"}, "answer": "C", "explanation": "A consumer cooperative society is a group of buyers who pool their resources to buy goods in large quantities and sell to its members. The main aim of such societies is to obtain goods at a lower price and pass on the benefits to its members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>9", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Average stock is derived by adding", "images": [], "options": {"A": "closing stock to purchase divided by 2", "B": "closing stock to opening stock", "C": "opening stock to closing stock divided by 2", "D": "opening stock to purchases"}, "answer": "C", "explanation": "Average stock is derived by adding the opening stock to the closing stock and then dividing by 2. This gives the average amount of stock held over a certain period.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>10", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail business that sells goods by post, using catalogue is a", "images": [], "options": {"A": "chain store", "B": "department store", "C": "mail order firm", "D": "shopping mail"}, "answer": "C", "explanation": "A mail order firm is a retail business that sells goods by post, using a catalogue. Customers choose products from a catalogue and place orders by mail or phone, and the goods are then delivered by post. This is different from a chain store or department store, which are physical retail locations, and a shopping mall, which is a large enclosed building that contains many individual shops.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>11", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "Which of the following documents would a shareholder inspect to know his voting rights?", "images": [], "options": {"A": "Articles of Association", "B": "Certificate of Incorporation", "C": "Certificate of Trading", "D": "Memorandum of Association"}, "answer": "A", "explanation": "The Articles of Association is a document that specifies the regulations for a company's operations and defines the company's purpose. It also includes the process for appointing directors and the handling of financial records. Importantly, it outlines the shareholders' rights, including voting rights. The Certificate of Incorporation is a legal document relating to the formation of a company or corporation. The Certificate of Trading is not a standard document in company formation or operation. The Memorandum of Association is a legal document that defines the relationship between the company and the outside. It does not typically contain information about shareholder voting rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>12", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "An internal source of finance to an enterpreneur is", "images": [], "options": {"A": "trade credit", "B": "retained earning", "C": "overdraft", "D": "debenture"}, "answer": "B", "explanation": "Retained earnings are an internal source of finance for an entrepreneur. They represent the net income of a company that is retained by the company after it has paid out dividends to its shareholders. The money is reinvested in the business or used to pay off debt. Trade credit, overdrafts, and debentures are all external sources of finance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2022>13", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "Use the information below to answer questions below   \t#\tSales\t50,000.00\tDebtors\t10,000.00\tCash in hand\t5,000.00\tOpening stock\t30,000.00\tCreditors\t8,000.00\tPurchases\t16,000.00\tOverdraft\t12,000.00\tClosing stock\t10,000.00\t    Calculate the working capital", "images": [], "options": {"A": "#35,000.00", "B": "#20,000.00", "C": "#5,000.00", "D": "#14,000.00"}, "answer": "C", "explanation": "Working capital is calculated as Current Assets - Current Liabilities. From the given data, Current Assets = Debtors + Cash in hand + Closing stock = 10,000 + 5,000 + 10,000 = 25,000. Current Liabilities = Creditors + Overdraft = 8,000 + 12,000 = 20,000. Therefore, Working Capital = 25,000 - 20,000 = 5,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>14", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer questions below   \t#\tSales\t50,000.00\tDebtors\t10,000.00\tCash in hand\t5,000.00\tOpening stock\t30,000.00\tCreditors\t8,000.00\tPurchases\t16,000.00\tOverdraft\t12,000.00\tClosing stock\t10,000.00\t   Calculate the gross profit", "images": [], "options": {"A": "#35,000.00", "B": "#20,000.00", "C": "#15,000.00", "D": "#14,000.00"}, "answer": "D", "explanation": "Gross profit is calculated as Sales - Cost of Goods Sold (COGS). COGS is calculated as Opening Stock + Purchases - Closing Stock. From the given data, COGS = 30,000 + 16,000 - 10,000 = 36,000. Therefore, Gross Profit = 50,000 - 36,000 = 14,000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>15", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partner who contributes only his name to the formation of a partnership is", "images": [], "options": {"A": "a nominal partner", "B": "a limited partner", "C": "a general partner", "D": "an active partner"}, "answer": "A", "explanation": "A partner who contributes only his name to the formation of a partnership is a nominal partner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>16", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "Which of the following groups would advocate for the supply of constant electricity to households?", "images": [], "options": {"A": "Consumer's association", "B": "Credit union", "C": "Employer's association", "D": "Labour union"}, "answer": "A", "explanation": "A Consumer's association is an organization that advocates for the rights and interests of consumers, including the supply of constant electricity to households. They work to ensure that consumers receive fair treatment and that their needs, such as reliable utilities, are met.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>17", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A retail store that sells a single product from a particular manufacturer is a", "images": [], "options": {"A": "tied shop", "B": "shopping mail", "C": "hypermarket", "D": "chain store"}, "answer": "A", "explanation": "A tied shop is a type of retail store that sells products from a single manufacturer. This is often due to an exclusive agreement between the retailer and the manufacturer. The other options, such as shopping malls, hypermarkets, and chain stores, typically carry a wide range of products from various manufacturers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>18", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "A country's visible balance of payment is made up of", "images": [], "options": {"A": "interest on loans to foreign countries", "B": "profit from investment abroad", "C": "earnings from goods exported", "D": "dividend earned from companies"}, "answer": "C", "explanation": "A country's visible balance of payment is made up of the value of its exports and imports of physical goods. Earnings from goods exported is a part of this balance. The other options, such as interest on loans to foreign countries, profit from investment abroad, and dividends earned from companies, are part of the invisible balance, which includes services and other non-physical items.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>19", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "The quality of money which makes it possible to buy goods in small quantities is", "images": [], "options": {"A": "portability", "B": "homogeneity", "C": "divisibility", "D": "durability"}, "answer": "C", "explanation": "The quality of money that allows it to be broken down into smaller units for the purchase of goods in small quantities is known as divisibility. This means that money can be divided into smaller units without losing its value. For example, a dollar can be divided into cents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2022>20", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "One of the functions of commerical banks that cannot be performed by central banks is", "images": [], "options": {"A": "collection of old notes", "B": "collection of deposits from the public", "C": "issuance of treasury bills", "D": "printing of bank notes"}, "answer": "B", "explanation": "Commercial banks have the function of collecting deposits from the public, which is something central banks do not do. Central banks are primarily responsible for monetary policy, issuing currency, and overseeing the operation of the banking system, but they do not deal directly with the public to collect deposits.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>21", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "A document that instructs an agent to buy goods from a named firm is", "images": [], "options": {"A": "proforma invoice", "B": "open indent", "C": "consular invoice", "D": "closed indent"}, "answer": "D", "explanation": "A closed indent is a document that instructs an agent to buy goods from a specific firm. It is a type of purchase order that provides detailed specifications about the goods to be purchased, including the name of the firm from which the goods are to be purchased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>22", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "The incentive given to a buyer to encourage prompt payment is", "images": [], "options": {"A": "cash discount", "B": "seasonal discount", "C": "quantity discount", "D": "trade discount"}, "answer": "A", "explanation": "A cash discount is a deduction allowed by the seller of goods or by the provider of services in order to motivate the customer to pay within a specified time. The seller or provider often refers to this discount as a sales discount, and the buyer refers to the same discount as a purchase discount.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>23", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The principle which prevents an insured from receiving a claim that is more than the value of the loss, if the property is insured by more than one company is", "images": [], "options": {"A": "indemnity", "B": "contribution", "C": "proximate cause", "D": "uberrimae fidei"}, "answer": "B", "explanation": "Contribution is one of the principle of insurance, this principle prevents the insured from making profit from the insurance because it is a contract of good faith.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>24", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "Dealers in stock exchange such as bulls, bears and stags are categorized as", "images": [], "options": {"A": "actuaries", "B": "promoters", "C": "speculators", "D": "underwriters"}, "answer": "C", "explanation": "In the context of stock exchange, bulls, bears and stags are types of speculators. A speculator is a person who trades derivatives, commodities, bonds, equities or currencies with a higher than average risk in return for a higher-than-average profit potential. Bulls are speculators who believe the prices will rise, bears believe prices will fall, and stags are speculators who buy securities with the expectation that the securities will soon be undergoing an initial public offering and hence, can be sold at a profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>25", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "Which of the following is not a characteristic of a commercial bank?", "images": [], "options": {"A": "Established as limited liability company", "B": "Established by individuals or organizations", "C": "Established to issue bank notes", "D": "Established with the view of making profit"}, "answer": "C", "explanation": "Commercial banks are not established to issue bank notes. This is the function of the central bank. Commercial banks are financial institutions that provide various services like accepting deposits, providing loans, and offering basic investment products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>26", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Central banks sell treasury bills to the public to", "images": [], "options": {"A": "increase cash in the banking system", "B": "raise revenue for commerical banks", "C": "raise revenue for private investors", "D": "reduce cash in circulation"}, "answer": "D", "explanation": "Central banks sell treasury bills to the public to reduce cash in circulation. This is a monetary policy tool used to control inflation. When the central bank sells treasury bills, it absorbs the excess liquidity in the economy, thereby reducing the money supply and controlling inflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>27", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A document used to ensure correct payment of duty at the importing country is", "images": [], "options": {"A": "documentary credit", "B": "consular invoice", "C": "certiifcate of origin", "D": "bill of lading"}, "answer": "B", "explanation": "A consular invoice is a document used to ensure correct payment of duty at the importing country. It is a document that represents a contract between the importer and exporter. The consular invoice is certified by the consular official of the importing country and used by the customs officials to verify the quantity, nature and value of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>28", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque is specially crossed if", "images": [], "options": {"A": "the name of the account holder is written between two parallel lines drawn across it", "B": "it could be paid over the counter", "C": "the name of the bank is written between two parallel lines drawn across it", "D": "only two parallel lines are drawn across it"}, "answer": "C", "explanation": "A cheque is specially crossed when the name of the bank is written between two parallel lines drawn across it. This means that the cheque can only be paid into an account at that particular bank. This is a measure to ensure security and prevent fraudulent activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>29", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "One of the functions of a trade association is to", "images": [], "options": {"A": "pay members salaries", "B": "promote members' welfare", "C": "provide loans to members", "D": "provide employment for members"}, "answer": "B", "explanation": "Trade associations are organizations founded and funded by businesses that operate in a specific industry. Their function is to promote and protect the interests of their members. One of the ways they do this is by promoting members' welfare, such as advocating for better working conditions, providing training and development opportunities, and lobbying for favorable legislation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2022>30", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS", "question": "When a share with a nominal value of #50 is quoted at #70, it is being sold", "images": [], "options": {"A": "cum div", "B": "ex-div", "C": "at a discount", "D": "at a premium"}, "answer": "D", "explanation": "When a share with a nominal value of #50 is quoted at #70, it means it is being sold at a premium. Selling 'at a premium' means that the share is being sold for more than its nominal (or face) value. This usually happens when the demand for the share is high.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>31", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Sea vessels that do not operate on regular times and routes are", "images": [], "options": {"A": "tramps", "B": "ocean liners", "C": "containers ships", "D": "ferries"}, "answer": "A", "explanation": "Sea vessels that do not operate on regular times and routes are referred to as 'tramps'. Unlike ocean liners, tramp ships don't have fixed schedules or ports of call. They go where the cargo is and where the cargo needs to go. The term 'tramp' comes from the British term 'tramp', which refers to a person who is always on the move and doesn't have a fixed home or job.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>32", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Payment made to a carrier for transportation of goods is", "images": [], "options": {"A": "freight", "B": "fee", "C": "fare", "D": "duty"}, "answer": "A", "explanation": "The payment made to a carrier for transportation of goods is known as 'freight'. Freight refers to the charge paid for the carriage or transportation of goods by air, sea, or land. The term 'freight' is used when the transportation is done in bulk and over a long distance. The other options, 'fee', 'fare', and 'duty', do not specifically refer to the payment for transportation of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>33", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "An advantage of rail transport is that it", "images": [], "options": {"A": "is less expensive to maintain", "B": "is not prone to delays", "C": "carries bulky and heavy goods", "D": "enhances door-to-door delivery"}, "answer": "C", "explanation": "An advantage of rail transport is that it 'carries bulky and heavy goods'. Rail transport is particularly suited to the movement of large and heavy goods over long distances. It is more economical and energy-efficient compared to other modes of transport for such goods. The other options, 'is less expensive to maintain', 'is not prone to delays', and 'enhances door-to-door delivery', are not specific advantages of rail transport.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>34", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The commission on a postal order is", "images": [], "options": {"A": "tariff", "B": "poundage", "C": "brokerage", "D": "fee"}, "answer": "B", "explanation": "The commission on a postal order is referred to as poundage. Poundage is a charge or fee that is levied on the transaction of postal orders. It is a type of service charge that is collected by the postal service for the service of transferring money through postal orders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>35", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "Consumers could be encouraged to purchase a company's product through", "images": [], "options": {"A": "research", "B": "planning", "C": "distribution", "D": "advertisement"}, "answer": "D", "explanation": "Consumers could be encouraged to purchase a company's product through advertisement. Advertisement is a marketing strategy that involves creating awareness about a product or service to potential customers. It is a way of communicating the benefits and value of a product or service to influence the purchasing decision of consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>36", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT", "question": "The marketing concept emphasizes", "images": [], "options": {"A": "sales of goods directly to customers", "B": "use of promotional tools to stimulate sale", "C": "mass production of goods", "D": "consumer's satisfaction at a profit"}, "answer": "D", "explanation": "The marketing concept emphasizes consumer's satisfaction at a profit. The marketing concept is a business philosophy that holds that the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its selected target customers. It puts the customer's needs first and aligns all functions of the business to meet those needs while still making a profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>37", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "An undertaking to repair a customer's vehicle for a certain period after it has been sold is", "images": [], "options": {"A": "after-sales service", "B": "marketing mix", "C": "market segmentation", "D": "sales promotion"}, "answer": "A", "explanation": "After-sales service refers to any service provided to a customer after a product has been sold. This can include services such as repair and maintenance, which are done to ensure customer satisfaction and loyalty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>38", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Which of the following is not a right of a consumer?", "images": [], "options": {"A": "Right to a fair hearing", "B": "Right to buy on credit", "C": "Right to obtain replacement", "D": "Right to safe product"}, "answer": "B", "explanation": "The right to buy on credit is not a universal consumer right. Consumer rights typically include the right to safety, the right to be informed, the right to choose, and the right to be heard. The right to buy on credit is a privilege that may be offered by some businesses, but it is not a fundamental right of all consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>39", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Advertisement which is geared towards a particular audience is", "images": [], "options": {"A": "direct advertising", "B": "indirect advertising", "C": "mass advertising", "D": "persuasive advertising"}, "answer": "A", "explanation": "Direct advertising is a type of advertising that is directed towards a specific audience, rather than a mass audience. This can be done through various methods, such as targeted online ads, direct mail, or personalized emails.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>40", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "The law by which a seller transfers the property in goods to a buyer at an agreed price is the", "images": [], "options": {"A": "Weights and Measure Act", "B": "Trade Description Act", "C": "Sale of Goods Act", "D": "Foods and Drugs Act"}, "answer": "C", "explanation": "The Sale of Goods Act is the law that governs the sale of goods by a seller to a buyer at an agreed price. It provides the framework for transactions involving the sale of physical goods. The Act defines the responsibilities of the buyer and the seller, and provides remedies for when things go wrong.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2022>41", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The act of removing government laws and allowing market forces to determine price is", "images": [], "options": {"A": "commercialization", "B": "deregulation", "C": "divestiture", "D": "privatization"}, "answer": "B", "explanation": "Deregulation is the process of removing or reducing state regulations, typically in the economic sphere. It is the repeal of governmental regulation of the economy. It became common in advanced industrial economies in the 1970s and 1980s, as a result of new trends in economic thinking about the inefficiencies of government regulation, and the risk that regulatory agencies would be controlled by the regulated industry to its benefit, and thereby hurt consumers and the wider economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>42", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "The purpose of commercialzation is to", "images": [], "options": {"A": "make state-owned firms more efficient", "B": "enable state-owned firms pay tax", "C": "encourage the flow of foreign capital", "D": "encourage greater participation of the private sector"}, "answer": "A", "explanation": "The purpose of commercialization is to make state-owned firms more efficient. Commercialization is the process of managing or running something principally for financial gain. In the context of state-owned firms, it involves the restructuring of enterprises partly or wholly owned by the state in order to make them operate as profit-making businesses, as opposed to being reliant on government subsidies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>43", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "An agency agreement in which the principal approves the action of his authorized representative is agency by", "images": [], "options": {"A": "ratification", "B": "necessity", "C": "implication", "D": "estoppel"}, "answer": "A", "explanation": "An agency by ratification occurs when a person misrepresents himself as an agent for another party, and the principal accepts or ratifies the unauthorized act. Therefore, an agency agreement in which the principal approves the action of his authorized representative is agency by ratification.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>44", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "A requirement for an offer to be valid is that it should be", "images": [], "options": {"A": "witnessed by a third party", "B": "something of value", "C": "made to one person only", "D": "communicated to the offeree"}, "answer": "D", "explanation": "For an offer to be valid, it must be communicated to the offeree. The offeree must know about the offer in order to accept it. Therefore, a requirement for an offer to be valid is that it should be communicated to the offeree.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>45", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "A disadvantage of privatization is", "images": [], "options": {"A": "high motive for profit than public interest", "B": "decline in the supply of goods", "C": "less efficiency in production of goods", "D": "increase in government expenditure"}, "answer": "A", "explanation": "A disadvantage of privatization is that private companies may prioritize profit over public interest. This is because private companies are primarily driven by profit motives, which can sometimes lead to a disregard for the public interest. Therefore, a disadvantage of privatization is a higher motive for profit than public interest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>46", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The number of subordinates a head of department supervises is", "images": [], "options": {"A": "unity of command", "B": "chain of command", "C": "span of control", "D": "unity of direction"}, "answer": "C", "explanation": "The number of subordinates a head of department supervises is referred to as the 'span of control'. This term is used in business management and refers to the number of subordinates that a manager or supervisor can effectively manage. This number varies depending on the nature of the work and the efficiency of the supervisor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>47", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "An organizational chart of a company shows the", "images": [], "options": {"A": "arrangement of equipment in the company", "B": "financial status of employees in the company", "C": "geographical location of the company", "D": "hierarchy of staff in the company"}, "answer": "D", "explanation": "An organizational chart of a company shows the 'hierarchy of staff in the company'. It is a diagram that shows the structure of an organization and the relationships and relative ranks of its parts and positions/jobs. It does not show the arrangement of equipment, financial status of employees, or geographical location of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>48", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "Which of the following is not a function of management?", "images": [], "options": {"A": "Controlling", "B": "Delegating", "C": "Directing", "D": "Organizing"}, "answer": "B", "explanation": "'Delegating' is not a function of management. The primary functions of management are planning, organizing, staffing, directing, and controlling. Delegating is a part of the directing function of management where a manager assigns responsibility and authority to subordinates to complete tasks or decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>49", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the aims of ECOWAS is to", "images": [], "options": {"A": "promote commercialization policies", "B": "promote trade within the region", "C": "discourage foreign investors", "D": "ensure production of quality goods"}, "answer": "B", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. One of its main aims is to promote economic integration across the region, which includes promoting trade within the region. This is done by removing trade barriers and encouraging free movement of goods, services, and people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2022>50", "subject": "Commerce", "year": "2022", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "The agreement which led to the formation of the West African Clearing House was signed in", "images": [], "options": {"A": "The Gambia", "B": "Sierra Leone", "C": "Nigeria", "D": "Ghana"}, "answer": "C", "explanation": "West African Clearing House is an association of central banks in some West African states which came up on March 14, 1975 through an agreement signed in Lagos, Nigeria. The members countries are: Benin, The Gambia, Ghana, Cote d'ivoire, Liberia, Mali, Niger, Nigeria, Sierra leone, Togo and Burkina Faso.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>1", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Buying and selling products through a network of digital devices is", "images": [], "options": {"A": "e-transfer", "B": "e-payment", "C": "e-mail", "D": "e-commerce"}, "answer": "D", "explanation": "E-commerce, also known as electronic commerce, refers to the buying and selling of goods or services using the internet, and the transfer of money and data to execute these transactions. It is conducted on computers, tablets, smartphones, and other digital devices. It includes online shopping, electronic payments, online auctions, internet banking, and online ticketing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>2", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is not a factor of production?", "images": [], "options": {"A": "Staffing", "B": "Land", "C": "Labour", "D": "Capital"}, "answer": "A", "explanation": "In economics, the four main factors of production are land, labor, capital, and entrepreneurship. Staffing is not considered a factor of production. It is rather a function of management that involves recruiting, selecting, training and developing employees.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>3", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Industrial, commercial and service are types of", "images": [], "options": {"A": "specialization", "B": "occupation", "C": "manufacturing", "D": "extraction"}, "answer": "B", "explanation": "Industrial, commercial, and service are types of occupations. An occupation is a job or profession. Industrial occupations involve the production of goods, commercial occupations involve trade, and service occupations involve providing services to others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>4", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "The reward for capital is", "images": [], "options": {"A": "rent", "B": "profit", "C": "interest", "D": "dividend"}, "answer": "C", "explanation": "In economics, the reward for capital is interest. Capital refers to the financial resources used by businesses to purchase the necessary equipment and other assets to produce goods or services. The return on this investment is typically in the form of interest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>5", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "A document in which the internal regulations of a company are stated is", "images": [], "options": {"A": "Partnership Deed", "B": "Memorandum of Association", "C": "Certificate of Incoporation", "D": "Articles of Association"}, "answer": "D", "explanation": "The 'Articles of Association' is the document in which the internal regulations of a company are stated. It contains the rules and regulations or by-laws of the company and covers areas such as the issue of shares, the appointment or removal of directors, the conduct of the board and general meetings, and the financial management of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>6", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "A business that can obtain capital through of sale of shares is a", "images": [], "options": {"A": "sole proprietorship", "B": "public corporation", "C": "public company", "D": "cooperative society"}, "answer": "C", "explanation": "A 'public company' is a type of business that can obtain capital through the sale of shares. This is because a public company is a company whose shares are traded freely on a stock exchange. This allows them to raise capital by selling shares of the company to the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>7", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "MONEY : MEANING AND TYPES OF MONEY", "question": "A problem associated with barter is", "images": [], "options": {"A": "difficulty in collecting debt", "B": "inability to measure what is to be exchanged", "C": "inability to produce enough goods", "D": "poor road network delaying transportation of goods"}, "answer": "B", "explanation": "One of the problems associated with barter is the 'inability to measure what is to be exchanged'. This is known as the 'lack of common measure of value' problem. In a barter system, there is no common measure (like money in modern economies) to decide how much of one good should be exchanged for another. This makes transactions difficult and inefficient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>8", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : DISSOLUTION AND LIQUIDATION", "question": "Dissolution of a partnership could arise from", "images": [], "options": {"A": "fall in output", "B": "death of a member", "C": "non access to capital", "D": "increase in market share"}, "answer": "B", "explanation": "Dissolution of a partnership could arise from the death of a member. A partnership is a business arrangement where two or more individuals share the ownership, profits, and liabilities of a business venture. When one of the partners dies, the partnership is usually dissolved unless there is an agreement in place that allows the partnership to continue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>9", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A source of capital to a cooperative society is", "images": [], "options": {"A": "contribution", "B": "debenture", "C": "ordinary share", "D": "retained profit"}, "answer": "A", "explanation": "A source of capital to a cooperative society is contribution. A cooperative society is a voluntary association of individuals who come together to protect their economic interests. Members contribute money as capital in a common fund.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>10", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Which of the following activities does not belong to the extractive industry?", "images": [], "options": {"A": "Barbing", "B": "Drilling", "C": "Farming", "D": "Mining"}, "answer": "A", "explanation": "Barbing does not belong to the extractive industry. The extractive industry involves the extraction of natural resources from the earth such as oil, minerals, and gas. Barbing, on the other hand, is a service industry.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>11", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "The excess value of total assets over total liabilites is", "images": [], "options": {"A": "working capital", "B": "paid-up capital", "C": "capital owned", "D": "borrowed capital"}, "answer": "C", "explanation": "The excess value of total assets over total liabilities is referred to as 'capital owned' or 'net assets'. This is because it represents the owner's equity in the business, i.e., the amount that the owner has invested or retained from the business profits. It does not refer to working capital (which is current assets minus current liabilities), paid-up capital (which is the amount of money a company has received from shareholders in exchange for shares of stock), or borrowed capital (which is money that has been borrowed and must be repaid).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>12", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A voluntary association of businessmen who are not in the same line of business is a", "images": [], "options": {"A": "bureau de change", "B": "trade union", "C": "trade association", "D": "chamber of commerce"}, "answer": "D", "explanation": "A voluntary association of businessmen who are not in the same line of business is a 'chamber of commerce'. A chamber of commerce is a local association to promote and protect the interests of the business community in a particular place. On the other hand, a trade union is an organization of workers who have banded together to achieve common goals such as better working conditions, and a trade association, also known as an industry trade group, is an organization founded and funded by businesses that operate in a specific industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>13", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE", "question": "A similarity of private and public company is that they", "images": [], "options": {"A": "are required to publish their final accounts", "B": "have equal number of members", "C": "receive certificate of incorporation", "D": "sell shares on the stock exchange"}, "answer": "C", "explanation": "A similarity of private and public companies is that they both 'receive certificate of incorporation'. A certificate of incorporation is a legal document relating to the formation of a company or corporation. It is a license to form a corporation issued by the state government or, in some jurisdictions, by non-governmental entity/corporation. Its precise meaning depends upon the legal system in which it is used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>14", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Which of the following is not a type of security?", "images": [], "options": {"A": "Debenture", "B": "Overdraft", "C": "Share", "D": "Stock"}, "answer": "B", "explanation": "In the context of finance, a security is a tradable financial asset. The term commonly refers to any form of financial instrument, but its legal definition varies by jurisdiction. Types of securities include debentures, shares, and stocks. An overdraft, however, is not a type of security but a credit facility that allows an account holder to withdraw money beyond the available balance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>15", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An organization that could strive for improvement in electricity and telephone services to users is", "images": [], "options": {"A": "a consumers'association", "B": "an employers' association", "C": "a manufacturers' association", "D": "a trade association"}, "answer": "A", "explanation": "A consumers' association is an organization that advocates for the rights and interests of consumers, including the improvement of services such as electricity and telephone. Employers' associations, manufacturers' associations, and trade associations, on the other hand, represent the interests of their respective members, not necessarily the users of services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>16", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "The business in which sale of goods involves use of vehicles is a", "images": [], "options": {"A": "chain store", "B": "mobile shop", "C": "shopping mail", "D": "tied shop"}, "answer": "B", "explanation": "A mobile shop is a type of business that involves the use of vehicles for the sale of goods. This is different from a chain store, which is a series of retail outlets owned by the same company, a shopping mall, which is a large enclosed building that contains many shops, or a tied shop, which is a type of shop that is obligated to sell goods from a particular supplier.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>17", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "The arrangement for the conveyance of goods abroad is performed by the", "images": [], "options": {"A": "ports authority", "B": "customs and excise authority", "C": "chamber of commerce", "D": "clearing and forwarding agents"}, "answer": "D", "explanation": "The arrangement for the conveyance of goods abroad is performed by the clearing and forwarding agents. Clearing and forwarding agents are intermediaries between the owners of goods and the owners of means of transport. They help in the efficient movement of goods to and from different points in a country or between countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>18", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "One of the barriers to foreign trade is", "images": [], "options": {"A": "trade liberalization", "B": "removal of tarrif", "C": "memorandum of understanding", "D": "imposition of embargo"}, "answer": "D", "explanation": "One of the barriers to foreign trade is the imposition of embargo. An embargo is a government order that restricts commerce or exchange with a specified country or the exchange of specific goods. It is usually created as a result of unfavorable political or economic circumstances between nations.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>19", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "The term 2%/15 net 30 represents a", "images": [], "options": {"A": "cash discount", "B": "quantity discount", "C": "seasonal discount", "D": "trade discount"}, "answer": "A", "explanation": "The term 2%/15 net 30 represents a cash discount. This is a common term used in business to signify that if the bill is paid within 15 days, there is a 2% discount. Otherwise, the full amount is due within 30 days.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>20", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram below to answer the question        The instrument in the diagram is a", "images": ["Commerce/imgs/2023/snip.png"], "options": {"A": "warrant", "B": "money order", "C": "cheque", "D": "deposit slip"}, "answer": "C", "explanation": "The instrument in the diagram is a cheque which is a negotiable instruments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>21", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram below to answer the question      The two lines on the instrument shows that it is", "images": ["Commerce/imgs/2023/snip.png"], "options": {"A": "paid", "B": "crossed", "C": "cancelled", "D": "altered"}, "answer": "B", "explanation": "Crossed cheque is a cheque having two parallel lines drawn across the its face. It cannot be cashed at the counter; it must be paid into a current account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>22", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "Use the diagram below to answer the question      The instrument will not be valid on", "images": ["Commerce/imgs/2023/snip.png"], "options": {"A": "October 25, 2023", "B": "September 25, 2023", "C": "July 25, 2023", "D": "June 25, 2023"}, "answer": "A", "explanation": "This is because the instrument, which appears to be a cheque, has a date of 24-04-23, which is April 24, 2023. Cheques typically expire six months after their date, meaning this check would expire on October 24, 2023.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>23", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "The rate at which a country's export exchange for its imports is", "images": [], "options": {"A": "terms of trade", "B": "terms of payment", "C": "balance of trade", "D": "balance of payment"}, "answer": "A", "explanation": "The rate at which a country's export exchange for its imports is known as the 'terms of trade'. The terms of trade are the ratio of an index of a country's export prices to an index of its import prices. It shows the quantity of import goods an economy can purchase per unit of export goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>24", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT", "question": "When a seller wishes to be paid before supplying goods, he would send the buyer a", "images": [], "options": {"A": "consular invoice", "B": "consignment note", "C": "credit note", "D": "proforma invoice"}, "answer": "D", "explanation": "When a seller wishes to be paid before supplying goods, he would send the buyer a 'proforma invoice'. A proforma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It notes the kind and quantity of goods, their value, and other important information such as weight and transportation charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>25", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A bill of lading that is tagged clean means that the goods being delivered are", "images": [], "options": {"A": "paid for", "B": "on credit", "C": "not damaged", "D": "duty free"}, "answer": "C", "explanation": "A bill of lading that is tagged clean means that the goods being delivered are 'not damaged'. A clean bill of lading is issued by the product carrier after thoroughly inspecting the packages for any damage, missing quantity, or deviations in quality. If the carrier finds the goods to be in good condition, they issue a clean bill of lading.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>26", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER", "question": "If opening and closing inventories of a business are D500 and D300 respectively and cost of sales is D1,200, rate of turnover will be", "images": [], "options": {"A": "4.0 times", "B": "3.0 times", "C": "2.4 times", "D": "1.5 times"}, "answer": "B", "explanation": "The rate of turnover is calculated by dividing the cost of sales by the average inventory. The average inventory is calculated by adding the opening and closing inventories and dividing by 2. In this case, the average inventory is (500+300)/2 = 400. Therefore, the rate of turnover is 1200/400 = 3.0 times.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>27", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "The function of money that makes it generally acceptable is", "images": [], "options": {"A": "medium of exchange", "B": "standard of deferred payment", "C": "store of value", "D": "unit of account"}, "answer": "A", "explanation": "The function of money that makes it generally acceptable is its function as a medium of exchange. This means that money is widely accepted in exchange for goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>28", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "TRADE : FOREIGN TRADE", "question": "A reduction in the value of a country's currency in relation to that of other countries is", "images": [], "options": {"A": "inflation", "B": "deflation", "C": "devaluation", "D": "revaluation"}, "answer": "C", "explanation": "A reduction in the value of a country's currency in relation to that of other countries is referred to as devaluation. This usually happens when a country's government deliberately lowers the value of its currency in relation to foreign currencies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>29", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "The penalty paid for not off-loading goods at a port within the stipulated time is", "images": [], "options": {"A": "charge", "B": "demurrage", "C": "dock due", "D": "freight"}, "answer": "B", "explanation": "Demurrage is the penalty paid for not off-loading goods at a port within the stipulated time. It is a charge payable to the owner of a chartered ship in respect of failure to load or discharge the ship within the time agreed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>30", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION", "question": "An advantage of road transport over other means of transport is that", "images": [], "options": {"A": "canteen services are provided during the course of transportation", "B": "packing and loading is easy as activities are handled by experts", "C": "specific vehicles could be used to carry certain loads", "D": "terminal handling is eliminated by door-to-door delivery"}, "answer": "D", "explanation": "Road transport has the advantage of providing door-to-door service, thus eliminating terminal handling. This means that goods are picked up from the sender's location and delivered directly to the receiver's location, reducing the need for additional handling at terminals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>31", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "A factor to be considered in selecting a means of transporting fish is the", "images": [], "options": {"A": "supply of fish", "B": "nature of the fish", "C": "demand for fish", "D": "cost of fish"}, "answer": "B", "explanation": "The nature of the fish is a factor to be considered in selecting a means of transporting fish. This is because different types of fish may require different conditions for transportation. For example, some fish may need to be transported in water, while others can be transported on ice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>32", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "The bank that conducts research on an economy, thereby identifying obstacles to growth is the", "images": [], "options": {"A": "central bank", "B": "commercial bank", "C": "development bank", "D": "mortgage bank"}, "answer": "C", "explanation": "Development banks are financial institutions that focus on providing long-term financing and support for economic development projects and initiatives. They play a vital role in promoting economic growth and addressing various obstacles to development within an economy.    One of the key functions of a development bank is to conduct research and analysis on the economy it operates in. This research helps identify obstacles or challenges to economic growth, such as infrastructure gaps, financing needs, industry bottlenecks, regulatory hurdles, and other barriers that hinder development.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>33", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "An advantage of advertising is that", "images": [], "options": {"A": "awareness is created on the existence of products", "B": "distribution channels for products are improved", "C": "prices of products are reduced", "D": "quality of products is improved"}, "answer": "A", "explanation": "Advertising creates awareness on the existence of products. It is a communication tool used by businesses to inform, persuade, and remind the public about their products or services. It does not directly improve distribution channels, reduce prices, or improve the quality of products.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>34", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKET SEGMENTATION", "question": "The means by which a firm obtains information before introducing new products is", "images": [], "options": {"A": "advertising", "B": "market research", "C": "market segmentation", "D": "promotion"}, "answer": "B", "explanation": "Market research is the means by which a firm obtains information before introducing new products. It involves gathering, analyzing, and interpreting information about a market, about a product or service to be offered for sale in that market, and about the past, present, and potential customers for the product or service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>35", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "A duty of the principal to his agent is to", "images": [], "options": {"A": "stop the sale of good in transit", "B": "renegotiate agreements made by the agent", "C": "pay the agent for services rendered", "D": "disclose confidential information"}, "answer": "C", "explanation": "One of the key duties of a principal to his agent is to pay the agent for services rendered. This is because an agent acts on behalf of the principal in business transactions and therefore deserves compensation for the services provided.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>36", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "An element of a valid contract is", "images": [], "options": {"A": "operation of law", "B": "performance", "C": "capacity to contract", "D": "breach"}, "answer": "C", "explanation": "Capacity to contract is a fundamental element of a valid contract. It refers to the ability of a party to enter into a legally binding contract. This means that the party must have the legal competence to contract, which is usually determined by their age and mental capacity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>37", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "An example of after-sales services is", "images": [], "options": {"A": "sorting and grading of goods", "B": "provision of price list and terms", "C": "granting of discount", "D": "free replacement of parts"}, "answer": "D", "explanation": "After-sales services are activities that improve the value of a product or service after it has been purchased. Free replacement of parts is an example of after-sales service because it enhances the value of the product for the customer after the purchase has been made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>38", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "Which of the following modes of transport could be used to convey both liquid and gas?", "images": [], "options": {"A": "Tramp", "B": "Tanker", "C": "Ferry", "D": "Aeroplane"}, "answer": "B", "explanation": "A tanker is a ship designed to transport or store liquids or gases in bulk. Major types of tankship include the oil tanker, the chemical tanker, and gas carrier. Hence, it can be used to convey both liquid and gas.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>39", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Advertising designed to sell more of a company's products than other brands is", "images": [], "options": {"A": "competitive", "B": "indirect", "C": "informative", "D": "persuasive"}, "answer": "A", "explanation": "Competitive advertising is a method of attracting buyers by comparing your products to those of your competitors. Companies use competitive advertising to differentiate their product from other similar products in the market. The goal is to show that their product is superior or offers more value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>40", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : MEANING AND CONDITIONS", "question": "In a contract of sale, the amount deposited with the seller for a particular product by a buyer is", "images": [], "options": {"A": "acceptance", "B": "counter offer", "C": "consideration", "D": "warranty"}, "answer": "C", "explanation": "In a contract of sale, the amount deposited with the seller for a particular product by a buyer is known as consideration. Consideration is the value that is given in return for a promise or for a performance. This can take the form of money, physical objects, services, promised actions, abstinence from a future action, and much more.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>41", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The use of brand names and trademarks is to", "images": [], "options": {"A": "control the supply of goods", "B": "make after-sale service possible", "C": "prevent imitation by competitors", "D": "stabilize the prices of goods"}, "answer": "C", "explanation": "Brand names and trademarks are used to prevent imitation by competitors. They are unique identifiers of a product or service and are legally protected. This means that other businesses cannot use the same or similar brand name or trademark, thus preventing imitation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>42", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES", "question": "A disadvantage of privatization is that", "images": [], "options": {"A": "there is decline in the supply of goods", "B": "there is less efficiency in the production of goods", "C": "public interest outweighs the profit motive", "D": "income is unevenly distributed"}, "answer": "D", "explanation": "A disadvantage of privatization is that income is unevenly distributed. Privatization often leads to a concentration of wealth in a small number of individuals or corporations. This can lead to income inequality, as the profits from privatized enterprises are not distributed evenly across society.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2023>43", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Operating a state owned enterprise with the intention of making more profit is", "images": [], "options": {"A": "commercialization", "B": "deregulation", "C": "nationalization", "D": "privatization"}, "answer": "A", "explanation": "Operating a state owned enterprise with the intention of making more profit is commercialization. Commercialization refers to the process of managing or running something principally for financial gain. It involves the transformation of a public sector entity into a business enterprise and changing its operations to adhere to market dynamics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>44", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES", "question": "The department that ensures that products are made available to consumers is", "images": [], "options": {"A": "finance", "B": "marketing", "C": "production", "D": "purchases"}, "answer": "B", "explanation": "The marketing department is responsible for ensuring that products are made available to consumers. They do this through various strategies such as advertising, sales promotions, and public relations. The finance department is responsible for managing the company's money, the production department is responsible for manufacturing the products, and the purchases department is responsible for acquiring the necessary resources to produce the products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>45", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "Which of the following is not a form of sales promotion?", "images": [], "options": {"A": "Free samples", "B": "Demonstrations", "C": "Cash on delivery", "D": "Buy one get one free"}, "answer": "C", "explanation": "Sales promotion is a marketing strategy where the product is promoted using short-term attractive initiatives to stimulate its demand and increase its sales. This includes strategies like free samples, demonstrations, and buy one get one free offers. Cash on delivery, however, is a type of transaction in which the recipient makes payment for a good at the time of delivery. It is a type of payment method, not a sales promotion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>46", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES", "question": "Divesting government interest in a business to the public is", "images": [], "options": {"A": "privatization", "B": "nationalization", "C": "deregulation", "D": "commercialization"}, "answer": "A", "explanation": "Divesting government interest in a business to the public is known as privatization. This is when the government sells off its ownership or interest in a state-owned enterprise to private owners. Nationalization is the opposite of privatization, it is when a government takes control of a private industry or assets. Deregulation is the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry. Commercialization is the process of bringing a new product or service to the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>47", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "The management function that is concerned with coordinating business resources efficiently is", "images": [], "options": {"A": "controlling", "B": "motivation", "C": "planning", "D": "organizing"}, "answer": "D", "explanation": "Organizing is the management function that is concerned with coordinating business resources efficiently. It involves arranging and structuring work to accomplish the organization's goals. This includes determining what tasks are to be done, who is to do them, how the tasks are to be grouped, who reports to whom, and where decisions are to be made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2023>48", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE", "question": "An organizational chart is used to", "images": [], "options": {"A": "determine the departmental objectives and targets", "B": "implement policies on staff welfare", "C": "measure variation on staff performance", "D": "show the hierarchy of staff"}, "answer": "D", "explanation": "An organizational chart is used to show the hierarchy of staff. It is a diagram that visually conveys a company's internal structure by detailing the roles, responsibilities, and relationships between individuals within an entity. It does not directly determine departmental objectives and targets, implement policies on staff welfare, or measure variation on staff performance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>49", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following countries is not a member of the European Union?", "images": [], "options": {"A": "Bolivia", "B": "Denmark", "C": "France", "D": "Greece"}, "answer": "A", "explanation": "Bolivia is not a member of the European Union. The European Union (EU) is a political and economic union of 27 member states that are located primarily in Europe. Bolivia is a country located in central South America, and it is not part of the EU. Denmark, France, and Greece are all members of the EU.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2023>50", "subject": "Commerce", "year": "2023", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "One of the aim of ECOWAS is to", "images": [], "options": {"A": "encourage foreign investments", "B": "ensure production of quality goods", "C": "improve transportation and communication", "D": "promote privatization policies"}, "answer": "C", "explanation": "The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. Its main aim is to promote economic integration across the region. This includes improving transportation and communication, which is crucial for economic integration and development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>1", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE", "question": "The development of Commerce was promoted by", "images": [], "options": {"A": "warehousing", "B": "transportation", "C": "specialization", "D": "manufacturing"}, "answer": "B", "explanation": "Transportation plays a crucial role in the development of commerce as it facilitates the movement of goods and services from producers to consumers. Efficient transportation systems reduce the cost and time of moving products, expand market reach, and enable trade on a larger scale. This connectivity fosters economic growth, allowing for specialization and economies of scale, and ultimately supports the flourishing of commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>2", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE", "question": "A major setback of e-commerce in West Africa is", "images": [], "options": {"A": "unbalanced economic growth", "B": "poor communication infrastructure", "C": "political interference", "D": "lack of industries"}, "answer": "B", "explanation": "Poor communication infrastructure is a significant challenge for the development of e-commerce in West Africa. Reliable internet connectivity and telecommunications are essential for conducting online transactions, managing e-commerce platforms, and ensuring customer satisfaction. In regions with inadequate infrastructure, there are frequent connectivity issues, slow internet speeds, and limited access to online services. This hinders the ability of businesses to operate efficiently and restricts consumers' access to e-commerce opportunities, thereby limiting the growth and potential of the e-commerce sector in West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2024>3", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Conversion of raw materials into finished goods is", "images": [], "options": {"A": "tertiary production", "B": "secondary production", "C": "primary production", "D": "batch production"}, "answer": "B", "explanation": "Secondary production refers to the industrial process of transforming raw materials into finished or semi-finished goods. This involves manufacturing and construction activities where raw inputs, such as minerals, agricultural products, and chemicals, are processed and assembled into products that are ready for use by consumers or other industries. Examples include turning iron ore into steel, manufacturing textiles from cotton, and producing electronics from various raw materials. This stage of production adds value to the raw materials and is essential for economic development and industrial growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>4", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : FEATURES AND IMPORTANCE", "question": "A source of finance peculiar to public companies is", "images": [], "options": {"A": "sale of shares", "B": "personal savings", "C": "membership contribution", "D": "borrowing from friends"}, "answer": "A", "explanation": "Public companies have the unique ability to raise capital by selling shares of stock to the public through stock exchanges. This process, known as equity financing, allows them to generate significant funds from a large pool of investors. Unlike private companies, which may rely on personal savings, membership contributions, or borrowing from friends, public companies can access vast amounts of capital by issuing shares, providing them with the necessary resources to expand operations, invest in new projects, and grow their business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>5", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "An example of an entrepreneur is a", "images": [], "options": {"A": "bank manager", "B": "board member", "C": "debenture holder", "D": "sole proprietor"}, "answer": "D", "explanation": "An entrepreneur is someone who starts and runs their own business, taking on financial risks in the hope of profit. A sole proprietor is a type of entrepreneur who owns and operates a business individually. This contrasts with a bank manager, board member, or debenture holder, who may have roles or investments in businesses but do not typically embody the entrepreneurial spirit of founding and managing a new enterprise from the ground up.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>6", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES", "question": "A partner who losses his capital only, in case of bankruptcy is", "images": [], "options": {"A": "a nominal partner", "B": "a limited partner", "C": "a general partner", "D": "an active partner"}, "answer": "B", "explanation": "A limited partner in a partnership has limited liability, meaning they can only lose the amount of capital they have invested in the business. They do not participate in the day-to-day management or operations of the business, and their liability does not extend beyond their initial investment. This contrasts with a general partner or active partner, who may have unlimited liability and be responsible for the business's debts beyond their capital contribution. A nominal partner, on the other hand, does not invest capital or actively participate in the business but allows their name to be used for the benefit of the partnership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>7", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "Ship building is an activity under", "images": [], "options": {"A": "commercial occupation", "B": "indirect service", "C": "industrial occupation", "D": "direct service"}, "answer": "C", "explanation": "Industrial occupations involve the manufacturing and production of goods. Shipbuilding is a type of industrial occupation because it entails the construction and assembly of ships, which requires substantial technical expertise, machinery, and materials. This activity is part of the secondary sector of the economy, where raw materials are converted into finished products, distinguishing it from commercial occupations, which involve trade and services, or direct and indirect services, which relate to providing services directly to consumers or supporting other businesses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>8", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "The process of making goods and providing services for consumption is", "images": [], "options": {"A": "exchange", "B": "occupation", "C": "production", "D": "specialization"}, "answer": "C", "explanation": "Production is the process of creating goods and services that are intended for consumption. This involves the transformation of raw materials and inputs into finished products or services that meet consumer needs. Production encompasses a wide range of activities, including manufacturing, agriculture, and the provision of services, all aimed at generating outputs that can be used or consumed by individuals or businesses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>9", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : ADVANTAGES & DISADVANTAGES", "question": "A disadvantage of a sole trader is that the", "images": [], "options": {"A": "pays tax to government", "B": "has limited liability", "C": "has unlimited liability", "D": "does not share profit with others"}, "answer": "C", "explanation": "A major disadvantage of being a sole trader is unlimited liability. This means that the sole trader is personally responsible for all the debts and liabilities of the business. If the business incurs debt or faces legal action, the sole trader's personal assets (such as their home or savings) can be used to satisfy business obligations. This poses a significant financial risk compared to limited liability structures, where owners' personal assets are protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>10", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "An organization formed mainly by traders in the same line of business is a", "images": [], "options": {"A": "trade association", "B": "trade union", "C": "chamber of commerce", "D": "cooperative society"}, "answer": "A", "explanation": "A trade association is an organization founded and funded by businesses that operate in a specific industry. These associations aim to collaborate on industry-specific issues, advocate for policies favorable to their industry, and provide a platform for networking, sharing best practices, and addressing common challenges. This distinguishes them from trade unions, which represent workers' rights; chambers of commerce, which serve the broader business community; and cooperative societies, which are owned and operated by members for their mutual benefit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>11", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "Raw materials are classified as", "images": [], "options": {"A": "capital employed", "B": "capital owned", "C": "circulating capital", "D": "fixed capital"}, "answer": "C", "explanation": "Circulating capital refers to capital that is used up in the production process and is constantly circulating or being replenished as goods are produced and sold. Raw materials are a part of circulating capital because they are purchased, transformed into finished goods, and then sold to customers. This contrasts with fixed capital, which refers to long-term assets like machinery and buildings used in production, and with capital employed or owned, which typically refers to the total capital invested in a business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>12", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "OCCUPATION : TYPES OF OCCUPATION", "question": "A factor that determines the occupation of people living along coastal areas is", "images": [], "options": {"A": "availability of housing", "B": "good road network", "C": "natural resources available", "D": "size of the population"}, "answer": "C", "explanation": "The availability of natural resources is a significant factor influencing the occupations and economic activities of people living along coastal areas. Coastal regions often have access to marine resources such as fish, minerals, and offshore oil and gas deposits. These resources can support livelihoods through fishing, aquaculture, tourism, shipping, and related industries. The presence of natural resources shapes the local economy and determines the types of occupations that are viable and sustainable in coastal communities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>13", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "An advantage of self-service to customers is that it", "images": [], "options": {"A": "encourages impulse buying", "B": "enables customers to inspect goods", "C": "enables customers to buy on credit", "D": "leads to a reduction in prices"}, "answer": "B", "explanation": "Self-service allows customers to directly inspect and evaluate the goods they are interested in purchasing. This hands-on approach enables customers to make informed decisions based on the quality, condition, and suitability of the products. It empowers customers to choose products that meet their preferences and requirements without relying solely on descriptions or the assistance of sales staff. This aspect of self-service enhances transparency and customer satisfaction by ensuring that customers have a clear understanding of what they are purchasing before making a buying decision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>14", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer the question     DOpening stock 22000.00Purchases 20000.00Debtors 12000.00Creditors 8000.00Closing stock8000.00Overdraft5000.00    Calculate average stock", "images": [], "options": {"A": "D15,000.00", "B": "D14,000.00", "C": "D13,000.00", "D": "D10,000.00"}, "answer": "A", "explanation": "Average Stock=(Opening Stock + Closing Stock) 2  Given:  Opening Stock = 22000.00  Closing Stock = 8000.00    Substitute these values into the formula:  Average Stock=(22000.00 + 8000.00) 2  Average Stock=30000.00 2  Average Stock = D15000.00", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2024>15", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer the question     DOpening stock 22000.00Purchases 20000.00Debtors 12000.00Creditors 8000.00Closing stock8000.00Overdraft5000.00    The value of current liabilities is", "images": [], "options": {"A": "D10,000.00", "B": "D13,000.00", "C": "D14,000.00", "D": "D15,000.00"}, "answer": "B", "explanation": "Current Liabilities = Creditors + Overdraft  Current Liabilities = 8000.00 + 5000.00  Current Liabilities = D13000.00", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2024>16", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "One of the aims of a consumer's association is to advocate for", "images": [], "options": {"A": "low-income tax", "B": "high wages", "C": "high prices of products", "D": "good quality products"}, "answer": "D", "explanation": "Consumer's associations aim to protect and promote the interests of consumers. One of their primary objectives is to advocate for good quality products. This involves ensuring that consumers have access to products that meet safety standards, perform as advertised, and provide value for money. By advocating for good quality products, consumer's associations seek to safeguard consumer rights, enhance consumer satisfaction, and promote fair practices within the marketplace.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>17", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE : HOME TRADE: WHOLESALE TRADE", "question": "Prefinancing production is a wholesaler's function to", "images": [], "options": {"A": "manufacturers", "B": "retailers", "C": "distribution", "D": "consumers"}, "answer": "A", "explanation": "Wholesalers often prefinance production by providing manufacturers with upfront payments or credit arrangements to finance the production process. This financial support enables manufacturers to purchase raw materials, cover production costs, and initiate the manufacturing process before goods are sold to retailers or consumers. By prefinancing production, wholesalers help manufacturers manage cash flow, reduce financial strain, and ensure continuous production and supply of goods to meet market demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>18", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "An adverse balance of payment could be corrected through", "images": [], "options": {"A": "increase in imports", "B": "increase in exports", "C": "reduction of exports", "D": "removal of tariffs"}, "answer": "B", "explanation": "By increasing exports, a country can earn more foreign exchange, which helps to balance out the deficit caused by excessive imports. This can improve the overall balance of payments by increasing the inflow of foreign currency and reducing reliance on foreign borrowing to finance the deficit. Other measures such as reducing unnecessary imports, improving competitiveness, and attracting foreign investments also contribute to correcting an adverse balance of payments over time.", "marks": "1", "difficulty": "3"}, {"id": "objective>Commerce>2024>19", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "A price quotation that includes the cost of delivering the goods up to the ship but excludes the cost of landing is", "images": [], "options": {"A": "FAS", "B": "FOR", "C": "Franco", "D": "CIF"}, "answer": "A", "explanation": "FAS (Free Alongside Ship) is a trade term indicating that the seller delivers the goods to a named port alongside a vessel designated by the buyer. Under FAS terms, the seller bears the costs and risks associated with delivering the goods alongside the ship at the port of shipment. However, the buyer assumes responsibility and costs for loading, transportation from the port of shipment, and all subsequent risks and costs. Therefore, FAS includes delivery up to the ship but excludes the cost of landing or unloading the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>20", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "To inform the buyer that goods are in transit, the seller sends", "images": [], "options": {"A": "a quotation", "B": "an invoice", "C": "a debit note", "D": "an advice note"}, "answer": "D", "explanation": "An advice note, also known as an advice of dispatch or shipping advice, is a document sent by the seller to inform the buyer that the goods have been dispatched or are in transit. It typically includes details such as the description of the goods, quantity shipped, shipping method, expected delivery date, and any relevant tracking information. This notification allows the buyer to prepare for the arrival of the goods, arrange for receipt, and monitor their shipment until delivery is completed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>21", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK", "question": "A financial institution established to raise funds for people who wish to build homes is a", "images": [], "options": {"A": "central bank", "B": "commercial bank", "C": "development bank", "D": "mortgage bank"}, "answer": "D", "explanation": "A mortgage bank is specifically established to provide loans (mortgages) to individuals or businesses for the purpose of purchasing real estate or constructing homes. These banks specialize in offering long-term loans secured by the property being purchased or built, with the property itself serving as collateral. Mortgage banks typically focus on providing financing for residential properties, although some may also offer loans for commercial real estate. This specialization distinguishes them from commercial banks, which offer a broader range of financial services, and development banks, which typically focus on funding economic development projects at a broader scale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>22", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "A market where items are sold in lots or by description is a", "images": [], "options": {"A": "supermarket", "B": "money market", "C": "commodity market", "D": "capital market"}, "answer": "C", "explanation": "A commodity market is a marketplace where goods that are standardized and interchangeable are bought and sold. These goods are typically raw materials or primary agricultural products such as wheat, gold, oil, coffee, etc. In commodity markets, items are often sold in lots (specific quantities) or by description (based on standardized quality and specifications). This contrasts with a supermarket, which is a retail store that sells a wide variety of consumer goods to the general public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>23", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES", "question": "The insurance policy that covers a company against cashier's dishonesty is", "images": [], "options": {"A": "consequential loss", "B": "employer's liability", "C": "fidelity guarantee", "D": "third party"}, "answer": "C", "explanation": "A fidelity guarantee insurance policy, also known as fidelity bond or employee dishonesty insurance, covers a company against financial losses resulting from acts of dishonesty, fraud, or theft committed by employees. This type of insurance specifically protects the employer against losses caused by the fraudulent actions of cashiers or other employees handling money or valuables. It helps mitigate the financial impact of employee dishonesty by reimbursing the employer for losses incurred due to theft, embezzlement, or other fraudulent activities committed by covered employees.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>24", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "Which of the following instruments is not a means of payment?", "images": [], "options": {"A": "Debit notes", "B": "Debit cards", "C": "Credit cards", "D": "Bank notes"}, "answer": "A", "explanation": "Debit notes are documents used in business transactions to inform a buyer of the amount owed for goods or services purchased on credit. They are not directly used as a means of payment but rather serve as a record of an obligation to make a payment. In contrast:    Debit cards and credit cards are payment cards issued by financial institutions that enable cardholders to make electronic payments at point-of-sale terminals or online.  Bank notes refer to physical currency issued by central banks and are widely accepted as a means of payment in transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>25", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING", "question": "To correct an overcharge for goods on an invoice, the seller sends the buyer", "images": [], "options": {"A": "an advice note", "B": "a credit note", "C": "a consignment note", "D": "a delivery note"}, "answer": "B", "explanation": "A credit note is a document issued by a seller to a buyer to correct an overcharge or error on an invoice. It serves as a formal acknowledgment of the amount that has been credited back to the buyer's account or as a reduction of the amount owed. Unlike an advice note, which informs the buyer of goods in transit, or a consignment note, which is used in logistics to document the contents of a shipment, a credit note specifically addresses billing discrepancies and ensures accurate financial records between the buyer and seller.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>26", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS", "question": "A market for long-term loans is the", "images": [], "options": {"A": "capital market", "B": "foreign exchange market", "C": "money market", "D": "new issues market"}, "answer": "A", "explanation": "The capital market is a financial market where long-term debt instruments (such as bonds) and equity securities (such as stocks) are bought and sold. It facilitates the raising of long-term funds for businesses and governments. Participants in the capital market include investors, financial institutions, corporations, and governments. This market provides a platform for companies and governments to raise capital through the issuance of securities, which are traded among investors seeking investment opportunities. The capital market contrasts with the money market, which deals with short-term debt instruments, and the foreign exchange market, which involves the trading of currencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>27", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The most suitable means of transporting liquid and gas over long distance within a country is by", "images": [], "options": {"A": "train", "B": "tanker", "C": "pipeline", "D": "aircraft"}, "answer": "C", "explanation": "Pipelines are the preferred method for transporting liquids (such as oil, natural gas, and water) and gases over long distances within a country. They offer several advantages, including:  -  Efficient and continuous transport without the need for multiple handling or transshipment.  -  Cost-effectiveness compared to other modes of transportation over long distances.  -  Safety and reliability in transporting hazardous or volatile materials.  -  Minimal environmental impact compared to other transport methods like tankers or trucks.    While tankers can transport liquids over shorter distances and trains can transport various goods including liquids, pipelines are specifically designed for the efficient, safe, and economical transport of liquids and gases over extensive distances within a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>28", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "INFORMATION COMMUNICATION TECHNOLOGY", "question": "A computer's main storage device is the", "images": [], "options": {"A": "compact disk", "B": "flash drive", "C": "hard disk", "D": "memory chip"}, "answer": "C", "explanation": "The main storage device in a computer, where data and programs are permanently stored and accessed, is the hard disk. Hard disks provide large storage capacities and are typically installed inside the computer's casing. They use magnetic storage to store data on spinning disks (platters) that are accessed using read/write heads. Hard disks are essential for storing the operating system, software applications, files, documents, and other digital content.    While options like compact disks (CDs), flash drives, and memory chips also provide storage capabilities, they are not typically considered the primary or main storage device within a computer system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>29", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "The amount and assured receives if he discontinues a life policy is", "images": [], "options": {"A": "surrender value", "B": "sum assured", "C": "net value", "D": "indemnity"}, "answer": "A", "explanation": "The surrender value of a life insurance policy is the amount paid to the policyholder if they decide to terminate or surrender the policy before its maturity date. It represents the cash value of the policy accumulated over time, taking into account premiums paid and any accrued interest or investment returns. Surrendering a policy typically involves forfeiting any additional benefits or coverage that may have been associated with the policy. This value may be less than the total premiums paid, especially in the early years of the policy, due to administrative costs and charges deducted by the insurance company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>30", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "Which of the following means of advertising generates a wider coverage?", "images": [], "options": {"A": "Radio", "B": "Neon signs", "C": "Cinema", "D": "Bill boards"}, "answer": "D", "explanation": "Billboards are large outdoor advertising structures typically placed in high-traffic areas such as alongside highways, busy roads, or in urban centers. They are designed to capture the attention of motorists and pedestrians, providing a broad reach and exposure to a diverse audience. Unlike radio, which targets listeners within a specific geographic region, or neon signs and cinema advertising, which have more localized or targeted audiences, billboards can effectively reach a wide demographic range due to their prominent visibility and constant exposure to passersby. Therefore, billboards are often chosen for their ability to generate broad coverage and maximize brand", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>31", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A cheque that bears a date later than the current date is a", "images": [], "options": {"A": "stale cheque", "B": "post-dated cheque", "C": "dishonoured cheque", "D": "certified cheque"}, "answer": "B", "explanation": "A post-dated cheque is a cheque issued with a future date written on it, rather than the current date. This means the cheque cannot be cashed or deposited until the date specified on the cheque. Post-dated cheques are often used for various reasons, such as payment scheduling or to ensure funds are available at a later date. It is important to note that presenting a post-dated cheque before the specified date may result in it being treated as a stale cheque, which is a cheque that is no longer valid due to its age, typically after six months from the date of issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>32", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "NEGOTIABLE INSTRUMENTS", "question": "The holder of a bill who wishes to dispose it before maturity would be paid", "images": [], "options": {"A": "dividend", "B": "interest", "C": "the discounted value", "D": "the face value"}, "answer": "C", "explanation": "When a holder wishes to sell or discount a bill (such as a promissory note or a bill of exchange) before its maturity date, they receive the discounted value. This value is calculated based on the face value of the bill minus the interest or discount rate applied for the period remaining until maturity. The buyer of the discounted bill pays the holder the discounted value upfront, effectively assuming ownership of the bill and the right to receive its full face value at maturity. This transaction allows the holder to convert the future value of the bill into cash immediately, providing liquidity and flexibility in managing financial obligations or investments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>33", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A medium of advertising that could be used by a hawker to promote sales is", "images": [], "options": {"A": "window display", "B": "hoarding", "C": "free samples", "D": "cinema"}, "answer": "C", "explanation": "Free samples are a promotional strategy where hawker or vendor offers potential customers a small amount of a product for free to try before they make a purchase. This method is effective for attracting attention, demonstrating product quality, and encouraging immediate sales. While options like window displays, hoardings (large outdoor advertisements), and cinema advertising are effective for broader marketing purposes, free samples are particularly suitable for hawker-style sales where direct interaction with potential customers can lead to immediate sales and customer satisfaction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2024>34", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING", "question": "Which of the following activities would make continuous production possible?", "images": [], "options": {"A": "Grading", "B": "Packaging", "C": "Transportation", "D": "Warehousing"}, "answer": "D", "explanation": "Warehousing plays a crucial role in continuous production by providing storage facilities for raw materials, work-in-progress inventory, and finished goods. It ensures that there is a continuous and uninterrupted supply of materials and components to the production line as needed. Warehousing allows manufacturers to accumulate sufficient stocks of inputs and outputs, smoothing out fluctuations in supply and demand. This contrasts with activities like grading, packaging, and transportation, which are essential but do not directly facilitate the continuous flow of production processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>35", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE", "question": "An advantage of personal selling is that it", "images": [], "options": {"A": "appeals to many people at a time", "B": "ensures a wider market coverage", "C": "involves little expenditure", "D": "generates immediate feedback"}, "answer": "D", "explanation": "Personal selling involves direct interaction between a salesperson and a potential customer. This direct engagement allows for immediate feedback from the customer regarding their needs, preferences, and concerns. Salespersons can adapt their sales pitch or strategy in real-time based on this feedback, which enhances the effectiveness of the sales process. Immediate feedback also enables salespersons to address objections or clarify information on the spot, potentially leading to higher conversion rates and customer satisfaction.    While personal selling can be effective in appealing to individual customers, ensuring tailored communication, and potentially covering a specific market segment comprehensively, its primary advantage lies in the immediacy of feedback and the ability to personalize the sales experience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>36", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : MEANING AND TYPES", "question": "The protection of an author's published work is", "images": [], "options": {"A": "copyright", "B": "patent", "C": "trade mark", "D": "warranty"}, "answer": "A", "explanation": "Copyright is the legal right granted to the creator of original works such as literary works (including novels, poems, and plays), music, artistic works (including drawings, paintings, photographs, and sculptures), and other intellectual creations. It provides the author or creator with exclusive rights to reproduce, distribute, perform, display, or license their work. Copyright protection ensures that authors have control over how their work is used and prevents others from copying or using their work without permission.    While patents protect inventions or new and useful processes, trademarks protect logos, symbols, or words used to distinguish products or services in the marketplace, and warranties provide assurances about the quality or performance of goods, copyright specifically protects the expression of creative works.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>37", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "Under which Act could a buyer of a faulty television set claim for replacement?", "images": [], "options": {"A": "Food and Drugs Act", "B": "Price Control Act", "C": "Rent Control Act", "D": "Standard Organization Act"}, "answer": "D", "explanation": "The Standard Organization Act or related consumer protection laws typically govern product quality standards and consumer rights regarding faulty goods. In many jurisdictions, consumer protection laws ensure that buyers have the right to demand replacements or refunds for goods that are defective, not functioning as advertised, or do not meet quality standards. These laws establish guidelines for product safety, labeling, and consumer recourse in cases of faulty products. Therefore, the Standard Organization Act or equivalent legislation would be relevant for a buyer seeking to claim replacement for a faulty television set.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>38", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ELEMENT OF MARKETING : MARKETING MIX", "question": "The process of providing cover for goods is", "images": [], "options": {"A": "blending", "B": "branding", "C": "grading", "D": "packaging"}, "answer": "D", "explanation": "Packaging refers to the process of enclosing or protecting products for distribution, storage, sale, and use. It involves designing and producing containers or wrappers that provide physical protection, facilitate handling and transportation, and convey information about the product to consumers. Packaging plays a crucial role in protecting goods from damage, contamination, or theft during their journey from production to consumption. It also serves marketing purposes by enhancing the product's visibility, attractiveness, and brand identification (though branding is specifically about creating a distinct identity for a product or company). Therefore, packaging is directly related to providing cover and protection for goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>39", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "TRADE : HOME TRADE: RETAIL TRADE", "question": "Which of the following retail businesses sells without shop assistants?", "images": [], "options": {"A": "Department store", "B": "Mail order", "C": "Multiple store", "D": "Tied shop"}, "answer": "B", "explanation": "Mail order retail businesses sell products directly to consumers through catalogs, websites, or other forms of advertising, without the need for shop assistants. Customers browse through catalogs or online platforms, select items they wish to purchase, and place orders either by mail, phone, or online. The goods are then shipped directly to the customer's address. This method of retailing allows customers to shop independently without the assistance of shop assistants commonly found in traditional brick-and-mortar stores like department stores, multiple stores, or tied shops, where personal interaction with sales staff is often required.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>40", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "The right of an unpaid seller includes the right to", "images": [], "options": {"A": "sue a debtor for amounts owed", "B": "stop a debtor from purchasing goods elsewhere", "C": "publish the act of a debtor", "D": "seize a debtor's property"}, "answer": "A", "explanation": "An unpaid seller has several rights under the Sale of Goods Act, which include the right to sue the buyer (debtor) for the amount owed for the goods sold. This legal right allows the seller to seek remedies through the courts to recover payment for goods delivered but not yet paid for by the buyer. Other rights such as stopping goods in transit (when the buyer is insolvent), retaining possession of the goods until payment is made, and selling the goods after giving notice to the buyer are also part of the unpaid seller's rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>41", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT", "question": "One of the legislation that protects consumers is the", "images": [], "options": {"A": "Copyright Act", "B": "Company Act", "C": "Partnership Act", "D": "Sale of Goods Act"}, "answer": "D", "explanation": "The Sale of Goods Act (or its equivalent legislation in various jurisdictions) is primarily focused on protecting consumers by setting out their rights and remedies when purchasing goods. Key provisions typically include:    Ensuring goods sold are of satisfactory quality.  Ensuring goods are fit for their intended purpose.  Providing remedies for faulty or defective goods, such as repair, replacement, or refund.  The Sale of Goods Act establishes legal standards for transactions involving goods between sellers and consumers, aiming to protect consumers from unfair practices and ensuring they receive goods that meet reasonable expectations of quality and performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>42", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "Internal and external factors that affect how a business functions is", "images": [], "options": {"A": "business environment", "B": "business structure", "C": "span of control", "D": "scalar chain"}, "answer": "A", "explanation": "The business environment refers to all internal and external factors that influence the operations, strategies, and decisions of a business. Internal factors include aspects such as organizational culture, management style, resources, and structure. External factors encompass the broader economic, social, technological, political, and legal conditions in which the business operates, along with market conditions, competition, customer preferences, and regulatory requirements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>43", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE", "question": "The management function that provides guidance and supervision to subordinates is", "images": [], "options": {"A": "organizing", "B": "planning", "C": "directing", "D": "controlling"}, "answer": "C", "explanation": "Directing is the management function that involves guiding, instructing, leading, and overseeing employees' performance to achieve organizational goals. It includes activities such as:    Providing instructions and communicating expectations to subordinates.  Motivating and inspiring employees to perform effectively.  Leading and coordinating efforts towards achieving objectives.  Supervising and monitoring work progress.    While organizing involves structuring resources and activities to achieve objectives, planning entails setting goals and determining how to achieve them, and controlling involves monitoring and evaluating performance against objectives, directing specifically focuses on providing guidance and supervision to subordinates in the day-to-day operations of the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>44", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION~~TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "A document issued by the captain of a ship to acknowledge receipt of goods is a", "images": [], "options": {"A": "dock receipt", "B": "bills of lading", "C": "mate's receipt", "D": "ship's manifest"}, "answer": "C", "explanation": "A mate's receipt is a document issued by the mate (or officer) of a ship to acknowledge the receipt of goods that have been loaded onto the vessel. It serves as a temporary receipt until the formal bill of lading is issued by the shipping company or its agent. The mate's receipt confirms the goods have been received on board and will be transported to their destination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>45", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "A reason for the privatization of the petroleum industry is to", "images": [], "options": {"A": "reduce production of petroleum product", "B": "reduce private businesses in the sector", "C": "encourage private businesses in the sector", "D": "control production in the sector"}, "answer": "C", "explanation": "Privatization of the petroleum industry involves transferring ownership and control of state-owned or national petroleum assets and enterprises to private entities or corporations. This policy shift is often intended to:    -  Stimulate competition and efficiency by allowing private companies to operate and invest in the sector.  -  Encourage innovation and technological advancements in exploration, production, and distribution.  -  Attract foreign investment and expertise.  -  Improve management practices and reduce bureaucratic inefficiencies associated with state-owned enterprises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>46", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "A disadvantage of commercialization to consumers is that", "images": [], "options": {"A": "it promotes inefficiency", "B": "it reduces loyalty of workers", "C": "customers do not have value for their money", "D": "prices of products increase"}, "answer": "D", "explanation": "Commercialization refers to the process of introducing a new product or service into the market for sale to consumers. While it can bring benefits such as increased availability of goods and services, enhanced competition, and innovation, it can also lead to higher prices for consumers due to several factors:    -  Profit motive: Commercialization often focuses on maximizing profits, which can lead to pricing strategies aimed at generating higher revenues.  -  Advertising and marketing costs: Companies invest in promoting their products, and these costs are often passed on to consumers in the form of higher prices.  -  Market power: In competitive markets, commercialization can lead to dominant firms setting prices that consumers must accept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>47", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "One of the social responsibilities of a business to the community is", "images": [], "options": {"A": "provision of after-sales service", "B": "payment of salaries", "C": "ensuring profitability", "D": "controlling pollution"}, "answer": "D", "explanation": "Social responsibility of a business to the community includes actions and policies that benefit society beyond maximizing profits. Controlling pollution is a critical aspect of corporate social responsibility (CSR) as it involves minimizing the negative environmental impact of business operations. Businesses can adopt practices such as reducing emissions, managing waste responsibly, conserving resources, and promoting sustainable practices to contribute positively to the community and environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>48", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.~~ELEMENT OF MARKETING : MARKETING MIX", "question": "An objective of the Niger Basin Commission is to", "images": [], "options": {"A": "enhance development of irrigation systems", "B": "encourage the use of common language", "C": "encourage free trade in the area", "D": "facilitate settlement of indebtedness"}, "answer": "A", "explanation": "The Niger Basin Commission is an intergovernmental organization established to promote cooperation and sustainable development within the Niger River Basin. One of its primary objectives is to enhance the development of irrigation systems in the region. This involves improving water management, increasing agricultural productivity, and supporting local communities through irrigation infrastructure projects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>49", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES", "question": "The act of reducing government intervention in business is", "images": [], "options": {"A": "commercialization", "B": "deregulation", "C": "merger", "D": "privatization"}, "answer": "B", "explanation": "Deregulation refers to the process of reducing or eliminating government regulations and controls in a particular industry or sector. It aims to increase market efficiency, promote competition, and reduce bureaucratic constraints on businesses. By deregulating, governments aim to create a more competitive environment where market forces can operate more freely, potentially leading to lower prices, increased innovation, and better consumer choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2024>50", "subject": "Commerce", "year": "2024", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following is not a problem of ECOWAS?", "images": [], "options": {"A": "Pursuit of different political ideologies", "B": "Existence of meagre resources in member countries", "C": "Difference in colonial history", "D": "Disagreement on leadership"}, "answer": "A", "explanation": "ECOWAS (Economic Community of West African States) primarily focuses on economic integration and cooperation among its member states in West Africa. While political differences may exist among member countries, the pursuit of different political ideologies is not typically cited as a significant problem within ECOWAS. Instead, the organization faces challenges such as:    -  Existence of meagre resources in member countries (option B): Economic disparities and resource constraints affect development and integration efforts.  -  Difference in colonial history (option C): Varied colonial legacies can impact cooperation and integration efforts.  -   Disagreement on leadership (option D): Issues related to leadership selection or decision-making processes within the organization can affect its functioning.    Pursuit of different political ideologies, is less commonly cited as a primary problem within ECOWAS compared to the other options listed, which are more directly related to the economic and political challenges the organization faces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>1", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS", "question": "A function of commerce is to", "images": [], "options": {"A": "collect revenue for government", "B": "create social amenities in rural areas", "C": "facilitate movement of goods and services", "D": "provide advisory services to government"}, "answer": "C", "explanation": "The primary function of commerce is to facilitate the movement of goods and services from producers to consumers. This involves various activities such as transportation, distribution, and marketing, which are essential for ensuring that products reach the market efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>2", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "Labour as a factor of production attracts", "images": [], "options": {"A": "wage", "B": "profit", "C": "interest", "D": "dividend"}, "answer": "A", "explanation": "Labour, as a factor of production, is compensated through wages. Wages are the payments made to workers for their labor, which is a crucial input in the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>3", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "PRODUCTION : MEANING & IMPORTANCE", "question": "Which of the following industries uses wood to make furniture?", "images": [], "options": {"A": "Service", "B": "Extraction", "C": "Construction", "D": "Commercial"}, "answer": "B", "explanation": "The extraction industry involves obtaining raw materials from nature, while the construction industry uses these materials to build structures. The furniture-making industry falls under the construction category as it involves using wood (a raw material) to create finished products like furniture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>4", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "OCCUPATION : MEANING & IMPORTANCE", "question": "A factor which will not influence choice of occupation is", "images": [], "options": {"A": "intelligence", "B": "risk", "C": "population", "D": "salary"}, "answer": "C", "explanation": "All the options listed except population can influence the choice of occupation in various ways. For instance, intelligence may affect the ability to perform certain jobs, risk may relate to job security, and salary is a significant factor in job choice.   Population is a factor that will not directly influence an individual's choice of occupation", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>5", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "An aid to trade that provides information about a product is", "images": [], "options": {"A": "advertising", "B": "insurance", "C": "tourism", "D": "warehousing"}, "answer": "A", "explanation": "Advertising is an aid to trade that provides information about a product. It helps inform potential customers about the features, benefits, and availability of products, thereby facilitating sales and enhancing market reach.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>6", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "PRODUCTION : FACTORS OF PRODUCTION", "question": "A feature of land is that", "images": [], "options": {"A": "it is homogeneous", "B": "its value falls over time", "C": "its supply is fixed", "D": "it attracts dividend"}, "answer": "C", "explanation": "A feature of land is that its supply is fixed. This means that the amount of land available for use does not increase, as land is a finite resource. Unlike other goods, land cannot be produced or created, which is why its supply is considered fixed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>7", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "The industry that transforms raw materials into finished goods is", "images": [], "options": {"A": "commercial", "B": "extraction", "C": "manufacturing", "D": "service"}, "answer": "C", "explanation": "The industry that transforms raw materials into finished goods is manufacturing. Manufacturing involves the conversion of raw materials into products through various processes, including assembly, fabrication, and production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>8", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE ASSOCIATION : OBJECTIVES , MERIT & DEMERIT", "question": "An organization formed to control prices of commodities by restricting the quantity supplied is  a", "images": [], "options": {"A": "trade union", "B": "trade association", "C": "cartel", "D": "consortium"}, "answer": "C", "explanation": "An organization formed to control prices of commodities by restricting the quantity supplied is a cartel. A cartel is a group of independent market participants who collude to improve their profits and dominate the market by controlling supply and prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>9", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER", "question": "If a groundnut farmer takes over a vegetable processing company, the merger is", "images": [], "options": {"A": "backward integration", "B": "diagonal integration", "C": "forward integration", "D": "horizontal integration"}, "answer": "A", "explanation": "If a groundnut farmer takes over a vegetable processing company, the merger is backward integration. Backward integration occurs when a company expands its role to fulfill tasks formerly completed by businesses up the supply chain, in this case, the farmer taking control of the processing of their own product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>10", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS", "question": "A chamber of commerce is an association of business individuals aimed at promoting the interest of the", "images": [], "options": {"A": "consumers", "B": "members", "C": "producers", "D": "public"}, "answer": "B", "explanation": "A chamber of commerce is an association of business individuals aimed at promoting the interest of its members. Chambers of commerce advocate for the interests of their members, which typically include businesses and entrepreneurs, by providing support, networking opportunities, and resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>11", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL", "question": "In business, the net value of the owner's assets is", "images": [], "options": {"A": "working capital", "B": "nominal capital", "C": "fixed capital", "D": "capital owned"}, "answer": "D", "explanation": "The net value of the owner's assets in business is referred to as 'capital owned'. This represents the total assets owned by the owner after deducting liabilities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>12", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: SOLE PROPRIETORSHIP : MEANING AND IMPORTANCE", "question": "Quick decision making is a feature of a", "images": [], "options": {"A": "sole proprietorship", "B": "public enterprise", "C": "joint stock company", "D": "cooperative society"}, "answer": "A", "explanation": "Quick decision making is a feature of a 'sole proprietorship' because it is owned and managed by a single individual, allowing for swift decisions without the need for consensus from multiple stakeholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>13", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES", "question": "A business unit that is restricted from transferring shares freely is a", "images": [], "options": {"A": "sole proprietorship", "B": "private company", "C": "public company", "D": "cooperative society"}, "answer": "B", "explanation": "A business unit that is restricted from transferring shares freely is a 'private company'. Unlike public companies, private companies have limitations on the sale and transfer of shares, which helps maintain control within a smaller group of owners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>14", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer the question     #Stock as at 01/01/2024 20000Stock as at 31/12/2024 50000Purchases 100000Sales 90000    The cost of goods sold is", "images": [], "options": {"A": "#10,000", "B": "#20,000", "C": "#50,000", "D": "#70,000"}, "answer": "D", "explanation": "To calculate the cost of goods sold (COGS), we use the formula: COGS = Opening Stock + Purchases - Closing Stock.     Here, COGS = 20000 + 100000 - 50000   =# 70000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>15", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer the question     #Stock as at 01/01/2024 20000Stock as at 31/12/2024 50000Purchases 100000Sales 90000    The gross profit is", "images": [], "options": {"A": "#10,000", "B": "#20,000", "C": "#50,000", "D": "#70,000"}, "answer": "B", "explanation": "Gross profit is calculated as Sales - Cost of Goods Sold (COGS).     From the previous question, we found COGS to be #70,000.     Thus, Gross Profit = 90000 - 70000     = #20,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>16", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Use the information below to answer the question     #Stock as at 01/01/2024 20000Stock as at 31/12/2024 50000Purchases 100000Sales 90000    The rate of stock turnover is", "images": [], "options": {"A": "2 times", "B": "2.6 times", "C": "3 times", "D": "3.5 times"}, "answer": "A", "explanation": "The rate of stock turnover is calculated using the formula: Stock Turnover = Cost of Goods Sold (COGS) / Average Stock.   COGS = 2000 + 100000 - 50000   = #70000.    Average Stock = Opening Stock + Closing Stock/2  =  20000 +50000/ 2  = 70000/2  = 35000    Therefore, stock turnover = 70000/35000  = 2 times", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>17", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETY : MEANING AND TYPES", "question": "An organization that protects users of products is a", "images": [], "options": {"A": "manufacturers' association", "B": "cooperative society", "C": "consumers' association", "D": "chamber of commerce"}, "answer": "C", "explanation": "A consumers' association is an organization that protects the interests of consumers by advocating for their rights and ensuring product safety. This aligns with the definition provided in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>18", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETY : MEANING AND TYPES", "question": "An attribute of a cooperative society that makes it democratic is", "images": [], "options": {"A": "possession of common interest by members", "B": "patronage as a criteria for profit sharing", "C": "high value placed on members' welfare", "D": "entitlement to one vote by each member"}, "answer": "D", "explanation": "The democratic nature of a cooperative society is characterized by the principle of one member, one vote, regardless of the amount of capital contributed. This ensures that all members have an equal say in decision-making processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>19", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "A function of  a wholesaler to a producer is", "images": [], "options": {"A": "stocking variety of products", "B": "provision of after-sales service", "C": "granting credit facilities", "D": "breaking bulk"}, "answer": "D", "explanation": "One of the primary functions of a wholesaler is breaking bulk, which involves purchasing large quantities of goods from producers and selling them in smaller quantities to retailers. This helps producers manage their inventory and allows retailers to stock products without needing to purchase large amounts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>20", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "A deficit in the balance of trade occurs when", "images": [], "options": {"A": "visible exports exceed visible imports", "B": "visible imports exceed visible exports", "C": "total payments exceed total receipts", "D": "total imports exceed total exports"}, "answer": "B", "explanation": "A deficit in the balance of trade occurs when a country's visible imports exceed its visible exports. This means that the country is buying more goods from other countries than it is selling to them, leading to a trade deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>21", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE : DOCUMENT USED IN INTERNATIONAL TRADE", "question": "Which of the following trade documents prevents understatement of prices?", "images": [], "options": {"A": "Consular invoice", "B": "Export invoice", "C": "Freight note", "D": "Mate's receipt"}, "answer": "A", "explanation": "A consular invoice is a document required by some countries for customs purposes, which includes a declaration of the value of the goods being shipped. It helps prevent the understatement of prices by providing an official record of the transaction value, which can be verified by customs authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>22", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "MONEY : QUALITIES OF MONEY", "question": "The quality of money that enable it to serve as a medium of exchange is", "images": [], "options": {"A": "acceptability", "B": "durability", "C": "portability", "D": "scarcity"}, "answer": "A", "explanation": "Acceptability refers to the quality of money that allows it to be widely accepted as a medium of exchange. For money to function effectively in an economy, it must be accepted by people in exchange for goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>23", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TERMS", "question": "Application for insurance cover could be done using a", "images": [], "options": {"A": "cover note", "B": "claim form", "C": "proposal form", "D": "renewal notice"}, "answer": "C", "explanation": "A proposal form is a document used to apply for insurance coverage. It typically includes details about the applicant and the risks to be insured, allowing the insurance company to assess the application and determine the terms of coverage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>24", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: INSURANCE : TYPES", "question": "Sharing of risks among insurance companies is", "images": [], "options": {"A": "indemnity", "B": "re-insurance", "C": "subrogation", "D": "underwriting"}, "answer": "B", "explanation": "Re-insurance is the practice of sharing risks among insurance companies. It allows insurers to protect themselves from large losses by transferring portions of risk to other insurers, thereby stabilizing their financial position.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>25", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.", "question": "An organization that provides facilities and arranges for the purchases and sale of goods is", "images": [], "options": {"A": "a ports authority", "B": "an export promotion council", "C": "a customs authority", "D": "a commodity exchange"}, "answer": "D", "explanation": "A commodity exchange is an organization that provides facilities for buying and selling commodities. It acts as a marketplace where various goods are traded, ensuring that transactions are conducted in an organized manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>26", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "TRADE : BALANCE OF PAYMENT", "question": "An example of an invisible item in the balance of payment account is", "images": [], "options": {"A": "goods exported", "B": "goods imported", "C": "salaries of expatriates", "D": "sale of assets"}, "answer": "C", "explanation": "Salaries of expatriates are considered invisible items in the balance of payments because they represent services rendered rather than tangible goods. Unlike goods exported or imported, which are visible transactions, salaries paid to expatriates fall under the category of services and are not directly linked to physical goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>27", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "Which of the following documents would be used to collect imported goods?", "images": [], "options": {"A": "Tariff note", "B": "Letter of hypothecation", "C": "Bill of lading", "D": "Bill of exchange"}, "answer": "C", "explanation": "A Bill of Lading is a document issued by a carrier to acknowledge receipt of cargo for shipment. It serves as a contract for the transportation of goods and is essential for collecting imported goods, as it provides proof of ownership and details about the shipment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>28", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE", "question": "A merit of credit is", "images": [], "options": {"A": "increase in the number of businesses", "B": "improvement in living standard", "C": "reduction in administrative cost", "D": "reduction in bad debts"}, "answer": "B", "explanation": "Improvement in living standards is a merit of credit as it indicates that access to credit can enable individuals and businesses to invest in better resources, education, and health, ultimately leading to enhanced quality of life. This is a broader economic benefit that can arise from increased credit availability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>29", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLENGES", "question": "A financial institution which offers loans to small scale businesses is a", "images": [], "options": {"A": "building society", "B": "central bank", "C": "forex bureau", "D": "micro finance institute"}, "answer": "D", "explanation": "A microfinance institute is a financial institution that provides loans to small scale businesses, particularly in developing areas where traditional banking services may not be accessible. These institutions focus on providing financial services to low-income individuals or those without access to typical banking services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>30", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Dealers in the stock exchange who buy and sell shares on their own account are", "images": [], "options": {"A": "brokers", "B": "investors", "C": "jobbers", "D": "underwriters"}, "answer": "C", "explanation": "Jobbers are dealers in the stock exchange who buy and sell shares on their own account. They act as market makers, providing liquidity to the market by trading shares for their own profit, as opposed to brokers who act on behalf of clients.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>31", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "The price quote when the exporter bears all the expenses up to the port of departure is", "images": [], "options": {"A": "F.A.S", "B": "F.I.S", "C": "F.O.B", "D": "LOCO"}, "answer": "C", "explanation": "The price quote when the exporter bears all the expenses up to the port of departure is known as F.O.B (Free On Board). This means that the seller is responsible for all costs and risks until the goods are loaded onto the shipping vessel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>32", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Use the information below to answer the question    Gibril bought shares from a company at D 40 per share and sold them to Sam at D 60 each.    Gibril sold the shares at a", "images": [], "options": {"A": "subsidy", "B": "par", "C": "premium", "D": "loss"}, "answer": "C", "explanation": "Gibril bought shares at D 40 and sold them at D 60, which means he sold them at a premium. A premium occurs when an asset is sold for more than its purchase price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>33", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES", "question": "Use the information below to answer the question    Gibril bought shares from a company at D 40 per share and sold them to Sam at D 60 each.    In his decision to buy the share at a high price, Sam is acting as  a", "images": [], "options": {"A": "stag", "B": "bull", "C": "broker", "D": "bear"}, "answer": "B", "explanation": "In this context, Sam is acting as a bull. A bull is an investor who believes that the price of a security will rise, which is why he is willing to buy shares at a higher price (D 60) than what Gibril paid (D 40).", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>34", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "An advert for the sale of cattle placed on a butcher's journal is", "images": [], "options": {"A": "mass", "B": "indirect", "C": "direct", "D": "persuasive"}, "answer": "C", "explanation": "An advert for the sale of cattle placed on a butcher's journal is considered direct advertising. Direct advertising targets specific audiences directly, in this case, potential buyers of cattle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>35", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION", "question": "The fastest means of delivering parcels is through", "images": [], "options": {"A": "telegram service", "B": "online service", "C": "haulage service", "D": "courier service"}, "answer": "D", "explanation": "The fastest means of delivering parcels is through courier service. Courier services specialize in the rapid delivery of packages and documents, often providing same-day or next-day delivery options.", "marks": "1", "difficulty": "1"}, {"id": "objective>Commerce>2025>36", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES", "question": "Which of the following medium of communication is used within an organization only?", "images": [], "options": {"A": "Memo", "B": "Handbill", "C": "Magazine", "D": "Press release"}, "answer": "A", "explanation": "A memo is a written message used for internal communication within an organization. It is typically used to inform or remind employees about policies, procedures, or other important information. Unlike handbills, magazines, or press releases, which are often intended for external audiences, memos are specifically designed for internal use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>37", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION", "question": "A body charged with the responsibility of ensuring that products being sold are of a specified requirement is a", "images": [], "options": {"A": "consumers' association", "B": "manufacturers' association", "C": "price control board", "D": "standards organization"}, "answer": "D", "explanation": "A standards organization is responsible for ensuring that products meet specific requirements and standards. These organizations develop and enforce guidelines that products must adhere to in order to ensure safety, quality, and interoperability. This is distinct from consumers' associations, manufacturers' associations, and price control boards, which have different roles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>38", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A trade fair is an example of", "images": [], "options": {"A": "sales promotion", "B": "public relations", "C": "marketing mix", "D": "customers' service"}, "answer": "A", "explanation": "A trade fair is primarily a form of sales promotion where businesses showcase their products and services to potential customers and partners. It provides an opportunity for companies to engage with their target audience, generate leads, and promote their brand, making it a key component of marketing strategies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>39", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION", "question": "The document used when goods are delivered by an independent carrier is", "images": [], "options": {"A": "advice note", "B": "bill of lading", "C": "consignment note", "D": "credit note"}, "answer": "C", "explanation": "A consignment note is a document used when goods are delivered by an independent carrier. It serves as a receipt for the goods being transported and outlines the details of the shipment. While a bill of lading is also related to shipping, it is more commonly used in the context of the contract of carriage, whereas a consignment note is specifically for the delivery process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>40", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA", "question": "A form of advertising where firms jointly finance the advertisement of their products is", "images": [], "options": {"A": "competitive advertising", "B": "direct advertising", "C": "mass advertising", "D": "persuasive advertising"}, "answer": "A", "explanation": "Competitive advertising is a form of advertising where firms jointly finance the advertisement of their products. This type of advertising is often used to promote a group of products or services that are similar in nature, allowing companies to share costs while reaching a broader audience. It contrasts with direct, mass, or persuasive advertising, which focus on individual brands or products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>41", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES", "question": "A contract of sale where the selling price includes interest is", "images": [], "options": {"A": "lease agreement", "B": "hire purchase agreement", "C": "credit sale agreement", "D": "cash sale agreement"}, "answer": "C", "explanation": "A credit sale agreement is a contract of sale where the selling price includes interest. In this type of agreement, the buyer receives the goods immediately but pays for them over time, often with interest added to the total price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>42", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITIES", "question": "An advantage of deregulation is that it", "images": [], "options": {"A": "reduces competition among businesses", "B": "reduces restrictions in business", "C": "increase access to funds", "D": "increases access to basic goods"}, "answer": "B", "explanation": "Deregulation refers to the reduction or elimination of government rules controlling how businesses operate. One of the main advantages of deregulation is that it reduces restrictions in business, allowing for more flexibility and potentially fostering competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>43", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES", "question": "A term used to identify a product is", "images": [], "options": {"A": "trademark", "B": "logo", "C": "copyright", "D": "brand name"}, "answer": "D", "explanation": "A brand name is a term used to identify a product and distinguish it from others. It is a key element of branding, which helps consumers recognize and choose products in the marketplace.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>44", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT", "question": "If Rose feeds her neighbour's son because of his inability to pick him on time, she becomes an agent by", "images": [], "options": {"A": "necessity", "B": "implication", "C": "estoppel", "D": "agreement"}, "answer": "A", "explanation": "Rose becomes an agent by necessity when she acts to protect the interests of her neighbor's son due to an emergency situation. This legal concept allows someone to act on behalf of another when that person is unable to do so, and it is necessary to prevent harm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>45", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "AIDS TO TRADE: COMMUNICATION : SERVICES", "question": "Which of the following activities is considered as pre-sale service?", "images": [], "options": {"A": "Maintenance", "B": "Installation", "C": "Home delivery", "D": "Display of goods"}, "answer": "D", "explanation": "The display of goods is considered a pre-sale service as it involves showcasing products to potential customers before they make a purchase. This activity is crucial in attracting customers and facilitating sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>46", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS UNIT: CO-OPERATIVE SOCIETIES : MEANING AND TYPES", "question": "Recruitment and placement of workers in an organization is a function of the", "images": [], "options": {"A": "finance department", "B": "human resources department", "C": "marketing department", "D": "production department"}, "answer": "B", "explanation": "The recruitment and placement of workers in an organization is primarily the function of the human resources department. This department is responsible for managing employee relations, hiring, training, and ensuring that the organization has the right personnel to meet its goals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>47", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "NATIONALIZATION AND PRIVATIZATION", "question": "A disadvantage of privatization is that", "images": [], "options": {"A": "less personal relationship exists among workers", "B": "political influence exists in business decisions", "C": "profit motive outweighs the needs to provide cheap basic goods", "D": "there is reduction in the production of goods"}, "answer": "C", "explanation": "A disadvantage of privatization is that the profit motive can outweigh the needs to provide cheap basic goods. When businesses are privatized, the focus often shifts to maximizing profits, which can lead to higher prices for essential goods and services, making them less accessible to the general population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>48", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "BUSINESS CAPITAL, PROFIT AND TURNOVER : PROFIT", "question": "Which of the following is not a business objective?", "images": [], "options": {"A": "Survival", "B": "Profitability", "C": "Growth", "D": "Competition"}, "answer": "D", "explanation": "Competition is not a business objective in itself; rather, it is a condition in the market. Business objectives typically include survival, profitability, and growth, which are goals that a business aims to achieve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>49", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "An objective of ECOWAS is to", "images": [], "options": {"A": "supervise political activities", "B": "regulate systems of taxation", "C": "provide sufficient labour", "D": "eliminate tariffs and quota"}, "answer": "D", "explanation": "One of the objectives of ECOWAS (Economic Community of West African States) is to eliminate tariffs and quotas among member states to promote trade and economic integration. This helps to facilitate easier movement of goods and services across borders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Commerce>2025>50", "subject": "Commerce", "year": "2025", "type": "Objective", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.", "question": "Which of the following countries is not a member of the Lake Chad Basin Commission?", "images": [], "options": {"A": "Nigeria", "B": "Niger", "C": "Ghana", "D": "Cameroon"}, "answer": "C", "explanation": "The Lake Chad Basin Commission (LCBC) is a regional body established in May 22,1964 by Cameroon, Chad, Niger, and Nigeria. Other countries, such as the Central African Republic and Libya, joined later.", "marks": "1", "difficulty": "2"}];